#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

namespace {

// This implementation targets modern NVIDIA GPUs (e.g. A100/H100) and uses:
//   * per-warp shared-memory histograms to reduce contention,
//   * warp-aggregated updates via __match_any_sync so equal byte values within a warp
//     collapse to one shared-memory atomic update,
//   * 16-byte vectorized loads on the aligned bulk of the input.
//
// A 256-thread block is intentional: the requested histogram range can never exceed 256 bins,
// so one thread can own one output bin during the shared-memory init and final flush steps.
constexpr int kBlockThreads  = 256;
constexpr int kWarpSize      = 32;
constexpr int kWarpsPerBlock = kBlockThreads / kWarpSize;
constexpr int kByteValues    = 256;

// One padding slot per 32 bins reduces shared-memory bank-aliasing for byte values that differ
// by multiples of 32. For 256 bins this yields 264 slots, with a few intentional holes.
constexpr int kPaddedBins = kByteValues + (kByteValues / kWarpSize);

// The hot path reads 16 bytes at a time.
constexpr unsigned int kVectorBytes = sizeof(uint4);

static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a multiple of warp size");

__device__ __forceinline__ int padded_bin_index(int value) {
    // Insert one hole every 32 bins.
    return value + (value >> 5);
}

__device__ __forceinline__ void accumulate_filtered_byte(
    unsigned int* __restrict__ warp_hist,
    unsigned char byte_value,
    int from,
    unsigned int range,
    unsigned int active_mask,
    int lane)
{
    const int value = static_cast<int>(byte_value);

    // Unsigned interval test: true iff from <= value < from + range.
    const bool in_range = static_cast<unsigned int>(value - from) < range;

    // Only the currently active lanes participate. This is important because the final iteration
    // of the grid-stride loop can leave only a subset of warp lanes active.
    const unsigned int participating = __ballot_sync(active_mask, in_range);

    if (in_range) {
        // Group all in-range lanes that saw the same byte value.
        const unsigned int group  = __match_any_sync(participating, value);
        const int leader_lane     = __ffs(group) - 1;
        const unsigned int count  = __popc(group);

        // Only one lane per equal-value group performs the shared-memory atomic update.
        if (lane == leader_lane) {
            atomicAdd(&warp_hist[padded_bin_index(value)], count);
        }
    }
}

__device__ __forceinline__ void process_packed_u32(
    unsigned int* __restrict__ warp_hist,
    unsigned int packed,
    int from,
    unsigned int range,
    unsigned int active_mask,
    int lane)
{
    // CUDA GPUs are little-endian, so the four source bytes are extracted with shifts.
    accumulate_filtered_byte(
        warp_hist,
        static_cast<unsigned char>( packed        & 0xFFu),
        from,
        range,
        active_mask,
        lane);

    accumulate_filtered_byte(
        warp_hist,
        static_cast<unsigned char>((packed >>  8) & 0xFFu),
        from,
        range,
        active_mask,
        lane);

    accumulate_filtered_byte(
        warp_hist,
        static_cast<unsigned char>((packed >> 16) & 0xFFu),
        from,
        range,
        active_mask,
        lane);

    accumulate_filtered_byte(
        warp_hist,
        static_cast<unsigned char>((packed >> 24) & 0xFFu),
        from,
        range,
        active_mask,
        lane);
}

__global__ __launch_bounds__(kBlockThreads, 4)
void histogram_range_kernel(
    const char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    // One full 256-bin histogram per warp, indexed by absolute byte value [0,255].
    // This keeps the update path simple and fast after the range test passes.
    __shared__ unsigned int warp_hist[kWarpsPerBlock][kPaddedBins];

    const unsigned int range = static_cast<unsigned int>(to - from + 1);
    const int lane           = static_cast<int>(threadIdx.x & (kWarpSize - 1));
    const int warp_id        = static_cast<int>(threadIdx.x >> 5);

    unsigned int* const warp_bins = warp_hist[warp_id];

    // Only bins in the requested range are ever touched or read, so only those shared-memory
    // slots need to be initialized even though the per-warp histogram covers all byte values.
    if (threadIdx.x < range) {
        const int value  = from + static_cast<int>(threadIdx.x);
        const int padded = padded_bin_index(value);

        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            warp_hist[w][padded] = 0u;
        }
    }

    __syncthreads();

    // Interpret the input bytes as unsigned ordinals [0,255] regardless of host-side char signedness.
    const unsigned char* const input_u8 = reinterpret_cast<const unsigned char*>(input);

    // Align the bulk path to 16-byte vector loads. The unaligned prefix is shorter than one vector
    // load, so block 0 handles it cheaply.
    const unsigned int misalignment =
        static_cast<unsigned int>(reinterpret_cast<uintptr_t>(input_u8) & (kVectorBytes - 1u));

    unsigned int prefix = (kVectorBytes - misalignment) & (kVectorBytes - 1u);
    if (prefix > inputSize) {
        prefix = inputSize;
    }

    if (blockIdx.x == 0 && threadIdx.x < prefix) {
        const unsigned int active_mask = __activemask();
        accumulate_filtered_byte(
            warp_bins,
            input_u8[threadIdx.x],
            from,
            range,
            active_mask,
            lane);
    }

    const unsigned int remaining   = inputSize - prefix;
    const unsigned int vec16_count = remaining / kVectorBytes;
    const uint4* const input16     = reinterpret_cast<const uint4*>(input_u8 + prefix);

    const unsigned int global_tid  = blockIdx.x * kBlockThreads + threadIdx.x;
    const unsigned int grid_stride = kBlockThreads * gridDim.x;

    // Main streaming loop over aligned 16-byte chunks.
    for (unsigned int idx = global_tid; idx < vec16_count; idx += grid_stride) {
        const unsigned int active_mask = __activemask();
        const uint4 v = input16[idx];

        process_packed_u32(warp_bins, v.x, from, range, active_mask, lane);
        process_packed_u32(warp_bins, v.y, from, range, active_mask, lane);
        process_packed_u32(warp_bins, v.z, from, range, active_mask, lane);
        process_packed_u32(warp_bins, v.w, from, range, active_mask, lane);
    }

    // Tail shorter than one vector load: again, block 0 handles it.
    const unsigned int tail_base  = prefix + vec16_count * kVectorBytes;
    const unsigned int tail_count = inputSize - tail_base;

    if (blockIdx.x == 0 && threadIdx.x < tail_count) {
        const unsigned int active_mask = __activemask();
        accumulate_filtered_byte(
            warp_bins,
            input_u8[tail_base + threadIdx.x],
            from,
            range,
            active_mask,
            lane);
    }

    __syncthreads();

    // Reduce the per-warp shared histograms into the caller-provided output.
    // Each block emits at most one global atomic add per requested bin.
    if (threadIdx.x < range) {
        const int value  = from + static_cast<int>(threadIdx.x);
        const int padded = padded_bin_index(value);

        unsigned int sum = 0u;
        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += warp_hist[w][padded];
        }

        if (sum != 0u) {
            atomicAdd(histogram + threadIdx.x, sum);
        }
    }
}

} // namespace

void run_histogram(
    const char *input,
    unsigned int *histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    // The input and output pointers are device pointers allocated by cudaMalloc.
    // The function performs no host-device copies and no synchronization.
    // Because the signature has no stream parameter, it uses the default stream.
    const unsigned int range = static_cast<unsigned int>(to - from + 1);

    if (cudaMemsetAsync(
            histogram,
            0,
            static_cast<std::size_t>(range) * sizeof(unsigned int),
            0) != cudaSuccess) {
        return;
    }

    if (inputSize == 0u) {
        return;
    }

    // Launch a persistent-style grid sized to the current device's occupancy for this kernel.
    // Extra work is handled by the kernel's grid-stride loop, which avoids launching excess blocks
    // that would only add another histogram-flush pass.
    unsigned int max_blocks = 1u;
    int device = 0;
    int sm_count = 0;
    int active_blocks_per_sm = 0;

    if (cudaGetDevice(&device) == cudaSuccess &&
        cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device) == cudaSuccess &&
        cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &active_blocks_per_sm,
            histogram_range_kernel,
            kBlockThreads,
            0) == cudaSuccess &&
        sm_count > 0 &&
        active_blocks_per_sm > 0) {
        max_blocks = static_cast<unsigned int>(sm_count) *
                     static_cast<unsigned int>(active_blocks_per_sm);
    }

    if (max_blocks == 0u) {
        max_blocks = 1u;
    }

    // Approximate work in units of 16 input bytes. The scalar prefix/tail are at most 15 bytes each
    // and do not materially affect launch sizing.
    const unsigned int work_items = (inputSize + kVectorBytes - 1u) / kVectorBytes;

    unsigned int blocks = (work_items + kBlockThreads - 1u) / kBlockThreads;
    if (blocks == 0u) {
        blocks = 1u;
    }
    if (blocks > max_blocks) {
        blocks = max_blocks;
    }

    histogram_range_kernel<<<blocks, kBlockThreads, 0, 0>>>(
        input,
        histogram,
        inputSize,
        from,
        to);
}

#include <cuda_runtime.h>
#include <cstddef>

namespace
{
/*
 * Range-restricted byte histogram specialized for modern NVIDIA GPUs.
 *
 * The public API uses `char*`, but histogramming is defined on byte ordinals 0..255,
 * so the kernel interprets the input as unsigned bytes.
 *
 * Hot-loop design:
 *   1) Each warp owns a private shared-memory sub-histogram.
 *   2) Input is read as 16-byte vectors (`uint4`) for efficient global loads.
 *   3) `__match_any_sync` groups lanes that saw the same bin in the current byte
 *      position; only the leader lane updates the warp-private histogram with the
 *      whole peer count. This removes atomics from the hot path.
 *   4) At the end of the block, per-warp histograms are reduced and each block emits
 *      only one global update per logical output bin.
 */
constexpr int HISTOGRAM_BLOCK_SIZE = 256;
constexpr int HISTOGRAM_WARP_SIZE = 32;
constexpr int HISTOGRAM_WARPS_PER_BLOCK = HISTOGRAM_BLOCK_SIZE / HISTOGRAM_WARP_SIZE;
constexpr int HISTOGRAM_MAX_BINS = 256;

/*
 * One pad slot per 32 logical bins. This cheap padding breaks the worst-case shared
 * memory bank aliasing for bins separated by multiples of 32.
 */
constexpr int HISTOGRAM_SHARED_PAD = HISTOGRAM_MAX_BINS / HISTOGRAM_WARP_SIZE;      // 8
constexpr int HISTOGRAM_SHARED_STRIDE = HISTOGRAM_MAX_BINS + HISTOGRAM_SHARED_PAD;  // 264
constexpr int HISTOGRAM_SHARED_WORDS = HISTOGRAM_WARPS_PER_BLOCK * HISTOGRAM_SHARED_STRIDE;

/*
 * 256 threads/block => 8 warps/block. Capping the grid to 4 blocks/SM gives 32 resident
 * warps/SM, which is enough to saturate this kernel on A100/H100-class parts while keeping
 * the final global flush relatively small.
 */
constexpr int HISTOGRAM_TARGET_BLOCKS_PER_SM = 4;

constexpr unsigned int HISTOGRAM_VECTOR_BYTES = 16u;
constexpr unsigned int HISTOGRAM_BLOCK_PASS_BYTES =
    static_cast<unsigned int>(HISTOGRAM_BLOCK_SIZE) * HISTOGRAM_VECTOR_BYTES;
constexpr unsigned int HISTOGRAM_INVALID_KEY = 0xFFFFFFFFu;

static_assert(HISTOGRAM_BLOCK_SIZE % HISTOGRAM_WARP_SIZE == 0, "Block size must be warp-aligned.");
static_assert(sizeof(uint4) == HISTOGRAM_VECTOR_BYTES, "Kernel assumes 16-byte uint4 loads.");

__device__ __forceinline__ unsigned int smem_bin_index(const unsigned int bin)
{
    return bin + (bin >> 5);
}

__device__ __forceinline__ void accumulate_byte_warp_private(const unsigned int byte_value,
                                                             unsigned int* const warp_hist,
                                                             const unsigned int from_u,
                                                             const unsigned int range_u,
                                                             const unsigned int lane_id)
{
    /*
     * Unsigned subtraction + one range comparison filters both sides of the inclusive
     * [from, to] interval: valid iff 0 <= byte_value - from_u < range_u.
     */
    const unsigned int bin = byte_value - from_u;
    const bool valid = (bin < range_u);

    /*
     * All currently active lanes must participate in __match_any_sync with the same mask.
     * Out-of-range bytes therefore use a sentinel key rather than skipping the intrinsic.
     */
    const unsigned int active = __activemask();
    const unsigned int key = valid ? bin : HISTOGRAM_INVALID_KEY;
    const unsigned int peers = __match_any_sync(active, key);

    /*
     * Only one lane per equal-key subgroup updates shared memory, adding the number of
     * peer lanes in one shot. Because each warp owns a private histogram slice, this is
     * a plain shared-memory add, not an atomic.
     */
    const unsigned int leader_lane = static_cast<unsigned int>(__ffs(static_cast<int>(peers)) - 1);
    if (valid && lane_id == leader_lane)
    {
        warp_hist[smem_bin_index(bin)] += __popc(peers);
    }
}

__device__ __forceinline__ void accumulate_word_warp_private(const unsigned int word,
                                                             unsigned int* const warp_hist,
                                                             const unsigned int from_u,
                                                             const unsigned int range_u,
                                                             const unsigned int lane_id)
{
    accumulate_byte_warp_private((word >> 0)  & 0xFFu, warp_hist, from_u, range_u, lane_id);
    accumulate_byte_warp_private((word >> 8)  & 0xFFu, warp_hist, from_u, range_u, lane_id);
    accumulate_byte_warp_private((word >> 16) & 0xFFu, warp_hist, from_u, range_u, lane_id);
    accumulate_byte_warp_private((word >> 24) & 0xFFu, warp_hist, from_u, range_u, lane_id);
}

__global__ __launch_bounds__(HISTOGRAM_BLOCK_SIZE, HISTOGRAM_TARGET_BLOCKS_PER_SM)
void histogram_range_kernel(const unsigned char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            const unsigned int inputSize,
                            const unsigned int from_u,
                            const unsigned int range_u)
{
    /*
     * Fixed 8.25 KiB/block shared footprint:
     *   8 warp-private histograms * 264 padded counters/warp.
     */
    __shared__ unsigned int shared_hist[HISTOGRAM_SHARED_WORDS];

    /* Zero all warp-private histograms cooperatively. */
#pragma unroll
    for (unsigned int i = threadIdx.x; i < static_cast<unsigned int>(HISTOGRAM_SHARED_WORDS); i += HISTOGRAM_BLOCK_SIZE)
    {
        shared_hist[i] = 0u;
    }
    __syncthreads();

    const unsigned int lane_id = threadIdx.x & (HISTOGRAM_WARP_SIZE - 1);
    const unsigned int warp_id = threadIdx.x >> 5;
    unsigned int* const warp_hist = &shared_hist[warp_id * HISTOGRAM_SHARED_STRIDE];

    const unsigned int global_thread = blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned int total_threads = gridDim.x * blockDim.x;

    /*
     * The problem statement says `input` comes from cudaMalloc, so the base address is
     * naturally aligned for 16-byte vector loads.
     */
    const unsigned int vectorized_count = inputSize / HISTOGRAM_VECTOR_BYTES;
    const uint4* const vector_input = reinterpret_cast<const uint4*>(input);

    for (unsigned int vec_idx = global_thread; vec_idx < vectorized_count; vec_idx += total_threads)
    {
        const uint4 packed = vector_input[vec_idx];
        accumulate_word_warp_private(packed.x, warp_hist, from_u, range_u, lane_id);
        accumulate_word_warp_private(packed.y, warp_hist, from_u, range_u, lane_id);
        accumulate_word_warp_private(packed.z, warp_hist, from_u, range_u, lane_id);
        accumulate_word_warp_private(packed.w, warp_hist, from_u, range_u, lane_id);
    }

    /* Handle the final 0..15 bytes that do not fit in a uint4. */
    const unsigned int tail_start = vectorized_count * HISTOGRAM_VECTOR_BYTES;
    for (unsigned int i = tail_start + global_thread; i < inputSize; i += total_threads)
    {
        accumulate_byte_warp_private(static_cast<unsigned int>(input[i]), warp_hist, from_u, range_u, lane_id);
    }

    __syncthreads();

    /* Reduce per-warp histograms into the compact output range [0, range_u). */
    const bool single_block = (gridDim.x == 1u);
    if (threadIdx.x < range_u)
    {
        const unsigned int bin = threadIdx.x;
        const unsigned int padded_bin = smem_bin_index(bin);

        unsigned int sum = 0u;
#pragma unroll
        for (int w = 0; w < HISTOGRAM_WARPS_PER_BLOCK; ++w)
        {
            sum += shared_hist[w * HISTOGRAM_SHARED_STRIDE + padded_bin];
        }

        /*
         * For a one-block launch there is no inter-block contention, so bypass the
         * global atomic entirely. Otherwise each block contributes once per bin.
         */
        if (single_block)
        {
            histogram[bin] = sum;
        }
        else if (sum != 0u)
        {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

inline unsigned int div_up_u32(const unsigned int n, const unsigned int d)
{
    return (n + d - 1u) / d;
}

inline int histogram_sm_count()
{
    /*
     * CUDA's current device is per host thread, so cache the SM count per host thread too.
     * This avoids a device-attribute query on every invocation while remaining correct if
     * different host threads use different current devices.
     */
    static thread_local int cached_device = -1;
    static thread_local int cached_sm_count = 1;

    int device = 0;
    if (cudaGetDevice(&device) != cudaSuccess)
    {
        return cached_sm_count;
    }

    if (device != cached_device)
    {
        int sm_count = 0;
        if (cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device) == cudaSuccess &&
            sm_count > 0)
        {
            cached_sm_count = sm_count;
        }
        else
        {
            cached_sm_count = 1;
        }
        cached_device = device;
    }

    return cached_sm_count;
}
} // namespace

void run_histogram(const char *input, unsigned int *histogram, unsigned int inputSize, int from, int to)
{
    /* Defensive validation; the prompt guarantees valid bounds, so this is not on the hot path. */
    if (from < 0 || to > 255 || from > to)
    {
        return;
    }

    /* Compact output: histogram[i] counts byte value (from + i). */
    const unsigned int range_u = static_cast<unsigned int>(to - from + 1);
    if (range_u == 0u || range_u > static_cast<unsigned int>(HISTOGRAM_MAX_BINS))
    {
        return;
    }

    /* The output buffer is defined as a fresh histogram, not an accumulator. */
    const size_t histogram_bytes = static_cast<size_t>(range_u) * sizeof(unsigned int);

    /*
     * The required API has no stream parameter, so this function enqueues work on the
     * default stream and returns immediately. Synchronization is intentionally left
     * to the caller, exactly as requested.
     */
    cudaMemsetAsync(histogram, 0, histogram_bytes);

    if (inputSize == 0u)
    {
        return;
    }

    /*
     * Grid-stride loops make large grids unnecessary. Launch a small multiple of SM count
     * so each block processes many bytes before the final global flush.
     */
    unsigned int grid = div_up_u32(inputSize, HISTOGRAM_BLOCK_PASS_BYTES);
    const unsigned int max_grid =
        static_cast<unsigned int>(histogram_sm_count()) * static_cast<unsigned int>(HISTOGRAM_TARGET_BLOCKS_PER_SM);
    if (grid > max_grid)
    {
        grid = max_grid;
    }

    histogram_range_kernel<<<grid, HISTOGRAM_BLOCK_SIZE>>>(
        reinterpret_cast<const unsigned char*>(input),
        histogram,
        inputSize,
        static_cast<unsigned int>(from),
        range_u);
}

#include <cuda_runtime.h>
#include <cstddef>

/*
 * Histogram implementation tuned for modern NVIDIA data-center GPUs (A100/H100 class).
 *
 * Design choices:
 * - The histogram range is at most 256 bins, so a block can cheaply keep private partial histograms
 *   in shared memory.
 * - Each warp owns its own shared-memory sub-histogram. This removes inter-warp update contention
 *   while keeping the shared-memory footprint tiny: 8 warps * 256 bins * 4 bytes = 8 KB/block.
 * - Input is scanned with grid-stride loops and 16-byte vector loads (uint4). The prompt guarantees
 *   cudaMalloc-allocated buffers, so using the original allocation pointer yields naturally aligned
 *   vector loads on the intended fast path.
 * - For ASCII-sized ranges and smaller, duplicate bin hits inside a warp are common for text. In that
 *   case we use warp-aggregated updates (__ballot_sync + __match_any_sync) so that each unique bin
 *   touched by a warp step performs only one shared-memory atomicAdd.
 * - For wider ranges, duplicate probability drops and plain shared-memory atomics to warp-private
 *   histograms are usually cheaper.
 * - After the local accumulation phase, each block reduces its warp-private histograms once into the
 *   final global histogram.
 *
 * The host launcher intentionally does not synchronize; the caller owns all host/device synchronization,
 * exactly as requested.
 */

namespace histogram_detail {

constexpr int kBlockThreads = 256;
constexpr int kWarpSize = 32;
constexpr int kWarpsPerBlock = kBlockThreads / kWarpSize;
constexpr int kVectorBytes = sizeof(uint4);
constexpr int kWarpAggregateThresholdBins = 128;  // Text-heavy / ASCII-sized ranges benefit most.

static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a multiple of warp size.");
static_assert(kVectorBytes == 16, "This kernel assumes uint4 is 16 bytes.");

inline std::size_t ceil_div(std::size_t n, std::size_t d) {
    return (n + d - 1) / d;
}

/*
 * Update policy specialization:
 *   WarpAggregate = true  -> use warp-aggregated shared-memory atomics.
 *   WarpAggregate = false -> direct shared-memory atomic per byte.
 */
template <bool WarpAggregate>
struct HistogramUpdater;

template <>
struct HistogramUpdater<true> {
    __device__ __forceinline__ static void add_byte(unsigned int byte_value,
                                                    unsigned int* warp_hist,
                                                    unsigned int from,
                                                    unsigned int range,
                                                    unsigned int lane,
                                                    unsigned int active_mask) {
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 700)
        const unsigned int rel = byte_value - from;
        const bool in_range = (rel < range);

        // Only lanes currently active in this divergent region participate in the ballot.
        const unsigned int valid_mask = __ballot_sync(active_mask, in_range);

        // Only lanes that actually hit the requested range participate in __match_any_sync.
        // Each unique bin in the warp elects one leader lane that performs a single atomicAdd
        // with the number of peers hitting the same bin.
        if (in_range) {
            const unsigned int peers = __match_any_sync(valid_mask, rel);
            if (lane == static_cast<unsigned int>(__ffs(peers) - 1)) {
                atomicAdd(warp_hist + rel, static_cast<unsigned int>(__popc(peers)));
            }
        }
#else
        // Fallback for pre-Volta architectures. The stated target is A100/H100, so this path is
        // not performance-critical; it exists only to keep the code broadly compilable.
        (void)lane;
        (void)active_mask;
        const unsigned int rel = byte_value - from;
        if (rel < range) {
            atomicAdd(warp_hist + rel, 1u);
        }
#endif
    }
};

template <>
struct HistogramUpdater<false> {
    __device__ __forceinline__ static void add_byte(unsigned int byte_value,
                                                    unsigned int* warp_hist,
                                                    unsigned int from,
                                                    unsigned int range,
                                                    unsigned int /*lane*/,
                                                    unsigned int /*active_mask*/) {
        const unsigned int rel = byte_value - from;
        if (rel < range) {
            atomicAdd(warp_hist + rel, 1u);
        }
    }
};

template <bool WarpAggregate>
__device__ __forceinline__ void add_word(unsigned int word,
                                         unsigned int* warp_hist,
                                         unsigned int from,
                                         unsigned int range,
                                         unsigned int lane,
                                         unsigned int active_mask) {
#pragma unroll
    for (int i = 0; i < 4; ++i) {
        HistogramUpdater<WarpAggregate>::add_byte(word & 0xFFu, warp_hist, from, range, lane, active_mask);
        word >>= 8;
    }
}

template <bool WarpAggregate>
__global__ __launch_bounds__(kBlockThreads)
void histogram_range_kernel(const char* __restrict__ input_chars,
                            unsigned int* __restrict__ histogram,
                            std::size_t input_size,
                            unsigned int from,
                            unsigned int range) {
    extern __shared__ unsigned int shared_hists[];

    const unsigned int tid = threadIdx.x;
    const unsigned int warp_id = tid >> 5;
    const unsigned int lane = tid & (kWarpSize - 1u);

    // One private histogram per warp.
    unsigned int* const warp_hist = shared_hists + warp_id * range;

    // Zero all warp-private histograms cooperatively.
    const unsigned int total_shared_bins = static_cast<unsigned int>(kWarpsPerBlock) * range;
    for (unsigned int i = tid; i < total_shared_bins; i += kBlockThreads) {
        shared_hists[i] = 0u;
    }
    __syncthreads();

    const unsigned char* const input = reinterpret_cast<const unsigned char*>(input_chars);
    const uint4* const vec_input = reinterpret_cast<const uint4*>(input);

    const std::size_t vec_count = input_size / kVectorBytes;
    const std::size_t global_thread = static_cast<std::size_t>(blockIdx.x) * kBlockThreads + tid;
    const std::size_t grid_stride = static_cast<std::size_t>(gridDim.x) * kBlockThreads;

    // Main vectorized path: each thread consumes 16 bytes per iteration.
    for (std::size_t vec_idx = global_thread; vec_idx < vec_count; vec_idx += grid_stride) {
        const uint4 v = vec_input[vec_idx];
        const unsigned int active_mask = __activemask();

        add_word<WarpAggregate>(v.x, warp_hist, from, range, lane, active_mask);
        add_word<WarpAggregate>(v.y, warp_hist, from, range, lane, active_mask);
        add_word<WarpAggregate>(v.z, warp_hist, from, range, lane, active_mask);
        add_word<WarpAggregate>(v.w, warp_hist, from, range, lane, active_mask);
    }

    // Tail path for the last [0, 15] bytes. Reusing the same update machinery keeps behavior
    // consistent even under partial-warp activity.
    const std::size_t tail_begin = vec_count * kVectorBytes;
    for (std::size_t idx = tail_begin + global_thread; idx < input_size; idx += grid_stride) {
        const unsigned int active_mask = __activemask();
        HistogramUpdater<WarpAggregate>::add_byte(static_cast<unsigned int>(input[idx]),
                                                  warp_hist,
                                                  from,
                                                  range,
                                                  lane,
                                                  active_mask);
    }

    __syncthreads();

    // Reduce warp-private histograms to the final global histogram.
    for (unsigned int bin = tid; bin < range; bin += kBlockThreads) {
        unsigned int sum = 0u;
#pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += shared_hists[w * range + bin];
        }
        if (sum != 0u) {
            atomicAdd(histogram + bin, sum);
        }
    }
}

}  // namespace histogram_detail

void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    const unsigned int range = static_cast<unsigned int>(to - from + 1);
    const unsigned int from_u = static_cast<unsigned int>(from);
    const std::size_t histogram_bytes = static_cast<std::size_t>(range) * sizeof(unsigned int);

    // The output must contain exactly the requested histogram, not an accumulation onto old data.
    // Use the default stream because the interface does not provide a stream parameter.
    cudaMemsetAsync(histogram, 0, histogram_bytes, 0);

    // No input bytes => a zeroed histogram is already the correct answer.
    if (inputSize == 0) {
        return;
    }

    int device = 0;
    int sm_count = 1;
    if (cudaGetDevice(&device) == cudaSuccess) {
        if (cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device) != cudaSuccess || sm_count < 1) {
            sm_count = 1;
        }
    }

    const bool use_warp_aggregate = (range <= histogram_detail::kWarpAggregateThresholdBins);
    const std::size_t shared_bytes =
        static_cast<std::size_t>(histogram_detail::kWarpsPerBlock) * range * sizeof(unsigned int);

    // Use occupancy to size the grid to one full device wave of resident blocks.
    int active_blocks_per_sm = 1;
    cudaError_t occ_status = cudaSuccess;
    if (use_warp_aggregate) {
        occ_status = cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &active_blocks_per_sm,
            histogram_detail::histogram_range_kernel<true>,
            histogram_detail::kBlockThreads,
            shared_bytes);
    } else {
        occ_status = cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &active_blocks_per_sm,
            histogram_detail::histogram_range_kernel<false>,
            histogram_detail::kBlockThreads,
            shared_bytes);
    }
    if (occ_status != cudaSuccess || active_blocks_per_sm < 1) {
        active_blocks_per_sm = 1;
    }

    const int max_blocks = sm_count * active_blocks_per_sm;

    // The main loop consumes 16 bytes per work item. A single occupancy-saturating wave is enough,
    // because the kernel uses grid-stride loops to cover arbitrarily large inputs.
    const std::size_t work_items =
        histogram_detail::ceil_div(static_cast<std::size_t>(inputSize),
                                   static_cast<std::size_t>(histogram_detail::kVectorBytes));
    const std::size_t blocks_needed =
        histogram_detail::ceil_div(work_items,
                                   static_cast<std::size_t>(histogram_detail::kBlockThreads));

    int blocks = max_blocks;
    if (blocks_needed < static_cast<std::size_t>(max_blocks)) {
        blocks = static_cast<int>(blocks_needed);
    }
    if (blocks < 1) {
        blocks = 1;
    }

    if (use_warp_aggregate) {
        histogram_detail::histogram_range_kernel<true>
            <<<blocks, histogram_detail::kBlockThreads, shared_bytes>>>(
                input,
                histogram,
                static_cast<std::size_t>(inputSize),
                from_u,
                range);
    } else {
        histogram_detail::histogram_range_kernel<false>
            <<<blocks, histogram_detail::kBlockThreads, shared_bytes>>>(
                input,
                histogram,
                static_cast<std::size_t>(inputSize),
                from_u,
                range);
    }

    // Intentionally no synchronization here. The caller owns synchronization and error handling.
}

#include <cuda_runtime.h>
#include <stdint.h>

// Restricted byte-range histogram for a device-resident char buffer.
//
// Design choices aimed at modern data-center GPUs (A100/H100):
// - The requested histogram has at most 256 bins, so a full per-block histogram fits easily in shared memory.
// - To cut shared-memory contention further, each warp owns a private histogram slice in shared memory.
// - The input is consumed with 16-byte vector loads (uint4) after peeling a tiny scalar prefix to guarantee
//   alignment even if the caller passes an offset pointer into a cudaMalloc allocation.
// - Within each warp, __match_any_sync aggregates identical byte values so repeated lanes issue one shared
//   atomicAdd with the popcount of participating lanes instead of many contending atomics.
// - The host wrapper launches only one occupancy-sized wave of blocks because the kernel already uses
//   grid-stride loops; oversubscribing the grid would only increase the final global histogram merge cost.

namespace
{
constexpr int          kWarpSize       = 32;
constexpr int          kBlockThreads   = 256;
constexpr int          kWarpsPerBlock  = kBlockThreads / kWarpSize;
constexpr unsigned int kBytesPerVector = 16u;
constexpr int          kMinBlocksPerSM = 4;

static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a multiple of warp size.");
static_assert(sizeof(uint4) == kBytesPerVector, "uint4 must be 16 bytes.");

// Update one warp-private shared-memory histogram bin.
//
// active_mask is passed in from the surrounding loop iteration instead of recomputing it here.
// That is both cheaper and correct for partially active warps in the last grid-stride iteration.
static __device__ __forceinline__
void update_warp_private_hist(unsigned int* __restrict__ warp_hist,
                              int from,
                              unsigned int num_bins,
                              unsigned int byte_value,
                              unsigned int active_mask,
                              int lane)
{
    const int  bin      = static_cast<int>(byte_value) - from;
    const bool in_range = static_cast<unsigned int>(bin) < num_bins;

    const unsigned int valid_mask = __ballot_sync(active_mask, in_range);
    if (!in_range)
    {
        return;
    }

    const unsigned int peer_mask   = __match_any_sync(valid_mask, bin);
    const int          leader_lane = __ffs(static_cast<int>(peer_mask)) - 1;

    if (lane == leader_lane)
    {
        atomicAdd(warp_hist + bin, static_cast<unsigned int>(__popc(peer_mask)));
    }
}

// Process four adjacent bytes packed into one 32-bit word.
static __device__ __forceinline__
void process_packed_u32(unsigned int packed,
                        unsigned int* __restrict__ warp_hist,
                        int from,
                        unsigned int num_bins,
                        unsigned int active_mask,
                        int lane)
{
    update_warp_private_hist(warp_hist, from, num_bins,  packed        & 0xFFu, active_mask, lane);
    update_warp_private_hist(warp_hist, from, num_bins, (packed >>  8) & 0xFFu, active_mask, lane);
    update_warp_private_hist(warp_hist, from, num_bins, (packed >> 16) & 0xFFu, active_mask, lane);
    update_warp_private_hist(warp_hist, from, num_bins,  packed >> 24,          active_mask, lane);
}

template <int BLOCK_THREADS>
__global__ __launch_bounds__(BLOCK_THREADS, kMinBlocksPerSM)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int input_size,
                            int from,
                            unsigned int num_bins)
{
    constexpr int WARPS_PER_BLOCK = BLOCK_THREADS / kWarpSize;

    // Shared layout is [warp0 bins][warp1 bins]...[warpN bins].
    extern __shared__ unsigned int s_warp_histograms[];

    const int tid      = static_cast<int>(threadIdx.x);
    const int lane     = tid & (kWarpSize - 1);
    const int warp_id  = tid >> 5;
    const int bins_i   = static_cast<int>(num_bins);
    const int sh_count = WARPS_PER_BLOCK * bins_i;

    unsigned int* const warp_hist = s_warp_histograms + warp_id * bins_i;

    // Zero the warp-private block histogram.
    for (int i = tid; i < sh_count; i += BLOCK_THREADS)
    {
        s_warp_histograms[i] = 0u;
    }
    __syncthreads();

    const unsigned int global_thread = static_cast<unsigned int>(blockIdx.x) * static_cast<unsigned int>(BLOCK_THREADS) +
                                       static_cast<unsigned int>(tid);
    const unsigned int total_threads = static_cast<unsigned int>(gridDim.x) * static_cast<unsigned int>(BLOCK_THREADS);

    // Interpret the input as raw bytes. This avoids any signed-char ambiguity for values 128..255.
    const unsigned char* const input_bytes = reinterpret_cast<const unsigned char*>(input);

    // Peel a small scalar prefix to guarantee 16-byte alignment for the main uint4 vectorized path.
    const uintptr_t    addr         = reinterpret_cast<uintptr_t>(input_bytes);
    const unsigned int misalignment = static_cast<unsigned int>(addr & static_cast<uintptr_t>(kBytesPerVector - 1u));

    unsigned int scalar_prefix = 0u;
    if (misalignment != 0u)
    {
        scalar_prefix = kBytesPerVector - misalignment;
        if (scalar_prefix > input_size)
        {
            scalar_prefix = input_size;
        }
    }

    // Scalar prefix.
    for (unsigned int idx = global_thread; idx < scalar_prefix; idx += total_threads)
    {
        const unsigned int active_mask = __activemask();
        update_warp_private_hist(
            warp_hist,
            from,
            num_bins,
            static_cast<unsigned int>(input_bytes[idx]),
            active_mask,
            lane);
    }

    // Vectorized main body: 16 bytes per thread per iteration.
    const unsigned int   main_bytes    = input_size - scalar_prefix;
    const unsigned int   num_vecs      = main_bytes / kBytesPerVector;
    const unsigned char* aligned_bytes = input_bytes + scalar_prefix;
    const uint4* const   input_vec     = reinterpret_cast<const uint4*>(aligned_bytes);

    for (unsigned int vec = global_thread; vec < num_vecs; vec += total_threads)
    {
        const unsigned int active_mask = __activemask();
        const uint4        v           = input_vec[vec];

        process_packed_u32(v.x, warp_hist, from, num_bins, active_mask, lane);
        process_packed_u32(v.y, warp_hist, from, num_bins, active_mask, lane);
        process_packed_u32(v.z, warp_hist, from, num_bins, active_mask, lane);
        process_packed_u32(v.w, warp_hist, from, num_bins, active_mask, lane);
    }

    // Scalar tail after the vectorized section.
    const unsigned int tail_base  = scalar_prefix + num_vecs * kBytesPerVector;
    const unsigned int tail_bytes = main_bytes & (kBytesPerVector - 1u);

    for (unsigned int t = global_thread; t < tail_bytes; t += total_threads)
    {
        const unsigned int active_mask = __activemask();
        update_warp_private_hist(
            warp_hist,
            from,
            num_bins,
            static_cast<unsigned int>(input_bytes[tail_base + t]),
            active_mask,
            lane);
    }

    __syncthreads();

    // Reduce warp-private shared histograms into the final global histogram.
    // One atomicAdd per non-zero bin per block is much cheaper than atomically updating global memory per byte.
    for (unsigned int bin = static_cast<unsigned int>(tid); bin < num_bins; bin += static_cast<unsigned int>(BLOCK_THREADS))
    {
        const int bin_i = static_cast<int>(bin);
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < WARPS_PER_BLOCK; ++w)
        {
            sum += s_warp_histograms[w * bins_i + bin_i];
        }

        if (sum != 0u)
        {
            atomicAdd(histogram + bin, sum);
        }
    }
}

} // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // The problem statement guarantees a valid inclusive range, but this keeps the wrapper safe if misused.
    // Supporting from == to is harmless even though the prompt says from < to.
    if (from < 0 || to > 255 || from > to)
    {
        return;
    }

    const unsigned int num_bins = static_cast<unsigned int>(to - from + 1);

    // As requested, this wrapper is asynchronous: it does not synchronize and it does not force error handling.
    // The caller can observe launch/memset errors later via cudaGetLastError/cudaStreamSynchronize/etc.
    (void)cudaMemsetAsync(histogram, 0, static_cast<size_t>(num_bins) * sizeof(unsigned int), 0);

    if (inputSize == 0u)
    {
        return;
    }

    const size_t shared_bytes = static_cast<size_t>(kWarpsPerBlock) *
                                static_cast<size_t>(num_bins) *
                                sizeof(unsigned int);

    int device = 0;
    int sm_count = 1;
    int active_blocks_per_sm = 1;

    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    (void)cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &active_blocks_per_sm,
        histogram_range_kernel<kBlockThreads>,
        kBlockThreads,
        shared_bytes);

    if (sm_count < 1)
    {
        sm_count = 1;
    }
    if (active_blocks_per_sm < 1)
    {
        active_blocks_per_sm = 1;
    }

    // Approximate work in units of 16-byte chunks, matching the main vectorized path.
    const unsigned int work_chunks =
        (inputSize / kBytesPerVector) +
        (((inputSize & (kBytesPerVector - 1u)) != 0u) ? 1u : 0u);

    const unsigned int blocks_by_work =
        (work_chunks + static_cast<unsigned int>(kBlockThreads) - 1u) /
        static_cast<unsigned int>(kBlockThreads);

    // Launch one occupancy-sized wave of CTAs at most. The kernel is grid-stride, so more CTAs would only add
    // extra block-level global histogram merges without increasing steady-state throughput.
    const unsigned int max_resident_blocks =
        static_cast<unsigned int>(sm_count) *
        static_cast<unsigned int>(active_blocks_per_sm);

    unsigned int grid = (blocks_by_work < max_resident_blocks) ? blocks_by_work : max_resident_blocks;
    if (grid == 0u)
    {
        grid = 1u;
    }

    histogram_range_kernel<kBlockThreads>
        <<<static_cast<int>(grid), kBlockThreads, shared_bytes, 0>>>(
            input,
            histogram,
            inputSize,
            from,
            num_bins);
}

#include <cuda_runtime.h>

/*
 * Range-restricted byte histogram for a device-resident text buffer.
 *
 * Optimization strategy tuned for modern NVIDIA data-center GPUs:
 * - 256-thread CTAs: this gives 8 warps/CTA and exactly one thread per possible output bin
 *   during the final block reduction (the requested range is at most 256 bytes wide).
 * - One 256-bin shared histogram per warp: 8 warps * 256 bins * 4 bytes = 8 KiB/CTA, which is
 *   cheap on A100/H100 and removes inter-warp contention in the hot path.
 * - The shared histograms are indexed by the raw byte value 0..255, not by (value - from).
 *   That keeps the inner loop simple and avoids variable-sized shared-memory indexing.
 * - The input buffer is guaranteed by the problem statement to come from cudaMalloc, so its base
 *   pointer is naturally aligned for 16-byte uint4 loads.
 * - __match_any_sync groups equal byte values within a warp. Only the leader of each group issues
 *   the shared-memory atomic add, which reduces atomic traffic for skewed text and for narrow
 *   [from, to] ranges where most bytes are discarded.
 */

namespace {
constexpr int           kBlockThreads         = 256;
constexpr unsigned int  kBlockThreadsU        = 256u;
constexpr int           kWarpSize             = 32;
constexpr int           kWarpsPerBlock        = kBlockThreads / kWarpSize;  // 8
constexpr int           kSharedBins           = 256;
constexpr unsigned int  kVectorBytes          = 16u;                        // sizeof(uint4)
constexpr unsigned int  kBytesPerBlock        = kBlockThreadsU * kVectorBytes;
constexpr unsigned int  kMaxBlocks            = 1024u;                      // ~8 CTAs/SM on H100-class GPUs
constexpr unsigned int  kSingleBlockThreshold = 64u * 1024u;               // small-input fast path
constexpr unsigned int  kInvalidKey           = 0xFFFFFFFFu;

static_assert(kBlockThreads == kSharedBins,
              "The final reduction relies on having one thread available per possible output bin.");

/*
 * Aggregate one byte into the warp-private shared histogram.
 *
 * Unsigned arithmetic folds the lower-bound and upper-bound tests into one compare:
 *   (byte_value - from_u) < bins
 *
 * All active lanes participate in __match_any_sync. Lanes whose byte is out of range use a sentinel
 * key so they still participate in the warp primitive but do not update the histogram.
 *
 * Only the leader lane of each equal-key group issues the atomic add, using the population count of
 * the group as the increment.
 */
__device__ __forceinline__
void aggregate_byte_to_warp_hist(unsigned int byte_value,
                                 unsigned int from_u,
                                 unsigned int bins,
                                 unsigned int* warp_hist,
                                 unsigned int active_mask,
                                 unsigned int lane_mask)
{
    const bool in_range = ((byte_value - from_u) < bins);
    const unsigned int key = in_range ? byte_value : kInvalidKey;

    const unsigned int peer_mask   = __match_any_sync(active_mask, key);
    const unsigned int leader_mask = peer_mask & (0u - peer_mask);  // isolate least-significant set bit

    if (in_range && leader_mask == lane_mask) {
        atomicAdd(warp_hist + key, static_cast<unsigned int>(__popc(peer_mask)));
    }
}

/*
 * Unpack four bytes from one 32-bit word and feed them to the warp-aggregation helper.
 * The function is force-inlined so the compiler can keep the whole hot path in registers.
 */
__device__ __forceinline__
void process_packed_word(unsigned int packed,
                         unsigned int from_u,
                         unsigned int bins,
                         unsigned int* warp_hist,
                         unsigned int active_mask,
                         unsigned int lane_mask)
{
    aggregate_byte_to_warp_hist( packed        & 0xFFu, from_u, bins, warp_hist, active_mask, lane_mask);
    aggregate_byte_to_warp_hist((packed >>  8) & 0xFFu, from_u, bins, warp_hist, active_mask, lane_mask);
    aggregate_byte_to_warp_hist((packed >> 16) & 0xFFu, from_u, bins, warp_hist, active_mask, lane_mask);
    aggregate_byte_to_warp_hist((packed >> 24) & 0xFFu, from_u, bins, warp_hist, active_mask, lane_mask);
}

__global__ __launch_bounds__(kBlockThreads)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from_u,
                            unsigned int bins)
{
    __shared__ unsigned int warp_histograms[kWarpsPerBlock][kSharedBins];

    const unsigned int tid          = threadIdx.x;
    const unsigned int global_tid   = blockIdx.x * kBlockThreadsU + tid;
    const unsigned int total_threads = gridDim.x * kBlockThreadsU;
    const unsigned int warp_id      = tid >> 5;
    const unsigned int lane_mask    = 1u << (tid & 31u);

    unsigned int* const warp_hist         = warp_histograms[warp_id];
    const unsigned char* const byte_input = reinterpret_cast<const unsigned char*>(input);
    const uint4* const vec_input          = reinterpret_cast<const uint4*>(input);

    // Zero the warp-private shared histograms. This is only 8 KiB/CTA.
    for (unsigned int i = tid; i < static_cast<unsigned int>(kWarpsPerBlock * kSharedBins); i += kBlockThreadsU) {
        reinterpret_cast<unsigned int*>(warp_histograms)[i] = 0u;
    }
    __syncthreads();

    // Main vectorized pass: each thread reads 16 bytes at a time via a naturally aligned uint4 load.
    const unsigned int vecCount = inputSize >> 4;  // inputSize / 16
    for (unsigned int i = global_tid; i < vecCount; i += total_threads) {
        const uint4 v = vec_input[i];
        const unsigned int active_mask = __activemask();

        process_packed_word(v.x, from_u, bins, warp_hist, active_mask, lane_mask);
        process_packed_word(v.y, from_u, bins, warp_hist, active_mask, lane_mask);
        process_packed_word(v.z, from_u, bins, warp_hist, active_mask, lane_mask);
        process_packed_word(v.w, from_u, bins, warp_hist, active_mask, lane_mask);
    }

    // Handle the tail (< 16 bytes total) with a scalar path. The overhead is negligible.
    const unsigned int tail_begin = vecCount * kVectorBytes;
    for (unsigned int i = tail_begin + global_tid; i < inputSize; i += total_threads) {
        const unsigned int key = static_cast<unsigned int>(byte_input[i]);
        if ((key - from_u) < bins) {
            atomicAdd(warp_hist + key, 1u);
        }
    }

    __syncthreads();

    /*
     * Reduce the warp-private histograms to the requested output range.
     * Because the output width is at most 256, one thread can own one output bin.
     *
     * - Single-CTA path: overwrite the output directly, so no prior memset is needed.
     * - Multi-CTA path: each CTA atomically accumulates its partial sums into the global histogram.
     */
    if (tid < bins) {
        const unsigned int out_bin = tid;
        const unsigned int key     = from_u + out_bin;

        unsigned int sum = 0u;
        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += warp_histograms[w][key];
        }

        if (gridDim.x == 1) {
            histogram[out_bin] = sum;
        } else if (sum != 0u) {
            atomicAdd(histogram + out_bin, sum);
        }
    }
}
}  // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // The contract guarantees: 0 <= from < to <= 255.
    const unsigned int from_u = static_cast<unsigned int>(from);
    const unsigned int bins   = static_cast<unsigned int>(to - from) + 1u;

    /*
     * Small-input fast path:
     * A single CTA usually wins for tiny inputs because it avoids:
     *   1) an asynchronous memset of the output buffer, and
     *   2) the final global atomic accumulation.
     *
     * Larger inputs use enough CTAs to saturate the GPU, but the count is capped so the
     * per-block global flush cost stays bounded.
     *
     * The caller is responsible for synchronization and error handling; this function only
     * enqueues work on the default stream.
     */
    if (inputSize == 0u) {
        (void)cudaMemsetAsync(histogram, 0, static_cast<size_t>(bins) * sizeof(unsigned int));
        return;
    }

    unsigned int blocks;
    if (inputSize <= kSingleBlockThreshold) {
        blocks = 1u;
    } else {
        blocks = 1u + ((inputSize - 1u) / kBytesPerBlock);  // overflow-safe ceil(inputSize / kBytesPerBlock)
        if (blocks > kMaxBlocks) {
            blocks = kMaxBlocks;
        }
    }

    if (blocks > 1u) {
        (void)cudaMemsetAsync(histogram, 0, static_cast<size_t>(bins) * sizeof(unsigned int));
    }

    histogram_range_kernel<<<blocks, kBlockThreads>>>(input, histogram, inputSize, from_u, bins);
}

#include <cuda_runtime.h>
#include <cstdint>

namespace detail {

/*
 * Range-restricted byte histogram tuned for modern data-center GPUs (A100/H100 class).
 *
 * Design choices:
 *  - One 256-counter shared histogram per warp (warp-private slices). This removes
 *    inter-warp contention in the hot accumulation path.
 *  - The aligned bulk of the input is consumed via 16-byte vector loads (uint4).
 *  - Within a warp, lanes targeting the same bin are coalesced with __match_any_sync(),
 *    so the shared histogram sees one update per distinct value seen by the participating
 *    lanes instead of one update per byte.
 *  - One final merge per block/bin into the global output.
 *
 * Bytes are always interpreted as unsigned values in [0, 255], independent of the
 * implementation-defined signedness of plain 'char'.
 */
constexpr int kBlockSize = 256;
constexpr int kWarpSize = 32;
constexpr int kWarpsPerBlock = kBlockSize / kWarpSize;
constexpr unsigned int kAlphabetBins = 256u;
constexpr unsigned int kVectorBytes = 16u;
constexpr unsigned int kVectorAlignMask = kVectorBytes - 1u;

/*
 * A fixed cap of 1024 blocks is close to ~8 resident-like blocks/SM on A100/H100-class
 * parts while avoiding too much per-block merge overhead once the device is saturated.
 */
constexpr unsigned int kMaxGridBlocks = 1024u;

/*
 * Launch heuristic: wider requested ranges require more per-block initialization/merge work,
 * so give each block more input to amortize that overhead.
 */
constexpr unsigned int kMinTargetBytesPerBlock = 8u * 1024u;
constexpr unsigned int kTargetBytesPerRequestedBin = 64u;

static_assert(kBlockSize % kWarpSize == 0, "Block size must be a multiple of warp size.");

template <bool kFullRange>
struct ByteAccumulator;

template <>
struct ByteAccumulator<true> {
    __device__ __forceinline__
    static void add(const unsigned int byte_value,
                    unsigned int* const warp_hist,
                    const unsigned int /*from*/,
                    const unsigned int /*bins*/,
                    const unsigned int lane,
                    const unsigned int active_mask)
    {
        const unsigned int peers = __match_any_sync(active_mask, byte_value);
        const unsigned int leader_lane = static_cast<unsigned int>(__ffs(peers) - 1);
        if (lane == leader_lane) {
            const unsigned int count = static_cast<unsigned int>(__popc(peers));
            /*
             * Even though each warp owns its own shared-memory slice, keeping the update as
             * an atomicAdd makes the code correct independent of compiler predication choices
             * and independent thread scheduling. On Ampere/Hopper, shared-memory atomics are
             * fast, and __match_any_sync() has already reduced the update rate sharply.
             */
            atomicAdd(warp_hist + byte_value, count);
        }
    }
};

template <>
struct ByteAccumulator<false> {
    __device__ __forceinline__
    static void add(const unsigned int byte_value,
                    unsigned int* const warp_hist,
                    const unsigned int from,
                    const unsigned int bins,
                    const unsigned int lane,
                    const unsigned int active_mask)
    {
        /*
         * Unsigned subtraction lets one compare implement both bounds:
         * bytes below 'from' underflow to a large unsigned value and fail idx < bins.
         */
        const unsigned int idx = byte_value - from;
        const bool valid = idx < bins;
        const unsigned int valid_mask = __ballot_sync(active_mask, valid);

        if (valid) {
            const unsigned int peers = __match_any_sync(valid_mask, idx);
            const unsigned int leader_lane = static_cast<unsigned int>(__ffs(peers) - 1);
            if (lane == leader_lane) {
                const unsigned int count = static_cast<unsigned int>(__popc(peers));
                atomicAdd(warp_hist + idx, count);
            }
        }
    }
};

template <bool kFullRange>
__device__ __forceinline__
void process_word(const unsigned int word,
                  unsigned int* const warp_hist,
                  const unsigned int from,
                  const unsigned int bins,
                  const unsigned int lane,
                  const unsigned int active_mask)
{
    ByteAccumulator<kFullRange>::add( word        & 0xFFu, warp_hist, from, bins, lane, active_mask);
    ByteAccumulator<kFullRange>::add((word >>  8) & 0xFFu, warp_hist, from, bins, lane, active_mask);
    ByteAccumulator<kFullRange>::add((word >> 16) & 0xFFu, warp_hist, from, bins, lane, active_mask);
    ByteAccumulator<kFullRange>::add((word >> 24) & 0xFFu, warp_hist, from, bins, lane, active_mask);
}

template <bool kFullRange>
__global__ __launch_bounds__(kBlockSize)
void histogram_kernel(const unsigned char* __restrict__ input,
                      unsigned int* __restrict__ histogram,
                      const unsigned int inputSize,
                      const unsigned int from,
                      const unsigned int bins)
{
    __shared__ unsigned int s_hist[kWarpsPerBlock][kAlphabetBins];

    const unsigned int tid = threadIdx.x;
    const unsigned int lane = tid & (kWarpSize - 1u);
    const unsigned int warp_id = tid >> 5;
    unsigned int* const warp_hist = s_hist[warp_id];

    /* Only initialize the requested bin subset; the rest of the 256-entry slice is unused. */
    for (unsigned int bin = lane; bin < bins; bin += kWarpSize) {
        warp_hist[bin] = 0u;
    }
    __syncthreads();

    const unsigned int global_thread = blockIdx.x * blockDim.x + tid;
    const unsigned int grid_threads = gridDim.x * blockDim.x;

    /* Align the main bulk to 16 bytes so the vectorized loop can use uint4 loads safely. */
    const unsigned int misalignment =
        static_cast<unsigned int>(reinterpret_cast<std::uintptr_t>(input) & kVectorAlignMask);
    unsigned int prefix = (kVectorBytes - misalignment) & kVectorAlignMask;
    if (prefix > inputSize) {
        prefix = inputSize;
    }

    /*
     * The prefix is shorter than 16 bytes, so assigning it to the first few global threads
     * is enough and avoids an extra scalar loop.
     */
    if (global_thread < prefix) {
        const unsigned int active_mask = __activemask();
        ByteAccumulator<kFullRange>::add(
            static_cast<unsigned int>(input[global_thread]),
            warp_hist,
            from,
            bins,
            lane,
            active_mask);
    }

    const unsigned char* const aligned_input = input + prefix;
    const unsigned int vec_bytes = (inputSize - prefix) & ~kVectorAlignMask;
    const unsigned int num_vec = vec_bytes / kVectorBytes;
    const uint4* const input4 = reinterpret_cast<const uint4*>(aligned_input);

    for (unsigned int i = global_thread; i < num_vec; i += grid_threads) {
        const unsigned int active_mask = __activemask();
        const uint4 v = input4[i];
        process_word<kFullRange>(v.x, warp_hist, from, bins, lane, active_mask);
        process_word<kFullRange>(v.y, warp_hist, from, bins, lane, active_mask);
        process_word<kFullRange>(v.z, warp_hist, from, bins, lane, active_mask);
        process_word<kFullRange>(v.w, warp_hist, from, bins, lane, active_mask);
    }

    const unsigned int tail_start = prefix + vec_bytes;
    const unsigned int tail_bytes = inputSize - tail_start;

    /* Like the prefix, the tail is also shorter than 16 bytes. */
    if (global_thread < tail_bytes) {
        const unsigned int active_mask = __activemask();
        ByteAccumulator<kFullRange>::add(
            static_cast<unsigned int>(input[tail_start + global_thread]),
            warp_hist,
            from,
            bins,
            lane,
            active_mask);
    }

    __syncthreads();

    /*
     * Merge warp-private shared histograms into the output.
     * - Single-block launch: direct stores avoid both a memset and global atomics.
     * - Multi-block launch: one global atomic per non-zero bin/block.
     */
    for (unsigned int bin = tid; bin < bins; bin += blockDim.x) {
        unsigned int sum = 0u;
#pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += s_hist[w][bin];
        }

        if (gridDim.x == 1) {
            histogram[bin] = sum;
        } else if (sum != 0u) {
            atomicAdd(histogram + bin, sum);
        }
    }
}

}  // namespace detail

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    /*
     * Preconditions from the prompt:
     *   - 0 <= from < to <= 255
     *   - input and histogram are device pointers allocated by cudaMalloc
     *   - histogram has length (to - from + 1)
     *
     * By design, this function only enqueues work on the default stream and does not
     * synchronize; ordering/error handling beyond launch submission is left to the caller.
     */
    const unsigned int bins = static_cast<unsigned int>(to - from + 1);
    const size_t histogram_bytes = static_cast<size_t>(bins) * sizeof(unsigned int);

    if (inputSize == 0u) {
        cudaMemsetAsync(histogram, 0, histogram_bytes, 0);
        return;
    }

    unsigned int target_bytes_per_block = bins * detail::kTargetBytesPerRequestedBin;
    if (target_bytes_per_block < detail::kMinTargetBytesPerBlock) {
        target_bytes_per_block = detail::kMinTargetBytesPerBlock;
    }

    unsigned int blocks = 1u + (inputSize - 1u) / target_bytes_per_block;
    if (blocks > detail::kMaxGridBlocks) {
        blocks = detail::kMaxGridBlocks;
    }

    /*
     * When only one block is used, the kernel writes the complete result directly,
     * so a separate memset is unnecessary.
     */
    if (blocks != 1u) {
        cudaMemsetAsync(histogram, 0, histogram_bytes, 0);
    }

    const dim3 grid(blocks);
    const dim3 block(detail::kBlockSize);
    const unsigned char* const input_u8 = reinterpret_cast<const unsigned char*>(input);
    const unsigned int from_u = static_cast<unsigned int>(from);

    /* Fast path for the full [0,255] alphabet: no range check in the hot loop. */
    if (from == 0 && bins == detail::kAlphabetBins) {
        detail::histogram_kernel<true><<<grid, block>>>(
            input_u8,
            histogram,
            inputSize,
            0u,
            detail::kAlphabetBins);
    } else {
        detail::histogram_kernel<false><<<grid, block>>>(
            input_u8,
            histogram,
            inputSize,
            from_u,
            bins);
    }
}

#include <cuda_runtime.h>
#include <cstdint>

namespace {

constexpr int kWarpSize = 32;
constexpr int kHistogramBlockSize = 256;
constexpr unsigned int kVectorBytes = 16u;
constexpr unsigned int kInvalidBinSentinel = ~0u;

static_assert((kHistogramBlockSize % kWarpSize) == 0, "Block size must be a multiple of warp size.");
static_assert(sizeof(uint4) == kVectorBytes, "Expected uint4 to be 16 bytes.");

// Warp-aggregate equal-bin updates so only one lane performs the shared-memory atomicAdd.
// Out-of-range bytes all use the same sentinel key, which collapses them into a single no-op group.
__device__ __forceinline__ void warp_aggregated_shared_increment(
    unsigned int bin,
    bool valid,
    int lane,
    unsigned int* warp_hist)
{
    const unsigned int active = __activemask();
    const unsigned int group = __match_any_sync(active, valid ? bin : kInvalidBinSentinel);

    if (valid && lane == (__ffs(group) - 1)) {
        atomicAdd(warp_hist + bin, static_cast<unsigned int>(__popc(group)));
    }
}

__device__ __forceinline__ void accumulate_byte(
    unsigned char value,
    unsigned int from_u,
    unsigned int bins_u,
    int lane,
    unsigned int* warp_hist)
{
    const unsigned int bin = static_cast<unsigned int>(value) - from_u;
    warp_aggregated_shared_increment(bin, bin < bins_u, lane, warp_hist);
}

__device__ __forceinline__ void accumulate_word(
    unsigned int word,
    unsigned int from_u,
    unsigned int bins_u,
    int lane,
    unsigned int* warp_hist)
{
    accumulate_byte(static_cast<unsigned char>( word        & 0xFFu), from_u, bins_u, lane, warp_hist);
    accumulate_byte(static_cast<unsigned char>((word >>  8) & 0xFFu), from_u, bins_u, lane, warp_hist);
    accumulate_byte(static_cast<unsigned char>((word >> 16) & 0xFFu), from_u, bins_u, lane, warp_hist);
    accumulate_byte(static_cast<unsigned char>((word >> 24) & 0xFFu), from_u, bins_u, lane, warp_hist);
}

/*
  Optimized histogram kernel for a contiguous byte range [from, from + bins - 1].

  Strategy:
  - Each warp owns a private histogram slice in shared memory, which removes inter-warp contention.
  - Within a warp, __match_any_sync() combines lanes that hit the same bin, reducing shared atomics.
  - Input is consumed mostly as aligned 16-byte vectors (uint4). Tiny scalar prologue/tail code
    handles arbitrary input pointer alignment without sacrificing vectorized bulk loads.
  - Each block flushes its shared histogram to global memory once, minimizing global atomics.

  Notes:
  - Bytes are interpreted as unsigned char values in [0, 255], independent of host/device char signedness.
  - The global histogram must be zero-initialized before launch.
  - This kernel targets modern NVIDIA GPUs (Volta+); A100/H100 are the intended targets.
*/
template <int BLOCK_SIZE>
__global__ __launch_bounds__(BLOCK_SIZE)
void histogram_range_kernel(
    const char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    int from,
    int bins)
{
    static_assert((BLOCK_SIZE % kWarpSize) == 0, "BLOCK_SIZE must be a multiple of warp size.");
    constexpr int WARPS_PER_BLOCK = BLOCK_SIZE / kWarpSize;

    extern __shared__ unsigned int s_private_hist[];

    const int tid = static_cast<int>(threadIdx.x);
    const unsigned int gtid =
        static_cast<unsigned int>(blockIdx.x) * static_cast<unsigned int>(BLOCK_SIZE) +
        static_cast<unsigned int>(tid);
    const unsigned int stride =
        static_cast<unsigned int>(gridDim.x) * static_cast<unsigned int>(BLOCK_SIZE);

    const int lane = tid & (kWarpSize - 1);
    const int warp_id = tid / kWarpSize;
    const unsigned int from_u = static_cast<unsigned int>(from);
    const unsigned int bins_u = static_cast<unsigned int>(bins);

    unsigned int* const warp_hist = s_private_hist + warp_id * bins;
    const int total_private_bins = WARPS_PER_BLOCK * bins;

    for (int i = tid; i < total_private_bins; i += BLOCK_SIZE) {
        s_private_hist[i] = 0u;
    }
    __syncthreads();

    const unsigned char* const input_bytes = reinterpret_cast<const unsigned char*>(input);

    // Scalar prologue: move to a 16-byte aligned address so the bulk loop can use uint4 loads.
    const uintptr_t base_addr = reinterpret_cast<uintptr_t>(input_bytes);
    const unsigned int misalignment =
        static_cast<unsigned int>(base_addr & static_cast<uintptr_t>(kVectorBytes - 1u));
    unsigned int prologue = (kVectorBytes - misalignment) & (kVectorBytes - 1u);
    if (prologue > inputSize) {
        prologue = inputSize;
    }

    // Prologue and tail are each < 16 bytes, so the first few global threads handle them directly.
    if (gtid < prologue) {
        accumulate_byte(input_bytes[gtid], from_u, bins_u, lane, warp_hist);
    }

    const unsigned int remaining = inputSize - prologue;
    const unsigned int vector_count = remaining / kVectorBytes;
    const unsigned int tail_count = remaining % kVectorBytes;
    const unsigned int tail_start = inputSize - tail_count;

    const unsigned char* const aligned_bytes = input_bytes + prologue;
    const uint4* const aligned_input4 = reinterpret_cast<const uint4*>(aligned_bytes);

    for (unsigned int vec_idx = gtid; vec_idx < vector_count; vec_idx += stride) {
        const uint4 v = aligned_input4[vec_idx];
        accumulate_word(v.x, from_u, bins_u, lane, warp_hist);
        accumulate_word(v.y, from_u, bins_u, lane, warp_hist);
        accumulate_word(v.z, from_u, bins_u, lane, warp_hist);
        accumulate_word(v.w, from_u, bins_u, lane, warp_hist);
    }

    if (gtid < tail_count) {
        accumulate_byte(input_bytes[tail_start + gtid], from_u, bins_u, lane, warp_hist);
    }

    __syncthreads();

    // By contract, bins <= 256, so one thread can flush one output bin.
    if (tid < bins) {
        const int bin = tid;
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < WARPS_PER_BLOCK; ++w) {
            sum += s_private_hist[w * bins + bin];
        }

        if (sum != 0u) {
            atomicAdd(histogram + bin, sum);
        }
    }
}

}  // namespace

/*
  Host wrapper:
  - Zeros the output histogram because the kernel accumulates into it with atomicAdd.
  - Uses the default stream because the API does not expose a stream parameter.
  - Does not synchronize; the caller is responsible for synchronization and optional error checks.
  - Caps the grid to the number of concurrently resident blocks to avoid unnecessary per-block flush traffic.
*/
void run_histogram(
    const char* input,
    unsigned int* histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    // The problem statement promises a valid range; this guard just avoids accidental misuse.
    if (from < 0 || to > 255 || from > to) {
        return;
    }

    const int bins = to - from + 1;
    const size_t histogram_bytes = static_cast<size_t>(bins) * sizeof(unsigned int);

    cudaMemsetAsync(histogram, 0, histogram_bytes, 0);

    if (inputSize == 0u) {
        return;
    }

    const size_t shared_bytes =
        static_cast<size_t>(kHistogramBlockSize / kWarpSize) *
        static_cast<size_t>(bins) *
        sizeof(unsigned int);

    // One block nominally covers 256 vector loads (4096 bytes of bulk data) before it needs to loop.
    // Prologue/tail are tiny and intentionally ignored in this heuristic.
    const size_t vector_chunks = static_cast<size_t>(inputSize) / kVectorBytes;
    int blocks_for_input = static_cast<int>(
        (vector_chunks + static_cast<size_t>(kHistogramBlockSize) - 1u) /
        static_cast<size_t>(kHistogramBlockSize));
    if (blocks_for_input < 1) {
        blocks_for_input = 1;
    }

    int grid_size = blocks_for_input;

    if (grid_size > 1) {
        int device = 0;
        int sm_count = 1;
        int active_blocks_per_sm = 1;

        cudaGetDevice(&device);
        cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
        cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &active_blocks_per_sm,
            histogram_range_kernel<kHistogramBlockSize>,
            kHistogramBlockSize,
            shared_bytes);

        if (sm_count < 1) {
            sm_count = 1;
        }
        if (active_blocks_per_sm < 1) {
            active_blocks_per_sm = 1;
        }

        const int max_concurrent_blocks = sm_count * active_blocks_per_sm;
        if (grid_size > max_concurrent_blocks) {
            grid_size = max_concurrent_blocks;
        }
        if (grid_size < 1) {
            grid_size = 1;
        }
    }

    histogram_range_kernel<kHistogramBlockSize>
        <<<grid_size, kHistogramBlockSize, shared_bytes, 0>>>(
            input,
            histogram,
            inputSize,
            from,
            bins);
}

#include <cuda_runtime.h>

namespace {

// Range-limited byte histogram tuned for modern data-center GPUs:
//
// - 256-thread blocks => 8 warps/block.
// - Each warp owns a private 256-bin histogram in shared memory.
//   That keeps inter-warp contention at zero while staying tiny:
//   8 warps * 256 bins * 4 bytes = 8 KiB/block.
// - The main path processes input in 512-byte warp tiles:
//   each lane loads 16 bytes (one uint4), so all 32 lanes stay converged.
// - Within a converged warp, __match_any_sync() collapses duplicate byte values;
//   only one lane per distinct value updates shared memory, and those updates
//   are plain increments (no atomics needed).
// - The leftover tail is < 512 bytes and may diverge a warp. For that small
//   region we deliberately use shared-memory atomics for correctness under
//   independent thread scheduling.
// - Final block reduction emits one global atomic per nonzero bin (or plain
//   stores when the launch uses a single block).

constexpr unsigned int WARP_THREADS             = 32u;
constexpr unsigned int BLOCK_THREADS            = 256u;
constexpr unsigned int WARPS_PER_BLOCK          = BLOCK_THREADS / WARP_THREADS;
constexpr unsigned int MAX_BINS                 = 256u;
constexpr unsigned int BYTES_PER_LANE           = sizeof(uint4);                 // 16
constexpr unsigned int BYTES_PER_WARP           = WARP_THREADS * BYTES_PER_LANE; // 512
constexpr unsigned int BYTES_PER_BLOCK          = BLOCK_THREADS * BYTES_PER_LANE;// 4096
constexpr unsigned int FULL_MASK                = 0xFFFFFFFFu;
constexpr unsigned int INVALID_BIN              = 0xFFFFFFFFu;
constexpr unsigned int FALLBACK_BLOCKS_PER_SM   = 8u;
constexpr unsigned int FALLBACK_MAX_GRID_BLOCKS = 1024u;

static_assert(BLOCK_THREADS % WARP_THREADS == 0u, "Block size must be a whole number of warps.");
static_assert(MAX_BINS == 256u, "This kernel assumes byte-valued input.");

__device__ __forceinline__
void update_byte_fullwarp(unsigned int* __restrict__ local_hist,
                          unsigned int lane,
                          unsigned int byte_value,
                          unsigned int from,
                          unsigned int num_bins)
{
    const unsigned int bin = byte_value - from;
    const unsigned int key = (bin < num_bins) ? bin : INVALID_BIN;

    // Full-warp call: every lane participates, so FULL_MASK is valid here.
    const unsigned int peers = __match_any_sync(FULL_MASK, key);

    // One leader per distinct key performs the increment by the group size.
    // INVALID_BIN is ignored, so out-of-range bytes do not touch the histogram.
    if ((key != INVALID_BIN) && (lane == static_cast<unsigned int>(__ffs(peers) - 1))) {
        local_hist[key] += __popc(peers);
    }
}

__device__ __forceinline__
void process_word_fullwarp(unsigned int* __restrict__ local_hist,
                           unsigned int lane,
                           unsigned int word,
                           unsigned int from,
                           unsigned int num_bins)
{
    update_byte_fullwarp(local_hist, lane,  word        & 0xFFu, from, num_bins);
    update_byte_fullwarp(local_hist, lane, (word >>  8) & 0xFFu, from, num_bins);
    update_byte_fullwarp(local_hist, lane, (word >> 16) & 0xFFu, from, num_bins);
    update_byte_fullwarp(local_hist, lane, (word >> 24) & 0xFFu, from, num_bins);
}

__global__ __launch_bounds__(BLOCK_THREADS)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from,
                            unsigned int num_bins)
{
    __shared__ unsigned int warp_hist[WARPS_PER_BLOCK][MAX_BINS];

    const unsigned int tid  = threadIdx.x;
    const unsigned int warp = tid >> 5;
    const unsigned int lane = tid & (WARP_THREADS - 1u);

    unsigned int* const local_hist = warp_hist[warp];

    // Only bins [0, num_bins) are ever touched/read for this launch, so zero only those.
    #pragma unroll
    for (unsigned int bin = lane; bin < num_bins; bin += WARP_THREADS) {
        local_hist[bin] = 0u;
    }

    // Warp-private histogram slices are independent, so a warp-level sync is sufficient here.
    __syncwarp();

    // Treat input chars as raw bytes in [0,255].
    const unsigned char* const input_bytes = reinterpret_cast<const unsigned char*>(input);

    // Fast path over full 512-byte warp tiles.
    // Because the prompt states the buffer itself is cudaMalloc'ed, the base pointer is
    // sufficiently aligned for 16-byte vector loads, and tile starts are multiples of 512.
    const size_t vectorized_end = static_cast<size_t>(inputSize) &
                                  ~(static_cast<size_t>(BYTES_PER_WARP) - 1);

    const size_t warp_index  = static_cast<size_t>(blockIdx.x) * WARPS_PER_BLOCK + warp;
    const size_t warp_stride = static_cast<size_t>(gridDim.x) * WARPS_PER_BLOCK * BYTES_PER_WARP;

    for (size_t base = warp_index * BYTES_PER_WARP; base < vectorized_end; base += warp_stride) {
        const uint4* const vec_ptr = reinterpret_cast<const uint4*>(input_bytes + base);
        const uint4 v = vec_ptr[lane];

        process_word_fullwarp(local_hist, lane, v.x, from, num_bins);
        process_word_fullwarp(local_hist, lane, v.y, from, num_bins);
        process_word_fullwarp(local_hist, lane, v.z, from, num_bins);
        process_word_fullwarp(local_hist, lane, v.w, from, num_bins);
    }

    // Tail path: < 512 bytes remain. This loop can diverge within a warp, so use shared-memory
    // atomics for correctness; the tail is tiny enough that the extra cost is negligible.
    const size_t global_thread = static_cast<size_t>(blockIdx.x) * BLOCK_THREADS + tid;
    const size_t thread_stride = static_cast<size_t>(gridDim.x) * BLOCK_THREADS;

    for (size_t i = vectorized_end + global_thread; i < static_cast<size_t>(inputSize); i += thread_stride) {
        const unsigned int bin = static_cast<unsigned int>(input_bytes[i]) - from;
        if (bin < num_bins) {
            atomicAdd(local_hist + bin, 1u);
        }
    }

    __syncthreads();

    // Reduce the per-warp histograms into the final output.
    if (tid < num_bins) {
        unsigned int sum = 0u;

        #pragma unroll
        for (unsigned int w = 0; w < WARPS_PER_BLOCK; ++w) {
            sum += warp_hist[w][tid];
        }

        // If only one block was launched, no global atomic is needed.
        if (gridDim.x == 1) {
            histogram[tid] = sum;
        } else if (sum != 0u) {
            atomicAdd(histogram + tid, sum);
        }
    }
}

} // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // The output buffer is specified as the result histogram, not as an accumulator,
    // so clear it here. This is asynchronous; the caller owns synchronization.
    const unsigned int num_bins = static_cast<unsigned int>(to - from + 1);
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(num_bins) * sizeof(unsigned int));

    if (inputSize == 0u) {
        return;
    }

    // Cache launch heuristics per host thread and per current device.
    // The kernel shape is fixed, so occupancy is stable for a given device/binary.
    thread_local int cached_device        = -1;
    thread_local int cached_sms           = 0;
    thread_local int cached_active_blocks = 0;

    int device = 0;
    cudaGetDevice(&device);

    if (device != cached_device) {
        cached_device        = device;
        cached_sms           = 0;
        cached_active_blocks = 0;
    }

    if (cached_sms <= 0) {
        int sms = 0;
        cudaDeviceGetAttribute(&sms, cudaDevAttrMultiProcessorCount, device);
        if (sms > 0) {
            cached_sms = sms;
        }
    }

    if (cached_active_blocks <= 0) {
        int active_blocks = 0;
        cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &active_blocks,
            histogram_range_kernel,
            static_cast<int>(BLOCK_THREADS),
            0);
        if (active_blocks > 0) {
            cached_active_blocks = active_blocks;
        }
    }

    // 4 KiB/block is the natural work quantum of the vectorized path.
    const unsigned int blocks_needed = 1u + (inputSize - 1u) / BYTES_PER_BLOCK;

    unsigned int max_grid_blocks = FALLBACK_MAX_GRID_BLOCKS;
    if (cached_sms > 0) {
        const unsigned int blocks_per_sm =
            (cached_active_blocks > 0)
                ? static_cast<unsigned int>(cached_active_blocks)
                : FALLBACK_BLOCKS_PER_SM;

        max_grid_blocks = static_cast<unsigned int>(cached_sms) * blocks_per_sm;
    }

    const unsigned int grid_blocks =
        (blocks_needed < max_grid_blocks) ? blocks_needed : max_grid_blocks;

    histogram_range_kernel<<<grid_blocks, BLOCK_THREADS>>>(
        input,
        histogram,
        inputSize,
        static_cast<unsigned int>(from),
        num_bins);

    // Intentionally no synchronization and no error consumption here:
    // the caller is responsible for synchronization and optional error handling.
}

#include <cuda_runtime.h>

namespace {

// Optimized for modern data-center GPUs (A100/H100 class).
// Requirements/assumptions from the prompt:
//   * input and histogram are already device pointers allocated with cudaMalloc.
//   * histogram has exactly (to - from + 1) bins.
//   * caller handles any required synchronization.
// Design:
//   * The requested range is at most 256 bins, so a 256-thread block can map
//     one thread to one final output bin during the block-local reduction.
//   * Each warp owns a private histogram in shared memory. With 8 warps/block
//     and at most 256 bins, this costs only 8 * 256 * 4 B = 8 KiB/block.
//   * The hot path uses __match_any_sync to aggregate identical bins inside a
//     warp so that duplicate characters generate a single shared-memory update.
//   * Final block partials are reduced and accumulated into the global output.
//   * This uses Volta+ warp-match intrinsics, which is appropriate for A100/H100.
constexpr int kHistogramBlockSize = 256;
constexpr int kWarpSize           = 32;
constexpr int kWarpsPerBlock      = kHistogramBlockSize / kWarpSize;
constexpr int kItemsPerThread     = 4;

static_assert(kHistogramBlockSize % kWarpSize == 0,
              "Block size must be a whole number of warps.");

// Branch-free select: pred ? when_true : when_false.
// These helpers intentionally avoid control-flow branches before warp-synchronous
// intrinsics so that all currently active lanes reach them together.
__device__ __forceinline__ unsigned int select_u32(unsigned int when_true,
                                                   unsigned int when_false,
                                                   bool pred) {
    const unsigned int mask = 0u - static_cast<unsigned int>(pred);
    return when_false ^ ((when_false ^ when_true) & mask);
}

__device__ __forceinline__ size_t select_size_t(size_t when_true,
                                                size_t when_false,
                                                bool pred) {
    const size_t mask = static_cast<size_t>(0) - static_cast<size_t>(pred);
    return when_false ^ ((when_false ^ when_true) & mask);
}

// Update one byte into a warp-private shared histogram.
// All currently active lanes participate in __match_any_sync. Misses are given a
// unique high-bit key so they cannot collide with any real histogram bin.
__device__ __forceinline__ void accumulate_byte_to_warp_hist(
    unsigned int* __restrict__ warp_hist,
    unsigned int range_begin,
    unsigned int num_bins,
    unsigned int byte_value,
    bool valid,
    int lane,
    unsigned int exec_mask) {

    const unsigned int bin = byte_value - range_begin;
    const bool hit = valid && (bin < num_bins);

    const unsigned int invalid_key = 0x80000000u | static_cast<unsigned int>(lane);
    const unsigned int key = select_u32(bin, invalid_key, hit);

    const unsigned int peers = __match_any_sync(exec_mask, key);
    const int leader_lane = __ffs(peers) - 1;

    if (hit && lane == leader_lane) {
        warp_hist[bin] += static_cast<unsigned int>(__popc(peers));
    }

    // The leader-only update can diverge; reconverge the active lanes before
    // processing the next byte.
    __syncwarp(exec_mask);
}

__global__ __launch_bounds__(kHistogramBlockSize)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int input_size,
                            unsigned int range_begin,
                            unsigned int num_bins) {
    extern __shared__ unsigned int shared_hist[];

    const int tid     = static_cast<int>(threadIdx.x);
    const int lane    = tid & (kWarpSize - 1);
    const int warp_id = tid / kWarpSize;

    const size_t warp_stride = static_cast<size_t>(num_bins);
    unsigned int* const warp_hist =
        shared_hist + static_cast<size_t>(warp_id) * warp_stride;

    // Zero the per-warp shared histograms.
    const int total_shared_bins = kWarpsPerBlock * static_cast<int>(num_bins);
    for (int i = tid; i < total_shared_bins; i += kHistogramBlockSize) {
        shared_hist[i] = 0u;
    }
    __syncthreads();

    // Treat the input as raw bytes in [0,255]. This avoids any ambiguity from
    // whether plain 'char' is signed or unsigned on the compilation target.
    const unsigned char* const data = reinterpret_cast<const unsigned char*>(input);

    const size_t n           = static_cast<size_t>(input_size);
    const size_t last        = n - 1u;
    const size_t thread_base = static_cast<size_t>(blockIdx.x) * kHistogramBlockSize +
                               static_cast<size_t>(tid);
    const size_t grid_stride = static_cast<size_t>(gridDim.x) * kHistogramBlockSize;
    const size_t loop_stride = grid_stride * kItemsPerThread;

    // Grid-stride loop. Each iteration processes 4 coalesced bytes per thread.
    for (size_t idx0 = thread_base; idx0 < n; idx0 += loop_stride) {
        // The set of active lanes is fixed for the four bytes handled in this
        // loop iteration, so capture it once and reuse it.
        const unsigned int exec_mask = __activemask();

        const size_t idx1 = idx0 + grid_stride;
        const size_t idx2 = idx1 + grid_stride;
        const size_t idx3 = idx2 + grid_stride;

        const bool v1 = idx1 < n;
        const bool v2 = idx2 < n;
        const bool v3 = idx3 < n;

        // Branch-free tail handling: out-of-range lanes read the last valid byte,
        // and the valid flag suppresses any contribution from those lanes.
        const unsigned int c0 = static_cast<unsigned int>(data[idx0]);
        const unsigned int c1 = static_cast<unsigned int>(
            data[select_size_t(idx1, last, v1)]);
        const unsigned int c2 = static_cast<unsigned int>(
            data[select_size_t(idx2, last, v2)]);
        const unsigned int c3 = static_cast<unsigned int>(
            data[select_size_t(idx3, last, v3)]);

        accumulate_byte_to_warp_hist(warp_hist, range_begin, num_bins, c0, true, lane, exec_mask);
        accumulate_byte_to_warp_hist(warp_hist, range_begin, num_bins, c1, v1,  lane, exec_mask);
        accumulate_byte_to_warp_hist(warp_hist, range_begin, num_bins, c2, v2,  lane, exec_mask);
        accumulate_byte_to_warp_hist(warp_hist, range_begin, num_bins, c3, v3,  lane, exec_mask);
    }

    __syncthreads();

    // num_bins <= 256, so one thread can own one final output bin.
    if (static_cast<unsigned int>(tid) < num_bins) {
        unsigned int sum = 0u;
        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += shared_hist[static_cast<size_t>(w) * warp_stride +
                               static_cast<size_t>(tid)];
        }

        // Single-block launch: write the final result directly.
        // Multi-block launch: atomically accumulate this block's partial result.
        if (gridDim.x == 1) {
            histogram[tid] = sum;
        } else if (sum != 0u) {
            atomicAdd(histogram + tid, sum);
        }
    }
}

} // namespace

void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    const int numBinsSigned = to - from + 1;
    if (numBinsSigned <= 0) {
        return;
    }

    const unsigned int rangeBegin = static_cast<unsigned int>(from);
    const unsigned int numBins    = static_cast<unsigned int>(numBinsSigned);
    const size_t histogramBytes   = static_cast<size_t>(numBins) * sizeof(unsigned int);

    // No input: just zero the output histogram asynchronously and return.
    if (inputSize == 0u) {
        cudaMemsetAsync(histogram, 0, histogramBytes);
        return;
    }

    const size_t sharedBytes =
        static_cast<size_t>(numBins) * kWarpsPerBlock * sizeof(unsigned int);

    // One block processes kHistogramBlockSize * kItemsPerThread bytes per
    // grid-stride "round". For very small inputs, one block is sufficient and
    // the kernel writes the final histogram directly, so no memset is needed.
    constexpr unsigned int kBytesPerBlockIteration =
        static_cast<unsigned int>(kHistogramBlockSize * kItemsPerThread);

    const unsigned int neededBlocks =
        1u + (inputSize - 1u) / kBytesPerBlockIteration;

    unsigned int gridSize = 1u;

    if (neededBlocks > 1u) {
        // Use an occupancy-sized resident grid. On large inputs, each resident
        // block keeps pulling work via the grid-stride loop until the whole
        // input is consumed.
        int device = 0;
        int smCount = 1;
        int activeBlocksPerSM = 1;

        cudaGetDevice(&device);
        cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
        cudaOccupancyMaxActiveBlocksPerMultiprocessor(&activeBlocksPerSM,
                                                      histogram_range_kernel,
                                                      kHistogramBlockSize,
                                                      sharedBytes);

        if (smCount < 1) {
            smCount = 1;
        }
        if (activeBlocksPerSM < 1) {
            activeBlocksPerSM = 1;
        }

        const unsigned int residentBlocks =
            static_cast<unsigned int>(smCount) *
            static_cast<unsigned int>(activeBlocksPerSM);

        gridSize = (neededBlocks < residentBlocks) ? neededBlocks : residentBlocks;
        if (gridSize == 0u) {
            gridSize = 1u;
        }
    }

    // Multi-block launches accumulate partials with atomicAdd, so the output
    // must start at zero. Single-block launches write every bin directly.
    if (gridSize > 1u) {
        cudaMemsetAsync(histogram, 0, histogramBytes);
    }

    // input and histogram are device pointers per the API contract; this host
    // wrapper only schedules asynchronous device work and does not synchronize.
    histogram_range_kernel<<<gridSize, kHistogramBlockSize, sharedBytes>>>(
        input,
        histogram,
        inputSize,
        rangeBegin,
        numBins);
}

#include <cuda_runtime.h>
#include <cstdint>

// Range-restricted histogram for a device-resident text buffer.
//
// Optimization strategy for modern NVIDIA data-center GPUs (A100/H100 class):
// - 256-thread blocks, so the final block-local reduction has one thread available for every
//   possible output bin (the requested range is at most 256 values wide).
// - One private 256-bin shared-memory histogram per warp. Full 256-bin tables are used even
//   for smaller requested ranges because 8 KiB/block is still tiny, while raw-byte indexing
//   becomes trivial and address arithmetic stays fast.
// - Warp-aggregated updates via __match_any_sync(): identical characters observed by multiple
//   lanes in the same warp collapse to a single shared-memory atomicAdd with the combined count.
// - 16-byte vectorized loads for 16-byte-aligned input pointers (the normal cudaMalloc case).
//   A scalar fallback kernel handles uncommon misaligned device pointers correctly.
// - The host wrapper zeroes the output with cudaMemsetAsync() and launches asynchronously on
//   the default stream. No host/device synchronization is performed here, per the requirement.
namespace {

constexpr int kAlphabetBins            = 256;
constexpr int kWarpSize                = 32;
constexpr int kBlockThreads            = 256;
constexpr int kWarpsPerBlock           = kBlockThreads / kWarpSize;
constexpr int kGridOversubscription    = 2;
constexpr int kVectorBytes             = static_cast<int>(sizeof(uint4));
constexpr unsigned int kInvalidKey     = 0xFFFFFFFFu;
constexpr int kSharedCountersPerBlock  = kWarpsPerBlock * kAlphabetBins;
constexpr int kSharedClearsPerThread   = kSharedCountersPerBlock / kBlockThreads;

static_assert(kBlockThreads == 256, "This implementation is tuned for 256-thread blocks.");
static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a whole number of warps.");
static_assert(kAlphabetBins == 256, "This implementation assumes byte values in the range 0..255.");
static_assert(kSharedCountersPerBlock % kBlockThreads == 0,
              "Shared histogram clearing must divide evenly across threads.");

struct LaunchConfigCache {
    int device                 = -1;
    int sm_count               = 1;
    int blocks_per_sm_aligned  = 1;
    int blocks_per_sm_scalar   = 1;
};

// Every active lane must participate in the same warp primitive. To keep the control flow
// uniform, out-of-range bytes are mapped to an invalid sentinel key; they participate in
// __match_any_sync(), but never issue an atomicAdd. Valid bytes use their raw ordinal value
// (0..255) directly as the shared-memory histogram index.
__device__ __forceinline__
void accumulate_raw_char_warp_aggregated(unsigned int raw_char,
                                         unsigned int from_u,
                                         unsigned int range_u,
                                         unsigned int* warp_hist,
                                         unsigned int lane_id)
{
    const unsigned int key =
        (((raw_char - from_u) <= range_u) ? raw_char : kInvalidKey);

    const unsigned int peers = __match_any_sync(__activemask(), key);

    if (key != kInvalidKey &&
        lane_id == static_cast<unsigned int>(__ffs(static_cast<int>(peers)) - 1))
    {
        atomicAdd(warp_hist + key, static_cast<unsigned int>(__popc(peers)));
    }
}

// A 32-bit packed word contains 4 characters. Extract them and feed each byte to the
// warp-aggregated update path.
__device__ __forceinline__
void process_packed_word(unsigned int packed_word,
                         unsigned int from_u,
                         unsigned int range_u,
                         unsigned int* warp_hist,
                         unsigned int lane_id)
{
    accumulate_raw_char_warp_aggregated((packed_word >>  0) & 0xFFu, from_u, range_u, warp_hist, lane_id);
    accumulate_raw_char_warp_aggregated((packed_word >>  8) & 0xFFu, from_u, range_u, warp_hist, lane_id);
    accumulate_raw_char_warp_aggregated((packed_word >> 16) & 0xFFu, from_u, range_u, warp_hist, lane_id);
    accumulate_raw_char_warp_aggregated((packed_word >> 24) & 0xFFu, from_u, range_u, warp_hist, lane_id);
}

// The template parameter selects between:
// - kAligned16 == true : vectorized uint4 loads (16 bytes/thread/iteration)
// - kAligned16 == false: generic scalar loads for uncommon misaligned device pointers
template <bool kAligned16>
__global__ __launch_bounds__(kBlockThreads)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from_u,
                            unsigned int to_u)
{
    // One full 256-bin histogram per warp in shared memory.
    __shared__ unsigned int warp_histograms[kWarpsPerBlock][kAlphabetBins];

    // Clear the shared histograms cooperatively. With 256 threads and 8 warps/block,
    // each thread clears exactly 8 counters.
    #pragma unroll
    for (int i = 0; i < kSharedClearsPerThread; ++i) {
        const unsigned int linear = threadIdx.x + i * kBlockThreads;
        warp_histograms[linear >> 8][linear & 0xFFu] = 0u;
    }
    __syncthreads();

    const unsigned int lane_id = threadIdx.x & (kWarpSize - 1);
    const unsigned int warp_id = threadIdx.x >> 5;
    unsigned int* const warp_hist = warp_histograms[warp_id];

    const unsigned int range_u   = to_u - from_u;
    const unsigned int bin_count = range_u + 1u;

    const unsigned char* __restrict__ input_bytes =
        reinterpret_cast<const unsigned char*>(input);

    const size_t global_thread = static_cast<size_t>(blockIdx.x) * kBlockThreads + threadIdx.x;
    const size_t grid_stride   = static_cast<size_t>(gridDim.x) * kBlockThreads;

    if (kAligned16) {
        // cudaMalloc() base pointers are heavily aligned, so this is the common fast path.
        const uint4* __restrict__ input_vec =
            reinterpret_cast<const uint4*>(input_bytes);

        const size_t chunk_count = static_cast<size_t>(inputSize) / kVectorBytes;

        for (size_t chunk = global_thread; chunk < chunk_count; chunk += grid_stride) {
            const uint4 v = input_vec[chunk];
            process_packed_word(v.x, from_u, range_u, warp_hist, lane_id);
            process_packed_word(v.y, from_u, range_u, warp_hist, lane_id);
            process_packed_word(v.z, from_u, range_u, warp_hist, lane_id);
            process_packed_word(v.w, from_u, range_u, warp_hist, lane_id);
        }

        // Handle the final 0..15 bytes not covered by the vectorized loop.
        const size_t tail_start = chunk_count * static_cast<size_t>(kVectorBytes);
        for (size_t i = tail_start + global_thread; i < static_cast<size_t>(inputSize); i += grid_stride) {
            accumulate_raw_char_warp_aggregated(static_cast<unsigned int>(input_bytes[i]),
                                                from_u, range_u, warp_hist, lane_id);
        }
    } else {
        // Generic path for device pointers that are not 16-byte aligned.
        for (size_t i = global_thread; i < static_cast<size_t>(inputSize); i += grid_stride) {
            accumulate_raw_char_warp_aggregated(static_cast<unsigned int>(input_bytes[i]),
                                                from_u, range_u, warp_hist, lane_id);
        }
    }

    __syncthreads();

    // Reduce the per-warp shared histograms into the final output range.
    // Because kBlockThreads == 256 and bin_count <= 256, each thread handles at most one bin.
    if (threadIdx.x < bin_count) {
        const unsigned int raw_char = from_u + threadIdx.x;

        unsigned int sum = 0u;
        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += warp_histograms[w][raw_char];
        }

        if (sum != 0u) {
            // For a single-block launch, each output bin is produced by exactly one thread,
            // so a plain store is sufficient and cheaper than a global atomic.
            if (gridDim.x == 1) {
                histogram[threadIdx.x] = sum;
            } else {
                atomicAdd(histogram + threadIdx.x, sum);
            }
        }
    }
}

inline bool is_16_byte_aligned(const void* ptr)
{
    return (reinterpret_cast<std::uintptr_t>(ptr) &
            static_cast<std::uintptr_t>(kVectorBytes - 1)) == 0u;
}

// The kernel uses grid-stride loops, so only enough blocks to fully occupy the GPU
// (plus a small oversubscription factor) are needed. "logical_work_items" means:
// - aligned kernel: number of 16-byte chunks
// - scalar kernel : number of bytes
inline int choose_grid_size(size_t logical_work_items, int sm_count, int blocks_per_sm)
{
    if (sm_count < 1) {
        sm_count = 1;
    }
    if (blocks_per_sm < 1) {
        blocks_per_sm = 1;
    }

    int grid = static_cast<int>((logical_work_items + static_cast<size_t>(kBlockThreads) - 1) /
                                static_cast<size_t>(kBlockThreads));
    if (grid < 1) {
        grid = 1;
    }

    int max_grid = sm_count * blocks_per_sm * kGridOversubscription;
    if (max_grid < 1) {
        max_grid = 1;
    }

    return (grid < max_grid) ? grid : max_grid;
}

// Cache per host thread and current device so repeated calls do not keep re-querying
// occupancy and SM count. This is purely a launch-configuration cache; the kernel
// itself remains fully asynchronous.
inline const LaunchConfigCache& get_launch_config_for_current_device()
{
    static thread_local LaunchConfigCache cache;

    int current_device = 0;
    cudaGetDevice(&current_device);

    if (cache.device != current_device) {
        cache.device = current_device;
        cache.sm_count = 1;
        cache.blocks_per_sm_aligned = 1;
        cache.blocks_per_sm_scalar  = 1;

        cudaDeviceGetAttribute(&cache.sm_count, cudaDevAttrMultiProcessorCount, current_device);
        cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &cache.blocks_per_sm_aligned,
            histogram_range_kernel<true>,
            kBlockThreads,
            0);
        cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &cache.blocks_per_sm_scalar,
            histogram_range_kernel<false>,
            kBlockThreads,
            0);

        if (cache.sm_count < 1) {
            cache.sm_count = 1;
        }
        if (cache.blocks_per_sm_aligned < 1) {
            cache.blocks_per_sm_aligned = 1;
        }
        if (cache.blocks_per_sm_scalar < 1) {
            cache.blocks_per_sm_scalar = 1;
        }
    }

    return cache;
}

} // anonymous namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // The function is intentionally fully asynchronous. Because the signature does not provide
    // a stream, operations are issued to the default stream. The caller is responsible for any
    // later synchronization and/or CUDA error checking.
    cudaStream_t stream = 0;

    const unsigned int from_u   = static_cast<unsigned int>(from);
    const unsigned int to_u     = static_cast<unsigned int>(to);
    const unsigned int bin_count = (to_u - from_u) + 1u;

    // The output is defined as the histogram for this call, not an accumulation across calls.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(bin_count) * sizeof(unsigned int), stream);

    if (inputSize == 0u) {
        return;
    }

    const bool aligned16 = is_16_byte_aligned(input);
    const LaunchConfigCache& cfg = get_launch_config_for_current_device();

    if (aligned16) {
        const size_t chunk_count = static_cast<size_t>(inputSize) / static_cast<size_t>(kVectorBytes);
        const int grid = choose_grid_size(chunk_count, cfg.sm_count, cfg.blocks_per_sm_aligned);

        histogram_range_kernel<true><<<grid, kBlockThreads, 0, stream>>>(
            input, histogram, inputSize, from_u, to_u);
    } else {
        const int grid = choose_grid_size(static_cast<size_t>(inputSize),
                                          cfg.sm_count,
                                          cfg.blocks_per_sm_scalar);

        histogram_range_kernel<false><<<grid, kBlockThreads, 0, stream>>>(
            input, histogram, inputSize, from_u, to_u);
    }
}

#include <cuda_runtime.h>
#include <cstddef>

/*
  Range-restricted histogram over a device-resident char buffer.

  Output convention:
    histogram[i] counts occurrences of byte value (from + i), for i in [0, to-from].

  Optimization strategy for modern NVIDIA GPUs:
    - Each warp owns a private shared-memory histogram row to avoid cross-warp
      contention while scanning the input.
    - Within a warp, __match_any_sync() groups lanes that saw the same byte/bin,
      so one lane can issue a single shared-memory atomicAdd weighted by popc(peers).
      This is effective for text, where many lanes often see the same characters.
    - Input is read as uint4 (16 bytes per thread per iteration) to improve
      global-memory throughput.
    - Each block flushes its shared partials to global memory with at most one
      update per output bin, so global atomic pressure scales with
      (#blocks * #requested_bins), not with inputSize.
    - The byte domain is fixed at 256 values, so we reserve a full 256-bin shared
      histogram per warp. On A100/H100-class GPUs the 8 KiB/block cost is tiny
      and enables fixed-size, low-overhead indexing.
*/

namespace {

constexpr unsigned int kByteDomain          = 256u;
constexpr unsigned int kBlockSize           = kByteDomain;  // 1 thread per possible byte value during init/flush.
constexpr unsigned int kWarpSize            = 32u;
constexpr unsigned int kNumWarps            = kBlockSize / kWarpSize;  // 8 warps for 256 threads.
constexpr unsigned int kVectorBytes         = 16u;                     // uint4 load width.
constexpr unsigned int kInvalidBin          = 0xFFFFFFFFu;
constexpr unsigned int kTargetBlocksPerSM   = 8u;                      // 8 * 256 threads = 2048 threads/SM.

static_assert(kBlockSize % kWarpSize == 0u, "Block size must be a multiple of warp size.");
static_assert(kBlockSize == kByteDomain,
              "This implementation relies on one thread per byte value during shared-memory init/flush.");
static_assert(sizeof(uint4) == kVectorBytes, "kVectorBytes must match the vectorized load width.");

/*
  Accumulate one byte into the warp-private shared histogram.

  - rangeBase is `from`.
  - numBins is `(to - from + 1)`.
  - The local/output bin is (byte_value - rangeBase) when the byte is in range.
  - Out-of-range bytes use a sentinel key so every currently active lane can still
    participate in the same warp collective without branching beforehand.
*/
__device__ __forceinline__
void accumulate_byte(const unsigned int byte_value,
                     const unsigned int rangeBase,
                     const unsigned int numBins,
                     const unsigned int lane,
                     const unsigned int activeMask,
                     unsigned int* const warpHist)
{
    const unsigned int bin = byte_value - rangeBase;

#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 700)
    const unsigned int key   = (bin < numBins) ? bin : kInvalidBin;
    const unsigned int peers = __match_any_sync(activeMask, key);

    if (key != kInvalidBin) {
        const unsigned int leader = static_cast<unsigned int>(__ffs(peers) - 1);
        if (lane == leader) {
            atomicAdd(warpHist + key, static_cast<unsigned int>(__popc(peers)));
        }
    }
#else
    // Fallback path for older compilation targets: still correct, just without
    // warp-level duplicate collapsing.
    (void)lane;
    (void)activeMask;
    if (bin < numBins) {
        atomicAdd(warpHist + bin, 1u);
    }
#endif
}

__device__ __forceinline__
void accumulate_word(const unsigned int word,
                     const unsigned int rangeBase,
                     const unsigned int numBins,
                     const unsigned int lane,
                     const unsigned int activeMask,
                     unsigned int* const warpHist)
{
    accumulate_byte((word      ) & 0xFFu, rangeBase, numBins, lane, activeMask, warpHist);
    accumulate_byte((word >>  8) & 0xFFu, rangeBase, numBins, lane, activeMask, warpHist);
    accumulate_byte((word >> 16) & 0xFFu, rangeBase, numBins, lane, activeMask, warpHist);
    accumulate_byte((word >> 24) & 0xFFu, rangeBase, numBins, lane, activeMask, warpHist);
}

__global__ __launch_bounds__(kBlockSize)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            const unsigned int inputSize,
                            const unsigned int rangeBase,
                            const unsigned int numBins)
{
    // One shared histogram row per warp; rows are indexed by output-bin offset [0, 255].
    __shared__ unsigned int s_warpHist[kNumWarps][kByteDomain];

    const unsigned int tid    = threadIdx.x;
    const unsigned int lane   = tid & (kWarpSize - 1u);
    const unsigned int warpId = tid >> 5;

    // Fixed 256-thread block: every thread zeroes one byte-value column across all warp rows.
#pragma unroll
    for (unsigned int w = 0; w < kNumWarps; ++w) {
        s_warpHist[w][tid] = 0u;
    }
    __syncthreads();

    unsigned int* const myWarpHist = s_warpHist[warpId];

    // Read bytes as unsigned values; plain `char` may be signed, but histogram
    // bins are defined over ordinal values [0, 255].
    const unsigned char* const inputBytes = reinterpret_cast<const unsigned char*>(input);
    const uint4* const inputVec = reinterpret_cast<const uint4*>(inputBytes);

    const unsigned int globalThread = blockIdx.x * kBlockSize + tid;
    const unsigned int totalThreads = gridDim.x * kBlockSize;

    const unsigned int vecCount = inputSize / kVectorBytes;
    for (unsigned int idx = globalThread; idx < vecCount; idx += totalThreads) {
        // All threads that reach this point participate in the same collectives for
        // this loop iteration, so one active mask is valid for all 16 bytes here.
        const unsigned int activeMask = __activemask();
        const uint4 v = inputVec[idx];

        accumulate_word(v.x, rangeBase, numBins, lane, activeMask, myWarpHist);
        accumulate_word(v.y, rangeBase, numBins, lane, activeMask, myWarpHist);
        accumulate_word(v.z, rangeBase, numBins, lane, activeMask, myWarpHist);
        accumulate_word(v.w, rangeBase, numBins, lane, activeMask, myWarpHist);
    }

    // Handle the final 0..15 leftover bytes. Only the first `tailCount` global
    // threads do work here, so each leftover byte is processed exactly once.
    const unsigned int tailBase  = vecCount * kVectorBytes;
    const unsigned int tailCount = inputSize - tailBase;
    if (globalThread < tailCount) {
        const unsigned int activeMask = __activemask();
        accumulate_byte(static_cast<unsigned int>(inputBytes[tailBase + globalThread]),
                        rangeBase, numBins, lane, activeMask, myWarpHist);
    }

    __syncthreads();

    // Reduce the 8 warp-private rows into the final output.
    // Only bins [0, numBins) are meaningful for this launch.
    if (tid < numBins) {
        unsigned int sum = 0u;
#pragma unroll
        for (unsigned int w = 0; w < kNumWarps; ++w) {
            sum += s_warpHist[w][tid];
        }

        // If the whole job fits in one block, this block owns the final answer and
        // can overwrite the output directly. Otherwise, accumulate block partials.
        if (gridDim.x == 1u) {
            histogram[tid] = sum;
        } else if (sum != 0u) {
            atomicAdd(histogram + tid, sum);
        }
    }
}

}  // namespace

void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // Per the API contract:
    //   - `input` and `histogram` are device pointers allocated with cudaMalloc.
    //   - 0 <= from < to <= 255.
    //   - The output buffer has exactly (to - from + 1) elements.
    //
    // This function only enqueues work. It does not synchronize; the caller owns
    // any host/device synchronization. Because the API has no stream parameter,
    // work is issued to the current default stream.

    const unsigned int rangeBase = static_cast<unsigned int>(from);
    const unsigned int numBins   = static_cast<unsigned int>(to - from + 1);

    // Empty input still requires a valid zero histogram.
    if (inputSize == 0u) {
        cudaMemsetAsync(histogram, 0, static_cast<std::size_t>(numBins) * sizeof(unsigned int));
        return;
    }

    // One thread processes one 16-byte vector item per loop iteration.
    const unsigned int vecWorkItems = inputSize / kVectorBytes;
    const unsigned int tailCount    = inputSize - vecWorkItems * kVectorBytes;
    const unsigned int workItems    = vecWorkItems + (tailCount != 0u ? 1u : 0u);
    const unsigned int maxBlocksNeeded = (workItems + kBlockSize - 1u) / kBlockSize;

    unsigned int gridSize = maxBlocksNeeded;

    // If more than 8 blocks are needed, cap the launch to ~8 CTAs/SM. With 256-thread
    // blocks this matches the 2048-thread/SM limit on modern data-center GPUs; extra
    // work is covered by the grid-stride loop.
    //
    // Cache the SM count per host thread/device pair so repeated launches avoid a
    // runtime attribute query in the hot path.
    if (gridSize > kTargetBlocksPerSM) {
        thread_local int cachedDevice  = -1;
        thread_local int cachedSMCount = 0;

        int device = 0;
        cudaGetDevice(&device);
        if (device != cachedDevice) {
            cachedSMCount = 0;
            cudaDeviceGetAttribute(&cachedSMCount, cudaDevAttrMultiProcessorCount, device);
            cachedDevice = device;
        }

        const unsigned int targetGrid =
            static_cast<unsigned int>(cachedSMCount) * kTargetBlocksPerSM;

        if (targetGrid != 0u && gridSize > targetGrid) {
            gridSize = targetGrid;
        }
    }

    if (gridSize == 0u) {
        gridSize = 1u;
    }

    // Multi-block launches accumulate partials with global atomicAdd, so the output
    // histogram must be zeroed first. Single-block launches overwrite every output
    // bin directly, so skipping memset avoids an extra runtime call on small inputs.
    if (gridSize != 1u) {
        cudaMemsetAsync(histogram, 0, static_cast<std::size_t>(numBins) * sizeof(unsigned int));
    }

    histogram_range_kernel<<<gridSize, kBlockSize>>>(input, histogram, inputSize, rangeBase, numBins);
}

#include <cuda_runtime.h>
#include <stdint.h>

namespace {

// Histogram for a contiguous byte sub-range [from, to].
//
// Design choices for modern NVIDIA data-center GPUs:
// - One private shared-memory histogram per warp reduces shared-memory atomic contention versus a
//   single block-wide histogram.
// - The block size is 256 threads, which matches the maximum possible number of output bins.
//   That lets one thread naturally correspond to one possible output bin during initialization
//   and final reduction.
// - The input is processed through:
//     1) a short scalar prologue to reach 16-byte alignment,
//     2) a vectorized main loop using uint4 loads (16 bytes/thread/iteration),
//     3) a short scalar epilogue.
// - The final merge performs one global update per nonzero bin per block.

constexpr int kWarpSize      = 32;
constexpr int kBlockSize     = 256;
constexpr int kWarpsPerBlock = kBlockSize / kWarpSize;
constexpr int kMaxBins       = 256;
constexpr unsigned int kVectorBytes = sizeof(uint4);

static_assert(kBlockSize % kWarpSize == 0, "Block size must be a multiple of the warp size.");
static_assert(kBlockSize == kMaxBins, "This implementation relies on one thread per possible byte bin.");
static_assert(kVectorBytes == 16u, "uint4 is expected to be 16 bytes.");

__device__ __forceinline__ void shared_hist_atomic_add(unsigned int* address, unsigned int value) {
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 700)
    // The shared histogram is private to the current CTA, so block-scope atomics are sufficient
    // and can be slightly cheaper than full device-scope atomics on modern architectures.
    atomicAdd_block(address, value);
#else
    atomicAdd(address, value);
#endif
}

__device__ __forceinline__ void accumulate_byte_to_hist(const unsigned int byteValue,
                                                        unsigned int* const warpHist,
                                                        const unsigned int from,
                                                        const unsigned int rangeLen) {
    // Unsigned subtraction + bounds check compactly implements:
    //   from <= byteValue <= to
    // because values smaller than `from` wrap to a large unsigned integer and fail the check.
    const unsigned int bin = byteValue - from;
    if (bin < rangeLen) {
        shared_hist_atomic_add(warpHist + bin, 1u);
    }
}

__device__ __forceinline__ void accumulate_word_to_hist(const unsigned int word,
                                                        unsigned int* const warpHist,
                                                        const unsigned int from,
                                                        const unsigned int rangeLen) {
    accumulate_byte_to_hist( word        & 0xFFu, warpHist, from, rangeLen);
    accumulate_byte_to_hist((word >>  8) & 0xFFu, warpHist, from, rangeLen);
    accumulate_byte_to_hist((word >> 16) & 0xFFu, warpHist, from, rangeLen);
    accumulate_byte_to_hist((word >> 24) & 0xFFu, warpHist, from, rangeLen);
}

template <int BLOCK_SIZE>
__global__ __launch_bounds__(BLOCK_SIZE)
void histogram_range_kernel(const unsigned char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            const unsigned int inputSize,
                            const unsigned int from,
                            const unsigned int rangeLen) {
    constexpr int WARPS_PER_BLOCK = BLOCK_SIZE / kWarpSize;

    // One private 256-bin histogram per warp.
    // With BLOCK_SIZE == 256 this is 8 warps * 256 bins * 4 bytes = 8 KiB of shared memory.
    __shared__ unsigned int s_hist[WARPS_PER_BLOCK][kMaxBins];

    const unsigned int localBin = threadIdx.x;

    // Only bins [0, rangeLen) can ever be touched, so only those bins need initialization.
    if (localBin < rangeLen) {
#pragma unroll
        for (int w = 0; w < WARPS_PER_BLOCK; ++w) {
            s_hist[w][localBin] = 0u;
        }
    }
    __syncthreads();

    const unsigned int globalThread = blockIdx.x * BLOCK_SIZE + threadIdx.x;
    const unsigned int totalThreads = gridDim.x * BLOCK_SIZE;
    const unsigned int warpId       = threadIdx.x >> 5;
    unsigned int* const warpHist    = s_hist[warpId];

    // Even though cudaMalloc returns highly aligned pointers, this scalar prologue makes the vectorized
    // path safe if the caller passes an offset into that allocation.
    const unsigned int misalignment =
        static_cast<unsigned int>(reinterpret_cast<uintptr_t>(input) & (kVectorBytes - 1u));
    const unsigned int scalarPrefix =
        (kVectorBytes - misalignment) & (kVectorBytes - 1u);
    const unsigned int prefixCount =
        (scalarPrefix < inputSize) ? scalarPrefix : inputSize;

    // Scalar prologue: at most 15 bytes.
    for (unsigned int idx = globalThread; idx < prefixCount; idx += totalThreads) {
        accumulate_byte_to_hist(static_cast<unsigned int>(input[idx]), warpHist, from, rangeLen);
    }

    const unsigned char* const alignedInput = input + prefixCount;
    const unsigned int remaining = inputSize - prefixCount;
    const unsigned int vecCount  = remaining / kVectorBytes;
    const uint4* const input4    = reinterpret_cast<const uint4*>(alignedInput);

    // Main vectorized pass: 16 bytes per thread per iteration.
    for (unsigned int vecIdx = globalThread; vecIdx < vecCount; vecIdx += totalThreads) {
        const uint4 v = input4[vecIdx];
        accumulate_word_to_hist(v.x, warpHist, from, rangeLen);
        accumulate_word_to_hist(v.y, warpHist, from, rangeLen);
        accumulate_word_to_hist(v.z, warpHist, from, rangeLen);
        accumulate_word_to_hist(v.w, warpHist, from, rangeLen);
    }

    const unsigned int tailStart = prefixCount + vecCount * kVectorBytes;
    const unsigned int tailCount = inputSize - tailStart;

    // Scalar epilogue: at most 15 bytes.
    for (unsigned int idx = globalThread; idx < tailCount; idx += totalThreads) {
        accumulate_byte_to_hist(static_cast<unsigned int>(input[tailStart + idx]), warpHist, from, rangeLen);
    }

    __syncthreads();

    // Reduce the warp-private histograms and merge them into the final global histogram.
    if (localBin < rangeLen) {
        unsigned int sum = 0u;
#pragma unroll
        for (int w = 0; w < WARPS_PER_BLOCK; ++w) {
            sum += s_hist[w][localBin];
        }

        if (sum != 0u) {
            // run_histogram() zeros the destination histogram before launch, so a single-block launch
            // can store directly instead of using a global atomic.
            if (gridDim.x == 1) {
                histogram[localBin] = sum;
            } else {
                atomicAdd(histogram + localBin, sum);
            }
        }
    }
}

}  // namespace

void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    const unsigned int rangeLen = static_cast<unsigned int>(to - from + 1);

    // The result is accumulated with atomics, so the destination must start from zero.
    // Both operations are enqueued on stream 0; synchronization is intentionally left to the caller.
    (void)cudaMemsetAsync(
        histogram,
        0,
        static_cast<size_t>(rangeLen) * sizeof(unsigned int),
        0);

    if (inputSize == 0u) {
        return;
    }

    constexpr unsigned int kBytesPerBlock =
        static_cast<unsigned int>(kBlockSize) * kVectorBytes;

    unsigned int gridSize = 1u;

    // For very small inputs, a single block is enough and avoids host-side occupancy queries.
    if (inputSize > kBytesPerBlock) {
        int device = 0;
        (void)cudaGetDevice(&device);

        int smCount = 0;
        (void)cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

        int activeBlocksPerSM = 0;
        (void)cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &activeBlocksPerSM,
            histogram_range_kernel<kBlockSize>,
            kBlockSize,
            0);

        unsigned int maxResidentBlocks = 128u;
        if (smCount > 0 && activeBlocksPerSM > 0) {
            maxResidentBlocks = static_cast<unsigned int>(smCount * activeBlocksPerSM);
        } else if (smCount > 0) {
            maxResidentBlocks = static_cast<unsigned int>(smCount * 4);
        }

        // Size-based heuristic: enough blocks so that, before grid-striding, each thread gets about
        // one vector load on average. Cap to resident blocks so the final global merge does not create
        // excessive atomic traffic.
        const unsigned int blocksFromSize = 1u + (inputSize - 1u) / kBytesPerBlock;
        gridSize = (blocksFromSize < maxResidentBlocks) ? blocksFromSize : maxResidentBlocks;
        if (gridSize == 0u) {
            gridSize = 1u;
        }
    }

    // Reinterpret as unsigned bytes so byte values 128..255 are counted correctly even if `char` is signed.
    histogram_range_kernel<kBlockSize><<<gridSize, kBlockSize, 0, 0>>>(
        reinterpret_cast<const unsigned char*>(input),
        histogram,
        inputSize,
        static_cast<unsigned int>(from),
        rangeLen);
}

#include <cuda_runtime.h>

namespace {

// The kernel is specialized for a fixed 256-thread block size.
// On A100/H100-class GPUs this gives 8 warps per block, which is a good
// balance between occupancy, shared-memory footprint, and reduction cost.
constexpr int BLOCK_THREADS    = 256;
constexpr int WARP_SIZE        = 32;
constexpr int WARPS_PER_BLOCK  = BLOCK_THREADS / WARP_SIZE;
constexpr int ITEMS_PER_THREAD = 4;
constexpr int FULL_BYTE_RANGE  = 256;

static_assert(BLOCK_THREADS % WARP_SIZE == 0, "BLOCK_THREADS must be a multiple of warp size.");
static_assert(ITEMS_PER_THREAD == 4, "The vectorized load path assumes four bytes per thread.");
static_assert(FULL_BYTE_RANGE == 256, "This kernel is specialized for byte histograms.");

// Each warp owns a private histogram in shared memory.
// The caller passes a fixed participant mask captured at a converged point.
// That fixed mask is essential on Volta+ independent thread scheduling:
// it lets us safely use plain shared-memory increments (not shared atomics)
// because __syncwarp(participant_mask) closes each update step before the next
// byte is processed by any participating lane.
__device__ __forceinline__
void accumulate_rel_to_warp_histogram(unsigned int rel,
                                      unsigned int bins,
                                      unsigned int lane,
                                      unsigned int participant_mask,
                                      unsigned int* __restrict__ warp_hist)
{
    // Group equal values inside the participating subset of the warp.
    const unsigned int peers = __match_any_sync(participant_mask, rel);

    // Only the first lane in each equal-value group performs the update.
    // `rel < bins` is a branchless range test because `rel` was computed as
    // (byte_value - range_begin) in unsigned arithmetic.
    if (rel < bins && lane == static_cast<unsigned int>(__ffs(peers) - 1)) {
        warp_hist[rel] += static_cast<unsigned int>(__popc(peers));
    }

    // Ensure all participating lanes finish this byte's update before any of
    // them start the next one; this is what makes the plain shared-memory
    // increment above safe on modern GPUs with independent thread scheduling.
    __syncwarp(participant_mask);
}

// Shared-memory optimized histogram kernel.
// - One private 256-bin histogram per warp lives in shared memory.
// - Input is consumed in 4-byte vector loads for better global-memory efficiency.
// - __match_any_sync collapses duplicate byte values within a warp so each
//   distinct value updates the shared histogram once per sub-step.
// - At the end, the block reduces its warp-private histograms and accumulates
//   the result into the output histogram.
__global__ __launch_bounds__(BLOCK_THREADS)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int range_begin,
                            unsigned int bins)
{
    // Fixed-size shared storage is cheap here:
    // 8 warps * 256 bins * 4 bytes = 8 KiB per block.
    __shared__ unsigned int warp_histograms[WARPS_PER_BLOCK][FULL_BYTE_RANGE];

    const unsigned int tid     = threadIdx.x;
    const unsigned int warp_id = tid / WARP_SIZE;
    const unsigned int lane    = tid & (WARP_SIZE - 1u);

    unsigned int* const warp_hist = warp_histograms[warp_id];

    // Zero only the bins actually needed for this invocation.
    for (unsigned int bin = lane; bin < bins; bin += WARP_SIZE) {
        warp_hist[bin] = 0u;
    }
    __syncwarp();

    const unsigned char* const input_bytes = reinterpret_cast<const unsigned char*>(input);

    // The problem states the buffers are cudaMalloc-allocated, so the base
    // pointer is naturally aligned for efficient 4-byte vector loads.
    const uchar4* const input_vec4 = reinterpret_cast<const uchar4*>(input_bytes);

    const size_t n      = static_cast<size_t>(inputSize);
    size_t index        = (static_cast<size_t>(blockIdx.x) * BLOCK_THREADS + tid) * ITEMS_PER_THREAD;
    const size_t stride = static_cast<size_t>(gridDim.x) * BLOCK_THREADS * ITEMS_PER_THREAD;

    // Fast path: process four bytes per thread per iteration.
    for (; index + ITEMS_PER_THREAD <= n; index += stride) {
        // All lanes active in this loop body have a full 4-byte chunk, so a
        // single fixed mask is valid for all four sub-steps below.
        const unsigned int chunk_mask = __activemask();
        const uchar4 bytes = input_vec4[index >> 2];

        accumulate_rel_to_warp_histogram(static_cast<unsigned int>(bytes.x) - range_begin,
                                         bins, lane, chunk_mask, warp_hist);
        accumulate_rel_to_warp_histogram(static_cast<unsigned int>(bytes.y) - range_begin,
                                         bins, lane, chunk_mask, warp_hist);
        accumulate_rel_to_warp_histogram(static_cast<unsigned int>(bytes.z) - range_begin,
                                         bins, lane, chunk_mask, warp_hist);
        accumulate_rel_to_warp_histogram(static_cast<unsigned int>(bytes.w) - range_begin,
                                         bins, lane, chunk_mask, warp_hist);
    }

    // Tail path: at most three leftover bytes per thread.
    // A fresh mask is captured for each tail byte because the active subset can shrink.
    if (index < n) {
        const unsigned int tail_mask0 = __activemask();
        accumulate_rel_to_warp_histogram(static_cast<unsigned int>(input_bytes[index + 0]) - range_begin,
                                         bins, lane, tail_mask0, warp_hist);

        if (index + 1 < n) {
            const unsigned int tail_mask1 = __activemask();
            accumulate_rel_to_warp_histogram(static_cast<unsigned int>(input_bytes[index + 1]) - range_begin,
                                             bins, lane, tail_mask1, warp_hist);
        }

        if (index + 2 < n) {
            const unsigned int tail_mask2 = __activemask();
            accumulate_rel_to_warp_histogram(static_cast<unsigned int>(input_bytes[index + 2]) - range_begin,
                                             bins, lane, tail_mask2, warp_hist);
        }

        if (index + 3 < n) {
            const unsigned int tail_mask3 = __activemask();
            accumulate_rel_to_warp_histogram(static_cast<unsigned int>(input_bytes[index + 3]) - range_begin,
                                             bins, lane, tail_mask3, warp_hist);
        }
    }

    // Make all warp-private histograms visible to the whole block before reduction.
    __syncthreads();

    // One thread per output bin reduces the per-warp partials.
    for (unsigned int bin = tid; bin < bins; bin += BLOCK_THREADS) {
        unsigned int sum = 0u;

        #pragma unroll
        for (int warp = 0; warp < WARPS_PER_BLOCK; ++warp) {
            sum += warp_histograms[warp][bin];
        }

        if (sum != 0u) {
            // If the grid has only one block, no global atomic is needed.
            if (gridDim.x == 1) {
                histogram[bin] = sum;
            } else {
                atomicAdd(histogram + bin, sum);
            }
        }
    }
}

} // namespace

// Host launcher.
// Assumptions from the problem statement:
// - `input` and `histogram` are device pointers allocated with cudaMalloc.
// - `histogram` has exactly (to - from + 1) elements.
// - The caller handles any needed synchronization/error checking after launch.
void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    const unsigned int range_begin = static_cast<unsigned int>(from);
    const unsigned int bins        = static_cast<unsigned int>(to - from + 1);

    // Always clear the destination because the contract is to produce the full histogram.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(bins) * sizeof(unsigned int));

    if (inputSize == 0u) {
        return;
    }

    int device = 0;
    cudaGetDevice(&device);

    int sm_count = 0;
    cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    if (sm_count <= 0) {
        sm_count = 1;
    }

    // Grid-stride loops let us cap the launch to an occupancy-saturating grid.
    int active_blocks_per_sm = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &active_blocks_per_sm,
        histogram_range_kernel,
        BLOCK_THREADS,
        0);
    if (active_blocks_per_sm <= 0) {
        active_blocks_per_sm = 1;
    }

    const unsigned int bytes_per_block =
        static_cast<unsigned int>(BLOCK_THREADS * ITEMS_PER_THREAD);

    const unsigned int blocks_needed =
        (inputSize + bytes_per_block - 1u) / bytes_per_block;

    const unsigned int max_grid =
        static_cast<unsigned int>(sm_count) *
        static_cast<unsigned int>(active_blocks_per_sm);

    const unsigned int grid =
        (blocks_needed < max_grid) ? blocks_needed : max_grid;

    histogram_range_kernel<<<grid, BLOCK_THREADS>>>(
        input,
        histogram,
        inputSize,
        range_begin,
        bins);
}

#include <cuda_runtime.h>

namespace {

// Tuned for modern datacenter GPUs (A100/H100 class):
// - 256 threads/block lets the final block-local reduction map one thread to one
//   possible output bin (the range is at most 256 bins).
// - 4-way unrolling reduces loop/control overhead without creating excessive
//   register pressure for this histogram-style workload.
constexpr int kWarpSize        = 32;
constexpr int kBlockThreads    = 256;
constexpr int kItemsPerLoop    = 4;
constexpr int kWarpsPerBlock   = kBlockThreads / kWarpSize;

static_assert((kBlockThreads % kWarpSize) == 0, "Block size must be a multiple of 32.");
static_assert(kBlockThreads >= 256, "Block size must cover the maximum possible bin count.");

inline unsigned int ceil_div_u32(const unsigned int n, const unsigned int d) {
    return (n == 0u) ? 0u : (1u + (n - 1u) / d);
}

// Called collectively by the currently active lanes of a warp.
// Fast path for Volta+ (the intended target: A100/H100) uses:
//   1) a warp-private histogram slice in shared memory,
//   2) __match_any_sync() to collapse identical bytes inside the warp so only
//      one leader lane updates a given bin per step, and
//   3) __syncwarp() as the ordering primitive that makes plain shared-memory
//      increments safe across consecutive update steps.
//
// Important detail:
//   We synchronize the full active mask, not just the lanes that matched the
//   range, because a lane that is "invalid" for the current byte may become the
//   leader for the next byte and must observe all prior shared-memory updates.
__device__ __forceinline__
void accumulate_warp_private_byte(const unsigned int c,
                                  const unsigned int from,
                                  const unsigned int numBins,
                                  const unsigned int activeMask,
                                  unsigned int* const warpHistogram,
                                  const unsigned int lane)
{
    const unsigned int bin   = c - from;
    const bool         valid = (bin < numBins);

    const unsigned int validMask = __ballot_sync(activeMask, valid);

    // validMask is the same in every participating lane because it is produced
    // by the ballot itself, so this branch is warp-uniform for active lanes.
    if (validMask != 0u) {
        const unsigned int peerMask = __match_any_sync(validMask, bin);

        // Only one leader lane per distinct bin updates the warp-private slice.
        // Because each warp owns a disjoint slice of shared memory and because
        // __match_any_sync() guarantees one leader per distinct bin in this
        // update step, a plain increment is sufficient here.
        if (valid) {
            const unsigned int leader = static_cast<unsigned int>(__ffs(peerMask) - 1);
            if (lane == leader) {
                warpHistogram[bin] += static_cast<unsigned int>(__popc(peerMask));
            }
        }

        __syncwarp(activeMask);
    }
}

// Range-restricted histogram kernel.
// Input is treated as unsigned bytes (0..255) regardless of whether host-side
// char is signed or unsigned.
__global__ __launch_bounds__(kBlockThreads)
void histogram_char_range_kernel(const unsigned char* __restrict__ input,
                                 unsigned int* __restrict__ histogram,
                                 const unsigned int inputSize,
                                 const unsigned int from,
                                 const unsigned int numBins)
{
    extern __shared__ unsigned int sharedHistogram[];

    const unsigned int tid    = static_cast<unsigned int>(threadIdx.x);
    const unsigned int warpId = tid >> 5;
    const unsigned int lane   = tid & 31u;

    // One private histogram per warp. This reduces contention versus a single
    // block-wide shared histogram, while still keeping the per-block footprint small.
    unsigned int* const warpHistogram = sharedHistogram + warpId * numBins;
    const unsigned int sharedBins = static_cast<unsigned int>(kWarpsPerBlock) * numBins;

    // Cooperative zero-initialization of all warp-private histograms.
    for (unsigned int i = tid; i < sharedBins; i += kBlockThreads) {
        sharedHistogram[i] = 0u;
    }
    __syncthreads();

    const unsigned int globalThread = static_cast<unsigned int>(blockIdx.x) * kBlockThreads + tid;
    const unsigned int totalThreads = static_cast<unsigned int>(gridDim.x) * kBlockThreads;

    // Unrolled grid-stride loop.
    // For a fixed unroll slot, consecutive lanes read consecutive bytes, so
    // accesses remain coalesced.
    unsigned int idx = globalThread;
    const unsigned int unrolledStep  = totalThreads * static_cast<unsigned int>(kItemsPerLoop);
    const unsigned int unrolledLimit =
        (inputSize > static_cast<unsigned int>(kItemsPerLoop - 1) * totalThreads)
            ? (inputSize - static_cast<unsigned int>(kItemsPerLoop - 1) * totalThreads)
            : 0u;

    for (; idx < unrolledLimit; idx += unrolledStep) {
        // The final trip can have a partially active warp, so the helper uses
        // the true active mask rather than assuming all 32 lanes participate.
        const unsigned int activeMask = __activemask();

        accumulate_warp_private_byte(static_cast<unsigned int>(input[idx]),
                                     from, numBins, activeMask, warpHistogram, lane);
        accumulate_warp_private_byte(static_cast<unsigned int>(input[idx + totalThreads]),
                                     from, numBins, activeMask, warpHistogram, lane);
        accumulate_warp_private_byte(static_cast<unsigned int>(input[idx + 2u * totalThreads]),
                                     from, numBins, activeMask, warpHistogram, lane);
        accumulate_warp_private_byte(static_cast<unsigned int>(input[idx + 3u * totalThreads]),
                                     from, numBins, activeMask, warpHistogram, lane);
    }

    // Scalar tail.
    for (; idx < inputSize; idx += totalThreads) {
        const unsigned int activeMask = __activemask();
        accumulate_warp_private_byte(static_cast<unsigned int>(input[idx]),
                                     from, numBins, activeMask, warpHistogram, lane);
    }

    __syncthreads();

    // Finalize this block's private histograms into the global output.
    // The requested range has at most 256 bins, so with 256 threads/block each
    // possible output bin can be handled by one thread.
    if (tid < numBins) {
        unsigned int sum = 0u;
#pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += sharedHistogram[static_cast<unsigned int>(w) * numBins + tid];
        }

        if (sum != 0u) {
            atomicAdd(histogram + tid, sum);
        }
    }
}

} // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // Problem contract guarantees:
    //   0 <= from < to <= 255
    // and both pointers refer to device memory allocated by cudaMalloc.
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);

    // The kernel accumulates partial block results into the output histogram,
    // so clear the destination first. This is intentionally asynchronous; the
    // caller requested to handle synchronization externally.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(numBins) * sizeof(unsigned int));

    if (inputSize == 0u) {
        return;
    }

    const size_t sharedBytes =
        static_cast<size_t>(kWarpsPerBlock) * static_cast<size_t>(numBins) * sizeof(unsigned int);

    // Use occupancy information, but cap the launch to 4 blocks/SM.
    // This kernel has a non-trivial fixed cost per block (shared-memory zeroing
    // and final merge), and on A100/H100-class GPUs 4 resident 256-thread blocks/SM
    // already provide ample occupancy while avoiding unnecessary extra block-level
    // merge traffic to the global histogram.
    int device = 0;
    (void)cudaGetDevice(&device);

    int smCount = 1;
    (void)cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1) {
        smCount = 1;
    }

    int maxBlocksPerSM = 1;
    (void)cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &maxBlocksPerSM,
        histogram_char_range_kernel,
        kBlockThreads,
        static_cast<int>(sharedBytes));
    if (maxBlocksPerSM < 1) {
        maxBlocksPerSM = 1;
    }

    const int targetBlocksPerSM = (maxBlocksPerSM > 4) ? 4 : maxBlocksPerSM;
    int grid = smCount * targetBlocksPerSM;

    // Do not launch more blocks than can do useful work in the first unrolled pass.
    const unsigned int maxUsefulBlocks =
        ceil_div_u32(inputSize, static_cast<unsigned int>(kBlockThreads * kItemsPerLoop));
    if (grid > static_cast<int>(maxUsefulBlocks)) {
        grid = static_cast<int>(maxUsefulBlocks);
    }
    if (grid < 1) {
        grid = 1;
    }

    // Reinterpret as unsigned bytes so values 128..255 are handled by ordinal
    // value rather than sign extension of plain char.
    histogram_char_range_kernel<<<grid, kBlockThreads, sharedBytes>>>(
        reinterpret_cast<const unsigned char*>(input),
        histogram,
        inputSize,
        static_cast<unsigned int>(from),
        numBins);
}

#include <cuda_runtime.h>

namespace detail {

// Tuned for modern NVIDIA data-center GPUs (A100/H100 class):
// - 256 threads/block gives exactly one thread per possible byte value in the final reduction.
// - 8 warps/block is enough to keep the machine busy while keeping shared-memory usage tiny.
// - Each thread vector-loads 16 bytes at a time via uint4.
constexpr int kWarpSize = 32;
constexpr int kBlockThreads = 256;
constexpr int kWarpsPerBlock = kBlockThreads / kWarpSize;
constexpr unsigned int kVectorBytes = sizeof(uint4);
constexpr unsigned int kBytesPerBlockIteration =
    static_cast<unsigned int>(kBlockThreads) * kVectorBytes;

// For this kernel, launching at the absolute occupancy limit is not always optimal:
// every extra block adds another per-block reduction into the global histogram.
// On Ampere/Hopper, 4 CTAs/SM (32 resident warps/SM) is typically enough to saturate
// memory throughput for this workload while reducing global atomic pressure.
constexpr unsigned int kTargetBlocksPerSM = 4u;

static_assert(kBlockThreads % kWarpSize == 0,
              "Block size must be a multiple of the warp size.");
static_assert(kBlockThreads >= 256,
              "Block size must be at least 256 so one thread can reduce each possible byte bin.");

// Count one byte into this warp's shared-memory histogram.
//
// The histogram is private per warp, which removes inter-warp contention.
// __match_any_sync() collapses identical byte values inside a warp, so a whole group
// of equal characters becomes one shared-memory atomic instead of up to 32 atomics.
//
// A shared-memory atomic is intentionally retained here even though the histogram is
// warp-private: on Volta+ GPUs with independent thread scheduling, atomics keep the
// updates correct without relying on undocumented warp-synchronous memory behavior.
__device__ __forceinline__ void accumulate_byte(
    unsigned int value,
    unsigned int from,
    unsigned int bins,
    unsigned int lane,
    unsigned int* warp_hist)
{
    const unsigned int bin = value - from;
    if (bin < bins) {
        const unsigned int active = __activemask();
        const unsigned int peers = __match_any_sync(active, bin);
        const unsigned int leader = static_cast<unsigned int>(__ffs(static_cast<int>(peers)) - 1);
        if (lane == leader) {
            atomicAdd(warp_hist + bin, static_cast<unsigned int>(__popc(peers)));
        }
    }
}

// Unpack four bytes from a 32-bit word and feed them to the byte accumulator.
// NVIDIA GPUs are little-endian, so the low byte is the first byte in memory.
__device__ __forceinline__ void accumulate_word(
    unsigned int word,
    unsigned int from,
    unsigned int bins,
    unsigned int lane,
    unsigned int* warp_hist)
{
    accumulate_byte((word >>  0) & 0xFFu, from, bins, lane, warp_hist);
    accumulate_byte((word >>  8) & 0xFFu, from, bins, lane, warp_hist);
    accumulate_byte((word >> 16) & 0xFFu, from, bins, lane, warp_hist);
    accumulate_byte((word >> 24) & 0xFFu, from, bins, lane, warp_hist);
}

// One-pass histogram kernel:
// 1) each warp accumulates into its own shared-memory histogram,
// 2) the block reduces warp-private histograms,
// 3) the block contributes to the final global histogram.
//
// The requested histogram range is continuous and at most 256 bins wide, so the shared
// footprint is very small: warps_per_block * bins * sizeof(unsigned int), i.e. at most 8 KB.
template <int BLOCK_THREADS>
__launch_bounds__(BLOCK_THREADS)
__global__ void histogram_range_kernel(
    const char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    unsigned int from,
    unsigned int bins)
{
    constexpr int kWarps = BLOCK_THREADS / kWarpSize;
    extern __shared__ unsigned int s_hist[];

    const unsigned int tid  = threadIdx.x;
    const unsigned int warp = tid >> 5;
    const unsigned int lane = tid & 31u;

    // Layout in shared memory:
    //   [warp0 bins][warp1 bins][warp2 bins]...[warpN bins]
    unsigned int* const warp_hist = s_hist + warp * bins;

    // Zero only this warp's private histogram. Because the histogram is warp-private,
    // a warp-level sync is sufficient before accumulation starts.
    for (unsigned int bin = lane; bin < bins; bin += static_cast<unsigned int>(kWarpSize)) {
        warp_hist[bin] = 0u;
    }
    __syncwarp();

    // Treat the input as raw bytes. This is important because plain 'char' may be signed,
    // but histogram bins are defined over ordinal byte values 0..255.
    const unsigned char* const bytes = reinterpret_cast<const unsigned char*>(input);

    const unsigned int global_thread = blockIdx.x * BLOCK_THREADS + tid;
    const unsigned int total_threads = gridDim.x * BLOCK_THREADS;

    // Alignment-safe vectorization:
    // cudaMalloc() pointers are well aligned, but handling an arbitrary sub-buffer pointer
    // costs almost nothing and preserves correctness for all callers.
    const unsigned int misalignment =
        static_cast<unsigned int>(reinterpret_cast<size_t>(bytes) & (kVectorBytes - 1u));
    const unsigned int prefix = (kVectorBytes - misalignment) & (kVectorBytes - 1u);
    const unsigned int scalar_prefix = (prefix < inputSize) ? prefix : inputSize;

    // Scalar prefix until the pointer is 16-byte aligned.
    for (unsigned int i = global_thread; i < scalar_prefix; i += total_threads) {
        accumulate_byte(static_cast<unsigned int>(bytes[i]), from, bins, lane, warp_hist);
    }

    // Vectorized main loop: one uint4 == 16 input bytes.
    const unsigned int aligned_size = inputSize - scalar_prefix;
    const unsigned int vec_count = aligned_size / kVectorBytes;
    const uint4* const vec_input = reinterpret_cast<const uint4*>(bytes + scalar_prefix);

    for (unsigned int i = global_thread; i < vec_count; i += total_threads) {
        const uint4 v = vec_input[i];

        accumulate_word(v.x, from, bins, lane, warp_hist);
        accumulate_word(v.y, from, bins, lane, warp_hist);
        accumulate_word(v.z, from, bins, lane, warp_hist);
        accumulate_word(v.w, from, bins, lane, warp_hist);
    }

    // Scalar tail for the final 0..15 bytes.
    const unsigned int tail_start = scalar_prefix + vec_count * kVectorBytes;
    for (unsigned int i = tail_start + global_thread; i < inputSize; i += total_threads) {
        accumulate_byte(static_cast<unsigned int>(bytes[i]), from, bins, lane, warp_hist);
    }

    // Make every warp's shared histogram visible before the block-wide reduction.
    __syncthreads();

    // Final block reduction:
    // BLOCK_THREADS == 256 and bins <= 256, so at most one bin per thread.
    if (tid < bins) {
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < kWarps; ++w) {
            sum += s_hist[w * bins + tid];
        }

        // If only one block was launched, the kernel can overwrite the output directly and
        // the host-side memset can be skipped entirely. Otherwise each block atomically
        // contributes its partial sum to the global histogram.
        if (gridDim.x == 1u) {
            histogram[tid] = sum;
        } else if (sum != 0u) {
            atomicAdd(histogram + tid, sum);
        }
    }
}

__host__ __forceinline__ unsigned int ceil_div_u32(unsigned int n, unsigned int d)
{
    return (n + d - 1u) / d;
}

inline unsigned int choose_grid(unsigned int inputSize, size_t shared_bytes)
{
    int device = 0;
    cudaGetDevice(&device);

    int sm_count = 0;
    cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);

    int active_blocks_per_sm = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &active_blocks_per_sm,
        histogram_range_kernel<kBlockThreads>,
        kBlockThreads,
        shared_bytes);

    unsigned int blocks_per_sm =
        static_cast<unsigned int>((active_blocks_per_sm > 0) ? active_blocks_per_sm : 1);
    if (blocks_per_sm > kTargetBlocksPerSM) {
        blocks_per_sm = kTargetBlocksPerSM;
    }

    const unsigned int max_launch_blocks =
        static_cast<unsigned int>((sm_count > 0) ? sm_count : 1) * blocks_per_sm;

    const unsigned int blocks_for_coverage =
        ceil_div_u32(inputSize, kBytesPerBlockIteration);

    return (blocks_for_coverage < max_launch_blocks) ? blocks_for_coverage : max_launch_blocks;
}

} // namespace detail

// Launch helper expected by the prompt.
//
// Notes:
// - input and histogram are assumed to be device pointers allocated by cudaMalloc().
// - histogram has exactly (to - from + 1) elements.
// - the function enqueues work on stream 0 and performs no host/device synchronization;
//   the caller remains responsible for synchronization and error handling policy.
void run_histogram(
    const char* input,
    unsigned int* histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    const unsigned int bins = static_cast<unsigned int>(to - from + 1);
    const size_t histogram_bytes = static_cast<size_t>(bins) * sizeof(unsigned int);

    // Empty input is a pure "write zeros" case.
    if (inputSize == 0u) {
        cudaMemsetAsync(histogram, 0, histogram_bytes);
        return;
    }

    const size_t shared_bytes =
        static_cast<size_t>(detail::kWarpsPerBlock) *
        static_cast<size_t>(bins) *
        sizeof(unsigned int);

    const unsigned int grid = detail::choose_grid(inputSize, shared_bytes);

    // For a single-block launch, the kernel overwrites every output bin directly,
    // so the explicit memset can be skipped.
    if (grid != 1u) {
        cudaMemsetAsync(histogram, 0, histogram_bytes);
    }

    detail::histogram_range_kernel<detail::kBlockThreads>
        <<<grid, detail::kBlockThreads, shared_bytes>>>(
            input,
            histogram,
            inputSize,
            static_cast<unsigned int>(static_cast<unsigned char>(from)),
            bins);
}

#include <cuda_runtime.h>
#include <cstdint>

namespace {

// Fixed at 256 because:
// 1) the byte domain is exactly [0, 255], so threadIdx.x can map directly to byte values
//    during shared-memory initialization, and
// 2) the requested output range can never exceed 256 bins, so the same block size lets the
//    first `range_size` threads perform the final reduction, one thread per output bin.
constexpr int kBlockSize = 256;
constexpr int kWarpSize = 32;
constexpr int kWarpsPerBlock = kBlockSize / kWarpSize;
constexpr unsigned int kByteValueCount = 256u;

static_assert(kBlockSize == static_cast<int>(kByteValueCount),
              "kBlockSize must be 256.");
static_assert((kBlockSize % kWarpSize) == 0,
              "kBlockSize must be a multiple of the warp size.");

inline unsigned int div_up_u32(const unsigned int n, const unsigned int d)
{
    // Overflow-safe ceil(n / d) for unsigned 32-bit values.
    return (n == 0u) ? 0u : 1u + (n - 1u) / d;
}

static __device__ __forceinline__ void accumulate_byte(
    const unsigned int byte_value,
    const unsigned int from,
    const unsigned int range_size,
    const unsigned int active_mask,
    const unsigned int lane,
    unsigned int* __restrict__ warp_hist)
{
    const unsigned int output_bin = byte_value - from;
    const bool in_range = output_bin < range_size;

    // Only lanes whose byte is inside [from, to] participate.
    // __match_any_sync groups equal byte values inside the active valid lanes, so exactly
    // one leader lane updates the warp-private shared histogram and adds the whole group's
    // population at once. This removes both global atomics in the hot path and nearly all
    // shared-memory update contention.
    const unsigned int valid_mask = __ballot_sync(active_mask, in_range);
    if (in_range) {
        const unsigned int peers = __match_any_sync(valid_mask, byte_value);
        const unsigned int leader = static_cast<unsigned int>(__ffs(peers) - 1);
        if (lane == leader) {
            // Safe without atomics:
            // - this histogram is private to one warp, and
            // - within this helper invocation there is exactly one leader per distinct byte.
            warp_hist[byte_value] += __popc(peers);
        }
    }
}

static __device__ __forceinline__ void accumulate_word(
    const unsigned int word,
    const unsigned int from,
    const unsigned int range_size,
    const unsigned int active_mask,
    const unsigned int lane,
    unsigned int* __restrict__ warp_hist)
{
    accumulate_byte( word        & 0xFFu, from, range_size, active_mask, lane, warp_hist);
    accumulate_byte((word >>  8) & 0xFFu, from, range_size, active_mask, lane, warp_hist);
    accumulate_byte((word >> 16) & 0xFFu, from, range_size, active_mask, lane, warp_hist);
    accumulate_byte((word >> 24) & 0xFFu, from, range_size, active_mask, lane, warp_hist);
}

// Range-restricted byte histogram.
// Optimization strategy:
// - Each warp owns a private 256-bin histogram in shared memory.
// - Using full 256-bin warp histograms costs only 8 KiB/block at 256 threads, but it
//   enables direct indexing by raw byte value and very simple block-wide init/reduction.
// - The input is processed with aligned 32-bit loads for the bulk path.
// - Each block emits at most one global atomic add per requested output bin.
__global__ __launch_bounds__(kBlockSize)
void histogram_range_kernel(
    const char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    const unsigned int input_size,
    const unsigned int from,
    const unsigned int range_size)
{
    __shared__ unsigned int shared_hist[kWarpsPerBlock][kByteValueCount];

    // One thread per possible byte value; each thread clears that value across all warp
    // histograms. This is conflict-free and maps perfectly onto the 256-thread block.
    #pragma unroll
    for (int w = 0; w < kWarpsPerBlock; ++w) {
        shared_hist[w][threadIdx.x] = 0u;
    }
    __syncthreads();

    const unsigned int lane = threadIdx.x & (kWarpSize - 1u);
    const unsigned int warp = threadIdx.x >> 5;
    unsigned int* const warp_hist = shared_hist[warp];

    const unsigned char* const input_u8 =
        reinterpret_cast<const unsigned char*>(input);

    const unsigned int global_thread =
        static_cast<unsigned int>(blockIdx.x) * static_cast<unsigned int>(kBlockSize) + threadIdx.x;
    const unsigned int global_stride =
        static_cast<unsigned int>(gridDim.x) * static_cast<unsigned int>(kBlockSize);

    // Peel a tiny scalar prefix so the bulk path can use aligned 32-bit loads even if the
    // caller passes a sub-buffer pointer. For a plain cudaMalloc base pointer, the prefix
    // is normally zero.
    const uintptr_t input_addr = reinterpret_cast<uintptr_t>(input_u8);
    const unsigned int prefix = static_cast<unsigned int>((4u - (input_addr & 3u)) & 3u);
    const unsigned int aligned_prefix = (prefix < input_size) ? prefix : input_size;

    for (unsigned int idx = global_thread; idx < aligned_prefix; idx += global_stride) {
        const unsigned int active = __activemask();
        accumulate_byte(static_cast<unsigned int>(input_u8[idx]),
                        from, range_size, active, lane, warp_hist);
    }

    const unsigned int remaining = input_size - aligned_prefix;
    const unsigned int num_words = remaining >> 2;
    const unsigned int* const input_words =
        reinterpret_cast<const unsigned int*>(input_u8 + aligned_prefix);

    for (unsigned int word_idx = global_thread; word_idx < num_words; word_idx += global_stride) {
        const unsigned int active = __activemask();
        const unsigned int word = input_words[word_idx];
        accumulate_word(word, from, range_size, active, lane, warp_hist);
    }

    const unsigned int tail_base = aligned_prefix + (num_words << 2);
    for (unsigned int idx = tail_base + global_thread; idx < input_size; idx += global_stride) {
        const unsigned int active = __activemask();
        accumulate_byte(static_cast<unsigned int>(input_u8[idx]),
                        from, range_size, active, lane, warp_hist);
    }

    __syncthreads();

    // One thread per requested output bin. Because the range length is at most 256, the
    // first `range_size` threads can reduce the requested bins directly.
    if (threadIdx.x < range_size) {
        const unsigned int byte_value = from + threadIdx.x;
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += shared_hist[w][byte_value];
        }

        if (sum != 0u) {
            atomicAdd(histogram + threadIdx.x, sum);
        }
    }
}

} // namespace

void run_histogram(
    const char *input,
    unsigned int *histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    // The prompt guarantees valid inputs, but this defensive guard avoids undefined
    // behavior if the function is called incorrectly.
    if (from < 0 || to > 255 || from > to) {
        return;
    }

    const unsigned int from_u = static_cast<unsigned int>(from);
    const unsigned int range_size = static_cast<unsigned int>(to - from) + 1u;

    // The caller provides device pointers. Clear the output asynchronously, then launch
    // the kernel in the same default stream. By contract, synchronization is the caller's
    // responsibility, so this function deliberately does not synchronize.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(range_size) * sizeof(unsigned int));
    if (inputSize == 0u) {
        return;
    }

    int device = 0;
    int sm_count = 1;
    int blocks_per_sm = 4;

    cudaGetDevice(&device);
    cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &blocks_per_sm,
        histogram_range_kernel,
        kBlockSize,
        0);

    if (sm_count < 1) {
        sm_count = 1;
    }
    if (blocks_per_sm < 1) {
        blocks_per_sm = 4;
    }

    // One resident wave is sufficient because the kernel uses a grid-stride loop; more
    // blocks would mostly increase the number of final block-to-global atomic updates.
    // For small inputs, cap the grid so we do not launch many nearly idle blocks.
    unsigned int grid =
        static_cast<unsigned int>(sm_count) * static_cast<unsigned int>(blocks_per_sm);
    const unsigned int blocks_for_input =
        div_up_u32(inputSize, static_cast<unsigned int>(kBlockSize));

    if (blocks_for_input < grid) {
        grid = blocks_for_input;
    }
    if (grid == 0u) {
        grid = 1u;
    }

    histogram_range_kernel<<<grid, kBlockSize>>>(
        input,
        histogram,
        inputSize,
        from_u,
        range_size);
}

#include <cuda_runtime.h>
#include <cstddef>

/*
    Restricted-range byte histogram for a device-resident text buffer.

    histogram[i] counts occurrences of byte value (from + i), for i in [0, to - from].

    Optimization strategy:
      - Treat the input as unsigned bytes so ordinals 128..255 are counted correctly even if
        the C++ 'char' type is signed.
      - Each block owns one private histogram per warp in shared memory. This removes cross-warp
        contention inside the block.
      - Each warp-private histogram is padded every 32 logical bins, which breaks the shared-memory
        bank-aliasing pattern for bins that differ by 32 (a common case for text, e.g. 'A' vs 'a').
      - Within each warp, duplicate updates to the same bin are merged with __match_any_sync():
        only one lane performs the shared-memory atomicAdd(), adding the population count of the
        whole peer group.
      - Blocks traverse the input with a grid-stride loop and flush only one partial histogram
        per block to global memory.

    The host launcher is intentionally asynchronous and uses the current default stream because
    the requested API does not take an explicit stream parameter.
*/

namespace {

constexpr int kWarpSize             = 32;
constexpr int kBlockSize            = 256;
constexpr int kItemsPerThread       = 8;
constexpr int kWarpsPerBlock        = kBlockSize / kWarpSize;
constexpr int kTargetBlocksPerSM    = 8;   // 256 threads/block * 8 blocks/SM = 64 warps/SM.
constexpr int kBankGroupLog2        = 5;   // 32 shared-memory banks.

static_assert(kBlockSize % kWarpSize == 0, "Block size must be a multiple of 32.");

__host__ __device__ __forceinline__
unsigned int warp_histogram_stride(unsigned int bins) {
    // One padding element after each complete group of 32 logical bins.
    // Equivalent to: bins + floor((bins - 1) / 32), with bins >= 1.
    return bins + ((bins - 1u) >> kBankGroupLog2);
}

__device__ __forceinline__
unsigned int padded_bin_index(unsigned int local_bin) {
    return local_bin + (local_bin >> kBankGroupLog2);
}

__device__ __forceinline__
void accumulate_byte(unsigned int* warp_hist,
                     unsigned char byte,
                     unsigned int from_u,
                     unsigned int bins,
                     int lane) {
    const unsigned int local_bin = static_cast<unsigned int>(byte) - from_u;

#if __CUDA_ARCH__ >= 700
    const bool valid = (local_bin < bins);

    // Use the current execution mask because this helper is also called from the tail path,
    // where only a subset of lanes may still be in bounds.
    const unsigned int valid_mask = __ballot_sync(__activemask(), valid);
    if (valid_mask == 0u) {
        return;
    }

    // Collapse identical updates inside the warp. Only the leader of each peer group performs
    // the shared-memory atomic, adding the number of lanes in that group.
    if (valid) {
        const unsigned int peers = __match_any_sync(valid_mask, local_bin);
        if (lane == (__ffs(peers) - 1)) {
            atomicAdd(&warp_hist[padded_bin_index(local_bin)],
                      static_cast<unsigned int>(__popc(peers)));
        }
    }
#else
    // Fallback for older architectures. The target hardware in this task is modern (A100/H100
    // class), so the fast path above is the intended one.
    if (local_bin < bins) {
        atomicAdd(&warp_hist[padded_bin_index(local_bin)], 1u);
    }
#endif
}

template <int BLOCK_SIZE, int ITEMS_PER_THREAD>
__global__ __launch_bounds__(BLOCK_SIZE, kTargetBlocksPerSM)
void histogram_kernel(const unsigned char* __restrict__ input,
                      unsigned int* __restrict__ histogram,
                      unsigned int input_size,
                      unsigned int from_u,
                      unsigned int bins) {
    constexpr int WARPS_PER_BLOCK = BLOCK_SIZE / kWarpSize;

    extern __shared__ unsigned int shared_hist[];

    const int tid     = static_cast<int>(threadIdx.x);
    const int lane    = tid & (kWarpSize - 1);
    const int warp_id = tid / kWarpSize;

    // Shared-memory layout: WARPS_PER_BLOCK private histograms, each padded to reduce bank conflicts.
    const unsigned int warp_stride           = warp_histogram_stride(bins);
    const unsigned int total_shared_counters = static_cast<unsigned int>(WARPS_PER_BLOCK) * warp_stride;

    for (unsigned int i = static_cast<unsigned int>(tid); i < total_shared_counters; i += BLOCK_SIZE) {
        shared_hist[i] = 0u;
    }
    __syncthreads();

    unsigned int* const warp_hist = shared_hist + static_cast<unsigned int>(warp_id) * warp_stride;

    const unsigned long long tile_span =
        static_cast<unsigned long long>(BLOCK_SIZE) * static_cast<unsigned long long>(ITEMS_PER_THREAD);
    const unsigned long long stride =
        static_cast<unsigned long long>(gridDim.x) * tile_span;
    const unsigned long long input_size_64 =
        static_cast<unsigned long long>(input_size);

    // Fast path: whole block-sized tiles are in bounds, so no per-load bounds checks are needed.
    unsigned long long block_base = static_cast<unsigned long long>(blockIdx.x) * tile_span;
    for (; block_base + tile_span <= input_size_64; block_base += stride) {
        const unsigned long long thread_base = block_base + static_cast<unsigned long long>(tid);

        #pragma unroll
        for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
            const unsigned long long pos =
                thread_base + static_cast<unsigned long long>(item * BLOCK_SIZE);
            accumulate_byte(warp_hist, input[pos], from_u, bins, lane);
        }
    }

    // Tail path for the final partial tile, if any.
    for (; block_base < input_size_64; block_base += stride) {
        const unsigned long long thread_base = block_base + static_cast<unsigned long long>(tid);

        #pragma unroll
        for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
            const unsigned long long pos =
                thread_base + static_cast<unsigned long long>(item * BLOCK_SIZE);
            if (pos < input_size_64) {
                accumulate_byte(warp_hist, input[pos], from_u, bins, lane);
            }
        }
    }

    __syncthreads();

    const bool single_block = (gridDim.x == 1);

    // Reduce the warp-private histograms into one block histogram and flush it.
    // Because bins <= 256 and BLOCK_SIZE == 256, each thread handles at most one logical bin.
    for (unsigned int bin = static_cast<unsigned int>(tid); bin < bins; bin += BLOCK_SIZE) {
        const unsigned int idx = padded_bin_index(bin);
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < WARPS_PER_BLOCK; ++w) {
            sum += shared_hist[static_cast<unsigned int>(w) * warp_stride + idx];
        }

        if (single_block) {
            // Single-block launch: write final results directly, so no prior memset is needed.
            histogram[bin] = sum;
        } else if (sum != 0u) {
            // Multi-block launch: accumulate block partials into the global histogram.
            atomicAdd(&histogram[bin], sum);
        }
    }
}

inline int current_sm_count() {
    // Per-thread cache keeps the launcher cheap when called repeatedly.
    thread_local int cached_device   = -1;
    thread_local int cached_sm_count = 0;

    int device = 0;
    if (cudaGetDevice(&device) == cudaSuccess) {
        if (device != cached_device || cached_sm_count <= 0) {
            int sm_count = 1;
            if (cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device) != cudaSuccess ||
                sm_count < 1) {
                sm_count = 1;
            }
            cached_device   = device;
            cached_sm_count = sm_count;
        }
    }

    return (cached_sm_count > 0) ? cached_sm_count : 1;
}

} // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    // The contract states that:
    //   - input and histogram are device pointers allocated with cudaMalloc
    //   - 0 <= from < to <= 255
    //   - histogram has exactly (to - from + 1) entries
    //
    // The operation is inclusive on both ends of the range.
    const unsigned int bins = static_cast<unsigned int>(to - from + 1);
    const size_t histogram_bytes = static_cast<size_t>(bins) * sizeof(unsigned int);

    // Stream 0 means "current default stream" and therefore follows the application's chosen
    // default-stream semantics (legacy default stream or per-thread default stream).
    const cudaStream_t stream = 0;

    if (inputSize == 0u) {
        // Empty input: the correct histogram is all zeros.
        cudaMemsetAsync(histogram, 0, histogram_bytes, stream);
        return;
    }

    constexpr unsigned int kBlockItems =
        static_cast<unsigned int>(kBlockSize * kItemsPerThread);

    const int max_blocks_by_input = static_cast<int>(
        (static_cast<unsigned long long>(inputSize) +
         static_cast<unsigned long long>(kBlockItems) - 1ull) /
        static_cast<unsigned long long>(kBlockItems));

    int blocks = max_blocks_by_input;

    // Cap the grid to a GPU-sized working set. On A100/H100-class GPUs, 8 resident 256-thread
    // blocks per SM reaches the 64-warp occupancy limit while keeping the number of block partials low.
    if (blocks > kTargetBlocksPerSM) {
        const int max_blocks_by_gpu = current_sm_count() * kTargetBlocksPerSM;
        if (blocks > max_blocks_by_gpu) {
            blocks = max_blocks_by_gpu;
        }
    }

    // For multi-block launches the kernel atomically accumulates block partials, so the global
    // histogram must start from zero. For the single-block case the kernel writes final values
    // directly and we can skip the memset.
    if (blocks > 1) {
        cudaMemsetAsync(histogram, 0, histogram_bytes, stream);
    }

    const size_t shared_mem_bytes =
        static_cast<size_t>(kWarpsPerBlock) *
        static_cast<size_t>(warp_histogram_stride(bins)) *
        sizeof(unsigned int);

    histogram_kernel<kBlockSize, kItemsPerThread>
        <<<blocks, kBlockSize, shared_mem_bytes, stream>>>(
            reinterpret_cast<const unsigned char*>(input),
            histogram,
            inputSize,
            static_cast<unsigned int>(from),
            bins);
}

#include <cuda_runtime.h>
#include <cstddef>

// Range-restricted byte histogram for GPU-resident input.
//
// Performance strategy:
// - Each warp owns a private histogram in shared memory, so updates never
//   contend across warps within a block.
// - __match_any_sync collapses equal bins among currently active lanes; only the
//   leader of each equal-value group performs the shared-memory increment.
// - After the scan, the block merges its warp-private histograms and updates the
//   global histogram once per non-zero bin.
// - Host launch logic uses:
//     * 256-thread blocks for medium inputs to expose more CTAs,
//     * 512-thread blocks for larger inputs to reduce the cost of the per-block
//       final merge once there is enough work to keep all SMs busy.
//
// This requires Volta+ warp-match intrinsics; the target hardware here is a
// modern data-center GPU such as A100/H100.

namespace {

constexpr int kWarpSize = 32;
constexpr int kMaxBins = 256;
constexpr unsigned int kVectorBytes = 16u;    // One uint4 load = 16 input bytes.
constexpr unsigned int kInvalidBin = 0xFFFFFFFFu;

static_assert(sizeof(uint4) == kVectorBytes, "uint4 must be 16 bytes.");

__device__ __forceinline__
void accumulate_bin_warp_private(unsigned int* warpHistogram,
                                 unsigned int relativeBin,
                                 unsigned int binCount,
                                 unsigned int lane)
{
    // All currently active lanes participate. Using __activemask() keeps the
    // warp match correct in partially active final grid-stride iterations.
    const unsigned int active = __activemask();
    const unsigned int key = (relativeBin < binCount) ? relativeBin : kInvalidBin;
    const unsigned int peers = __match_any_sync(active, key);

    // Exactly one lane per distinct valid bin performs the increment by the size
    // of its peer group. Because each warp writes only to its own shared-memory
    // slice, a normal shared-memory increment is sufficient here.
    if (key != kInvalidBin &&
        lane == static_cast<unsigned int>(__ffs(static_cast<int>(peers)) - 1)) {
        warpHistogram[key] += static_cast<unsigned int>(__popc(peers));
    }
}

__device__ __forceinline__
void process_packed_u32(unsigned int* warpHistogram,
                        unsigned int packed,
                        unsigned int from,
                        unsigned int binCount,
                        unsigned int lane)
{
    // Each 32-bit word contains four text bytes. Order does not matter for a
    // histogram, so simple bit extraction is sufficient.
    accumulate_bin_warp_private(warpHistogram, ((packed      ) & 0xFFu) - from, binCount, lane);
    accumulate_bin_warp_private(warpHistogram, ((packed >>  8) & 0xFFu) - from, binCount, lane);
    accumulate_bin_warp_private(warpHistogram, ((packed >> 16) & 0xFFu) - from, binCount, lane);
    accumulate_bin_warp_private(warpHistogram, ((packed >> 24) & 0xFFu) - from, binCount, lane);
}

template <int BlockSize>
__global__ __launch_bounds__(BlockSize)
void histogram_range_kernel(const unsigned char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from,
                            unsigned int binCount)
{
    static_assert(BlockSize % kWarpSize == 0, "Block size must be a multiple of 32.");
    static_assert(BlockSize >= kMaxBins,
                  "Block size must be at least the maximum number of output bins.");

    constexpr int kWarpsPerBlock = BlockSize / kWarpSize;
    constexpr unsigned int kBlockSizeU = static_cast<unsigned int>(BlockSize);

    extern __shared__ unsigned int sharedHistogram[];

    const unsigned int tid    = threadIdx.x;
    const unsigned int lane   = tid & (kWarpSize - 1u);
    const unsigned int warpId = tid >> 5;
    unsigned int* const warpHistogram = sharedHistogram + warpId * binCount;

    // Zero the block's warp-private histograms in shared memory.
    const unsigned int totalSharedBins =
        static_cast<unsigned int>(kWarpsPerBlock) * binCount;
    for (unsigned int i = tid; i < totalSharedBins; i += kBlockSizeU) {
        sharedHistogram[i] = 0u;
    }
    __syncthreads();

    const unsigned int globalThread = blockIdx.x * kBlockSizeU + tid;
    const unsigned int globalStride = gridDim.x * kBlockSizeU;

    // Align to 16 bytes for vector loads. cudaMalloc already provides strong
    // alignment, but handling an arbitrary subspan keeps the kernel correct even
    // if the caller passes an offset pointer.
    const size_t inputAddress = reinterpret_cast<size_t>(input);
    const unsigned int misalignment =
        static_cast<unsigned int>(inputAddress & static_cast<size_t>(kVectorBytes - 1u));
    unsigned int prefixBytes = (kVectorBytes - misalignment) & (kVectorBytes - 1u);
    if (prefixBytes > inputSize) {
        prefixBytes = inputSize;
    }

    // Scalar prefix before the aligned vector region. prefixBytes < 16, so only
    // the first few global threads ever participate here.
    if (globalThread < prefixBytes) {
        accumulate_bin_warp_private(
            warpHistogram,
            static_cast<unsigned int>(input[globalThread]) - from,
            binCount,
            lane);
    }

    const unsigned char* const alignedInput = input + prefixBytes;
    const unsigned int remainingBytes = inputSize - prefixBytes;
    const unsigned int vectorCount = remainingBytes / kVectorBytes;
    const uint4* const vectorInput = reinterpret_cast<const uint4*>(alignedInput);

    // Main vectorized scan: one 16-byte load per iteration, then update the
    // warp-private shared-memory histogram.
    for (unsigned int vec = globalThread; vec < vectorCount; vec += globalStride) {
        const uint4 packed = vectorInput[vec];
        process_packed_u32(warpHistogram, packed.x, from, binCount, lane);
        process_packed_u32(warpHistogram, packed.y, from, binCount, lane);
        process_packed_u32(warpHistogram, packed.z, from, binCount, lane);
        process_packed_u32(warpHistogram, packed.w, from, binCount, lane);
    }

    // Scalar tail after the vector region. tailBytes < 16, so again only the
    // first few global threads participate.
    const unsigned int tailStart = prefixBytes + vectorCount * kVectorBytes;
    const unsigned int tailBytes = inputSize - tailStart;
    if (globalThread < tailBytes) {
        accumulate_bin_warp_private(
            warpHistogram,
            static_cast<unsigned int>(input[tailStart + globalThread]) - from,
            binCount,
            lane);
    }

    __syncthreads();

    // The requested range is at most 256 bins wide, so a single block always has
    // enough threads to assign one thread per output bin for the final merge.
    if (tid < binCount) {
        unsigned int sum = 0u;
        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += sharedHistogram[static_cast<unsigned int>(w) * binCount + tid];
        }

        // For a single-block launch, write the complete histogram directly and
        // avoid global atomics and a separate memset. For multi-block launches,
        // accumulate into a zeroed output array.
        if (gridDim.x == 1) {
            histogram[tid] = sum;
        } else if (sum != 0u) {
            atomicAdd(histogram + tid, sum);
        }
    }
}

template <int BlockSize>
inline void launch_histogram_kernel(const unsigned char* input,
                                    unsigned int* histogram,
                                    unsigned int inputSize,
                                    unsigned int from,
                                    unsigned int binCount,
                                    size_t histogramBytes,
                                    unsigned int workUnits16,
                                    unsigned int smCount)
{
    static_assert(BlockSize % kWarpSize == 0, "Block size must be a multiple of 32.");
    static_assert(BlockSize >= kMaxBins,
                  "Block size must be at least the maximum number of output bins.");

    constexpr int kWarpsPerBlock = BlockSize / kWarpSize;
    constexpr unsigned int kBlockSizeU = static_cast<unsigned int>(BlockSize);
    constexpr unsigned int kBlocksPerSm = 2048u / kBlockSizeU;

    unsigned int blocksForWork = (workUnits16 + kBlockSizeU - 1u) / kBlockSizeU;
    if (blocksForWork == 0u) {
        blocksForWork = 1u;
    }

    // smCount == 0 is used intentionally for the small-input fast paths below:
    // it forces a single-block launch, which lets the kernel write the full
    // histogram directly without a prior memset.
    const unsigned int maxBlocks = (smCount != 0u) ? (smCount * kBlocksPerSm) : 1u;

    unsigned int gridSize = blocksForWork;
    if (gridSize > maxBlocks) {
        gridSize = maxBlocks;
    }
    if (gridSize == 0u) {
        gridSize = 1u;
    }

    if (gridSize != 1u) {
        // Multi-block launches atomically accumulate into the output array, so it
        // must be zeroed first. The operation is intentionally async; the caller
        // owns any required synchronization.
        cudaMemsetAsync(histogram, 0, histogramBytes, 0);
    }

    const size_t sharedMemoryBytes =
        static_cast<size_t>(kWarpsPerBlock) * static_cast<size_t>(binCount) * sizeof(unsigned int);

    histogram_range_kernel<BlockSize>
        <<<gridSize, BlockSize, sharedMemoryBytes, 0>>>(
            input,
            histogram,
            inputSize,
            from,
            binCount);
}

}  // namespace

void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    if (histogram == nullptr) {
        return;
    }
    if (from < 0 || to < from || to > 255) {
        return;
    }

    const unsigned int binCount = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes =
        static_cast<size_t>(binCount) * sizeof(unsigned int);

    // An empty input still needs a valid zero histogram.
    if (input == nullptr || inputSize == 0u) {
        cudaMemsetAsync(histogram, 0, histogramBytes, 0);
        return;
    }

    const unsigned int fromU = static_cast<unsigned int>(from);
    const unsigned int workUnits16 =
        (inputSize >> 4) + static_cast<unsigned int>((inputSize & (kVectorBytes - 1u)) != 0u);
    const unsigned char* const inputBytes =
        reinterpret_cast<const unsigned char*>(input);

    // Small fast paths:
    // - <= 256 vector units  -> one 256-thread block
    // - <= 512 vector units  -> one 512-thread block
    //
    // Both avoid a pre-launch memset because the single block writes the entire
    // output histogram directly.
    if (workUnits16 <= 256u) {
        launch_histogram_kernel<256>(
            inputBytes,
            histogram,
            inputSize,
            fromU,
            binCount,
            histogramBytes,
            workUnits16,
            0u);
        return;
    }

    if (workUnits16 <= 512u) {
        launch_histogram_kernel<512>(
            inputBytes,
            histogram,
            inputSize,
            fromU,
            binCount,
            histogramBytes,
            workUnits16,
            0u);
        return;
    }

    int currentDevice = 0;
    cudaGetDevice(&currentDevice);

    int smCountInt = 0;
    cudaDeviceGetAttribute(&smCountInt, cudaDevAttrMultiProcessorCount, currentDevice);
    const unsigned int smCount =
        (smCountInt > 0) ? static_cast<unsigned int>(smCountInt) : 0u;

    // Adaptive block-size selection:
    // - 256 threads exposes more CTAs for medium-sized inputs.
    // - 512 threads cuts block-final merge traffic once there is enough work to
    //   keep all SMs busy even with the larger block.
    if (smCount != 0u && workUnits16 >= smCount * 512u) {
        launch_histogram_kernel<512>(
            inputBytes,
            histogram,
            inputSize,
            fromU,
            binCount,
            histogramBytes,
            workUnits16,
            smCount);
    } else {
        launch_histogram_kernel<256>(
            inputBytes,
            histogram,
            inputSize,
            fromU,
            binCount,
            histogramBytes,
            workUnits16,
            smCount);
    }

    // No synchronization here by design; the caller requested to handle it.
}

#include <cuda_runtime.h>

namespace histogram_detail {

// High-level design:
// - The requested histogram range is contiguous and has at most 256 bins.
// - We therefore use a fixed 256-thread block so the final reduction can map one
//   thread to one possible logical bin.
// - Each block owns a shared-memory histogram, but it is privatized per warp to
//   reduce contention further.
// - Input is consumed with 16-byte vector loads (uint4) for good memory throughput.
// - On modern NVIDIA GPUs (A100/H100 and other Volta+ parts), __match_any_sync()
//   lets a warp collapse duplicate byte values so only one lane performs the
//   shared-memory update for each distinct byte seen by that warp step.
// - After the block finishes scanning its grid-stride slice, the per-warp shared
//   histograms are reduced and the block emits one global atomicAdd per nonzero bin.

constexpr int          kHistogramBlockThreads = 256;
constexpr int          kTargetBlocksPerSM     = 4;
constexpr int          kMaxLogicalBins        = 256;
constexpr int          kSharedBankCount       = 32;
constexpr int          kWarpHistogramStride   = kMaxLogicalBins + (kMaxLogicalBins / kSharedBankCount); // 264
constexpr unsigned int kVectorLoadBytes       = 16u;    // one uint4
constexpr unsigned int kOutOfRangeKey         = ~0u;    // sentinel for lanes whose byte is outside [from, to]

static_assert(sizeof(uint4) == kVectorLoadBytes, "uint4 must remain a 16-byte vector load.");
static_assert(kHistogramBlockThreads % 32 == 0, "Block size must be a whole number of warps.");
static_assert(kHistogramBlockThreads >= kMaxLogicalBins,
              "Block size must cover the maximum possible histogram bin count.");

// Skew the shared-memory layout by one padding slot per 32 logical bins.
// This spreads accesses that would otherwise land on the same bank when bins differ by 32.
__device__ __forceinline__ unsigned int shared_bin_index(const unsigned int logical_bin) {
    return logical_bin + (logical_bin >> 5);
}

__device__ __forceinline__ void accumulate_byte_to_warp_hist(
    const unsigned int byte_value,
    const unsigned int from,
    const unsigned int bins,
    const unsigned int lane_id,
    const unsigned int active_mask,
    unsigned int* const warp_hist)
{
    const unsigned int logical_bin = byte_value - from;
    const bool         in_range    = logical_bin < bins;
    const unsigned int key         = in_range ? logical_bin : kOutOfRangeKey;

    // Group lanes that saw the same logical bin. Typical text has a skewed byte
    // distribution (spaces, vowels, punctuation, etc.), so this often reduces
    // many per-byte updates into a single shared-memory atomicAdd.
    const unsigned int peer_mask   = __match_any_sync(active_mask, key);

    if (in_range) {
        const unsigned int leader_lane =
            static_cast<unsigned int>(__ffs(static_cast<int>(peer_mask)) - 1);

        if (leader_lane == lane_id) {
            // Even though the histogram is warp-private, we still use atomics here.
            // On Volta+ GPUs, independent thread scheduling means some lanes can
            // reach different loop iterations at different times; atomics keep the
            // update correct without forcing a __syncwarp() after every byte.
            atomicAdd(&warp_hist[shared_bin_index(logical_bin)],
                      static_cast<unsigned int>(__popc(peer_mask)));
        }
    }
}

__device__ __forceinline__ void accumulate_packed_word_to_warp_hist(
    const unsigned int packed_word,
    const unsigned int from,
    const unsigned int bins,
    const unsigned int lane_id,
    const unsigned int active_mask,
    unsigned int* const warp_hist)
{
    // packed_word contains 4 adjacent bytes loaded from the input stream.
    accumulate_byte_to_warp_hist((packed_word >>  0) & 0xFFu, from, bins, lane_id, active_mask, warp_hist);
    accumulate_byte_to_warp_hist((packed_word >>  8) & 0xFFu, from, bins, lane_id, active_mask, warp_hist);
    accumulate_byte_to_warp_hist((packed_word >> 16) & 0xFFu, from, bins, lane_id, active_mask, warp_hist);
    accumulate_byte_to_warp_hist((packed_word >> 24) & 0xFFu, from, bins, lane_id, active_mask, warp_hist);
}

template <int BLOCK_THREADS>
__launch_bounds__(BLOCK_THREADS, kTargetBlocksPerSM)
__global__ void histogram_range_kernel(
    const unsigned char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    const unsigned int inputSize,
    const unsigned int from,
    const unsigned int bins)
{
    static_assert(BLOCK_THREADS % 32 == 0, "Block size must be a whole number of warps.");
    static_assert(BLOCK_THREADS >= kMaxLogicalBins,
                  "Block size must cover the maximum possible histogram bin count.");

    constexpr unsigned int kBlockThreadsU = static_cast<unsigned int>(BLOCK_THREADS);
    constexpr int          kWarpsPerBlock = BLOCK_THREADS / 32;

    // One histogram per warp. Keeping warps private avoids inter-warp contention.
    __shared__ unsigned int warp_histograms[kWarpsPerBlock][kWarpHistogramStride];

    // Flattened pointer makes the initialization loop simple and fast.
    unsigned int* const shared_storage = &warp_histograms[0][0];

    for (unsigned int i = threadIdx.x;
         i < static_cast<unsigned int>(kWarpsPerBlock * kWarpHistogramStride);
         i += kBlockThreadsU)
    {
        shared_storage[i] = 0u;
    }
    __syncthreads();

    const unsigned int lane_id       = threadIdx.x & 31u;
    const unsigned int warp_id       = threadIdx.x >> 5;
    unsigned int* const warp_hist    = warp_histograms[warp_id];
    const unsigned int global_thread = blockIdx.x * kBlockThreadsU + threadIdx.x;
    const unsigned int global_stride = gridDim.x * kBlockThreadsU;

    // Vectorized main pass over 16-byte chunks.
    const unsigned int vector_count  = inputSize / kVectorLoadBytes;
    const uint4* const input_vectors = reinterpret_cast<const uint4*>(input);

    for (unsigned int i = global_thread; i < vector_count; i += global_stride) {
        const uint4 packed = input_vectors[i];

        // All lanes currently executing this loop iteration use the same mask.
        const unsigned int active_mask = __activemask();

        accumulate_packed_word_to_warp_hist(packed.x, from, bins, lane_id, active_mask, warp_hist);
        accumulate_packed_word_to_warp_hist(packed.y, from, bins, lane_id, active_mask, warp_hist);
        accumulate_packed_word_to_warp_hist(packed.z, from, bins, lane_id, active_mask, warp_hist);
        accumulate_packed_word_to_warp_hist(packed.w, from, bins, lane_id, active_mask, warp_hist);
    }

    // Scalar cleanup for the final 0..15 leftover bytes.
    const unsigned int tail_start = vector_count * kVectorLoadBytes;
    for (unsigned int i = tail_start + global_thread; i < inputSize; i += global_stride) {
        const unsigned int active_mask = __activemask();
        accumulate_byte_to_warp_hist(static_cast<unsigned int>(input[i]),
                                     from, bins, lane_id, active_mask, warp_hist);
    }

    __syncthreads();

    // Final reduction: one thread per logical bin sums the per-warp partials and
    // emits exactly one global atomicAdd for this block/bin pair.
    if (threadIdx.x < bins) {
        const unsigned int logical_bin = threadIdx.x;
        const unsigned int shared_bin  = shared_bin_index(logical_bin);

        unsigned int block_sum = 0u;
        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            block_sum += warp_histograms[w][shared_bin];
        }

        if (block_sum != 0u) {
            atomicAdd(histogram + logical_bin, block_sum);
        }
    }
}

} // namespace histogram_detail

// Assumptions from the problem statement:
// - input and histogram are device pointers allocated with cudaMalloc.
// - histogram has room for (to - from + 1) unsigned ints.
// - The caller is responsible for any needed synchronization.
// This function therefore queues work asynchronously on default-stream semantics
// and returns immediately.
void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // The prompt guarantees a valid inclusive range, but guard anyway to avoid UB.
    if (from < 0 || to > 255 || from > to) {
        return;
    }

    const unsigned int bins = static_cast<unsigned int>(to - from) + 1u;
    const size_t       histogram_bytes = static_cast<size_t>(bins) * sizeof(unsigned int);

    // Zero the output asynchronously before accumulation.
    cudaMemsetAsync(histogram, 0, histogram_bytes, 0);

    if (inputSize == 0u) {
        return;
    }

    int device = 0;
    cudaGetDevice(&device);

    int sm_count = 0;
    cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    if (sm_count < 1) {
        sm_count = 1;
    }

    // Each work item is one 16-byte vector load, plus a possible final tail item.
    const unsigned int work_items =
        (inputSize / histogram_detail::kVectorLoadBytes) +
        ((inputSize % histogram_detail::kVectorLoadBytes) != 0u ? 1u : 0u);

    unsigned int blocks_needed =
        (work_items + histogram_detail::kHistogramBlockThreads - 1u) /
        histogram_detail::kHistogramBlockThreads;

    if (blocks_needed == 0u) {
        blocks_needed = 1u;
    }

    // Cap the grid to a modest number of blocks per SM. That is enough to keep
    // A100/H100-class GPUs busy while limiting the final global-atomic pressure
    // (one global atomic per block/bin).
    unsigned int target_grid =
        static_cast<unsigned int>(sm_count) *
        static_cast<unsigned int>(histogram_detail::kTargetBlocksPerSM);

    if (target_grid == 0u) {
        target_grid = 1u;
    }

    const unsigned int grid = (blocks_needed < target_grid) ? blocks_needed : target_grid;

    histogram_detail::histogram_range_kernel<histogram_detail::kHistogramBlockThreads>
        <<<grid, histogram_detail::kHistogramBlockThreads, 0, 0>>>(
            reinterpret_cast<const unsigned char*>(input),
            histogram,
            inputSize,
            static_cast<unsigned int>(from),
            bins);
}

#include <cuda_runtime.h>

namespace {

// Tuned for recent data-center GPUs (A100/H100 class):
// - 256 threads/block gives 8 warps/block, a good balance of occupancy and per-block work.
// - 8 bytes/thread per outer-loop iteration keeps the loop overhead low without bloating
//   register usage.
constexpr int kBlockThreads      = 256;
constexpr int kWarpSize          = 32;
constexpr int kWarpsPerBlock     = kBlockThreads / kWarpSize;
constexpr int kItemsPerThread    = 8;
constexpr int kPrivateBins       = 256;  // Full 8-bit byte domain.
constexpr int kTileBytesPerBlock = kBlockThreads * kItemsPerThread;
constexpr unsigned int kFullMask = 0xFFFFFFFFu;

static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a multiple of warp size.");
static_assert(kPrivateBins == 256, "This kernel assumes 8-bit input characters.");

// Warp-aggregated update into a warp-private shared-memory histogram.
//
// Each warp owns its own 256-bin histogram in shared memory, so there is no inter-warp sharing.
// __match_any_sync() groups lanes that want to increment the same relative bin, and only the
// leader lane performs the increment with the population count of the whole group.
//
// Because the histogram is warp-private and there is at most one writer per bin per step,
// a regular shared-memory increment is sufficient here; __syncwarp() keeps the warp converged
// between steps on architectures with independent thread scheduling.
__device__ __forceinline__
void warp_aggregated_add(unsigned int rel_bin,
                         bool valid,
                         unsigned int* warp_hist,
                         int lane)
{
    const unsigned int valid_mask = __ballot_sync(kFullMask, valid);
    if (valid) {
        const unsigned int peers = __match_any_sync(valid_mask, rel_bin);
        if (lane == (__ffs(peers) - 1)) {
            warp_hist[rel_bin] += static_cast<unsigned int>(__popc(peers));
        }
    }
    __syncwarp(kFullMask);
}

// Kernel parameters:
// - input: device pointer to the raw text bytes.
// - histogram: device pointer to the output array of length `bins`.
// - inputSize: number of bytes in input.
// - from: first byte value in the requested range.
// - bins: number of output bins, i.e. (to - from + 1).
//
// The output convention is:
//   histogram[i] == count of byte value (from + i)
__global__ __launch_bounds__(kBlockThreads)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            int from,
                            int bins)
{
    const int tid     = threadIdx.x;
    const int warp_id = tid >> 5;
    const int lane    = tid & (kWarpSize - 1);

    const unsigned int from_u = static_cast<unsigned int>(from);
    const unsigned int bins_u = static_cast<unsigned int>(bins);

    // Reinterpret as unsigned bytes so values 128..255 are handled correctly even when
    // the host/compiler treats char as signed.
    const unsigned char* const text = reinterpret_cast<const unsigned char*>(input);

    // One full 256-bin private histogram per warp:
    // 8 warps * 256 bins * 4 bytes = 8 KiB shared memory per block.
    // This is small on A100/H100 and keeps indexing simple and fast.
    __shared__ unsigned int s_hist[kWarpsPerBlock * kPrivateBins];

    // Zero the whole shared histogram. The fixed 256-bin stride is intentional:
    // it avoids dynamic address arithmetic and still costs very little shared memory.
    #pragma unroll
    for (int i = tid; i < kWarpsPerBlock * kPrivateBins; i += kBlockThreads) {
        s_hist[i] = 0u;
    }
    __syncthreads();

    unsigned int* const warp_hist = s_hist + warp_id * kPrivateBins;

    // Use size_t for indexing so inputs close to 4 GiB cannot wrap a 32-bit grid-stride index.
    const size_t input_size  = static_cast<size_t>(inputSize);
    const size_t tile_bytes  = static_cast<size_t>(kTileBytesPerBlock);
    const size_t grid_stride = static_cast<size_t>(gridDim.x) * tile_bytes;

    size_t tile_start = static_cast<size_t>(blockIdx.x) * tile_bytes;

    while (tile_start < input_size) {
        // Fast path for a full tile: no bounds checks on the loads.
        if (tile_start + tile_bytes <= input_size) {
            size_t idx = tile_start + static_cast<size_t>(tid);

            #pragma unroll
            for (int item = 0; item < kItemsPerThread; ++item, idx += kBlockThreads) {
                const unsigned int rel = static_cast<unsigned int>(text[idx]) - from_u;
                warp_aggregated_add(rel, rel < bins_u, warp_hist, lane);
            }
        } else {
            // Tail tile: some lanes/items may fall outside the input range.
            size_t idx = tile_start + static_cast<size_t>(tid);

            #pragma unroll
            for (int item = 0; item < kItemsPerThread; ++item, idx += kBlockThreads) {
                const bool present = idx < input_size;

                unsigned int rel = 0u;
                if (present) {
                    rel = static_cast<unsigned int>(text[idx]) - from_u;
                }

                warp_aggregated_add(rel, present && (rel < bins_u), warp_hist, lane);
            }
        }

        tile_start += grid_stride;
    }

    __syncthreads();

    // Final block-local reduction:
    // because bins <= 256 by contract and blockDim.x == 256, one thread can own one output bin.
    const bool single_block = (gridDim.x == 1);

    if (tid < bins) {
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += s_hist[w * kPrivateBins + tid];
        }

        // If only one block is launched, it overwrites the whole output histogram directly,
        // so no global atomic and no pre-zeroing of the output are needed.
        if (single_block) {
            histogram[tid] = sum;
        } else if (sum != 0u) {
            atomicAdd(&histogram[tid], sum);
        }
    }
}

}  // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // Per the API contract:
    // - input and histogram are device pointers allocated by cudaMalloc.
    // - caller handles synchronization.
    // This function therefore uses the default stream and launches asynchronously.
    cudaStream_t stream = 0;

    const int bins = to - from + 1;
    const size_t hist_bytes = static_cast<size_t>(bins) * sizeof(unsigned int);

    // Empty input still requires a zeroed output histogram.
    if (inputSize == 0u) {
        cudaMemsetAsync(histogram, 0, hist_bytes, stream);
        return;
    }

    const size_t tile_bytes = static_cast<size_t>(kTileBytesPerBlock);
    const int needed_blocks =
        static_cast<int>((static_cast<size_t>(inputSize) + tile_bytes - 1u) / tile_bytes);

    // A single block can directly write the final histogram, so avoid the output memset in that
    // case. For multi-block launches, zero the output once and let blocks accumulate into it.
    int grid_size = 1;

    if (needed_blocks > 1) {
        int device = 0;
        int sm_count = 1;
        int blocks_per_sm = 1;

        cudaGetDevice(&device);
        cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
        cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &blocks_per_sm,
            histogram_range_kernel,
            kBlockThreads,
            0);

        int resident_blocks = sm_count * blocks_per_sm;
        if (resident_blocks < 1) {
            resident_blocks = 1;
        }

        // Grid-stride processing lets one resident wave cover arbitrarily large inputs, and
        // keeping the grid around one resident wave avoids unnecessary final global reductions.
        grid_size = (needed_blocks < resident_blocks) ? needed_blocks : resident_blocks;
    }

    if (grid_size != 1) {
        cudaMemsetAsync(histogram, 0, hist_bytes, stream);
    }

    histogram_range_kernel<<<grid_size, kBlockThreads, 0, stream>>>(
        input,
        histogram,
        inputSize,
        from,
        bins);
}

#include <cuda_runtime.h>

namespace {
// Tuned for modern NVIDIA data-center GPUs (A100/H100 class):
// - 256 threads/block gives 8 warps/block
// - one privatized shared-memory histogram per warp
// - up to 8 resident blocks/SM for 256-thread blocks (2048 threads/SM)
constexpr int kBlockThreads = 256;
constexpr unsigned int kWarpSizeConst = 32u;
constexpr unsigned int kBankPadShift = 5u;  // log2(32)
constexpr unsigned int kWarpsPerBlock = static_cast<unsigned int>(kBlockThreads) / kWarpSizeConst;
constexpr unsigned int kMaxBins = 256u;

// One padding slot per 32 bins to reduce shared-memory bank conflicts for indices that
// would otherwise alias every 32 entries. 256 bins -> 256 + 8 = 264 entries per sub-hist.
constexpr unsigned int kPaddedBins = kMaxBins + (kMaxBins >> kBankPadShift);
constexpr unsigned int kSharedHistEntries = kWarpsPerBlock * kPaddedBins;

constexpr unsigned int kVecBytes = 16u;  // sizeof(uint4)
constexpr unsigned int kBytesPerBlockIteration =
    static_cast<unsigned int>(kBlockThreads) * kVecBytes;
constexpr unsigned int kMaxResidentBlocksPerSM = 8u;

static_assert(kWarpSizeConst == 32u, "This kernel assumes 32-thread warps.");
static_assert((kBlockThreads % static_cast<int>(kWarpSizeConst)) == 0,
              "Block size must be a multiple of warp size.");
static_assert(sizeof(uint4) == kVecBytes, "uint4 must be 16 bytes.");
}  // namespace

__device__ __forceinline__ unsigned int padded_bin_index(unsigned int bin) {
    // Insert one hole every 32 bins so bins separated by 32 no longer map to the same bank.
    return bin + (bin >> kBankPadShift);
}

__device__ __forceinline__ void add_byte_to_private_hist(unsigned int byte_value,
                                                         unsigned int* __restrict__ warp_hist,
                                                         unsigned int from_u,
                                                         unsigned int range_size) {
    // Unsigned subtraction makes the range test branch-efficient:
    // if byte_value < from_u, bin underflows to a large unsigned value and fails the test.
    const unsigned int bin = byte_value - from_u;
    if (bin < range_size) {
        atomicAdd(warp_hist + padded_bin_index(bin), 1u);
    }
}

__device__ __forceinline__ void add_word_to_private_hist(unsigned int word,
                                                         unsigned int* __restrict__ warp_hist,
                                                         unsigned int from_u,
                                                         unsigned int range_size) {
    // Manually unpack 4 bytes from a 32-bit lane loaded via uint4.
    add_byte_to_private_hist((word      ) & 0xFFu, warp_hist, from_u, range_size);
    add_byte_to_private_hist((word >>  8) & 0xFFu, warp_hist, from_u, range_size);
    add_byte_to_private_hist((word >> 16) & 0xFFu, warp_hist, from_u, range_size);
    add_byte_to_private_hist((word >> 24) & 0xFFu, warp_hist, from_u, range_size);
}

__global__ __launch_bounds__(kBlockThreads)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from_u,
                            unsigned int range_size) {
    // Shared-memory privatization:
    // - one padded sub-histogram per warp to reduce inter-warp atomic contention
    // - final merge performs at most one global atomic per non-zero bin per block
    __shared__ unsigned int shared_hist[kSharedHistEntries];

    const unsigned int tid = threadIdx.x;
    const unsigned int global_tid = blockIdx.x * blockDim.x + tid;
    const unsigned int total_threads = gridDim.x * blockDim.x;

    // Scratch size is only 8 * 264 * 4 = 8448 bytes/block, so clearing it fully is cheap.
    for (unsigned int i = tid; i < kSharedHistEntries; i += blockDim.x) {
        shared_hist[i] = 0u;
    }
    __syncthreads();

    unsigned int* const warp_hist = shared_hist + (tid >> 5) * kPaddedBins;

    // The input buffer is assumed to be the cudaMalloc-allocated base pointer, which is
    // sufficiently aligned for 16-byte uint4 vector loads.
    const unsigned char* const uinput = reinterpret_cast<const unsigned char*>(input);
    const uint4* const input4 = reinterpret_cast<const uint4*>(uinput);

    // Main pass: 16 bytes/thread/iteration using vectorized global loads.
    const unsigned int vec_count = inputSize / kVecBytes;
    for (unsigned int i = global_tid; i < vec_count; i += total_threads) {
        const uint4 v = input4[i];
        add_word_to_private_hist(v.x, warp_hist, from_u, range_size);
        add_word_to_private_hist(v.y, warp_hist, from_u, range_size);
        add_word_to_private_hist(v.z, warp_hist, from_u, range_size);
        add_word_to_private_hist(v.w, warp_hist, from_u, range_size);
    }

    // Tail cleanup for the final 0..15 bytes.
    const unsigned int tail_start = vec_count * kVecBytes;
    for (unsigned int i = tail_start + global_tid; i < inputSize; i += total_threads) {
        add_byte_to_private_hist(static_cast<unsigned int>(uinput[i]), warp_hist, from_u, range_size);
    }

    __syncthreads();

    // histogram[bin] corresponds to character value from_u + bin.
    // For a single-block launch we can store directly because the output was pre-zeroed.
    const bool single_block = (gridDim.x == 1u);
    for (unsigned int bin = tid; bin < range_size; bin += blockDim.x) {
        const unsigned int pbin = padded_bin_index(bin);
        unsigned int sum = 0u;

#pragma unroll
        for (unsigned int w = 0; w < kWarpsPerBlock; ++w) {
            sum += shared_hist[w * kPaddedBins + pbin];
        }

        if (sum != 0u) {
            if (single_block) {
                histogram[bin] = sum;
            } else {
                atomicAdd(histogram + bin, sum);
            }
        }
    }
}

void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    // Assumes valid [from, to] as specified by the problem statement.
    const unsigned int from_u = static_cast<unsigned int>(from);
    const unsigned int range_size = static_cast<unsigned int>(to - from) + 1u;

    // Enqueue everything on the default stream. The caller explicitly owns synchronization.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(range_size) * sizeof(unsigned int), 0);

    if (inputSize == 0u) {
        return;
    }

    // One block iteration covers 16 bytes/thread = 4096 bytes/block.
    // Cap the grid to 8 blocks/SM so the GPU stays full without creating more block-local
    // histograms than useful for the final merge.
    unsigned int blocks = ((inputSize - 1u) / kBytesPerBlockIteration) + 1u;

    if (blocks > kMaxResidentBlocksPerSM) {
        int device = 0;
        cudaGetDevice(&device);

        int sm_count = 0;
        cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);

        const unsigned int max_blocks =
            static_cast<unsigned int>((sm_count > 0) ? sm_count : 1) * kMaxResidentBlocksPerSM;

        if (blocks > max_blocks) {
            blocks = max_blocks;
        }
    }

    histogram_range_kernel<<<blocks, kBlockThreads, 0, 0>>>(
        input, histogram, inputSize, from_u, range_size);
}

#include <cuda_runtime.h>

namespace {

// 256 threads is a natural fit for a byte histogram:
// - 8 warps per block gives good occupancy on A100/H100-class GPUs.
// - the reduction phase can map one thread to one possible output bin because the
//   requested range size is at most 256.
constexpr int kBlockThreads      = 256;
constexpr int kWarpSize          = 32;
constexpr int kWarpsPerBlock     = kBlockThreads / kWarpSize;
constexpr int kMaxBins           = 256;          // full unsigned-char domain
constexpr int kSharedHistEntries = kWarpsPerBlock * kMaxBins;
constexpr int kSharedInitIters   = kSharedHistEntries / kBlockThreads;
constexpr int kUnroll            = 4;
constexpr unsigned int kInvalidKey          = 0xFFFFFFFFu;
constexpr unsigned int kTargetBytesPerBlock = 16u * 1024u;  // amortize per-block init/flush cost

static_assert(kBlockThreads % kWarpSize == 0,
              "Block size must be a whole number of warps.");
static_assert(kBlockThreads == kMaxBins,
              "This implementation relies on one reducer thread per possible byte value.");
static_assert(kSharedHistEntries % kBlockThreads == 0,
              "Shared-histogram init expects an integer number of stores per thread.");

// Warp-aggregated update into a warp-private shared-memory histogram.
//
// The key optimization is:
//   1) each warp owns its own 256-bin shared-memory histogram slice;
//   2) __match_any_sync() groups lanes with the same target bin;
//   3) only one leader lane per unique bin performs the increment.
//
// Because a warp's histogram slice is private to that warp, once we reduce a bin to a
// single leader lane there is no same-address inter-thread race left, so the increment
// is a plain shared-memory add instead of a shared-memory atomic.
__device__ __forceinline__
void add_byte_to_warp_hist(const unsigned int value,
                           const unsigned int from,
                           const unsigned int numBins,
                           const unsigned int lane,
                           unsigned int* __restrict__ warpHist)
{
    const unsigned int active = __activemask();

    // Unsigned subtraction gives a cheap range test:
    // - in range  => bin in [0, numBins)
    // - out of range below 'from' underflows to a very large unsigned value
    // - out of range above 'to' also yields bin >= numBins
    const unsigned int bin   = value - from;
    const bool valid         = (bin < numBins);

    // All active lanes must participate in __match_any_sync(). Lanes that do not map
    // to the requested range use a sentinel key outside the real bin domain [0, 255].
    const unsigned int key     = valid ? bin : kInvalidKey;
    const unsigned int matches = __match_any_sync(active, key);

    if (valid) {
        const unsigned int leader = static_cast<unsigned int>(__ffs(matches) - 1);
        if (lane == leader) {
            warpHist[bin] += __popc(matches);
        }
    }
}

__global__ __launch_bounds__(kBlockThreads)
void histogram_range_kernel(const unsigned char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from,
                            unsigned int numBins)
{
    // One private 256-bin histogram per warp.
    __shared__ unsigned int s_warpHist[kSharedHistEntries];

    const unsigned int tid    = threadIdx.x;
    const unsigned int lane   = tid & (kWarpSize - 1);
    const unsigned int warpId = tid >> 5;

    unsigned int* const warpHist = s_warpHist + warpId * kMaxBins;

    // Fixed-size shared footprint (8 warps * 256 bins = 8 KiB). Zeroing the full shared
    // histogram keeps the kernel simple and avoids dynamic-shared-memory bookkeeping.
    #pragma unroll
    for (int i = 0; i < kSharedInitIters; ++i) {
        s_warpHist[tid + i * kBlockThreads] = 0u;
    }
    __syncthreads();

    const unsigned long long inputSize64 = static_cast<unsigned long long>(inputSize);
    const unsigned long long globalTid   =
        static_cast<unsigned long long>(blockIdx.x) * kBlockThreads + tid;
    const unsigned long long gridStride  =
        static_cast<unsigned long long>(gridDim.x) * kBlockThreads;
    const unsigned long long loopStride  = gridStride * kUnroll;

    // Grid-stride traversal with modest unrolling to raise ILP without bloating register use.
    for (unsigned long long base = globalTid; base < inputSize64; base += loopStride) {
        add_byte_to_warp_hist(static_cast<unsigned int>(input[base]), from, numBins, lane, warpHist);

        const unsigned long long idx1 = base + gridStride;
        if (idx1 < inputSize64) {
            add_byte_to_warp_hist(static_cast<unsigned int>(input[idx1]), from, numBins, lane, warpHist);
        }

        const unsigned long long idx2 = idx1 + gridStride;
        if (idx2 < inputSize64) {
            add_byte_to_warp_hist(static_cast<unsigned int>(input[idx2]), from, numBins, lane, warpHist);
        }

        const unsigned long long idx3 = idx2 + gridStride;
        if (idx3 < inputSize64) {
            add_byte_to_warp_hist(static_cast<unsigned int>(input[idx3]), from, numBins, lane, warpHist);
        }
    }

    __syncthreads();

    // Because kBlockThreads == 256 and numBins <= 256, each output bin is owned by at most
    // one thread in the block during the final reduction.
    if (tid < numBins) {
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += s_warpHist[w * kMaxBins + tid];
        }

        if (gridDim.x == 1) {
            // Single-block launch: write every output bin directly, including zeros.
            histogram[tid] = sum;
        } else if (sum != 0u) {
            // Multi-block launch: one global atomic per non-zero bin contribution from this block.
            atomicAdd(histogram + tid, sum);
        }
    }
}

// Cache the maximum resident grid size for the current device.
// The kernel shape is fixed, so the occupancy result is stable per device.
inline int max_resident_blocks_for_kernel()
{
    thread_local int cachedDevice    = -1;
    thread_local int cachedGridLimit = 0;

    int device = 0;
    if (cudaGetDevice(&device) != cudaSuccess) {
        return 1;
    }

    if (device != cachedDevice || cachedGridLimit <= 0) {
        int smCount = 1;
        int activeBlocksPerSm = 1;

        if (cudaDeviceGetAttribute(&smCount,
                                   cudaDevAttrMultiProcessorCount,
                                   device) != cudaSuccess || smCount <= 0) {
            smCount = 1;
        }

        if (cudaOccupancyMaxActiveBlocksPerMultiprocessor(&activeBlocksPerSm,
                                                          histogram_range_kernel,
                                                          kBlockThreads,
                                                          0) != cudaSuccess ||
            activeBlocksPerSm <= 0) {
            activeBlocksPerSm = 1;
        }

        cachedGridLimit = smCount * activeBlocksPerSm;
        if (cachedGridLimit <= 0) {
            cachedGridLimit = 1;
        }

        cachedDevice = device;
    }

    return cachedGridLimit;
}

} // namespace

// Enqueues the histogram work on stream 0. The caller is responsible for any later
// synchronization and error handling, per the requested API contract.
void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    const unsigned int fromU   = static_cast<unsigned int>(from);
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes = static_cast<size_t>(numBins) * sizeof(unsigned int);

    if (inputSize == 0u) {
        cudaMemsetAsync(histogram, 0, histogramBytes, 0);
        return;
    }

    // Launch enough blocks to fill the GPU on large inputs, but avoid launching an excessive
    // number of blocks for small/medium buffers because each block has a fixed histogram
    // init/reduction cost.
    const unsigned int blocksForInput =
        static_cast<unsigned int>(
            (static_cast<unsigned long long>(inputSize) +
             static_cast<unsigned long long>(kTargetBytesPerBlock) - 1ull) /
            static_cast<unsigned long long>(kTargetBytesPerBlock));

    const unsigned int maxBlocks =
        static_cast<unsigned int>(max_resident_blocks_for_kernel());

    unsigned int launchBlocks =
        (blocksForInput < maxBlocks) ? blocksForInput : maxBlocks;

    if (launchBlocks == 0u) {
        launchBlocks = 1u;
    }

    // Multi-block launches accumulate into global memory, so the destination must be zeroed
    // first. Single-block launches skip the memset because the kernel writes every output bin.
    if (launchBlocks > 1u) {
        cudaMemsetAsync(histogram, 0, histogramBytes, 0);
    }

    // Reinterpret the input as unsigned bytes so values 128..255 are handled by ordinal value,
    // independent of whether host-side 'char' is signed or unsigned.
    const unsigned char* const inputBytes =
        reinterpret_cast<const unsigned char*>(input);

    histogram_range_kernel<<<launchBlocks, kBlockThreads, 0, 0>>>(
        inputBytes,
        histogram,
        inputSize,
        fromU,
        numBins);
}

#include <cuda_runtime.h>

// Restricted-range character histogram for device-resident text.
//
// Design choices aimed at modern data-center GPUs (A100/H100 class):
//   * 256-thread blocks so the final flush can map one thread to one possible output bin.
//   * One 256-bin shared histogram per warp (8 warp-private histograms per block).  This is only
//     8 KiB of shared memory per block, which is small on A100/H100, yet it removes cross-warp
//     shared-memory contention while reducing global-memory atomics to one add per bin per block.
//   * 16-byte vectorized input loads (uint4) from the cudaMalloc-allocated input buffer.
//   * Warp-aggregated shared-memory atomics via __match_any_sync() to collapse identical bin
//     updates seen by multiple lanes in the same warp before touching shared memory.
//
// Notes:
//   * Input bytes are interpreted as unsigned values, so characters 128..255 are handled
//     correctly even when `char` is signed on the host/device compiler.
//   * The host launcher zeros the output histogram asynchronously because the kernel only
//     accumulates counts with atomicAdd().
//   * No host/device synchronization is performed here; the caller owns synchronization.

namespace {
constexpr int kBlockThreads   = 256;
constexpr int kWarpSize       = 32;
constexpr int kWarpsPerBlock  = kBlockThreads / kWarpSize;
constexpr int kMaxBins        = 256;
constexpr int kSharedBins     = kWarpsPerBlock * kMaxBins;
constexpr unsigned int kVecBytes = static_cast<unsigned int>(sizeof(uint4));

static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a multiple of the warp size.");
static_assert(kBlockThreads >= kMaxBins,
              "This kernel relies on one thread being available for each possible output bin.");

// Overflow-safe ceil(x / y) for 32-bit unsigned integers.
__host__ __device__ constexpr unsigned int ceil_div_u32(unsigned int x, unsigned int y) {
    return x == 0u ? 0u : 1u + (x - 1u) / y;
}

// Warp-aggregated increment into a warp-private shared histogram.
// Only the leader of each group of lanes targeting the same bin issues the shared-memory atomic,
// with the increment equal to the number of matching lanes.
__device__ __forceinline__ void warp_aggregated_shared_add(
    unsigned int* hist,
    unsigned int rel_bin,
    bool valid,
    unsigned int lane,
    unsigned int active_mask)
{
    const unsigned int valid_mask = __ballot_sync(active_mask, valid);
    if (valid) {
        const unsigned int peers = __match_any_sync(valid_mask, rel_bin);
        if (lane == static_cast<unsigned int>(__ffs(peers) - 1)) {
            atomicAdd(hist + rel_bin, __popc(peers));
        }
    }
}

// Consume 4 packed bytes from a 32-bit word loaded from the input stream.
__device__ __forceinline__ void process_packed_u32(
    unsigned int word,
    unsigned int from_u,
    unsigned int range,
    unsigned int* hist,
    unsigned int lane,
    unsigned int active_mask)
{
    unsigned int rel = ( word        & 0xFFu) - from_u;
    warp_aggregated_shared_add(hist, rel, rel < range, lane, active_mask);

    rel = ((word >>  8) & 0xFFu) - from_u;
    warp_aggregated_shared_add(hist, rel, rel < range, lane, active_mask);

    rel = ((word >> 16) & 0xFFu) - from_u;
    warp_aggregated_shared_add(hist, rel, rel < range, lane, active_mask);

    rel = ((word >> 24) & 0xFFu) - from_u;
    warp_aggregated_shared_add(hist, rel, rel < range, lane, active_mask);
}
} // namespace

__global__ __launch_bounds__(kBlockThreads)
void histogram_range_kernel(
    const char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    unsigned int from_u,
    unsigned int range)
{
    // Each warp owns a full 256-bin shared histogram.  The range is at most 256, so this fixed
    // layout gives constant-stride addressing while staying very small (8 KiB/block total).
    __shared__ unsigned int shared_hists[kSharedBins];

    const unsigned int tid  = threadIdx.x;
    const unsigned int lane = tid & 31u;
    const unsigned int warp = tid >> 5;

    unsigned int* const my_hist = shared_hists + warp * kMaxBins;

    // Only the bins that can be touched by this launch (0 .. range-1 in the relative histogram)
    // need to be cleared.  __syncwarp() is required here because different lanes zero different
    // bins, and independent thread scheduling could otherwise let some lanes start updating bins
    // before other lanes finished clearing them.
    for (unsigned int bin = lane; bin < range; bin += kWarpSize) {
        my_hist[bin] = 0u;
    }
    __syncwarp();

    // Interpret input as unsigned bytes so ordinals 128..255 are handled correctly regardless of
    // `char` signedness.  The prompt states that the input buffer is cudaMalloc-allocated, which
    // makes 16-byte vector loads a good fit on modern GPUs.
    const unsigned char* const input_u8  = reinterpret_cast<const unsigned char*>(input);
    const uint4* const input_vec4        = reinterpret_cast<const uint4*>(input_u8);

    const unsigned int num_vec     = inputSize / kVecBytes;
    const unsigned int tail_base   = num_vec * kVecBytes;
    const unsigned int global_tid  = blockIdx.x * kBlockThreads + tid;
    const unsigned int grid_stride = gridDim.x * kBlockThreads;

    // Main vectorized grid-stride loop over 16-byte chunks.
    for (unsigned int vec_idx = global_tid; vec_idx < num_vec; vec_idx += grid_stride) {
        // The loop can be partially active in the last iteration, so use the current active mask
        // for warp-synchronous aggregation.
        const unsigned int active_mask = __activemask();
        const uint4 v = input_vec4[vec_idx];

        process_packed_u32(v.x, from_u, range, my_hist, lane, active_mask);
        process_packed_u32(v.y, from_u, range, my_hist, lane, active_mask);
        process_packed_u32(v.z, from_u, range, my_hist, lane, active_mask);
        process_packed_u32(v.w, from_u, range, my_hist, lane, active_mask);
    }

    // Handle the <= 15-byte tail once, using block 0 only, so the hot loop stays fully vectorized.
    if (blockIdx.x == 0u) {
        const unsigned int tail_count = inputSize - tail_base;
        if (tid < tail_count) {
            const unsigned int rel =
                static_cast<unsigned int>(input_u8[tail_base + tid]) - from_u;
            if (rel < range) {
                atomicAdd(my_hist + rel, 1u);
            }
        }
    }

    // Block-wide barrier before reading other warps' privatized histograms.
    __syncthreads();

    // Final flush: because range <= 256 and blockDim.x == 256, thread tid can own output bin tid.
    // Each block contributes at most one global atomic add per output bin.
    if (tid < range) {
        unsigned int block_total = 0u;
        const unsigned int* hist_ptr = shared_hists + tid;

        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            block_total += *hist_ptr;
            hist_ptr += kMaxBins;
        }

        if (block_total != 0u) {
            atomicAdd(histogram + tid, block_total);
        }
    }
}

void run_histogram(
    const char *input,
    unsigned int *histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    // The problem statement guarantees valid inputs, but keep minimal defensive checks.
    if (histogram == nullptr || from < 0 || to > 255 || from > to) {
        return;
    }

    const unsigned int from_u = static_cast<unsigned int>(from);
    const unsigned int range  = static_cast<unsigned int>(to - from + 1);

    // The kernel accumulates with atomicAdd(), so start by clearing the output histogram.
    // This is intentionally asynchronous; the caller owns synchronization.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(range) * sizeof(unsigned int), 0);

    if (input == nullptr || inputSize == 0u) {
        return;
    }

    // The kernel uses a grid-stride loop, so an occupancy-sized grid is enough to fully cover
    // arbitrarily large inputs.  Launching many more blocks would mainly increase the number of
    // final global atomic flushes (one per bin per block) without increasing steady-state SM use.
    int device = 0;
    cudaGetDevice(&device);

    int sm_count = 1;
    cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    if (sm_count < 1) {
        sm_count = 1;
    }

    int active_blocks_per_sm = 1;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &active_blocks_per_sm,
        histogram_range_kernel,
        kBlockThreads,
        0);
    if (active_blocks_per_sm < 1) {
        active_blocks_per_sm = 1;
    }

    const unsigned int work_items         = ceil_div_u32(inputSize, kVecBytes); // 16-byte chunks
    const unsigned int blocks_needed      = ceil_div_u32(work_items, static_cast<unsigned int>(kBlockThreads));
    const unsigned int max_occupancy_grid =
        static_cast<unsigned int>(sm_count) * static_cast<unsigned int>(active_blocks_per_sm);

    unsigned int grid = blocks_needed;
    if (grid == 0u) {
        grid = 1u;
    }
    if (grid > max_occupancy_grid) {
        grid = max_occupancy_grid;
    }
    if (grid == 0u) {
        grid = 1u;
    }

    histogram_range_kernel<<<grid, kBlockThreads>>>(
        input,
        histogram,
        inputSize,
        from_u,
        range);
}

#include <cuda_runtime.h>

// Internal implementation notes:
//
// 1) The histogram range is always at most 256 bins, so a 256-thread block is a good fit:
//    the final flush stage can map one thread to one possible output bin.
//
// 2) The hot counting path uses shared-memory privatization at warp granularity:
//      - each warp owns its own private histogram in shared memory,
//      - threads update only that private histogram while scanning input,
//      - the block merges those warp-private histograms into the global output once at the end.
//    This replaces O(inputSize) global atomics with only O(gridDim.x * range) global atomics.
//
// 3) The kernel reads input through 128-bit vector loads (uint4) when possible.
//    To keep that path correct even if the caller passes an interior device pointer that is not
//    16-byte aligned, the kernel first consumes a tiny scalar prefix until the address is aligned.

namespace {

constexpr int kBlockSize = 256;
constexpr int kWarpSize = 32;
constexpr int kWarpsPerBlock = kBlockSize / kWarpSize;
constexpr unsigned int kMaxHistogramBins = 256u;
constexpr unsigned int kVectorBytes = sizeof(uint4);
constexpr size_t kWorkPerBlock =
    static_cast<size_t>(kBlockSize) * static_cast<size_t>(kVectorBytes);

static_assert(kBlockSize % kWarpSize == 0,
              "Block size must be an integer number of warps.");
static_assert(kBlockSize >= static_cast<int>(kMaxHistogramBins),
              "The flush stage expects at least one thread per possible output bin.");

// Unsigned subtraction turns the membership test for [from_u, from_u + range) into one compare.
// Values below from_u underflow and automatically fail the compare.
__device__ __forceinline__ void accumulate_byte(const unsigned int c,
                                                const unsigned int from_u,
                                                const unsigned int range,
                                                unsigned int* const warp_hist)
{
    const unsigned int rel = c - from_u;
    if (rel < range) {
        atomicAdd(&warp_hist[rel], 1u);
    }
}

__device__ __forceinline__ void accumulate_word(unsigned int word,
                                                const unsigned int from_u,
                                                const unsigned int range,
                                                unsigned int* const warp_hist)
{
#pragma unroll
    for (int i = 0; i < 4; ++i) {
        accumulate_byte(word & 0xFFu, from_u, range, warp_hist);
        word >>= 8;
    }
}

__device__ __forceinline__ void accumulate_vec16(const uint4& v,
                                                 const unsigned int from_u,
                                                 const unsigned int range,
                                                 unsigned int* const warp_hist)
{
    accumulate_word(v.x, from_u, range, warp_hist);
    accumulate_word(v.y, from_u, range, warp_hist);
    accumulate_word(v.z, from_u, range, warp_hist);
    accumulate_word(v.w, from_u, range, warp_hist);
}

// Clear all warp-private histograms in parallel.
__device__ __forceinline__ void zero_private_hist(unsigned int* const shared_hist,
                                                  const unsigned int total_private_bins)
{
    for (unsigned int i = threadIdx.x; i < total_private_bins; i += kBlockSize) {
        shared_hist[i] = 0u;
    }
}

// Collapse all warp-private histograms in the block into the final output.
//
// If the grid has only one block, every output bin is fully determined inside this block, so
// we can store directly and skip both the host-side memset and global atomics.
// Otherwise each block contributes a partial histogram and must atomically merge into global memory.
__device__ __forceinline__ void flush_private_hist_to_global(const unsigned int* const shared_hist,
                                                             unsigned int* const histogram,
                                                             const unsigned int range)
{
    const unsigned int tid = threadIdx.x;

    if (tid < range) {
        unsigned int sum = 0u;

#pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += shared_hist[static_cast<unsigned int>(w) * range + tid];
        }

        if (gridDim.x == 1) {
            histogram[tid] = sum;
        } else if (sum != 0u) {
            atomicAdd(histogram + tid, sum);
        }
    }
}

// Per-warp shared-memory-privatized histogram kernel.
__global__ __launch_bounds__(kBlockSize)
void histogram_kernel(const char* __restrict__ input,
                      unsigned int* __restrict__ histogram,
                      const unsigned int inputSize,
                      const unsigned int from_u,
                      const unsigned int range)
{
    extern __shared__ unsigned int shared_hist[];

    const unsigned int tid = threadIdx.x;
    const unsigned int warp_id = tid >> 5;
    const unsigned int total_private_bins =
        static_cast<unsigned int>(kWarpsPerBlock) * range;

    zero_private_hist(shared_hist, total_private_bins);
    __syncthreads();

    unsigned int* const warp_hist = shared_hist + warp_id * range;

    const unsigned int global_thread =
        static_cast<unsigned int>(blockIdx.x) * static_cast<unsigned int>(kBlockSize) + tid;
    const unsigned int global_stride =
        static_cast<unsigned int>(gridDim.x) * static_cast<unsigned int>(kBlockSize);

    const unsigned char* const input_bytes =
        reinterpret_cast<const unsigned char*>(input);

    // Align to 16 bytes so the main loop can legally use uint4 vector loads.
    const size_t input_addr = reinterpret_cast<size_t>(input_bytes);
    const size_t vector_mask = static_cast<size_t>(kVectorBytes - 1u);
    const size_t misalignment = input_addr & vector_mask;
    unsigned int prefix = static_cast<unsigned int>(
        (static_cast<size_t>(kVectorBytes) - misalignment) & vector_mask);
    if (prefix > inputSize) {
        prefix = inputSize;
    }

    // Small unaligned prefix.
    for (unsigned int idx = global_thread; idx < prefix; idx += global_stride) {
        accumulate_byte(static_cast<unsigned int>(input_bytes[idx]), from_u, range, warp_hist);
    }

    // Main aligned vectorized body.
    const unsigned char* const aligned_bytes = input_bytes + prefix;
    const unsigned int aligned_size = inputSize - prefix;
    const unsigned int vec_count = aligned_size / kVectorBytes;
    const uint4* const vec_input = reinterpret_cast<const uint4*>(aligned_bytes);

    for (unsigned int vec_idx = global_thread; vec_idx < vec_count; vec_idx += global_stride) {
        const uint4 v = vec_input[vec_idx];
        accumulate_vec16(v, from_u, range, warp_hist);
    }

    // Final scalar tail.
    const unsigned int tail_base = prefix + vec_count * kVectorBytes;
    for (unsigned int idx = tail_base + global_thread; idx < inputSize; idx += global_stride) {
        accumulate_byte(static_cast<unsigned int>(input_bytes[idx]), from_u, range, warp_hist);
    }

    __syncthreads();
    flush_private_hist_to_global(shared_hist, histogram, range);
}

// The kernel uses a grid-stride loop, so one fully resident wave of blocks is enough to process
// arbitrarily large inputs. Capping the grid to the number of simultaneously resident blocks
// avoids paying extra final global atomics for surplus blocks.
inline unsigned int compute_resident_grid_cap(const size_t shared_mem_bytes)
{
    int active_blocks_per_sm = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &active_blocks_per_sm,
        histogram_kernel,
        kBlockSize,
        shared_mem_bytes);

    int device = 0;
    cudaGetDevice(&device);

    int sm_count = 0;
    cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);

    const unsigned int active =
        static_cast<unsigned int>((active_blocks_per_sm > 0) ? active_blocks_per_sm : 1);
    const unsigned int sms =
        static_cast<unsigned int>((sm_count > 0) ? sm_count : 1);

    return active * sms;
}

}  // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // The prompt guarantees valid bounds, but keep a defensive guard so accidental misuse does
    // not turn into an out-of-range memset or shared-memory size.
    if (from < 0 || to > 255 || from > to) {
        return;
    }

    const unsigned int from_u = static_cast<unsigned int>(from);
    const unsigned int range = static_cast<unsigned int>(to - from + 1);
    const size_t histogram_bytes =
        static_cast<size_t>(range) * sizeof(unsigned int);
    const size_t shared_mem_bytes =
        static_cast<size_t>(kWarpsPerBlock) * static_cast<size_t>(range) * sizeof(unsigned int);

    // The interface does not expose a stream parameter, so this function uses stream 0.
    // The caller explicitly owns synchronization, so there is intentionally no cudaDeviceSynchronize().
    if (inputSize == 0u) {
        cudaMemsetAsync(histogram, 0, histogram_bytes, 0);
        return;
    }

    // Fast path: if one block is enough, skip the extra memset.
    // The kernel detects gridDim.x == 1 and overwrites every output bin directly.
    const size_t blocks_for_input =
        (static_cast<size_t>(inputSize) + kWorkPerBlock - 1u) / kWorkPerBlock;

    if (blocks_for_input <= 1u) {
        histogram_kernel<<<1, kBlockSize, shared_mem_bytes, 0>>>(
            input, histogram, inputSize, from_u, range);
        return;
    }

    // Multi-block path: zero the output first, then launch at most one resident wave of blocks.
    // The memset is enqueued before the occupancy/device queries so the device can start it while
    // the host computes the launch configuration.
    cudaMemsetAsync(histogram, 0, histogram_bytes, 0);

    const unsigned int resident_grid_cap = compute_resident_grid_cap(shared_mem_bytes);
    unsigned int grid =
        (blocks_for_input < static_cast<size_t>(resident_grid_cap))
            ? static_cast<unsigned int>(blocks_for_input)
            : resident_grid_cap;

    if (grid == 0u) {
        grid = 1u;
    }

    histogram_kernel<<<grid, kBlockSize, shared_mem_bytes, 0>>>(
        input, histogram, inputSize, from_u, range);
}

#include <cuda_runtime.h>

namespace histogram_detail {

// Range-restricted byte histogram optimized for modern NVIDIA GPUs.
// Hot-path design:
//   * 256-thread blocks (8 warps per block).
//   * One 256-bin shared-memory histogram slice per warp.
//   * __match_any_sync() aggregates identical byte values inside a warp so only
//     one lane issues the shared-memory atomicAdd for each equal-value group.
//   * uchar4 vectorized loads reduce loop/control overhead and preserve coalescing.
// After processing its grid-stride share of the input, each block emits at most
// one global update per requested output bin.

constexpr int kHistogramBlockSize = 256;
constexpr int kWarpSize = 32;
constexpr int kWarpsPerBlock = kHistogramBlockSize / kWarpSize;
constexpr int kByteValueCount = 256;
constexpr int kSharedHistogramSize = kWarpsPerBlock * kByteValueCount;

constexpr unsigned int kVectorBytes = 4u;  // uchar4
constexpr unsigned int kGridHeuristicBytesPerBlock =
    static_cast<unsigned int>(kHistogramBlockSize) * kVectorBytes;

static_assert(kHistogramBlockSize % kWarpSize == 0,
              "Histogram block size must be a multiple of warp size.");

inline unsigned int div_up_u32(unsigned int n, unsigned int d) {
    return n / d + static_cast<unsigned int>(n % d != 0u);
}

__device__ __forceinline__
void accumulate_byte(unsigned int* __restrict__ warp_hist,
                     unsigned char value,
                     unsigned int from,
                     unsigned int range,
                     unsigned int active_mask,
                     unsigned int lane) {
    // Convert the byte value to the output histogram index relative to 'from'.
    // Unsigned arithmetic makes values below 'from' wrap above 'range', so a
    // single "bin < range" check filters both sides of the interval.
    const unsigned int bin = static_cast<unsigned int>(value) - from;

    // Group lanes that saw the same bin value. Only the first lane in each
    // equal-value group updates shared memory, using the group population as
    // the increment. This substantially reduces shared-memory atomic pressure
    // on skewed text distributions.
    const unsigned int peers = __match_any_sync(active_mask, bin);
    const unsigned int leader = static_cast<unsigned int>(__ffs(peers) - 1);

    if (bin < range && lane == leader) {
        atomicAdd(warp_hist + bin, static_cast<unsigned int>(__popc(peers)));
    }
}

__global__ __launch_bounds__(kHistogramBlockSize)
void histogram_range_kernel(const unsigned char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from,
                            unsigned int range) {
    // Fixed 256-bin stride per warp keeps shared-memory addressing simple and fast.
    // Only bins [0, range) are touched and later reduced into the output.
    __shared__ unsigned int s_warp_hist[kSharedHistogramSize];

    const unsigned int tid = threadIdx.x;
    const unsigned int warp_id = tid >> 5;
    const unsigned int lane = tid & (kWarpSize - 1u);

    // Zero the full 8 KiB shared footprint. This is cheap and avoids any range-
    // dependent addressing in the hot path.
    #pragma unroll
    for (unsigned int i = tid; i < static_cast<unsigned int>(kSharedHistogramSize); i += kHistogramBlockSize) {
        s_warp_hist[i] = 0u;
    }
    __syncthreads();

    unsigned int* const my_hist = s_warp_hist + warp_id * kByteValueCount;
    const unsigned int global_thread = blockIdx.x * kHistogramBlockSize + tid;
    const unsigned int global_stride = gridDim.x * kHistogramBlockSize;

    // The problem states that the input array itself is allocated by cudaMalloc,
    // so the base pointer is naturally aligned for uchar4 vector loads.
    const unsigned int vec_count = inputSize / kVectorBytes;
    const uchar4* const input4 = reinterpret_cast<const uchar4*>(input);

    for (unsigned int i = global_thread; i < vec_count; i += global_stride) {
        const uchar4 v = input4[i];
        const unsigned int mask = __activemask();

        accumulate_byte(my_hist, v.x, from, range, mask, lane);
        accumulate_byte(my_hist, v.y, from, range, mask, lane);
        accumulate_byte(my_hist, v.z, from, range, mask, lane);
        accumulate_byte(my_hist, v.w, from, range, mask, lane);
    }

    // At most 3 bytes remain after the uchar4 sweep.
    const unsigned int tail_base = vec_count * kVectorBytes;
    const unsigned int tail_count = inputSize - tail_base;
    if (global_thread < tail_count) {
        const unsigned int mask = __activemask();
        accumulate_byte(my_hist, input[tail_base + global_thread], from, range, mask, lane);
    }

    __syncthreads();

    // Reduce the warp-private histograms to the final global histogram.
    // Output position i stores the count for byte value (from + i).
    for (unsigned int bin = tid; bin < range; bin += kHistogramBlockSize) {
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += s_warp_hist[w * kByteValueCount + bin];
        }

        if (sum != 0u) {
            if (gridDim.x == 1) {
                histogram[bin] = sum;
            } else {
                atomicAdd(histogram + bin, sum);
            }
        }
    }
}

} // namespace histogram_detail

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    // histogram[i] counts occurrences of byte value (from + i).
    // The API provides no stream parameter, so work is enqueued on the default stream.
    // Synchronization and post-launch error handling are intentionally left to the caller.
    cudaStream_t stream = 0;

    const unsigned int from_u = static_cast<unsigned int>(from);
    const unsigned int range = static_cast<unsigned int>(to - from) + 1u;

    // The kernel accumulates into global memory, so clear only the requested output range.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(range) * sizeof(unsigned int), stream);

    if (inputSize == 0u) {
        return;
    }

    int grid = static_cast<int>(
        histogram_detail::div_up_u32(inputSize, histogram_detail::kGridHeuristicBytesPerBlock));

    // The kernel uses a grid-stride loop, so launching more blocks than can be
    // resident at once only increases the number of final global flushes.
    if (grid > 1) {
        int device = 0;
        int sm_count = 1;
        int blocks_per_sm = 1;

        cudaGetDevice(&device);
        cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
        cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &blocks_per_sm,
            histogram_detail::histogram_range_kernel,
            histogram_detail::kHistogramBlockSize,
            0);

        const int max_grid = sm_count * (blocks_per_sm > 0 ? blocks_per_sm : 1);
        if (grid > max_grid) {
            grid = max_grid;
        }
    }

    histogram_detail::histogram_range_kernel<<<grid, histogram_detail::kHistogramBlockSize, 0, stream>>>(
        reinterpret_cast<const unsigned char*>(input),
        histogram,
        inputSize,
        from_u,
        range);
}

#include <cuda_runtime.h>
#include <stddef.h>

namespace
{

// The histogram range is restricted to byte values, so the maximum number of bins is 256.
// Choosing 256 threads/block lets the final shared->global flush map one thread to one bin.
constexpr int kWarpSize      = 32;
constexpr int kMaxBins       = 256;
constexpr int kBlockSize     = kMaxBins;
constexpr int kWarpsPerBlock = kBlockSize / kWarpSize;
constexpr int kVectorBytes   = static_cast<int>(sizeof(uint4));

static_assert(kBlockSize % kWarpSize == 0, "Block size must be a whole number of warps.");
static_assert(kBlockSize == kMaxBins, "This kernel relies on one thread per possible output bin.");
static_assert(sizeof(uint4) == 16, "The vectorized load path assumes 16-byte uint4 loads.");

// Update one warp-private shared-memory histogram with a single byte.
// activeMask names the currently participating lanes in the warp for this loop iteration.
__device__ __forceinline__ void accumulate_byte_warp_private(
    unsigned int c,
    int from,
    unsigned int numBins,
    unsigned int activeMask,
    int lane,
    unsigned int* warpHist)
{
    const int  bin     = static_cast<int>(c) - from;
    const bool inRange = static_cast<unsigned int>(bin) < numBins;

    // Group equal bins inside the warp so only one lane performs the shared-memory atomic.
    // Invalid bytes use -1 as a sentinel key and are ignored after the match.
    const unsigned int peers = __match_any_sync(activeMask, inRange ? bin : -1);

    if (inRange && lane == (__ffs(peers) - 1)) {
        atomicAdd(&warpHist[bin], static_cast<unsigned int>(__popc(peers)));
    }
}

// Process four bytes packed in a 32-bit word.  Byte order does not matter for a histogram.
__device__ __forceinline__ void accumulate_packed_word(
    unsigned int packed,
    int from,
    unsigned int numBins,
    unsigned int activeMask,
    int lane,
    unsigned int* warpHist)
{
#pragma unroll
    for (int byte = 0; byte < 4; ++byte) {
        accumulate_byte_warp_private(packed & 0xFFu, from, numBins, activeMask, lane, warpHist);
        packed >>= 8;
    }
}

/*
 * Histogram kernel for the contiguous byte range [from, from + numBins - 1].
 *
 * Optimization strategy:
 *   1) Each block uses shared memory for histogram privatization.
 *   2) Privatization is further split per warp to reduce intra-block contention.
 *   3) __match_any_sync collapses same-bin updates within a warp before shared atomics.
 *   4) The common fast path reads input as uint4 (16 bytes/load) when the pointer is aligned.
 *   5) Each block flushes only one partial sum per bin to global memory.
 *
 * The output histogram is indexed from zero: output bin i counts byte value (from + i).
 */
__global__ __launch_bounds__(kBlockSize)
void histogram_range_kernel(
    const char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    int from,
    unsigned int numBins)
{
    extern __shared__ unsigned int sharedHist[];

    const unsigned int tid         = threadIdx.x;
    const unsigned int warpId      = tid / kWarpSize;
    const int          lane        = static_cast<int>(tid % kWarpSize);
    const size_t       globalTid   = static_cast<size_t>(blockIdx.x) * static_cast<size_t>(blockDim.x) + tid;
    const size_t       totalThreads = static_cast<size_t>(blockDim.x) * static_cast<size_t>(gridDim.x);

    // Shared layout: [warp0 bins][warp1 bins]...[warpN bins].
    const unsigned int sharedEntries = static_cast<unsigned int>(kWarpsPerBlock) * numBins;
    for (unsigned int i = tid; i < sharedEntries; i += blockDim.x) {
        sharedHist[i] = 0u;
    }
    __syncthreads();

    unsigned int* const warpHist = sharedHist + warpId * numBins;
    const unsigned char* __restrict__ bytes = reinterpret_cast<const unsigned char*>(input);
    const size_t inputBytes = static_cast<size_t>(inputSize);

    // Fast path: cudaMalloc allocations are naturally aligned, so this is the expected case.
    if ((reinterpret_cast<size_t>(input) & static_cast<size_t>(kVectorBytes - 1)) == 0u) {
        const size_t numVec = inputBytes / static_cast<size_t>(kVectorBytes);
        const uint4* __restrict__ vecInput = reinterpret_cast<const uint4*>(input);

        for (size_t i = globalTid; i < numVec; i += totalThreads) {
            const unsigned int activeMask = __activemask();
            const uint4 v = vecInput[i];

            accumulate_packed_word(v.x, from, numBins, activeMask, lane, warpHist);
            accumulate_packed_word(v.y, from, numBins, activeMask, lane, warpHist);
            accumulate_packed_word(v.z, from, numBins, activeMask, lane, warpHist);
            accumulate_packed_word(v.w, from, numBins, activeMask, lane, warpHist);
        }

        const size_t tailStart = numVec * static_cast<size_t>(kVectorBytes);
        for (size_t pos = tailStart + globalTid; pos < inputBytes; pos += totalThreads) {
            const unsigned int activeMask = __activemask();
            accumulate_byte_warp_private(
                static_cast<unsigned int>(bytes[pos]),
                from,
                numBins,
                activeMask,
                lane,
                warpHist);
        }
    } else {
        // Rare correctness fallback for misaligned sub-pointers.
        for (size_t pos = globalTid; pos < inputBytes; pos += totalThreads) {
            const unsigned int activeMask = __activemask();
            accumulate_byte_warp_private(
                static_cast<unsigned int>(bytes[pos]),
                from,
                numBins,
                activeMask,
                lane,
                warpHist);
        }
    }

    __syncthreads();

    // Because kBlockSize == 256 and numBins <= 256, one thread can own one output bin.
    if (tid < numBins) {
        unsigned int sum = 0u;
#pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += sharedHist[static_cast<unsigned int>(w) * numBins + tid];
        }
        if (sum != 0u) {
            atomicAdd(&histogram[tid], sum);
        }
    }
}

} // namespace

void run_histogram(
    const char* input,
    unsigned int* histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    // Preconditions are those stated in the problem:
    //   - input and histogram are device pointers allocated with cudaMalloc
    //   - 0 <= from < to <= 255
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes = static_cast<size_t>(numBins) * sizeof(unsigned int);

    // This API computes a fresh histogram each time; keep the memset asynchronous.
    (void)cudaMemsetAsync(histogram, 0, histogramBytes, 0);

    if (inputSize == 0u) {
        return;
    }

    const size_t sharedMemBytes =
        static_cast<size_t>(kWarpsPerBlock) * static_cast<size_t>(numBins) * sizeof(unsigned int);

    // Cap the grid at the occupancy-saturating resident block count so the final shared->global
    // merge does not create more block flushes than needed.
    int device = 0;
    int smCount = 1;
    int activeBlocksPerSM = 1;

    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    (void)cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM,
        histogram_range_kernel,
        kBlockSize,
        static_cast<int>(sharedMemBytes));

    if (smCount < 1) {
        smCount = 1;
    }
    if (activeBlocksPerSM < 1) {
        activeBlocksPerSM = 1;
    }

    const unsigned int maxResidentBlocks =
        static_cast<unsigned int>(smCount) * static_cast<unsigned int>(activeBlocksPerSM);

    // Use one 16-byte vector per thread as the first-pass work estimate; grid-stride loops
    // handle larger inputs without needing more launch-time blocks.
    const size_t bytesPerBlockFirstPass =
        static_cast<size_t>(kBlockSize) * static_cast<size_t>(kVectorBytes);

    unsigned int gridSize = static_cast<unsigned int>(
        (static_cast<size_t>(inputSize) + bytesPerBlockFirstPass - 1u) / bytesPerBlockFirstPass);

    if (gridSize == 0u) {
        gridSize = 1u;
    }
    if (gridSize > maxResidentBlocks) {
        gridSize = maxResidentBlocks;
    }

    histogram_range_kernel<<<gridSize, kBlockSize, sharedMemBytes, 0>>>(
        input,
        histogram,
        inputSize,
        from,
        numBins);
}

#include <cuda_runtime.h>

namespace {

// Fixed launch configuration tuned for modern data-center GPUs (A100/H100 class).
//
// 256 threads/block is deliberate:
// - the maximum possible histogram width is 256 bins (byte values 0..255),
// - so a block can map one thread to one logical output bin during shared-memory
//   initialization and the final flush step.
//
// 8 resident 256-thread blocks/SM = 2048 threads/SM = 64 warps/SM, which matches
// Ampere/Hopper's thread/warp occupancy limit. With the shared-memory footprint used
// below (8 KiB/block), this still fits comfortably.
constexpr int kBlockSize          = 256;
constexpr int kItemsPerThread     = 8;    // Unroll factor: good ILP without excessive code size.
constexpr int kWarpSize           = 32;
constexpr int kWarpsPerBlock      = kBlockSize / kWarpSize;
constexpr int kLocalHistogramBins = 256;  // Full byte alphabet.
constexpr int kTargetBlocksPerSM  = 8;

constexpr unsigned int kFullMask   = 0xFFFFFFFFu;
constexpr unsigned int kInvalidBin = 0xFFFFFFFFu;

static_assert(kBlockSize % kWarpSize == 0, "Block size must be a whole number of warps.");

// Warp-local duplicate aggregation.
// For the current byte position, lanes with the same bin key are grouped with __match_any_sync().
// Only the leader of each equal-key group performs the shared-memory atomicAdd, with the increment
// equal to the group size. This reduces the number of shared-memory atomics substantially for
// text-like inputs with hot characters (space, letters, newline, punctuation, ...).
//
// Even though each warp owns a private sub-histogram, atomicAdd is still used here instead of
// plain "+=" because modern GPUs support independent thread scheduling; non-atomic updates are
// not guaranteed safe across divergent paths / loop iterations. With warp aggregation, these
// atomics are low-contention and therefore cheap.
__device__ __forceinline__ void warpAggregateAndAdd(unsigned int key,
                                                    unsigned int lane,
                                                    unsigned int* __restrict__ warpHist) {
    const unsigned int peers = __match_any_sync(kFullMask, key);
    if (key != kInvalidBin && lane == static_cast<unsigned int>(__ffs(peers) - 1)) {
        atomicAdd(warpHist + key, static_cast<unsigned int>(__popc(peers)));
    }
}

// Keep launch_bounds in sync with kBlockSize / kTargetBlocksPerSM above.
__launch_bounds__(256, 8)
__global__ void histogram_range_kernel(const char* __restrict__ input,
                                       unsigned int* __restrict__ histogram,
                                       unsigned int inputSize,
                                       unsigned int from,
                                       unsigned int range) {
    // One private 256-bin sub-histogram per warp.
    // Shared-memory footprint = 8 warps * 256 bins * 4 bytes = 8 KiB/block.
    //
    // Using full 256-bin warp-private histograms keeps addressing simple and removes inter-warp
    // contention entirely. Only the requested output range is initialized and flushed, so the
    // extra unused bins add negligible cost while keeping the kernel compact and fast.
    __shared__ unsigned int sharedHist[kWarpsPerBlock * kLocalHistogramBins];

    const unsigned int warpId = threadIdx.x >> 5;
    const unsigned int lane   = threadIdx.x & (kWarpSize - 1u);
    unsigned int* const warpHist = sharedHist + warpId * kLocalHistogramBins;

    // range <= 256 by problem definition, so threads 0..range-1 map 1:1 to logical bins.
    // Local bin b corresponds to byte value (from + b).
    if (threadIdx.x < range) {
        const unsigned int bin = threadIdx.x;
        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sharedHist[w * kLocalHistogramBins + bin] = 0u;
        }
    }
    __syncthreads();

    // Read through unsigned char so bytes are interpreted as 0..255 regardless of whether
    // plain char is signed or unsigned on the compilation platform.
    const unsigned char* const inputBytes = reinterpret_cast<const unsigned char*>(input);

    // Unrolled grid-stride processing.
    //
    // blockBase is block-uniform on purpose: every lane executes the same number of warp-level
    // match operations. Lanes that fall past the end of the input simply contribute kInvalidBin.
    //
    // For each unrolled item, a warp reads a contiguous 32-byte segment. Across all 8 warps,
    // the block reads a contiguous 256-byte stripe, so the byte loads are fully coalesced.
    const size_t n          = static_cast<size_t>(inputSize);
    const size_t blockChunk = static_cast<size_t>(kBlockSize) * kItemsPerThread;
    const size_t gridChunk  = static_cast<size_t>(gridDim.x) * blockChunk;

    for (size_t blockBase = static_cast<size_t>(blockIdx.x) * blockChunk;
         blockBase < n;
         blockBase += gridChunk) {
        #pragma unroll
        for (int item = 0; item < kItemsPerThread; ++item) {
            const size_t i = blockBase + static_cast<size_t>(item) * kBlockSize + threadIdx.x;

            unsigned int key = kInvalidBin;
            if (i < n) {
                // Convert the input byte into a local bin index in [0, range) if it belongs to
                // the requested interval [from, from + range - 1]. Unsigned arithmetic makes the
                // lower-bound check branchless.
                key = static_cast<unsigned int>(inputBytes[i]) - from;
                if (key >= range) {
                    key = kInvalidBin;
                }
            }

            warpAggregateAndAdd(key, lane, warpHist);
        }
    }

    __syncthreads();

    // Reduce the warp-private sub-histograms inside the block and flush once per logical bin.
    // This reduces global-memory atomics from "one per matching byte" to "one per bin per block".
    if (threadIdx.x < range) {
        const unsigned int bin = threadIdx.x;
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += sharedHist[w * kLocalHistogramBins + bin];
        }

        // histogram[bin] counts occurrences of byte value (from + bin).
        //
        // If a single block processes the entire input, it can write the final answer directly.
        // Otherwise multiple blocks contribute to the same output bin, so global atomicAdd is
        // required when flushing block-private counts.
        if (gridDim.x == 1) {
            histogram[bin] = sum;
        } else if (sum != 0u) {
            atomicAdd(histogram + bin, sum);
        }
    }
}

}  // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    // The problem statement guarantees valid device allocations and lets the caller manage
    // synchronization. This function therefore only enqueues work into the default stream
    // and returns immediately.
    //
    // Small defensive guards are kept to avoid illegal launches if the contract is violated.
    if (histogram == nullptr) {
        return;
    }
    if (from < 0 || to > 255 || from > to) {
        return;
    }

    const unsigned int fromU = static_cast<unsigned int>(from);
    const unsigned int range = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes = static_cast<size_t>(range) * sizeof(unsigned int);

    // Empty input: just zero the requested output range.
    if (input == nullptr || inputSize == 0u) {
        cudaMemsetAsync(histogram, 0, histogramBytes, 0);
        return;
    }

    // One block covers kBlockSize * kItemsPerThread bytes per outer loop iteration.
    const size_t blockChunk = static_cast<size_t>(kBlockSize) * kItemsPerThread;
    unsigned int blocksForInput = static_cast<unsigned int>(
        (static_cast<size_t>(inputSize) + blockChunk - 1u) / blockChunk);

    unsigned int grid = blocksForInput;

    // If one block is enough, skip the memset: the kernel writes every output bin directly.
    if (grid > 1u) {
        // Cap the grid at 8 blocks/SM. On Ampere/Hopper, that already fills the 64-warp / 2048-thread
        // SM limit. Launching more blocks would only increase per-block flush traffic to global memory
        // and the amount of shared-histogram initialization work.
        int device = 0;
        int smCount = 1;
        cudaGetDevice(&device);
        cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

        const unsigned int maxBlocks = static_cast<unsigned int>(
            (smCount > 0 ? smCount : 1) * kTargetBlocksPerSM);

        if (grid > maxBlocks) {
            grid = maxBlocks;
        }

        // Multi-block accumulation requires the output histogram to start at zero.
        cudaMemsetAsync(histogram, 0, histogramBytes, 0);
    }

    histogram_range_kernel<<<grid, kBlockSize>>>(input, histogram, inputSize, fromU, range);
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

constexpr int kWarpSize = 32;
constexpr int kBlockThreads = 256;
constexpr int kWarpsPerBlock = kBlockThreads / kWarpSize;
static_assert((kBlockThreads % kWarpSize) == 0, "kBlockThreads must be a multiple of 32.");

constexpr unsigned int kMaxBins = 256u;

// One extra slot is reserved per warp-private histogram.
// - It acts as padding, so neighboring warp histograms are not separated by an exact
//   multiple of 32 banks.
// - It is also used as the out-of-range sentinel key for warp matching.
constexpr unsigned int kInvalidBin = kMaxBins;         // index 256
constexpr unsigned int kWarpHistStride = kMaxBins + 1u; // 257

constexpr std::size_t kVectorBytes = sizeof(uint4);
constexpr std::size_t kVectorAlignMask = kVectorBytes - 1u;

// Launch heuristic: bias slightly toward more CTAs on mid-size inputs.
// The per-block global merge cost is only one atomic add per output bin, so a
// moderately larger grid is usually worth it to keep the GPU busy.
constexpr unsigned int kLaunchBytesPerThread = 8u;
constexpr unsigned int kTargetBytesPerBlock =
    static_cast<unsigned int>(kBlockThreads) * kLaunchBytesPerThread;

// Collapse equal-bin lanes inside a warp before touching shared memory.
// Because each warp owns a private histogram segment, one elected leader lane can
// update shared memory with a plain increment instead of a shared-memory atomic.
//
// The explicit __syncwarp(activeMask) is required for correctness on Volta+
// independent thread scheduling: all participating lanes must reconverge before the
// next warp-wide primitive that uses the same active mask.
__device__ __forceinline__
void warp_aggregated_private_add(const unsigned int bin,
                                 const unsigned int numBins,
                                 const unsigned int activeMask,
                                 const unsigned int laneBit,
                                 unsigned int* const warpHist)
{
    const unsigned int key = (bin < numBins) ? bin : kInvalidBin;
    const unsigned int peers = __match_any_sync(activeMask, key);

    if (key < numBins && (peers & (laneBit - 1u)) == 0u) {
        warpHist[key] += __popc(peers);
    }

    __syncwarp(activeMask);
}

__device__ __forceinline__
void accumulate_packed_u32(const unsigned int word,
                           const unsigned int from,
                           const unsigned int numBins,
                           const unsigned int activeMask,
                           const unsigned int laneBit,
                           unsigned int* const warpHist)
{
    warp_aggregated_private_add(((word >>  0) & 0xFFu) - from, numBins, activeMask, laneBit, warpHist);
    warp_aggregated_private_add(((word >>  8) & 0xFFu) - from, numBins, activeMask, laneBit, warpHist);
    warp_aggregated_private_add(((word >> 16) & 0xFFu) - from, numBins, activeMask, laneBit, warpHist);
    warp_aggregated_private_add(((word >> 24) & 0xFFu) - from, numBins, activeMask, laneBit, warpHist);
}

// Per-block algorithm:
// 1) Zero warp-private histograms in shared memory.
// 2) Process the input with grid-stride loops. A short scalar prefix is peeled so
//    the main path can use aligned uint4 loads.
// 3) Reduce the warp-private histograms and merge one partial histogram per block
//    into the global output.
__global__ __launch_bounds__(kBlockThreads)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            const unsigned int inputSize,
                            const unsigned int from,
                            const unsigned int numBins)
{
    __shared__ unsigned int sharedHist[kWarpsPerBlock * kWarpHistStride];

    #pragma unroll
    for (unsigned int i = threadIdx.x; i < kWarpsPerBlock * kWarpHistStride; i += kBlockThreads) {
        sharedHist[i] = 0u;
    }
    __syncthreads();

    const unsigned int lane = threadIdx.x & (kWarpSize - 1u);
    const unsigned int laneBit = 1u << lane;
    const unsigned int warp = threadIdx.x / kWarpSize;
    unsigned int* const warpHist = sharedHist + warp * kWarpHistStride;

    const std::size_t globalThread = static_cast<std::size_t>(blockIdx.x) * kBlockThreads + threadIdx.x;
    const std::size_t totalThreads = static_cast<std::size_t>(gridDim.x) * kBlockThreads;

    const unsigned char* const inputBytes =
        reinterpret_cast<const unsigned char*>(input);
    const std::size_t totalBytes = static_cast<std::size_t>(inputSize);

    // Peel up to 15 bytes so the main uint4 path is always 16-byte aligned even if
    // the incoming char* is not.
    const std::size_t misalignment =
        static_cast<std::size_t>(reinterpret_cast<std::uintptr_t>(inputBytes)) & kVectorAlignMask;
    const std::size_t rawHeadBytes = (kVectorBytes - misalignment) & kVectorAlignMask;
    const std::size_t headBytes = (rawHeadBytes < totalBytes) ? rawHeadBytes : totalBytes;

    // Scalar prefix.
    for (std::size_t i = globalThread; i < headBytes; i += totalThreads) {
        const unsigned int activeMask = __activemask();
        const unsigned int bin = static_cast<unsigned int>(inputBytes[i]) - from;
        warp_aggregated_private_add(bin, numBins, activeMask, laneBit, warpHist);
    }

    // Main aligned vectorized body.
    const std::size_t remainingBytes = totalBytes - headBytes;
    const std::size_t vecCount = remainingBytes / kVectorBytes;
    const uint4* const input4 =
        reinterpret_cast<const uint4*>(inputBytes + headBytes);

    for (std::size_t vec = globalThread; vec < vecCount; vec += totalThreads) {
        const unsigned int activeMask = __activemask();
        const uint4 packed = input4[vec];

        accumulate_packed_u32(packed.x, from, numBins, activeMask, laneBit, warpHist);
        accumulate_packed_u32(packed.y, from, numBins, activeMask, laneBit, warpHist);
        accumulate_packed_u32(packed.z, from, numBins, activeMask, laneBit, warpHist);
        accumulate_packed_u32(packed.w, from, numBins, activeMask, laneBit, warpHist);
    }

    // Scalar tail.
    const std::size_t tailStart = headBytes + vecCount * kVectorBytes;
    for (std::size_t i = tailStart + globalThread; i < totalBytes; i += totalThreads) {
        const unsigned int activeMask = __activemask();
        const unsigned int bin = static_cast<unsigned int>(inputBytes[i]) - from;
        warp_aggregated_private_add(bin, numBins, activeMask, laneBit, warpHist);
    }

    __syncthreads();

    // Merge the per-warp private histograms.
    // With a multi-block launch we need global atomics, but only one per block/bin.
    const bool singleBlock = (gridDim.x == 1u);

    for (unsigned int bin = threadIdx.x; bin < numBins; bin += kBlockThreads) {
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += sharedHist[w * kWarpHistStride + bin];
        }

        if (sum != 0u) {
            if (singleBlock) {
                histogram[bin] = sum;
            } else {
                atomicAdd(histogram + bin, sum);
            }
        }
    }
}

static inline unsigned int ceil_div_u32(const unsigned int x, const unsigned int y)
{
    return (x + y - 1u) / y;
}

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);

    // The kernel merges block-private results with global atomic adds, so the
    // requested output range must be cleared first. This is intentionally async;
    // the caller owns host-device synchronization.
    (void)cudaMemsetAsync(histogram, 0, static_cast<std::size_t>(numBins) * sizeof(unsigned int));

    if (inputSize == 0u) {
        return;
    }

    // The API does not expose a stream parameter, so all work is enqueued on the
    // default stream. Occupancy is queried at runtime so the launch adapts to the
    // actual target GPU and compiler register allocation.
    int device = 0;
    int smCount = 1;
    int activeBlocksPerSM = 1;

    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    (void)cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM, histogram_range_kernel, kBlockThreads, 0);

    if (smCount < 1) {
        smCount = 1;
    }
    if (activeBlocksPerSM < 1) {
        activeBlocksPerSM = 1;
    }

    const unsigned int maxResidentBlocks =
        static_cast<unsigned int>(smCount) * static_cast<unsigned int>(activeBlocksPerSM);

    const unsigned int logicalBlocks = ceil_div_u32(inputSize, kTargetBytesPerBlock);
    unsigned int grid = (logicalBlocks < maxResidentBlocks) ? logicalBlocks : maxResidentBlocks;
    if (grid == 0u) {
        grid = 1u;
    }

    histogram_range_kernel<<<grid, kBlockThreads>>>(
        input,
        histogram,
        inputSize,
        static_cast<unsigned int>(from),
        numBins);
}

#include <cuda_runtime.h>
#include <stdint.h>

// Restricted-range text histogram optimized for modern NVIDIA data-center GPUs.
//
// High-level strategy:
//   1) Each block keeps one private histogram per warp in shared memory.
//      With 256 threads/block this is 8 warp-private histograms, so the shared-memory
//      footprint is only 8 * range_len * sizeof(unsigned int), at most 8 KiB.
//   2) Input is scanned with grid-stride loops. The main path uses 16-byte vector loads
//      (uint4) for good memory throughput. A tiny scalar prefix keeps the code correct
//      even if the caller passes a misaligned sub-buffer pointer.
//   3) Matching bytes update the warp-private shared histogram. On Volta+ we first
//      aggregate equal bins within the warp via __match_any_sync(), so one shared atomic
//      can account for multiple lanes hitting the same character.
//   4) After all input has been consumed, each block reduces its 8 private histograms
//      and emits a single global update per output bin. This cuts global atomic traffic
//      from O(number_of_matching_characters) to O(number_of_blocks * range_len).

constexpr int          kHistogramBlockThreads = 256;
constexpr unsigned int kHistogramBlockThreadsU = 256u;
constexpr int          kHistogramWarpSize = 32;
constexpr unsigned int kHistogramWarpMask = 31u;
constexpr int          kHistogramWarpsPerBlock = kHistogramBlockThreads / kHistogramWarpSize;
constexpr unsigned int kHistogramVectorBytes = 16u;
constexpr unsigned int kHistogramVectorMask = kHistogramVectorBytes - 1u;
constexpr unsigned int kHistogramVectorShift = 4u;

static_assert(kHistogramBlockThreads % kHistogramWarpSize == 0,
              "Block size must be a multiple of warp size.");
static_assert(kHistogramBlockThreads >= 256,
              "The final reduction expects at least one thread per possible output bin.");
static_assert(sizeof(uint4) == kHistogramVectorBytes,
              "This implementation assumes 16-byte uint4 vector loads.");

// Map an input byte to a histogram bin in [0, range_len) or return -1 if the byte
// is outside the requested inclusive range [from_u, from_u + range_len - 1].
__device__ __forceinline__
int restricted_bin(const unsigned char c,
                   const unsigned int from_u,
                   const unsigned int range_len)
{
    const unsigned int bin = static_cast<unsigned int>(c) - from_u;
    return (bin < range_len) ? static_cast<int>(bin) : -1;
}

// Increment one bin in the warp-private shared histogram.
// Modern path:
//   - __match_any_sync() groups lanes with identical bin values.
//   - Only one leader lane performs the shared atomicAdd with the group population.
// Fallback path:
//   - One shared atomic per matching byte.
__device__ __forceinline__
void warp_aggregated_shared_increment(const int bin,
                                      unsigned int * const warp_hist,
                                      const unsigned int lane)
{
#if __CUDA_ARCH__ >= 700
    const unsigned int active = __activemask();
    const unsigned int peers  = __match_any_sync(active, bin);
    const int leader_lane     = __ffs(static_cast<int>(peers)) - 1;

    if (bin >= 0 && static_cast<int>(lane) == leader_lane) {
        atomicAdd(warp_hist + bin, static_cast<unsigned int>(__popc(peers)));
    }
#else
    (void)lane;
    if (bin >= 0) {
        atomicAdd(warp_hist + bin, 1u);
    }
#endif
}

__device__ __forceinline__
void process_byte(const unsigned char c,
                  const unsigned int from_u,
                  const unsigned int range_len,
                  unsigned int * const warp_hist,
                  const unsigned int lane)
{
    warp_aggregated_shared_increment(restricted_bin(c, from_u, range_len), warp_hist, lane);
}

// Process four bytes packed in one 32-bit word. Byte order does not matter for the
// histogram, so simple bit extraction is sufficient.
__device__ __forceinline__
void process_u32(const unsigned int word,
                 const unsigned int from_u,
                 const unsigned int range_len,
                 unsigned int * const warp_hist,
                 const unsigned int lane)
{
    process_byte(static_cast<unsigned char>( word        & 0xFFu), from_u, range_len, warp_hist, lane);
    process_byte(static_cast<unsigned char>((word >>  8) & 0xFFu), from_u, range_len, warp_hist, lane);
    process_byte(static_cast<unsigned char>((word >> 16) & 0xFFu), from_u, range_len, warp_hist, lane);
    process_byte(static_cast<unsigned char>((word >> 24) & 0xFFu), from_u, range_len, warp_hist, lane);
}

__global__ __launch_bounds__(kHistogramBlockThreads)
void histogram_range_kernel(const char * __restrict__ input,
                            unsigned int * __restrict__ histogram,
                            const unsigned int inputSize,
                            const unsigned int from_u,
                            const unsigned int range_len)
{
    // Shared memory layout:
    //   [ warp0 bins ][ warp1 bins ] ... [ warp7 bins ]
    // Each slice has exactly range_len counters, so narrow ranges pay less zeroing cost.
    extern __shared__ unsigned int s_hist[];

    const unsigned int tid     = threadIdx.x;
    const unsigned int lane    = tid & kHistogramWarpMask;
    const unsigned int warp_id = tid >> 5;

    unsigned int * const warp_hist = s_hist + warp_id * range_len;
    const unsigned int shared_bins = static_cast<unsigned int>(kHistogramWarpsPerBlock) * range_len;

    // Zero the block-private shared histograms.
    for (unsigned int i = tid; i < shared_bins; i += kHistogramBlockThreadsU) {
        s_hist[i] = 0u;
    }
    __syncthreads();

    const unsigned int global_tid    = blockIdx.x * kHistogramBlockThreadsU + tid;
    const unsigned int total_threads = gridDim.x  * kHistogramBlockThreadsU;

    // cudaMalloc() base pointers are naturally well aligned, but this scalar prefix keeps
    // the vectorized path correct even if the caller passes an offset sub-buffer pointer.
    const uintptr_t address = reinterpret_cast<uintptr_t>(input);
    unsigned int scalar_prefix =
        static_cast<unsigned int>((kHistogramVectorBytes - (address & kHistogramVectorMask)) &
                                  kHistogramVectorMask);
    if (scalar_prefix > inputSize) {
        scalar_prefix = inputSize;
    }

    // Small misalignment prefix.
    for (unsigned int i = global_tid; i < scalar_prefix; i += total_threads) {
        process_byte(static_cast<unsigned char>(input[i]), from_u, range_len, warp_hist, lane);
    }

    // Main vectorized body.
    const char * const aligned_input = input + scalar_prefix;
    const unsigned int aligned_size  = inputSize - scalar_prefix;
    const uint4 * const vec_input    = reinterpret_cast<const uint4 *>(aligned_input);
    const unsigned int vec_count     = aligned_size >> kHistogramVectorShift;

    for (unsigned int vec_idx = global_tid; vec_idx < vec_count; vec_idx += total_threads) {
        const uint4 v = vec_input[vec_idx];
        process_u32(v.x, from_u, range_len, warp_hist, lane);
        process_u32(v.y, from_u, range_len, warp_hist, lane);
        process_u32(v.z, from_u, range_len, warp_hist, lane);
        process_u32(v.w, from_u, range_len, warp_hist, lane);
    }

    // Tail after the vectorized body.
    const unsigned int tail_start = vec_count << kHistogramVectorShift;
    for (unsigned int i = tail_start + global_tid; i < aligned_size; i += total_threads) {
        process_byte(static_cast<unsigned char>(aligned_input[i]), from_u, range_len, warp_hist, lane);
    }

    __syncthreads();

    // One thread per output bin (range_len <= 256 by problem statement).
    // Sum the 8 warp-private counters and emit one global update per block/bin.
    if (tid < range_len) {
        const unsigned int histogram_bin = tid;
        const unsigned int * const bin_base = s_hist + histogram_bin;

        unsigned int sum = 0u;
#pragma unroll
        for (int w = 0; w < kHistogramWarpsPerBlock; ++w) {
            sum += bin_base[static_cast<unsigned int>(w) * range_len];
        }

        if (sum != 0u) {
            // Fast path for tiny launches: if there is only one block, the output bin is
            // written directly because the histogram was already zeroed before launch.
            if (gridDim.x == 1u) {
                histogram[histogram_bin] = sum;
            } else {
                atomicAdd(histogram + histogram_bin, sum);
            }
        }
    }
}

// Host entry point requested by the problem statement.
//
// Notes:
//   - input and histogram are assumed to be device pointers allocated with cudaMalloc().
//   - from and to are assumed valid per the problem statement.
//   - The function uses the default stream because the signature does not provide one.
//   - The caller handles synchronization.
//   - The histogram is explicitly zeroed here because the kernel performs accumulation.
void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    const unsigned int from_u    = static_cast<unsigned int>(from);
    const unsigned int range_len = static_cast<unsigned int>(to - from + 1);
    const size_t histogram_bytes = static_cast<size_t>(range_len) * sizeof(unsigned int);

    (void)cudaMemsetAsync(histogram, 0, histogram_bytes, 0);

    if (inputSize == 0u) {
        return;
    }

    const size_t dynamic_smem_bytes =
        static_cast<size_t>(kHistogramWarpsPerBlock) *
        static_cast<size_t>(range_len) *
        sizeof(unsigned int);

    // Grid-stride loops mean we only need enough blocks to fill the machine once.
    // Occupancy is queried so launch size adapts if compiler register usage changes.
    int device = 0;
    (void)cudaGetDevice(&device);

    int sm_count = 0;
    (void)cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, device);
    if (sm_count < 1) {
        sm_count = 1;
    }

    int blocks_per_sm = 0;
    (void)cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &blocks_per_sm,
        histogram_range_kernel,
        kHistogramBlockThreads,
        dynamic_smem_bytes);
    if (blocks_per_sm < 1) {
        blocks_per_sm = 1;
    }

    const int max_resident_blocks = sm_count * blocks_per_sm;

    // Rough work estimate in 16-byte chunks; enough to avoid launching far more blocks
    // than the input can use while still saturating the GPU for large inputs.
    const unsigned int work_items =
        (inputSize + kHistogramVectorBytes - 1u) / kHistogramVectorBytes;

    int blocks_for_work = static_cast<int>(
        (work_items + kHistogramBlockThreadsU - 1u) / kHistogramBlockThreadsU);
    if (blocks_for_work < 1) {
        blocks_for_work = 1;
    }

    int grid = blocks_for_work;
    if (grid > max_resident_blocks) {
        grid = max_resident_blocks;
    }
    if (grid < 1) {
        grid = 1;
    }

    histogram_range_kernel<<<grid, kHistogramBlockThreads, dynamic_smem_bytes>>>(
        input,
        histogram,
        inputSize,
        from_u,
        range_len);
}

#include <cuda_runtime.h>
#include <cstdint>

// Optimized range-restricted byte histogram for modern NVIDIA GPUs.
// Design choices:
//  - 32-bit vectorized input loads. The prompt guarantees cudaMalloc-allocated buffers,
//    so the input base pointer is naturally aligned for 32-bit accesses.
//  - Per-warp privatized histograms in shared memory. This dramatically reduces the
//    number of global atomics: each block emits at most one atomicAdd per non-zero bin.
//  - Warp-aggregated updates using __match_any_sync. When multiple lanes in a warp see
//    the same byte/bin, a single leader lane performs one shared-memory atomicAdd with
//    the population count of that group. This is especially effective on skewed text.
//  - Shared-memory padding: one extra slot is inserted every 32 logical bins so bins
//    separated by multiples of 32 do not systematically alias the same bank.
//  - A 256-thread block is a good fit here because the maximum histogram width is 256;
//    in the merge phase, a full-range histogram maps naturally to one thread per bin.

constexpr int kWarpSize = 32;
constexpr int kBlockThreads = 256;
constexpr unsigned int kInvalidTag = 0xFFFFFFFFu;  // Cannot collide with any valid bin (< 256).
static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a multiple of warp size.");

// Map a logical bin index to a padded physical shared-memory index.
// Physical layout inserts one padding element after every 32 logical bins:
//   phys = bin + floor(bin / 32)
// Example for bins 0..63:
//   logical 0..31  -> phys 0..31
//   logical 32..63 -> phys 33..64  (phys 32 is padding)
__device__ __forceinline__ unsigned int padded_bin_index(unsigned int bin) {
    return bin + (bin >> 5);
}

// Warp-aggregated shared-memory histogram update.
// Every currently active lane participates in __match_any_sync using the same active mask.
// Invalid lanes contribute a sentinel tag and are ignored afterwards.
// For each distinct valid bin value present in the warp, only one leader lane performs
// the atomicAdd, with the increment equal to the number of matching lanes.
__device__ __forceinline__ void update_warp_histogram(
    unsigned int active_mask,
    bool valid,
    unsigned int bin,
    unsigned int* __restrict__ warp_hist,
    unsigned int lane_id) {
    const unsigned int tag = valid ? bin : kInvalidTag;
    const unsigned int group = __match_any_sync(active_mask, tag);
    const unsigned int leader = static_cast<unsigned int>(__ffs(group) - 1);

    if (valid && lane_id == leader) {
        atomicAdd(&warp_hist[padded_bin_index(bin)], __popc(group));
    }
}

template <int BLOCK_THREADS>
__global__ __launch_bounds__(BLOCK_THREADS)
void histogram_range_kernel(
    const char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    unsigned int from,
    unsigned int bins,
    unsigned int paddedBins) {
    constexpr int kWarpsPerBlock = BLOCK_THREADS / kWarpSize;

    extern __shared__ unsigned int shared_histograms[];

    const unsigned int tid = threadIdx.x;
    const unsigned int lane_id = tid & (kWarpSize - 1);
    const unsigned int warp_id = tid >> 5;
    unsigned int* const warp_hist = shared_histograms + warp_id * paddedBins;

    // Zero all warp-private shared histograms cooperatively.
    const unsigned int shared_elems =
        static_cast<unsigned int>(kWarpsPerBlock) * paddedBins;
    for (unsigned int i = tid; i < shared_elems; i += BLOCK_THREADS) {
        shared_histograms[i] = 0u;
    }
    __syncthreads();

    const unsigned int global_tid = blockIdx.x * BLOCK_THREADS + tid;
    const unsigned int total_threads = gridDim.x * BLOCK_THREADS;

    const unsigned char* const input_u8 =
        reinterpret_cast<const unsigned char*>(input);
    const uint32_t* const input_u32 =
        reinterpret_cast<const uint32_t*>(input_u8);

    const unsigned int wordCount = inputSize >> 2;   // Number of full 4-byte words.
    const unsigned int tailStart = wordCount << 2;   // First leftover byte.
    const unsigned int tailCount = inputSize - tailStart;  // 0..3

    // Main path: process 4 bytes per iteration with a grid-stride loop.
    // Byte order inside the 32-bit word is irrelevant because histogram accumulation
    // is commutative; we simply unpack all four bytes and count them.
    for (unsigned int wordIdx = global_tid; wordIdx < wordCount; wordIdx += total_threads) {
        const uint32_t packed = input_u32[wordIdx];
        const unsigned int active_mask = __activemask();

        uint32_t v = packed;
        #pragma unroll
        for (int i = 0; i < 4; ++i) {
            const unsigned int byte = v & 0xFFu;
            const unsigned int bin = byte - from;  // Underflow is fine; the range check is bin < bins.
            update_warp_histogram(active_mask, bin < bins, bin, warp_hist, lane_id);
            v >>= 8;
        }
    }

    // Tail path: at most 3 bytes remain. Let only the first warp of the first block
    // process them; this avoids extra kernel launches and avoids overflow-prone
    // tailStart + global_tid arithmetic when inputSize is close to UINT_MAX.
    if (blockIdx.x == 0u && warp_id == 0u && tailCount != 0u) {
        const unsigned int active_mask = __activemask();
        const bool valid_lane = lane_id < tailCount;
        const unsigned int byte = valid_lane ? static_cast<unsigned int>(input_u8[tailStart + lane_id]) : 0u;
        const unsigned int bin = byte - from;
        update_warp_histogram(active_mask, valid_lane && (bin < bins), bin, warp_hist, lane_id);
    }

    __syncthreads();

    // Merge all warp-private shared histograms in the block and emit one global atomicAdd
    // per non-zero bin for this block.
    for (unsigned int bin = tid; bin < bins; bin += BLOCK_THREADS) {
        const unsigned int phys = padded_bin_index(bin);
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += shared_histograms[w * paddedBins + phys];
        }

        if (sum != 0u) {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

void run_histogram(
    const char *input,
    unsigned int *histogram,
    unsigned int inputSize,
    int from,
    int to) {
    const unsigned int bins = static_cast<unsigned int>(to - from + 1);
    const unsigned int paddedBins = bins + ((bins - 1u) >> 5);
    const size_t histogramBytes = static_cast<size_t>(bins) * sizeof(unsigned int);

    // The caller explicitly handles synchronization, so keep the API fully async.
    cudaMemsetAsync(histogram, 0, histogramBytes);

    if (inputSize == 0u) {
        return;
    }

    constexpr int kWarpsPerBlock = kBlockThreads / kWarpSize;
    const size_t sharedBytes =
        static_cast<size_t>(kWarpsPerBlock) *
        static_cast<size_t>(paddedBins) *
        sizeof(unsigned int);

    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1) {
        smCount = 1;
    }

    int activeBlocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM,
        histogram_range_kernel<kBlockThreads>,
        kBlockThreads,
        sharedBytes);
    if (activeBlocksPerSM < 1) {
        activeBlocksPerSM = 1;
    }

    // Safe ceil(inputSize / 4) without overflow.
    const unsigned int workItems =
        (inputSize >> 2) + ((inputSize & 3u) != 0u ? 1u : 0u);

    unsigned int grid =
        (workItems + static_cast<unsigned int>(kBlockThreads) - 1u) /
        static_cast<unsigned int>(kBlockThreads);
    if (grid == 0u) {
        grid = 1u;
    }

    // Saturate the GPU but avoid launching excess blocks, since each block contributes
    // a final block-to-global histogram merge.
    const unsigned int maxResidentGrid =
        static_cast<unsigned int>(smCount) *
        static_cast<unsigned int>(activeBlocksPerSM);
    if (grid > maxResidentGrid) {
        grid = maxResidentGrid;
    }

    histogram_range_kernel<kBlockThreads><<<grid, kBlockThreads, sharedBytes>>>(
        input,
        histogram,
        inputSize,
        static_cast<unsigned int>(from),
        bins,
        paddedBins);
}

#include <cuda_runtime.h>
#include <cstddef>

namespace {

// A 256-thread block is a good fit for modern data-center GPUs and for this
// problem specifically: the histogram range is at most 256 bins, so the final
// flush can map one thread to one bin.
constexpr int blockThreads   = 256;
constexpr int warpThreads    = 32;
constexpr int warpsPerBlock  = blockThreads / warpThreads;

// Tuned default for A100/H100-class GPUs:
// - 16 bytes per thread gives one naturally aligned 128-bit load (uint4) per
//   thread in the fast path.
// - This amortizes loop/index overhead well without materially hurting occupancy.
// Keep this a multiple of 16 to preserve the aligned vectorized load path.
constexpr int itemsPerThread = 16;

constexpr unsigned int invalidBinKey = 0xFFFFFFFFu;

static_assert((blockThreads % warpThreads) == 0, "blockThreads must be a multiple of 32.");
static_assert(blockThreads >= 256, "blockThreads must be at least 256 to cover the maximum 256-bin range.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert((itemsPerThread % 16) == 0, "itemsPerThread must be a multiple of 16.");

// Warp-aggregated increment into a warp-private shared histogram.
// Each block owns warpsPerBlock histograms in shared memory, one per warp.
// __match_any_sync groups lanes that saw the same bin; only the leader for each
// distinct bin performs the increment, adding the population count of the group.
// Because the histogram is private to the warp, no shared-memory atomic is needed
// on the hot path.
__device__ __forceinline__
void add_byte_to_warp_hist(unsigned int* warpHist,
                           unsigned int rangeBins,
                           unsigned int fromValue,
                           unsigned int byteValue,
                           bool valid,
                           unsigned int activeMask,
                           unsigned int lane)
{
    const unsigned int bin = byteValue - fromValue;
    const bool counted = valid && (bin < rangeBins);
    const unsigned int key = counted ? bin : invalidBinKey;

    const unsigned int peers = __match_any_sync(activeMask, key);

    if (counted) {
        const unsigned int leader = static_cast<unsigned int>(__ffs(static_cast<int>(peers)) - 1);
        if (lane == leader) {
            warpHist[bin] += __popc(peers);
        }
    }
}

// Process four bytes packed in one 32-bit word. The histogram is order-insensitive,
// so the byte order of updates is irrelevant as long as every byte is visited once.
__device__ __forceinline__
void add_packed_word_to_warp_hist(unsigned int packed,
                                  unsigned int* warpHist,
                                  unsigned int rangeBins,
                                  unsigned int fromValue,
                                  unsigned int activeMask,
                                  unsigned int lane)
{
    add_byte_to_warp_hist(warpHist, rangeBins, fromValue,  packed        & 0xFFu, true, activeMask, lane);
    add_byte_to_warp_hist(warpHist, rangeBins, fromValue, (packed >>  8) & 0xFFu, true, activeMask, lane);
    add_byte_to_warp_hist(warpHist, rangeBins, fromValue, (packed >> 16) & 0xFFu, true, activeMask, lane);
    add_byte_to_warp_hist(warpHist, rangeBins, fromValue, (packed >> 24) & 0xFFu, true, activeMask, lane);
}

__global__ __launch_bounds__(blockThreads)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int fromValue,
                            unsigned int rangeBins)
{
    constexpr int vectorLoadsPerThread = itemsPerThread / 16;

    // Shared memory layout:
    //   [warp0 histogram][warp1 histogram]...[warpN histogram]
    // Range width is <= 256, so even 8 warp-private histograms only require
    // 8 * 256 * 4 bytes = 8 KiB at the largest range.
    extern __shared__ unsigned int sharedHist[];

    const unsigned int tid    = static_cast<unsigned int>(threadIdx.x);
    const unsigned int lane   = tid & (warpThreads - 1u);
    const unsigned int warpId = tid >> 5;

    const unsigned int totalSharedBins = static_cast<unsigned int>(warpsPerBlock) * rangeBins;
    for (unsigned int i = tid; i < totalSharedBins; i += blockThreads) {
        sharedHist[i] = 0u;
    }
    __syncthreads();

    // Interpret input as bytes 0..255 regardless of whether plain char is signed.
    const unsigned char* const data = reinterpret_cast<const unsigned char*>(input);
    unsigned int* const warpHist = sharedHist + warpId * rangeBins;

    const size_t inputSizeBytes = static_cast<size_t>(inputSize);
    const size_t tileItems      = static_cast<size_t>(blockThreads) * itemsPerThread;
    const size_t gridStride     = static_cast<size_t>(gridDim.x) * tileItems;

    for (size_t tileBase = static_cast<size_t>(blockIdx.x) * tileItems;
         tileBase < inputSizeBytes;
         tileBase += gridStride) {
        const size_t threadBase = tileBase + static_cast<size_t>(tid) * itemsPerThread;

        // Fast path: this lane owns a full, aligned chunk, so use vectorized loads.
        // __activemask() makes the warp intrinsics safe even in the final mixed warp,
        // where some lanes may take the fast path while others fall back to scalar.
        if ((threadBase + itemsPerThread) <= inputSizeBytes) {
            const unsigned int branchMask = __activemask();
            const uint4* const vecPtr = reinterpret_cast<const uint4*>(data + threadBase);

#pragma unroll
            for (int v = 0; v < vectorLoadsPerThread; ++v) {
                const uint4 packed16 = vecPtr[v];
                add_packed_word_to_warp_hist(packed16.x, warpHist, rangeBins, fromValue, branchMask, lane);
                add_packed_word_to_warp_hist(packed16.y, warpHist, rangeBins, fromValue, branchMask, lane);
                add_packed_word_to_warp_hist(packed16.z, warpHist, rangeBins, fromValue, branchMask, lane);
                add_packed_word_to_warp_hist(packed16.w, warpHist, rangeBins, fromValue, branchMask, lane);
            }
        } else {
            // Tail path for the final partial chunk.
            const unsigned int branchMask = __activemask();

#pragma unroll
            for (int i = 0; i < itemsPerThread; ++i) {
                const size_t idx = threadBase + static_cast<size_t>(i);
                const bool valid = idx < inputSizeBytes;
                const unsigned int activeMask = __ballot_sync(branchMask, valid);

                if (activeMask != 0u) {
                    unsigned int byteValue = 0u;
                    if (valid) {
                        byteValue = static_cast<unsigned int>(data[idx]);
                    }
                    add_byte_to_warp_hist(warpHist, rangeBins, fromValue, byteValue, valid, activeMask, lane);
                }
            }
        }
    }

    __syncthreads();

    // Reduce the warp-private histograms into the caller-provided global histogram.
    // blockThreads == 256 and rangeBins <= 256, so each thread handles at most one bin.
    if (tid < rangeBins) {
        unsigned int sum = 0u;
#pragma unroll
        for (int w = 0; w < warpsPerBlock; ++w) {
            sum += sharedHist[static_cast<unsigned int>(w) * rangeBins + tid];
        }
        if (sum != 0u) {
            atomicAdd(histogram + tid, sum);
        }
    }
}

} // anonymous namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    const unsigned int fromValue = static_cast<unsigned int>(from);
    const unsigned int rangeBins = static_cast<unsigned int>(to - from) + 1u;
    const size_t histogramBytes  = static_cast<size_t>(rangeBins) * sizeof(unsigned int);

    // The result buffer must start from zero. This stays asynchronous with respect
    // to the host; the caller owns any host/device synchronization.
    cudaMemsetAsync(histogram, 0, histogramBytes, 0);

    if (inputSize == 0u) {
        return;
    }

    const size_t sharedMemBytes =
        static_cast<size_t>(warpsPerBlock) * static_cast<size_t>(rangeBins) * sizeof(unsigned int);

    // Launch roughly one resident wave of blocks. Because each block grid-strides
    // over the full input and pays fixed costs to clear and flush its private
    // histogram, more blocks than the GPU can keep resident usually only increase
    // overhead for this workload.
    int device = 0;
    int smCount = 1;
    int blocksPerSM = 1;
    cudaGetDevice(&device);
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &blocksPerSM,
        histogram_range_kernel,
        blockThreads,
        sharedMemBytes);

    if (smCount < 1) {
        smCount = 1;
    }
    if (blocksPerSM < 1) {
        blocksPerSM = 1;
    }

    const size_t tileItems = static_cast<size_t>(blockThreads) * itemsPerThread;
    const unsigned int numTiles =
        static_cast<unsigned int>((static_cast<size_t>(inputSize) + tileItems - 1u) / tileItems);
    const unsigned int residentGrid = static_cast<unsigned int>(smCount * blocksPerSM);

    unsigned int launchGrid = (numTiles < residentGrid) ? numTiles : residentGrid;
    if (launchGrid == 0u) {
        launchGrid = 1u;
    }

    histogram_range_kernel<<<launchGrid, blockThreads, sharedMemBytes>>>(
        input,
        histogram,
        inputSize,
        fromValue,
        rangeBins);
}

#include <cuda_runtime.h>
#include <cstdint>

// Compute a histogram over a runtime-selected inclusive byte range [from, to].
// Output bin i corresponds to byte value (from + i).
//
// Optimization strategy tuned for modern datacenter GPUs (A100/H100 class):
// - 256 threads/block -> 8 warps/block.
// - One warp-private 256-bin histogram in shared memory per warp.
//   This costs only 8 KiB/block (8 warps * 256 bins * 4 bytes) and removes
//   inter-warp contention inside the block.
// - On Volta+ the update path uses __match_any_sync() to collapse duplicate bins
//   within the active subset of a warp to one shared-memory increment.
// - itemsPerThread = 16 is a good default for large inputs on recent GPUs:
//   it provides useful ILP, amortizes loop/index overhead, and maps naturally
//   to aligned 16-byte vector loads from cudaMalloc memory.
constexpr int itemsPerThread = 16;
constexpr int blockThreads   = 256;
constexpr int vectorLoadBytes = 16;

constexpr unsigned int warpSizeConst  = 32u;
constexpr unsigned int warpsPerBlock  = static_cast<unsigned int>(blockThreads) / warpSizeConst;
constexpr unsigned int fullCharDomain = 256u;
constexpr unsigned int invalidBin     = 0xFFFFFFFFu;

static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert(blockThreads % static_cast<int>(warpSizeConst) == 0,
              "blockThreads must be a multiple of warp size.");
static_assert(blockThreads >= static_cast<int>(fullCharDomain),
              "blockThreads must be at least 256 so one thread can reduce one output bin.");
static_assert(vectorLoadBytes == static_cast<int>(sizeof(uint4)),
              "uint4 is expected to be a 16-byte vector load.");

// Add one logical histogram hit into a warp-private shared-memory histogram.
// Fast path (sm_70+): collapse all lanes that target the same bin into one leader
// update. Because each warp owns its own histogram segment, the shared-memory
// increment can be a plain add instead of an atomic.
// Fallback path: shared atomic within the warp-private histogram.
static __device__ __forceinline__
void warp_histogram_add_key(unsigned int key,
                            unsigned int range,
                            unsigned int* warpHist,
                            unsigned int lane,
                            unsigned int activeMask)
{
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 700)
    const unsigned int bin   = (key < range) ? key : invalidBin;
    const unsigned int peers = __match_any_sync(activeMask, bin);
    if (bin != invalidBin && lane == static_cast<unsigned int>(__ffs(peers) - 1)) {
        warpHist[bin] += static_cast<unsigned int>(__popc(peers));
    }
#else
    (void)lane;
    (void)activeMask;
    if (key < range) {
        atomicAdd(warpHist + key, 1u);
    }
#endif
}

// Process four packed bytes loaded from global memory.
static __device__ __forceinline__
void process_packed_u32(uint32_t word,
                        unsigned int from_u,
                        unsigned int range,
                        unsigned int* warpHist,
                        unsigned int lane,
                        unsigned int activeMask)
{
    warp_histogram_add_key(((word      ) & 0xFFu) - from_u, range, warpHist, lane, activeMask);
    warp_histogram_add_key(((word >>  8) & 0xFFu) - from_u, range, warpHist, lane, activeMask);
    warp_histogram_add_key(((word >> 16) & 0xFFu) - from_u, range, warpHist, lane, activeMask);
    warp_histogram_add_key(((word >> 24) & 0xFFu) - from_u, range, warpHist, lane, activeMask);
}

template <int ITEMS_PER_THREAD>
__global__ __launch_bounds__(blockThreads)
void histogram_kernel(const char* __restrict__ input,
                      unsigned int* __restrict__ histogram,
                      unsigned int inputSize,
                      unsigned int from_u,
                      unsigned int range)
{
    // Full 256-bin warp-private histograms keep addressing fixed and cheap.
    // Only bins [0, range) are initialized and reduced because only those map
    // to the user-requested output subrange.
    __shared__ unsigned int s_hist[warpsPerBlock * fullCharDomain];

    const unsigned int tid    = static_cast<unsigned int>(threadIdx.x);
    const unsigned int warpId = tid >> 5;
    const unsigned int lane   = tid & (warpSizeConst - 1u);

    unsigned int* const warpHist = s_hist + warpId * fullCharDomain;
    const unsigned char* const inputBytes = reinterpret_cast<const unsigned char*>(input);

    // Each warp initializes only its own histogram segment.
    for (unsigned int bin = lane; bin < range; bin += warpSizeConst) {
        warpHist[bin] = 0u;
    }
    __syncthreads();

    const uint64_t size64      = static_cast<uint64_t>(inputSize);
    const uint64_t fullChunk   = static_cast<uint64_t>(ITEMS_PER_THREAD);
    const uint64_t chunkStride = static_cast<uint64_t>(gridDim.x) *
                                 static_cast<uint64_t>(blockThreads) *
                                 static_cast<uint64_t>(ITEMS_PER_THREAD);

    // Thread-contiguous chunking is chosen so the main path can use aligned
    // 16-byte vector loads when ITEMS_PER_THREAD is a multiple of 16. The prompt
    // states that input comes from cudaMalloc, so the base pointer is suitably
    // aligned and idx stays aligned because it advances in multiples of 16 for
    // the default itemsPerThread = 16.
    uint64_t idx = (static_cast<uint64_t>(blockIdx.x) * static_cast<uint64_t>(blockThreads) +
                    static_cast<uint64_t>(tid)) *
                   static_cast<uint64_t>(ITEMS_PER_THREAD);

    // Main path: full chunks only.
    if ((ITEMS_PER_THREAD % vectorLoadBytes) == 0) {
        if (size64 >= fullChunk) {
            for (; idx + fullChunk <= size64; idx += chunkStride) {
                const unsigned int activeMask = __activemask();
                const size_t base = static_cast<size_t>(idx);
                const uint4* const vec = reinterpret_cast<const uint4*>(inputBytes + base);

#pragma unroll
                for (int v = 0; v < ITEMS_PER_THREAD / vectorLoadBytes; ++v) {
                    const uint4 packed = vec[v];
                    process_packed_u32(packed.x, from_u, range, warpHist, lane, activeMask);
                    process_packed_u32(packed.y, from_u, range, warpHist, lane, activeMask);
                    process_packed_u32(packed.z, from_u, range, warpHist, lane, activeMask);
                    process_packed_u32(packed.w, from_u, range, warpHist, lane, activeMask);
                }
            }
        }
    } else {
        if (size64 >= fullChunk) {
            for (; idx + fullChunk <= size64; idx += chunkStride) {
                const unsigned int activeMask = __activemask();
                const size_t base = static_cast<size_t>(idx);

#pragma unroll
                for (int j = 0; j < ITEMS_PER_THREAD; ++j) {
                    const unsigned int key =
                        static_cast<unsigned int>(inputBytes[base + static_cast<size_t>(j)]) - from_u;
                    warp_histogram_add_key(key, range, warpHist, lane, activeMask);
                }
            }
        }
    }

    // Tail path: at most one partial chunk per thread remains after the full-chunk loop.
    // Lanes that have run out of valid input still participate in the warp-level grouping
    // with an invalid bin so the active subset remains well-defined.
    for (; idx < size64; idx += chunkStride) {
        const unsigned int activeMask = __activemask();
        const size_t base = static_cast<size_t>(idx);
        const unsigned int remaining = static_cast<unsigned int>(size64 - idx);

#pragma unroll
        for (int j = 0; j < ITEMS_PER_THREAD; ++j) {
            unsigned int key = invalidBin;
            if (static_cast<unsigned int>(j) < remaining) {
                key = static_cast<unsigned int>(inputBytes[base + static_cast<size_t>(j)]) - from_u;
            }
            warp_histogram_add_key(key, range, warpHist, lane, activeMask);
        }
    }

    __syncthreads();

    // One thread per output bin reduces the warp-private histograms for this block.
    // If there is only one block in the grid, a direct store is enough because the
    // host launcher clears the output histogram beforehand.
    if (tid < range) {
        unsigned int sum = 0u;
#pragma unroll
        for (unsigned int w = 0; w < warpsPerBlock; ++w) {
            sum += s_hist[w * fullCharDomain + tid];
        }

        if (sum != 0u) {
            if (gridDim.x == 1u) {
                histogram[tid] = sum;
            } else {
                atomicAdd(histogram + tid, sum);
            }
        }
    }
}

static inline unsigned int ceil_div_u32(unsigned int x, unsigned int y)
{
    return (x == 0u) ? 0u : (1u + (x - 1u) / y);
}

// input and histogram are device pointers allocated with cudaMalloc.
// The function clears the output histogram and then launches the kernel.
// Both operations are asynchronous; synchronization is intentionally left
// to the caller as requested.
void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    const unsigned int from_u = static_cast<unsigned int>(from);
    const unsigned int range  = static_cast<unsigned int>(to - from + 1);

    // The kernel accumulates into the destination histogram, so clear it first.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(range) * sizeof(unsigned int));

    if (inputSize == 0u) {
        return;
    }

    int device = 0;
    if (cudaGetDevice(&device) != cudaSuccess) {
        device = 0;
    }

    int smCount = 0;
    if (cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device) != cudaSuccess ||
        smCount <= 0) {
        smCount = 1;
    }

    int activeBlocksPerSM = 0;
    if (cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &activeBlocksPerSM,
            histogram_kernel<itemsPerThread>,
            blockThreads,
            0) != cudaSuccess || activeBlocksPerSM <= 0) {
        activeBlocksPerSM = 1;
    }

    // Grid-stride looping means an occupancy-sized grid is enough for large inputs.
    const unsigned int blockChunk     = static_cast<unsigned int>(blockThreads) *
                                        static_cast<unsigned int>(itemsPerThread);
    const unsigned int blocksNeeded   = ceil_div_u32(inputSize, blockChunk);
    const unsigned int residentBlocks = static_cast<unsigned int>(smCount) *
                                        static_cast<unsigned int>(activeBlocksPerSM);
    const unsigned int grid           = (blocksNeeded < residentBlocks) ? blocksNeeded
                                                                        : residentBlocks;

    if (grid == 0u) {
        return;
    }

    histogram_kernel<itemsPerThread><<<grid, blockThreads>>>(
        input,
        histogram,
        inputSize,
        from_u,
        range);
}

#include <cuda_runtime.h>

// Histogram over a restricted byte range [from, to], where both input and output live in device memory.
//
// Performance-oriented design for modern NVIDIA GPUs (A100/H100 class):
//   1. Shared-memory privatization is done at warp granularity: each warp gets its own sub-histogram.
//      This sharply reduces contention compared to a single block-private histogram, especially for
//      skewed text distributions (e.g. spaces, newlines, vowels).
//   2. One padding element is inserted every 32 logical bins in shared memory to reduce bank conflicts.
//   3. Each thread processes multiple bytes (itemsPerThread) to amortize loop/index overhead.
//   4. The default itemsPerThread = 16 is chosen because it maps naturally to one 128-bit load
//      (uint4) per thread on the fast path, which is a strong default for large inputs on recent GPUs.
//
// The host wrapper intentionally does not synchronize; the caller requested fully asynchronous behavior.

namespace histogram_detail {

constexpr int warpWidth       = 32;
constexpr int threadsPerBlock = 256;

// Tuned default:
// - 16 bytes/thread enables one aligned 128-bit load per thread on the vectorized path.
// - This is a good balance between memory efficiency, ILP, and register pressure on A100/H100.
constexpr int itemsPerThread  = 16;

static_assert((threadsPerBlock % warpWidth) == 0,
              "threadsPerBlock must be a multiple of the warp size.");
static_assert(threadsPerBlock >= 256,
              "threadsPerBlock must be at least 256 so the final reduction can cover all 256 byte values.");
static_assert(itemsPerThread > 0,
              "itemsPerThread must be positive.");

// Total shared-memory counters needed for a padded histogram with 'bins' logical bins.
// Padding rule: add one extra element after every 32 logical bins.
__host__ __device__ inline unsigned int padded_histogram_bins(const unsigned int bins) {
    return bins + ((bins - 1u) / warpWidth);
}

// Map a logical bin index to its padded shared-memory index.
__device__ __forceinline__ unsigned int padded_bin_index(const unsigned int bin) {
    return bin + (bin / warpWidth);
}

// Increment the warp-private shared histogram if the byte falls in the requested [from, to] range.
// The range check is written as (byte - from) < bins, which is a standard branch-efficient form.
__device__ __forceinline__ void update_warp_histogram(
    const unsigned int byteValue,
    const unsigned int from_u,
    const unsigned int bins,
    unsigned int* const warpHistogram)
{
    const unsigned int localBin = byteValue - from_u;
    if (localBin < bins) {
        atomicAdd(&warpHistogram[padded_bin_index(localBin)], 1u);
    }
}

// Unpack four bytes from one 32-bit word and update the warp-private histogram.
__device__ __forceinline__ void process_packed_word(
    const unsigned int packedBytes,
    const unsigned int from_u,
    const unsigned int bins,
    unsigned int* const warpHistogram)
{
    update_warp_histogram( packedBytes        & 0xFFu, from_u, bins, warpHistogram);
    update_warp_histogram((packedBytes >>  8) & 0xFFu, from_u, bins, warpHistogram);
    update_warp_histogram((packedBytes >> 16) & 0xFFu, from_u, bins, warpHistogram);
    update_warp_histogram((packedBytes >> 24) & 0xFFu, from_u, bins, warpHistogram);
}

// Scalar fallback: used when the input pointer is not 16-byte aligned or when ITEMS_PER_THREAD is not
// a multiple of 16. This preserves correctness for any positive itemsPerThread value.
template <int ITEMS_PER_THREAD>
__device__ __forceinline__ void process_tile_scalar(
    const unsigned char* const __restrict__ input,
    const unsigned int base,
    const unsigned int inputSize,
    const unsigned int from_u,
    const unsigned int bins,
    unsigned int* const warpHistogram)
{
    #pragma unroll
    for (int i = 0; i < ITEMS_PER_THREAD; ++i) {
        const unsigned int idx = base + static_cast<unsigned int>(i);
        if (idx < inputSize) {
            update_warp_histogram(input[idx], from_u, bins, warpHistogram);
        }
    }
}

// Vectorized fast path: assumes the input pointer is 16-byte aligned and ITEMS_PER_THREAD is a multiple
// of 16. Each thread consumes 16 bytes at a time via one uint4 load.
template <int ITEMS_PER_THREAD>
__device__ __forceinline__ void process_tile_vectorized(
    const unsigned char* const __restrict__ input,
    const unsigned int base,
    const unsigned int inputSize,
    const unsigned int from_u,
    const unsigned int bins,
    unsigned int* const warpHistogram)
{
    const uint4* const inputVec = reinterpret_cast<const uint4*>(input);

    #pragma unroll
    for (int i = 0; i < ITEMS_PER_THREAD; i += 16) {
        const unsigned int idx = base + static_cast<unsigned int>(i);

        // 64-bit comparison avoids corner-case wraparound when inputSize is near UINT_MAX.
        if (static_cast<unsigned long long>(idx) + 16ull <= static_cast<unsigned long long>(inputSize)) {
            const uint4 vec = inputVec[idx >> 4];
            process_packed_word(vec.x, from_u, bins, warpHistogram);
            process_packed_word(vec.y, from_u, bins, warpHistogram);
            process_packed_word(vec.z, from_u, bins, warpHistogram);
            process_packed_word(vec.w, from_u, bins, warpHistogram);
        } else {
            // Only the very end of the input reaches this path.
            #pragma unroll
            for (int j = 0; j < 16; ++j) {
                const unsigned int scalarIdx = idx + static_cast<unsigned int>(j);
                if (scalarIdx < inputSize) {
                    update_warp_histogram(input[scalarIdx], from_u, bins, warpHistogram);
                }
            }
        }
    }
}

template <int BLOCK_THREADS, int ITEMS_PER_THREAD>
__global__ void histogram_kernel(
    const unsigned char* const __restrict__ input,
    unsigned int* const __restrict__ histogram,
    const unsigned int inputSize,
    const unsigned int from_u,
    const unsigned int bins)
{
    constexpr int warpsPerBlock = BLOCK_THREADS / warpWidth;

    // Shared memory layout:
    //   [ warp0 padded histogram ][ warp1 padded histogram ] ... [ warpN padded histogram ]
    extern __shared__ unsigned int sharedHistogram[];

    const unsigned int tid        = threadIdx.x;
    const unsigned int warpId     = tid / warpWidth;
    const unsigned int paddedBins = padded_histogram_bins(bins);
    const unsigned int sharedSpan = static_cast<unsigned int>(warpsPerBlock) * paddedBins;

    unsigned int* const warpHistogram = sharedHistogram + warpId * paddedBins;

    // Zero all warp-private histograms.
    for (unsigned int i = tid; i < sharedSpan; i += BLOCK_THREADS) {
        sharedHistogram[i] = 0u;
    }
    __syncthreads();

    // Grid-stride over tiles. Each thread handles ITEMS_PER_THREAD consecutive bytes per iteration.
    const unsigned int globalThread = blockIdx.x * BLOCK_THREADS + tid;
    const unsigned int gridStride   = static_cast<unsigned int>(gridDim.x) * BLOCK_THREADS * ITEMS_PER_THREAD;

    // cudaMalloc returns pointers with enough alignment for 16-byte vector loads, but this runtime check
    // also keeps the kernel correct if the caller passes an offset pointer.
    const bool inputIsAligned16 = ((reinterpret_cast<unsigned long long>(input) & 0xFull) == 0ull);

    if (((ITEMS_PER_THREAD % 16) == 0) && inputIsAligned16) {
        for (unsigned int base = globalThread * ITEMS_PER_THREAD; base < inputSize; base += gridStride) {
            process_tile_vectorized<ITEMS_PER_THREAD>(input, base, inputSize, from_u, bins, warpHistogram);
        }
    } else {
        for (unsigned int base = globalThread * ITEMS_PER_THREAD; base < inputSize; base += gridStride) {
            process_tile_scalar<ITEMS_PER_THREAD>(input, base, inputSize, from_u, bins, warpHistogram);
        }
    }

    __syncthreads();

    // Reduce the warp-private shared histograms into the final global histogram.
    // Because BLOCK_THREADS is 256 and bins <= 256, the full-range case maps one thread per output bin.
    if (tid < bins) {
        const unsigned int paddedBin = padded_bin_index(tid);
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < warpsPerBlock; ++w) {
            sum += sharedHistogram[w * paddedBins + paddedBin];
        }

        if (sum != 0u) {
            atomicAdd(&histogram[tid], sum);
        }
    }
}

} // namespace histogram_detail

void run_histogram(const char *input, unsigned int *histogram, unsigned int inputSize, int from, int to)
{
    // The output histogram stores only the requested inclusive range [from, to].
    const unsigned int bins   = static_cast<unsigned int>(to - from + 1);
    const unsigned int from_u = static_cast<unsigned int>(from);

    // The kernel accumulates with atomic adds, so the destination must start from zero.
    // This is asynchronous and ordered before the kernel launch in the same stream.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(bins) * sizeof(unsigned int));

    if (inputSize == 0u) {
        return;
    }

    const size_t sharedMemBytes =
        static_cast<size_t>(histogram_detail::threadsPerBlock / histogram_detail::warpWidth) *
        static_cast<size_t>(histogram_detail::padded_histogram_bins(bins)) *
        sizeof(unsigned int);

    // Launch enough blocks to fill the machine, but do not oversubscribe unnecessarily.
    // The kernel is grid-stride, so a resident-sized grid is sufficient even for very large inputs.
    int device = 0;
    cudaGetDevice(&device);

    int multiprocessorCount = 0;
    cudaDeviceGetAttribute(&multiprocessorCount, cudaDevAttrMultiProcessorCount, device);

    int activeBlocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM,
        histogram_detail::histogram_kernel<histogram_detail::threadsPerBlock, histogram_detail::itemsPerThread>,
        histogram_detail::threadsPerBlock,
        sharedMemBytes);

    const unsigned long long tileItems =
        static_cast<unsigned long long>(histogram_detail::threadsPerBlock) *
        static_cast<unsigned long long>(histogram_detail::itemsPerThread);

    const unsigned int blocksForInput = static_cast<unsigned int>(
        (static_cast<unsigned long long>(inputSize) + tileItems - 1ull) / tileItems);

    const unsigned int maxResidentBlocks =
        static_cast<unsigned int>(activeBlocksPerSM * multiprocessorCount);

    const unsigned int gridSize =
        (blocksForInput < maxResidentBlocks) ? blocksForInput : maxResidentBlocks;

    if (gridSize == 0u) {
        return;
    }

    histogram_detail::histogram_kernel<histogram_detail::threadsPerBlock, histogram_detail::itemsPerThread>
        <<<gridSize, histogram_detail::threadsPerBlock, sharedMemBytes>>>(
            reinterpret_cast<const unsigned char*>(input),
            histogram,
            inputSize,
            from_u,
            bins);

    // Intentionally no synchronization here; the caller requested asynchronous behavior.
}

#include <cuda_runtime.h>

namespace {

// Tuned for modern data-center GPUs (A100/H100):
// - 256 threads/block gives 8 full warps and lets threadIdx.x map directly to the 256 possible byte values.
// - itemsPerThread = 16 makes each CTA process 4 KiB per grid-stride tile, which is a good default for
//   large byte streams: it amortizes shared-histogram setup/flush costs without hurting occupancy.
constexpr int threadsPerBlock = 256;
constexpr int itemsPerThread = 16;
constexpr int warpSizeConst = 32;
constexpr int warpsPerBlock = threadsPerBlock / warpSizeConst;
constexpr int histogramBinsMax = 256;
constexpr unsigned int invalidBin = histogramBinsMax;  // sentinel outside the legal [0,255] bin range
constexpr unsigned int fullWarpMask = 0xffffffffu;

static_assert(threadsPerBlock == histogramBinsMax,
              "The flush phase assumes one thread per possible byte value.");
static_assert(threadsPerBlock % warpSizeConst == 0,
              "threadsPerBlock must be a multiple of warp size.");

__device__ __forceinline__
void add_to_warp_private_histogram(unsigned int* myWarpHist,
                                   unsigned int key,
                                   unsigned int lane)
{
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 700)
    // Warp-aggregated atomic update:
    // lanes that saw the same byte value form an equivalence class, and only the leader
    // performs the shared-memory atomic with the class population count.
    const unsigned int sameKeyMask = __match_any_sync(fullWarpMask, key);
    if (key != invalidBin && lane == static_cast<unsigned int>(__ffs(sameKeyMask) - 1)) {
        atomicAdd(myWarpHist + key, __popc(sameKeyMask));
    }
#else
    // Fallback for pre-Volta builds.
    if (key != invalidBin) {
        atomicAdd(myWarpHist + key, 1u);
    }
#endif
}

__global__ __launch_bounds__(threadsPerBlock)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from,
                            unsigned int range)
{
    // Each warp owns a private 256-bin histogram in shared memory.
    // Using the full byte space keeps indexing trivial; the cost is only 8 KiB/CTA,
    // which is not occupancy-limiting on A100/H100 with 256-thread blocks.
    __shared__ unsigned int warpHist[warpsPerBlock * histogramBinsMax];

    // Zero the privatized histograms. Because 8 warps * 256 bins = 2048 counters and we use
    // 256 threads, every thread clears exactly 8 counters.
    #pragma unroll
    for (int w = 0; w < warpsPerBlock; ++w) {
        warpHist[w * threadsPerBlock + threadIdx.x] = 0u;
    }
    __syncthreads();

    const unsigned char* __restrict__ bytes =
        reinterpret_cast<const unsigned char*>(input);

    const unsigned int lane = threadIdx.x & (warpSizeConst - 1u);
    const unsigned int warp = threadIdx.x >> 5;
    unsigned int* const myWarpHist = warpHist + warp * histogramBinsMax;

    const size_t n = static_cast<size_t>(inputSize);
    const size_t blockTileSize = static_cast<size_t>(threadsPerBlock) * itemsPerThread;
    const size_t gridTileStride = blockTileSize * gridDim.x;

    // Persistent/grid-stride traversal:
    // each block accumulates many tiles into its shared histogram and flushes to global memory once,
    // which greatly reduces global atomic traffic.
    for (size_t tileBase = static_cast<size_t>(blockIdx.x) * blockTileSize;
         tileBase < n;
         tileBase += gridTileStride)
    {
        const size_t threadBase = tileBase + threadIdx.x;

        // Per-thread work is laid out as threadIdx.x + item*blockDim.x so each unrolled step
        // issues coalesced byte loads across the warp.
        #pragma unroll
        for (int item = 0; item < itemsPerThread; ++item) {
            const size_t idx = threadBase + static_cast<size_t>(item) * threadsPerBlock;

            // Sentinel 256 means "ignore this byte" (either out of bounds or outside [from, to]).
            unsigned int key = invalidBin;

            if (idx < n) {
                const unsigned int value = bytes[idx];
                // Unsigned wraparound turns the lower-bound check into part of the same compare:
                // value is in range iff (value - from) <= (to - from).
                const unsigned int delta = value - from;
                if (delta <= range) {
                    key = delta;  // output histogram is indexed from zero: value -> value - from
                }
            }

            add_to_warp_private_histogram(myWarpHist, key, lane);
        }
    }

    __syncthreads();

    // Final reduction: one thread per possible byte value sums the 8 warp-private counters
    // and atomically adds the block total to the global histogram.
    if (threadIdx.x <= range) {
        unsigned int sum = 0u;
        #pragma unroll
        for (int w = 0; w < warpsPerBlock; ++w) {
            sum += warpHist[w * histogramBinsMax + threadIdx.x];
        }
        if (sum != 0u) {
            atomicAdd(histogram + threadIdx.x, sum);
        }
    }
}

} // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    const unsigned int ufrom = static_cast<unsigned int>(from);
    const unsigned int range = static_cast<unsigned int>(to - from);
    const size_t histogramBytes =
        static_cast<size_t>(range + 1u) * sizeof(unsigned int);

    // The kernel accumulates into the destination histogram, so clear it first.
    // Per the requested interface, this function only enqueues work; synchronization
    // and asynchronous error handling are left to the caller.
    cudaMemsetAsync(histogram, 0, histogramBytes);

    if (inputSize == 0u) {
        return;
    }

    int device = 0;
    int smCount = 1;
    int activeBlocksPerSM = 1;

    // Query a resident-grid launch size. Because the kernel uses a grid-stride loop,
    // launching roughly one resident wave of CTAs is usually best: it keeps the GPU full
    // while avoiding unnecessary per-CTA init/final-flush overhead.
    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    (void)cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM, histogram_range_kernel, threadsPerBlock, 0);

    if (smCount < 1) {
        smCount = 1;
    }
    if (activeBlocksPerSM < 1) {
        activeBlocksPerSM = 1;
    }

    const unsigned int blockTileSize = threadsPerBlock * itemsPerThread;
    const int totalTiles = static_cast<int>(
        (static_cast<unsigned long long>(inputSize) + blockTileSize - 1ull) /
        blockTileSize);
    const int residentGridSize = smCount * activeBlocksPerSM;
    const int gridSize = (totalTiles < residentGridSize) ? totalTiles : residentGridSize;

    histogram_range_kernel<<<gridSize, threadsPerBlock>>>(
        input, histogram, inputSize, ufrom, range);
}

#include <cuda_runtime.h>

namespace
{
    // Tuned for large streaming inputs on modern data-center GPUs (A100/H100 class).
    // - 256 threads/block -> 8 warps/block, a good balance for histogramming.
    // - The logical histogram size is at most 256 bins, so the final flush can map one thread
    //   to one logical bin.
    // - 16 items/thread gives each block a 4 KiB tile, which amortizes control overhead well
    //   without pushing register pressure too high.
    constexpr int blockThreads   = 256;
    constexpr int itemsPerThread = 16;
    constexpr int warpsPerBlock  = blockThreads / 32;

    constexpr unsigned int fullWarpMask = 0xFFFFFFFFu;
    constexpr unsigned int invalidBin   = 0xFFFFFFFFu;

    static_assert(blockThreads % 32 == 0, "blockThreads must be a multiple of warp size");
    static_assert(itemsPerThread > 0, "itemsPerThread must be positive");

    // Shared memory has 32 banks. Padding one slot after every completed 32-bin group
    // changes the bank mapping so bins k and k+32 do not alias the same bank.
    // Example: 256 logical bins -> 263 physical counters.
    constexpr unsigned int padded_range_bins(unsigned int rangeBins)
    {
        return rangeBins ? (rangeBins + ((rangeBins - 1u) >> 5)) : 0u;
    }

    __device__ __forceinline__ unsigned int padded_bin_index(unsigned int bin)
    {
        return bin + (bin >> 5);
    }

    // Canonicalized input values use:
    //   - [0, rangeBins) for valid bins
    //   - invalidBin for both out-of-range characters and tail elements past inputSize
    //
    // __match_any_sync groups equal bins inside the warp; only the leader performs the update.
    // Because each warp owns a private histogram slice in shared memory, this is a plain
    // shared-memory increment instead of a shared-memory atomic.
    //
    // This implementation intentionally targets Volta+ (__match_any_sync), which matches the
    // requested hardware class (A100/H100).
    __device__ __forceinline__ void accumulate_bin(unsigned int bin,
                                                   unsigned int* warpHist,
                                                   unsigned int lane)
    {
        const unsigned int peers = __match_any_sync(fullWarpMask, bin);

        if (bin != invalidBin)
        {
            const unsigned int leader = static_cast<unsigned int>(__ffs(peers) - 1);
            if (lane == leader)
            {
                warpHist[padded_bin_index(bin)] += static_cast<unsigned int>(__popc(peers));
            }
        }
    }

    __global__ __launch_bounds__(blockThreads)
    void histogram_range_kernel(const unsigned char* __restrict__ input,
                                unsigned int* __restrict__ histogram,
                                unsigned int inputSize,
                                unsigned int from,
                                unsigned int rangeBins,
                                unsigned int paddedRangeBins)
    {
        // Layout: one privatized histogram per warp.
        extern __shared__ unsigned int sharedWarpHist[];

        const unsigned int tid    = static_cast<unsigned int>(threadIdx.x);
        const unsigned int lane   = tid & 31u;
        const unsigned int warpId = tid >> 5;

        unsigned int* const warpHist = sharedWarpHist + warpId * paddedRangeBins;

        // Zero the privatized histograms.
        const unsigned int totalSharedCounters = static_cast<unsigned int>(warpsPerBlock) * paddedRangeBins;
        for (unsigned int i = tid; i < totalSharedCounters; i += blockThreads)
        {
            sharedWarpHist[i] = 0u;
        }
        __syncthreads();

        // Persistent/grid-stride processing over block-sized tiles.
        const size_t n              = static_cast<size_t>(inputSize);
        const size_t blockWorkItems = static_cast<size_t>(blockThreads) * static_cast<size_t>(itemsPerThread);
        const size_t gridStride     = static_cast<size_t>(gridDim.x) * blockWorkItems;
        const size_t fullTilesEnd   = (n / blockWorkItems) * blockWorkItems;

        for (size_t tileBase = static_cast<size_t>(blockIdx.x) * blockWorkItems; tileBase < n; tileBase += gridStride)
        {
            const size_t threadBase = tileBase + static_cast<size_t>(tid);

            if (tileBase < fullTilesEnd)
            {
                // Fast path: the whole block tile is in-bounds, so no per-item bounds checks.
                #pragma unroll
                for (int i = 0; i < itemsPerThread; ++i)
                {
                    const size_t idx = threadBase + static_cast<size_t>(i) * blockThreads;
                    const unsigned int offset =
                        static_cast<unsigned int>(input[idx]) - from;
                    const unsigned int bin = (offset < rangeBins) ? offset : invalidBin;
                    accumulate_bin(bin, warpHist, lane);
                }
            }
            else
            {
                // Tail path: keep all warp threads participating in every __match_any_sync call.
                #pragma unroll
                for (int i = 0; i < itemsPerThread; ++i)
                {
                    const size_t idx = threadBase + static_cast<size_t>(i) * blockThreads;

                    unsigned int bin = invalidBin;
                    if (idx < n)
                    {
                        const unsigned int offset =
                            static_cast<unsigned int>(input[idx]) - from;
                        bin = (offset < rangeBins) ? offset : invalidBin;
                    }

                    accumulate_bin(bin, warpHist, lane);
                }
            }
        }

        __syncthreads();

        // Flush warp-private histograms into the final output.
        // For a single-block launch we can store directly; for multi-block launches we use
        // global atomics because different blocks contribute to the same output bins.
        if (tid < rangeBins)
        {
            const unsigned int pbin = padded_bin_index(tid);

            unsigned int sum = 0u;
            #pragma unroll
            for (int w = 0; w < warpsPerBlock; ++w)
            {
                sum += sharedWarpHist[static_cast<unsigned int>(w) * paddedRangeBins + pbin];
            }

            if (gridDim.x == 1)
            {
                histogram[tid] = sum;
            }
            else if (sum != 0u)
            {
                atomicAdd(histogram + tid, sum);
            }
        }
    }
}

// Enqueues the histogram computation on the default stream.
// The caller is responsible for any host/device synchronization.
// For multi-block launches the output buffer must be zeroed first because blocks accumulate
// via global atomics. For a single-block launch the kernel writes the final histogram directly,
// so the memset can be skipped.
void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // The problem statement guarantees a valid range; this guard simply avoids undefined behavior
    // if the function is called incorrectly.
    if (from < 0 || to > 255 || from > to)
    {
        return;
    }

    const unsigned int fromU           = static_cast<unsigned int>(from);
    const unsigned int rangeBins       = static_cast<unsigned int>(to - from + 1);
    const unsigned int paddedRangeBins = padded_range_bins(rangeBins);
    const size_t histogramBytes        = static_cast<size_t>(rangeBins) * sizeof(unsigned int);
    const size_t sharedBytes           = static_cast<size_t>(warpsPerBlock) *
                                         static_cast<size_t>(paddedRangeBins) *
                                         sizeof(unsigned int);

    // No input: the correct result is an all-zero histogram.
    if (inputSize == 0u)
    {
        cudaMemsetAsync(histogram, 0, histogramBytes, 0);
        return;
    }

    const unsigned long long blockWorkItems =
        static_cast<unsigned long long>(blockThreads) * static_cast<unsigned long long>(itemsPerThread);

    const unsigned int workBlocks = static_cast<unsigned int>(
        (static_cast<unsigned long long>(inputSize) + blockWorkItems - 1ull) / blockWorkItems);

    // Launch only a resident wave of blocks. Because the kernel uses a grid-stride loop, this
    // keeps the machine full while minimizing per-block shared-histogram init/flush overhead.
    unsigned int gridBlocks = workBlocks;

    if (gridBlocks > 1u)
    {
        int device = 0;
        int smCount = 1;
        int maxBlocksPerSM = 1;

        cudaGetDevice(&device);
        cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
        cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &maxBlocksPerSM,
            histogram_range_kernel,
            blockThreads,
            sharedBytes);

        if (smCount < 1)       smCount = 1;
        if (maxBlocksPerSM < 1) maxBlocksPerSM = 1;

        const unsigned int residentBlocks =
            static_cast<unsigned int>(smCount) * static_cast<unsigned int>(maxBlocksPerSM);

        if (gridBlocks > residentBlocks)
        {
            gridBlocks = residentBlocks;
        }
    }

    if (gridBlocks > 1u)
    {
        cudaMemsetAsync(histogram, 0, histogramBytes, 0);
    }

    histogram_range_kernel<<<gridBlocks, blockThreads, sharedBytes, 0>>>(
        reinterpret_cast<const unsigned char*>(input),
        histogram,
        inputSize,
        fromU,
        rangeBins,
        paddedRangeBins);
}

#include <cuda_runtime.h>

namespace {

// 256 threads is deliberate: the histogram has at most 256 bins, so the final
// block->global flush can map one thread to one bin in the worst case.
constexpr int blockThreads = 256;

// Compile-time tuning knob requested by the problem.
// 16 is a strong default on A100/H100-class GPUs for large inputs: it gives
// enough ILP to hide byte-load/shared-atomic latency and keeps the unrolled
// inner loop compact enough to avoid unnecessary register/code-size growth.
constexpr int itemsPerThread = 16;

constexpr int warpsPerBlock = blockThreads / 32;
constexpr unsigned int invalidBin = ~0u;

static_assert(blockThreads % 32 == 0, "blockThreads must be a multiple of 32");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive");

// Update a warp-private shared-memory histogram.
// On Volta+ we use warp-aggregated atomics via __match_any_sync so that all
// lanes in a warp targeting the same bin collapse to a single shared atomic.
// This is especially effective for real text where spaces/newlines/common
// letters repeat frequently. The invalidBin sentinel lets every lane execute
// the warp intrinsic uniformly, even for out-of-range bytes or tail lanes.
__device__ __forceinline__ void warp_aggregated_shared_add(
    unsigned int* warpHistogram,
    unsigned int bin,
    unsigned int lane)
{
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 700)
    const unsigned int activeMask = __activemask();
    const unsigned int peers = __match_any_sync(activeMask, bin);
    const int leader = __ffs(static_cast<int>(peers)) - 1;

    if (bin != invalidBin && static_cast<int>(lane) == leader) {
        atomicAdd(warpHistogram + bin, static_cast<unsigned int>(__popc(peers)));
    }
#else
    (void)lane;
    if (bin != invalidBin) {
        atomicAdd(warpHistogram + bin, 1u);
    }
#endif
}

// Single-pass histogram kernel.
// - Input is treated as raw unsigned bytes [0, 255].
// - Only bytes in the inclusive range [fromOrdinal, fromOrdinal + numBins - 1]
//   are counted.
// - Shared-memory privatization is per warp, not just per block, which reduces
//   intra-block contention. Each block accumulates across all of its grid-stride
//   tiles and flushes once at the end, so global atomic traffic is only
//   O(blocks * bins), not O(input bytes).
template <int ITEMS_PER_THREAD>
__global__ __launch_bounds__(blockThreads)
void histogram_kernel(
    const unsigned char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    unsigned int fromOrdinal,
    unsigned int numBins)
{
    extern __shared__ unsigned int sharedHistogram[];

    const unsigned int tid = threadIdx.x;
    const unsigned int warpId = tid >> 5;
    const unsigned int lane = tid & 31u;

    // Shared layout: [warp0 bins][warp1 bins]...[warpN bins].
    // With 256 threads => 8 warps, and with at most 256 bins, the maximum shared
    // memory footprint is 8 * 256 * 4 B = 8 KiB.
    const unsigned int sharedBinCount = static_cast<unsigned int>(warpsPerBlock) * numBins;
    for (unsigned int i = tid; i < sharedBinCount; i += static_cast<unsigned int>(blockThreads)) {
        sharedHistogram[i] = 0u;
    }
    __syncthreads();

    unsigned int* const warpHistogram = sharedHistogram + warpId * numBins;

    const size_t n = static_cast<size_t>(inputSize);
    const size_t blockWork = static_cast<size_t>(blockThreads) * static_cast<size_t>(ITEMS_PER_THREAD);
    const size_t gridStride = static_cast<size_t>(gridDim.x) * blockWork;

    // Strip-mined access pattern:
    // item k of a warp reads 32 consecutive bytes, so loads are naturally
    // coalesced. With the default tuning, one block touches
    // 256 threads * 16 items/thread = 4096 bytes per outer-loop iteration.
    for (size_t blockOffset = static_cast<size_t>(blockIdx.x) * blockWork;
         blockOffset < n;
         blockOffset += gridStride) {
        const size_t threadBase = blockOffset + static_cast<size_t>(tid);

#pragma unroll
        for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
            const size_t idx =
                threadBase + static_cast<size_t>(item) * static_cast<size_t>(blockThreads);

            unsigned int bin = invalidBin;
            if (idx < n) {
                const unsigned int value = static_cast<unsigned int>(input[idx]);
                const unsigned int candidate = value - fromOrdinal;
                if (candidate < numBins) {
                    bin = candidate;
                }
            }

            warp_aggregated_shared_add(warpHistogram, bin, lane);
        }
    }

    __syncthreads();

    // End-of-block merge over the warp-private histograms. Because numBins <= 256
    // and blockThreads == 256, even the worst case is at most one bin per thread.
    for (unsigned int bin = tid; bin < numBins; bin += static_cast<unsigned int>(blockThreads)) {
        unsigned int sum = 0u;

#pragma unroll
        for (int w = 0; w < warpsPerBlock; ++w) {
            sum += sharedHistogram[static_cast<unsigned int>(w) * numBins + bin];
        }

        if (sum != 0u) {
            atomicAdd(histogram + bin, sum);
        }
    }
}

} // namespace

void run_histogram(const char* input, unsigned int* histogram, unsigned int inputSize, int from, int to)
{
    // The problem statement guarantees valid device pointers and a valid range,
    // so we keep the launcher lean and avoid extra host-side checks.

    // Inclusive range [from, to] => numBins = to - from + 1.
    // histogram[0] counts byte value `from`, histogram[numBins - 1] counts `to`.
    const unsigned int fromOrdinal = static_cast<unsigned int>(from);
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes = static_cast<size_t>(numBins) * sizeof(unsigned int);

    // The kernel only accumulates, so zero the output slice first.
    // No synchronization is performed here; the caller owns stream/device sync.
    // We use stream 0 because the requested API does not carry a stream handle.
    cudaMemsetAsync(histogram, 0, histogramBytes, 0);

    if (inputSize == 0u) {
        return;
    }

    const size_t sharedMemBytes =
        static_cast<size_t>(warpsPerBlock) * static_cast<size_t>(numBins) * sizeof(unsigned int);

    // The kernel grid-strides over the input, so correctness does not depend on
    // the exact grid size. We cap the launch to about two occupancy waves:
    // enough work to saturate the GPU while avoiding gratuitous extra blocks that
    // would only increase the final global merge traffic.
    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    int maxActiveBlocksPerSm = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &maxActiveBlocksPerSm,
        histogram_kernel<itemsPerThread>,
        blockThreads,
        sharedMemBytes);

    const size_t workPerBlock =
        static_cast<size_t>(blockThreads) * static_cast<size_t>(itemsPerThread);
    const unsigned int totalBlocksNeeded = static_cast<unsigned int>(
        (static_cast<size_t>(inputSize) + workPerBlock - 1) / workPerBlock);

    unsigned int launchBlocks = totalBlocksNeeded;
    if (smCount > 0 && maxActiveBlocksPerSm > 0) {
        const unsigned int launchCap =
            static_cast<unsigned int>(smCount) *
            static_cast<unsigned int>(maxActiveBlocksPerSm) * 2u;
        if (launchBlocks > launchCap) {
            launchBlocks = launchCap;
        }
    }

    if (launchBlocks == 0u) {
        launchBlocks = 1u;
    }

    // Reinterpret the device buffer as unsigned bytes so values 128..255 are
    // handled correctly even on platforms where plain char is signed.
    histogram_kernel<itemsPerThread><<<launchBlocks, blockThreads, sharedMemBytes, 0>>>(
        reinterpret_cast<const unsigned char*>(input),
        histogram,
        inputSize,
        fromOrdinal,
        numBins);
}

#include <cuda_runtime.h>

namespace histogram_detail {

// Tuned defaults for large inputs on recent datacenter GPUs (A100/H100 class):
// - 256 threads/block is a strong general-purpose sweet spot for this workload.
// - 16 chars/thread gives enough work to amortize shared-histogram setup/flush
//   while keeping register pressure and occupancy healthy.
constexpr int itemsPerThread = 16;
constexpr int blockSize = 256;
constexpr int warpSizeConst = 32;
constexpr int warpsPerBlock = blockSize / warpSizeConst;
constexpr int maxBins = 256;

// The range width is at most 256, so a fixed 256-bin private histogram per warp
// costs only 8 KiB/block with 8 warps/block. On modern datacenter GPUs this is
// small enough that occupancy is still thread-limited, while fixed-size storage
// keeps addressing simple and compile-time constant.
constexpr int sharedHistSize = warpsPerBlock * maxBins;
constexpr int sharedInitIterations = sharedHistSize / blockSize;

constexpr unsigned int blockItems =
    static_cast<unsigned int>(blockSize) * static_cast<unsigned int>(itemsPerThread);
constexpr unsigned int fullWarpMask = 0xFFFFFFFFu;
constexpr unsigned int invalidBinKey = 0xFFFFFFFFu;

static_assert(blockSize % warpSizeConst == 0, "blockSize must be a multiple of warp size");
static_assert(sharedHistSize % blockSize == 0, "shared histogram must divide evenly across threads");

inline unsigned int div_up_u32(unsigned int n, unsigned int d) {
    return (n / d) + static_cast<unsigned int>((n % d) != 0u);
}

// Warp-aggregated shared-memory update.
// Every lane participates in __match_any_sync using either its real bin or a sentinel
// for "invalid / out-of-range". For each distinct valid bin in the warp, exactly one
// lane performs the shared-memory atomicAdd with the number of matching lanes.
//
// This reduces atomic traffic substantially on text, where repeated characters such as
// spaces, vowels, punctuation, or common letters frequently appear within a warp.
__device__ __forceinline__ void warp_aggregate_add(
    const unsigned int bin,
    const bool valid,
    const unsigned int lane,
    unsigned int* const warpHist)
{
    const unsigned int key = valid ? bin : invalidBinKey;
    const unsigned int peers = __match_any_sync(fullWarpMask, key);

    if (valid && lane == static_cast<unsigned int>(__ffs(static_cast<int>(peers)) - 1)) {
        atomicAdd(warpHist + bin, static_cast<unsigned int>(__popc(peers)));
    }
}

__global__ __launch_bounds__(blockSize)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from_u,
                            unsigned int bins)
{
    // One private histogram per warp in shared memory.
    __shared__ unsigned int sharedHist[sharedHistSize];

    const unsigned int thread = static_cast<unsigned int>(threadIdx.x);
    const unsigned int warpId = thread >> 5;
    const unsigned int lane = thread & 31u;
    unsigned int* const warpHist = sharedHist + warpId * maxBins;

    // Zero the entire privatized histogram. With the fixed layout this is exactly
    // 8 stores/thread and the compiler can fully unroll it.
    #pragma unroll
    for (int i = 0; i < sharedInitIterations; ++i) {
        sharedHist[thread + static_cast<unsigned int>(i) * static_cast<unsigned int>(blockSize)] = 0u;
    }
    __syncthreads();

    // Grid-stride over tiles of blockSize * itemsPerThread bytes.
    // Inside each tile, threads use a block-strided index pattern:
    //   idx = blockBase + thread + item * blockSize
    // so each item iteration produces perfectly coalesced byte loads.
    const size_t inputSize64 = static_cast<size_t>(inputSize);
    const size_t blockSpan = static_cast<size_t>(blockItems);
    const size_t gridSpan = static_cast<size_t>(gridDim.x) * blockSpan;

    for (size_t blockBase = static_cast<size_t>(blockIdx.x) * blockSpan;
         blockBase < inputSize64;
         blockBase += gridSpan)
    {
        size_t idx = blockBase + thread;

        // Split the common full-tile path from the final partial-tile path so almost
        // all iterations avoid per-item bounds checks when the input is large.
        const bool fullTile = (inputSize64 - blockBase) >= blockSpan;

        if (fullTile) {
            #pragma unroll
            for (int item = 0; item < itemsPerThread; ++item) {
                // Interpret bytes as unsigned so values 128..255 are handled correctly
                // regardless of whether plain `char` is signed by the host compiler.
                const unsigned int c = static_cast<unsigned char>(input[idx]);
                const unsigned int bin = c - from_u;
                warp_aggregate_add(bin, bin < bins, lane, warpHist);
                idx += static_cast<size_t>(blockSize);
            }
        } else {
            #pragma unroll
            for (int item = 0; item < itemsPerThread; ++item) {
                unsigned int bin = 0u;
                const bool inBounds = idx < inputSize64;

                if (inBounds) {
                    const unsigned int c = static_cast<unsigned char>(input[idx]);
                    bin = c - from_u;
                }

                warp_aggregate_add(bin, inBounds && (bin < bins), lane, warpHist);
                idx += static_cast<size_t>(blockSize);
            }
        }
    }

    __syncthreads();

    // Reduce the warp-private histograms into the global histogram.
    // Since bins <= 256 and blockSize == 256, one thread can own one output bin.
    if (thread < bins) {
        unsigned int sum = sharedHist[thread];

        #pragma unroll
        for (int w = 1; w < warpsPerBlock; ++w) {
            sum += sharedHist[static_cast<unsigned int>(w) * static_cast<unsigned int>(maxBins) + thread];
        }

        if (sum != 0u) {
            atomicAdd(histogram + thread, sum);
        }
    }
}

}  // namespace histogram_detail

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // Lightweight asynchronous entry point:
    // - pointers are assumed to reference device memory allocated by cudaMalloc,
    // - caller is responsible for any required synchronization and error checking.
    if (histogram == nullptr) {
        return;
    }

    // The problem statement guarantees valid inputs, but keeping a minimal guard here
    // avoids undefined behavior if the function is called incorrectly.
    if (from < 0 || to > 255 || from > to) {
        return;
    }

    const unsigned int bins = static_cast<unsigned int>(to - from + 1);

    // The kernel accumulates with atomics, so start from a zeroed output histogram.
    (void)cudaMemsetAsync(
        histogram,
        0,
        static_cast<size_t>(bins) * sizeof(unsigned int),
        0);

    if (input == nullptr || inputSize == 0u) {
        return;
    }

    // Launch about one resident wave of blocks. Because the kernel uses a grid-stride
    // loop, this is enough to saturate the GPU while minimizing the number of final
    // global atomic reductions (one per bin per block).
    int device = 0;
    int smCount = 1;
    int residentBlocksPerSM = 1;

    if (cudaSuccess == cudaGetDevice(&device)) {
        (void)cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    }

    (void)cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &residentBlocksPerSM,
        histogram_detail::histogram_range_kernel,
        histogram_detail::blockSize,
        0);

    if (smCount < 1) {
        smCount = 1;
    }
    if (residentBlocksPerSM < 1) {
        residentBlocksPerSM = 1;
    }

    const unsigned int neededBlocks =
        histogram_detail::div_up_u32(inputSize, histogram_detail::blockItems);

    unsigned int gridBlocks =
        static_cast<unsigned int>(smCount) * static_cast<unsigned int>(residentBlocksPerSM);

    if (gridBlocks > neededBlocks) {
        gridBlocks = neededBlocks;
    }
    if (gridBlocks == 0u) {
        gridBlocks = 1u;
    }

    histogram_detail::histogram_range_kernel<<<gridBlocks, histogram_detail::blockSize>>>(
        input,
        histogram,
        inputSize,
        static_cast<unsigned int>(from),
        bins);
}

#include <cuda_runtime.h>

// Range-restricted byte histogram over device-resident text input.
// output[i] counts occurrences of the byte value (from + i); bytes outside
// the inclusive [from, to] interval are ignored.

namespace {

// The requested tuning knob.
// 16 bytes/thread is a strong default on A100/H100-class GPUs for large inputs:
// it maps the steady-state load to one aligned 128-bit load per thread and
// amortizes shared-histogram setup/reduction well. If changed, the code still
// works; the vectorized fast path is used whenever it remains a multiple of 16.
static constexpr int itemsPerThread = 16;

// 256 threads/block lets the block-wide merge map one thread to each possible
// compacted output bin because the byte domain is at most 256 values.
static constexpr int blockSize     = 256;
static constexpr int maxBins       = 256;
static constexpr int warpSizeConst = 32;
static constexpr int vectorBytes   = sizeof(uint4);

static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert(blockSize % warpSizeConst == 0, "blockSize must be a whole number of warps.");
static_assert(blockSize >= maxBins, "blockSize must be at least 256.");
static_assert(vectorBytes == 16, "uint4 is expected to be 16 bytes.");

__device__ __forceinline__
void accumulate_byte(unsigned int byteValue,
                     unsigned int from,
                     unsigned int numBins,
                     unsigned int* __restrict__ warpHist)
{
    // Unsigned subtraction collapses the two-sided range test into one compare:
    // values below `from` underflow and therefore fail `bin < numBins`.
    const unsigned int bin = byteValue - from;
    if (bin < numBins) {
        atomicAdd(warpHist + bin, 1u);
    }
}

__device__ __forceinline__
void accumulate_packed_word(unsigned int packed,
                            unsigned int from,
                            unsigned int numBins,
                            unsigned int* __restrict__ warpHist)
{
    accumulate_byte( packed        & 0xFFu, from, numBins, warpHist);
    accumulate_byte((packed >>  8) & 0xFFu, from, numBins, warpHist);
    accumulate_byte((packed >> 16) & 0xFFu, from, numBins, warpHist);
    accumulate_byte((packed >> 24) & 0xFFu, from, numBins, warpHist);
}

template <int ITEMS_PER_THREAD, bool VECTORIZED>
struct ThreadChunkProcessor;

template <int ITEMS_PER_THREAD>
struct ThreadChunkProcessor<ITEMS_PER_THREAD, true> {
    __device__ __forceinline__
    static void process_full(const unsigned char* __restrict__ input,
                             size_t base,
                             unsigned int from,
                             unsigned int numBins,
                             unsigned int* __restrict__ warpHist)
    {
        // Fast path: each thread owns a contiguous, 16-byte-aligned slice so a
        // multiple-of-16 itemsPerThread can be read as aligned uint4 vectors.
        #pragma unroll
        for (int v = 0; v < ITEMS_PER_THREAD / vectorBytes; ++v) {
            const size_t idx = base + static_cast<size_t>(v) * static_cast<size_t>(vectorBytes);
            const uint4 packed = *reinterpret_cast<const uint4*>(input + idx);
            accumulate_packed_word(packed.x, from, numBins, warpHist);
            accumulate_packed_word(packed.y, from, numBins, warpHist);
            accumulate_packed_word(packed.z, from, numBins, warpHist);
            accumulate_packed_word(packed.w, from, numBins, warpHist);
        }
    }
};

template <int ITEMS_PER_THREAD>
struct ThreadChunkProcessor<ITEMS_PER_THREAD, false> {
    __device__ __forceinline__
    static void process_full(const unsigned char* __restrict__ input,
                             size_t base,
                             unsigned int from,
                             unsigned int numBins,
                             unsigned int* __restrict__ warpHist)
    {
        #pragma unroll
        for (int i = 0; i < ITEMS_PER_THREAD; ++i) {
            accumulate_byte(static_cast<unsigned int>(input[base + static_cast<size_t>(i)]),
                            from,
                            numBins,
                            warpHist);
        }
    }
};

template <int ITEMS_PER_THREAD>
__device__ __forceinline__
void process_tail_chunk(const unsigned char* __restrict__ input,
                        size_t base,
                        size_t inputSize,
                        unsigned int from,
                        unsigned int numBins,
                        unsigned int* __restrict__ warpHist)
{
    #pragma unroll
    for (int i = 0; i < ITEMS_PER_THREAD; ++i) {
        const size_t idx = base + static_cast<size_t>(i);
        if (idx < inputSize) {
            accumulate_byte(static_cast<unsigned int>(input[idx]), from, numBins, warpHist);
        }
    }
}

template <int BLOCK_SIZE, int ITEMS_PER_THREAD>
__global__ __launch_bounds__(BLOCK_SIZE)
void histogram_range_kernel(const unsigned char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from,
                            unsigned int numBins)
{
    constexpr int WARPS_PER_BLOCK = BLOCK_SIZE / warpSizeConst;
    typedef ThreadChunkProcessor<ITEMS_PER_THREAD, (ITEMS_PER_THREAD % vectorBytes) == 0> Processor;

    // One private histogram per warp in shared memory.
    // This lowers hot-bin contention compared with a single block-private histogram
    // while still reducing global atomics to one add per block/bin in the final merge.
    __shared__ unsigned int s_hist[WARPS_PER_BLOCK][maxBins];

    const unsigned int tid    = threadIdx.x;
    const unsigned int warpId = tid / warpSizeConst;
    unsigned int* const warpHist = s_hist[warpId];

    // Only compacted bins [0, numBins) are live; the rest of each 256-entry row is unused.
    if (tid < numBins) {
        #pragma unroll
        for (int w = 0; w < WARPS_PER_BLOCK; ++w) {
            s_hist[w][tid] = 0u;
        }
    }
    __syncthreads();

    const size_t itemsPerThread64 = static_cast<size_t>(ITEMS_PER_THREAD);
    const size_t blockSpan        = static_cast<size_t>(BLOCK_SIZE) * itemsPerThread64;
    const size_t gridStride       = static_cast<size_t>(gridDim.x) * blockSpan;
    const size_t inputSize64      = static_cast<size_t>(inputSize);

    // Each thread owns a contiguous ITEMS_PER_THREAD-byte slice inside the block's chunk.
    size_t base =
        (static_cast<size_t>(blockIdx.x) * static_cast<size_t>(BLOCK_SIZE) +
         static_cast<size_t>(tid)) * itemsPerThread64;

    // Steady-state loop: the entire per-thread slice is in-bounds, so no per-byte bounds checks.
    for (; base + itemsPerThread64 <= inputSize64; base += gridStride) {
        Processor::process_full(input, base, from, numBins, warpHist);
    }

    // At most one partial slice can remain for this thread because the next candidate
    // slice would start a whole-grid stride later.
    if (base < inputSize64) {
        process_tail_chunk<ITEMS_PER_THREAD>(input, base, inputSize64, from, numBins, warpHist);
    }

    __syncthreads();

    // One thread per compacted output bin reduces the warp-private copies.
    if (tid < numBins) {
        unsigned int sum = 0u;
        #pragma unroll
        for (int w = 0; w < WARPS_PER_BLOCK; ++w) {
            sum += s_hist[w][tid];
        }
        if (sum != 0u) {
            atomicAdd(histogram + tid, sum);
        }
    }
}

}  // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // Per the prompt, `input` and `histogram` are device pointers allocated with cudaMalloc.
    // This function only enqueues work; synchronization is intentionally left to the caller.
    if (histogram == nullptr) {
        return;
    }

    const unsigned int fromU        = static_cast<unsigned int>(from);
    const unsigned int numBins      = static_cast<unsigned int>(to - from) + 1u;
    const size_t histogramBytes     = static_cast<size_t>(numBins) * sizeof(unsigned int);
    cudaStream_t stream             = 0;  // Required interface has no stream parameter.

    // Both operations go to the same stream, so the zero-fill completes before the
    // kernel starts without any host-side synchronization here.
    cudaMemsetAsync(histogram, 0, histogramBytes, stream);

    if (input == nullptr || inputSize == 0u) {
        return;
    }

    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    int activeBlocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM,
        histogram_range_kernel<blockSize, itemsPerThread>,
        blockSize,
        0);

    if (smCount <= 0 || activeBlocksPerSM <= 0) {
        return;
    }

    const size_t itemsPerBlock = static_cast<size_t>(blockSize) * static_cast<size_t>(itemsPerThread);
    const size_t totalChunks   = (static_cast<size_t>(inputSize) + itemsPerBlock - 1u) / itemsPerBlock;
    const size_t residentWaveBlocks =
        static_cast<size_t>(smCount) * static_cast<size_t>(activeBlocksPerSM);

    // Because the kernel is grid-stride, one occupancy-saturating resident wave of blocks
    // is enough to cover arbitrarily large inputs while keeping the final global merge cheap.
    const unsigned int gridBlocks = static_cast<unsigned int>(
        totalChunks < residentWaveBlocks ? totalChunks : residentWaveBlocks);

    if (gridBlocks == 0u) {
        return;
    }

    // Reinterpret as raw unsigned bytes so ordinals 128..255 are preserved correctly
    // regardless of whether plain `char` is signed or unsigned on the host toolchain.
    histogram_range_kernel<blockSize, itemsPerThread>
        <<<gridBlocks, blockSize, 0, stream>>>(
            reinterpret_cast<const unsigned char*>(input),
            histogram,
            inputSize,
            fromU,
            numBins);
}

#include <cuda_runtime.h>

// Range-restricted byte histogram for device-resident input.
//
// Design choices aimed at A100/H100-class GPUs:
// - Shared-memory privatization is done per warp, not just per block.
//   The histogram range is at most 256 bins, so one full 256-bin replica is only 1 KiB.
//   With 256 threads/block (= 8 warps), the entire shared working set is just 8 KiB/block,
//   which is small enough to keep occupancy high while sharply reducing shared-atomic contention.
// - itemsPerThread is the main tuning knob. 16 is a strong default on modern NVIDIA GPUs for
//   large inputs: it gives enough ILP to amortize index math and, in the fast path below,
//   maps naturally to one 16-byte vector load per thread.
// - blockSize is 256. That is a good default for histogram kernels on recent data-center GPUs,
//   and it also matches the maximum possible number of output bins so the final reduction can
//   assign one thread to each possible output bin.

namespace {

constexpr int itemsPerThread = 16;
constexpr int blockSize      = 256;
constexpr int warpSizeConst  = 32;
constexpr int maxBins        = 256;

constexpr unsigned int bytesPerBlockPerIteration =
    static_cast<unsigned int>(blockSize * itemsPerThread);

static_assert(blockSize % warpSizeConst == 0, "blockSize must be a multiple of 32.");
static_assert(blockSize >= maxBins, "blockSize must be at least 256.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");

// Single-bin update helper.
// The range check uses unsigned arithmetic so one comparison covers both bounds:
//   bin = value - from;
//   bin < numBins   <=>   from <= value <= from + numBins - 1
__device__ __forceinline__
void count_byte(const unsigned int byteValue,
                const unsigned int from,
                const unsigned int numBins,
                unsigned int* const warpHist)
{
    const unsigned int bin = byteValue - from;
    if (bin < numBins) {
        atomicAdd(&warpHist[bin], 1u);
    }
}

// Process four packed bytes held in one 32-bit word.
// NVIDIA GPUs are little-endian, so extracting 8-bit lanes this way preserves byte order.
__device__ __forceinline__
void count_packed32(const unsigned int packed,
                    const unsigned int from,
                    const unsigned int numBins,
                    unsigned int* const warpHist)
{
    count_byte((packed      ) & 0xFFu, from, numBins, warpHist);
    count_byte((packed >>  8) & 0xFFu, from, numBins, warpHist);
    count_byte((packed >> 16) & 0xFFu, from, numBins, warpHist);
    count_byte((packed >> 24) & 0xFFu, from, numBins, warpHist);
}

template <int ITEMS_PER_THREAD, int BLOCK_SIZE>
__global__ __launch_bounds__(BLOCK_SIZE)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from,
                            unsigned int numBins)
{
    static_assert(BLOCK_SIZE % 32 == 0, "BLOCK_SIZE must be a multiple of 32.");
    static_assert(BLOCK_SIZE >= maxBins, "BLOCK_SIZE must be at least 256.");
    static_assert(ITEMS_PER_THREAD > 0, "ITEMS_PER_THREAD must be positive.");

    constexpr int kWarpsPerBlock       = BLOCK_SIZE / 32;
    constexpr int kReplicaBins         = maxBins;
    constexpr bool kVectorizableItems  = ((ITEMS_PER_THREAD % 16) == 0);
    constexpr int kVecLoadsPerThread   = ITEMS_PER_THREAD / 16;

    // One fully private 256-bin histogram replica per warp.
    __shared__ unsigned int sharedHistograms[kWarpsPerBlock][kReplicaBins];

    // Zero the entire shared working set. This is only 8 KiB with the chosen defaults,
    // so clearing all replica bins is cheap and keeps address math simple.
    unsigned int* const sharedFlat = &sharedHistograms[0][0];
    #pragma unroll
    for (int i = threadIdx.x; i < kWarpsPerBlock * kReplicaBins; i += BLOCK_SIZE) {
        sharedFlat[i] = 0u;
    }
    __syncthreads();

    const unsigned int warpId = threadIdx.x >> 5;
    unsigned int* const warpHist = sharedHistograms[warpId];

    // Reinterpret as unsigned bytes so ordinal values 128..255 are handled correctly
    // regardless of the signedness of plain char.
    const unsigned char* const data = reinterpret_cast<const unsigned char*>(input);
    const size_t n = static_cast<size_t>(inputSize);

    // Fast path: if itemsPerThread is a multiple of 16 and the pointer is 16-byte aligned,
    // each thread fetches its chunk with 16-byte vector loads.
    //
    // cudaMalloc provides strong alignment, so the intended use hits this path. The explicit
    // alignment check keeps the code correct even if a sub-pointer is ever passed in.
    const bool useVectorFastPath =
        kVectorizableItems && ((reinterpret_cast<size_t>(data) & 0xFu) == 0u);

    if (useVectorFastPath) {
        const size_t gridStrideBytes =
            static_cast<size_t>(gridDim.x) * BLOCK_SIZE * ITEMS_PER_THREAD;

        for (size_t base =
                 (static_cast<size_t>(blockIdx.x) * BLOCK_SIZE + threadIdx.x) * ITEMS_PER_THREAD;
             base < n;
             base += gridStrideBytes)
        {
            if (base + ITEMS_PER_THREAD <= n) {
                const uint4* const vectorPtr =
                    reinterpret_cast<const uint4*>(data + base);

                #pragma unroll
                for (int vec = 0; vec < kVecLoadsPerThread; ++vec) {
                    const uint4 packed = vectorPtr[vec];
                    count_packed32(packed.x, from, numBins, warpHist);
                    count_packed32(packed.y, from, numBins, warpHist);
                    count_packed32(packed.z, from, numBins, warpHist);
                    count_packed32(packed.w, from, numBins, warpHist);
                }
            } else {
                // Only the final partial chunk reaches this path.
                #pragma unroll
                for (int i = 0; i < ITEMS_PER_THREAD; ++i) {
                    const size_t idx = base + static_cast<size_t>(i);
                    if (idx < n) {
                        count_byte(data[idx], from, numBins, warpHist);
                    }
                }
            }
        }
    } else {
        // Generic fallback when itemsPerThread is changed to a non-16-multiple or the input
        // pointer is not 16-byte aligned. The interleaved access pattern keeps scalar loads
        // coalesced across the warp.
        const size_t gridStride =
            static_cast<size_t>(gridDim.x) * BLOCK_SIZE * ITEMS_PER_THREAD;

        for (size_t base =
                 static_cast<size_t>(blockIdx.x) * BLOCK_SIZE * ITEMS_PER_THREAD + threadIdx.x;
             base < n;
             base += gridStride)
        {
            #pragma unroll
            for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
                const size_t idx = base + static_cast<size_t>(item) * BLOCK_SIZE;
                if (idx < n) {
                    count_byte(data[idx], from, numBins, warpHist);
                }
            }
        }
    }

    __syncthreads();

    // Because the maximum number of bins is 256 and BLOCK_SIZE is also 256, one thread can own
    // one final output bin during the block reduction.
    if (threadIdx.x < numBins) {
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < kWarpsPerBlock; ++w) {
            sum += sharedHistograms[w][threadIdx.x];
        }

        if (sum != 0u) {
            // Multiple blocks contribute to the same output bins, so the block flush uses
            // global atomics after the much larger amount of per-byte traffic has already
            // been absorbed in shared memory.
            atomicAdd(&histogram[threadIdx.x], sum);
        }
    }
}

} // anonymous namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // The prompt guarantees: 0 <= from < to <= 255.
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);

    // The requested output is a fresh histogram for this call, not an accumulation.
    // This memset is asynchronous with respect to the host; the caller owns synchronization.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(numBins) * sizeof(unsigned int));

    if (inputSize == 0u) {
        return;
    }

    // Launch one occupancy-saturating wave of blocks.
    // The kernel itself uses a grid-stride loop, so one full resident wave is enough to keep
    // all SMs busy on large inputs without oversharding the work into unnecessary block flushes.
    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    int activeBlocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM,
        histogram_range_kernel<itemsPerThread, blockSize>,
        blockSize,
        0);

    if (activeBlocksPerSM < 1) {
        activeBlocksPerSM = 1;
    }

    const unsigned int blocksNeeded =
        (inputSize + bytesPerBlockPerIteration - 1u) / bytesPerBlockPerIteration;

    unsigned int gridSize =
        static_cast<unsigned int>(smCount) * static_cast<unsigned int>(activeBlocksPerSM);

    if (gridSize > blocksNeeded) {
        gridSize = blocksNeeded;
    }
    if (gridSize == 0u) {
        gridSize = 1u;
    }

    histogram_range_kernel<itemsPerThread, blockSize>
        <<<gridSize, blockSize>>>(
            input,
            histogram,
            inputSize,
            static_cast<unsigned int>(from),
            numBins);

    // Intentionally no synchronization here; the caller requested enqueue-only behavior.
}

#include <cuda_runtime.h>
#include <cstddef>

/*
 * Range-restricted byte histogram for a device-resident text buffer.
 *
 * Key optimization choices:
 * - Shared-memory privatization: each warp owns its own private histogram in shared memory.
 *   This reduces contention versus a single block-private histogram, which matters for text
 *   where a few characters (space, newline, vowels, etc.) can be very hot.
 * - itemsPerThread = 16 by default: on A100/H100 this is a strong default for large inputs
 *   because it gives each thread one 16-byte aligned chunk per loop iteration, enabling
 *   vectorized uint4 loads, enough ILP to hide latency, and still low register pressure.
 * - Final merge: a block emits only one global atomic add per bin, instead of one global
 *   atomic per matching character.
 *
 * The input is interpreted as unsigned bytes, so the code is correct regardless of whether
 * the host compiler treats `char` as signed or unsigned.
 */
constexpr int threadsPerBlock = 256;
constexpr int itemsPerThread = 16;

static_assert(sizeof(unsigned int) == 4, "This implementation assumes 32-bit unsigned int.");
static_assert(threadsPerBlock % 32 == 0, "threadsPerBlock must be a multiple of 32.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");

namespace histogram_detail {

constexpr int histogramWarpSize = 32;
constexpr int targetBlocksPerSM = 8; // 256 threads/block * 8 blocks/SM = 2048 threads/SM on A100/H100.

__host__ __device__ constexpr unsigned int div_up_u32(unsigned int n, unsigned int d) {
    return n / d + static_cast<unsigned int>((n % d) != 0u);
}

__host__ __device__ constexpr unsigned int round_up_to_warp(unsigned int value) {
    return (value + static_cast<unsigned int>(histogramWarpSize - 1)) &
           ~static_cast<unsigned int>(histogramWarpSize - 1);
}

__device__ __forceinline__ void add_byte_to_private_hist(
    unsigned int byteValue,
    unsigned int from,
    unsigned int rangeSize,
    unsigned int* privateHist)
{
    // Unsigned subtraction folds the two range checks
    //    byteValue >= from  &&  byteValue < from + rangeSize
    // into a single comparison.
    const unsigned int bin = byteValue - from;
    if (bin < rangeSize) {
        atomicAdd(privateHist + bin, 1u);
    }
}

__device__ __forceinline__ void add_word_to_private_hist(
    unsigned int word,
    unsigned int from,
    unsigned int rangeSize,
    unsigned int* privateHist)
{
    #pragma unroll
    for (int i = 0; i < 4; ++i) {
        add_byte_to_private_hist(word & 0xFFu, from, rangeSize, privateHist);
        word >>= 8;
    }
}

// Compile-time load specialization:
// - multiples of 16 bytes use uint4 vector loads
// - other multiples of 4 bytes use 32-bit word loads
// - everything else falls back to scalar byte loads
template <int ITEMS_PER_THREAD, bool USE_VEC16 = (ITEMS_PER_THREAD % 16 == 0), bool USE_VEC4 = (ITEMS_PER_THREAD % 4 == 0)>
struct FullChunkProcessor;

template <int ITEMS_PER_THREAD>
struct FullChunkProcessor<ITEMS_PER_THREAD, true, true> {
    __device__ __forceinline__ static void run(
        const unsigned char* ptr,
        unsigned int from,
        unsigned int rangeSize,
        unsigned int* privateHist)
    {
        // The fast path assumes the device buffer comes directly from cudaMalloc, as specified,
        // so the base pointer is sufficiently aligned. With itemsPerThread being a multiple of 16,
        // each thread's chunk start is also 16-byte aligned.
        const uint4* const vecPtr = reinterpret_cast<const uint4*>(ptr);

        #pragma unroll
        for (int i = 0; i < ITEMS_PER_THREAD / 16; ++i) {
            const uint4 packed = vecPtr[i];
            add_word_to_private_hist(packed.x, from, rangeSize, privateHist);
            add_word_to_private_hist(packed.y, from, rangeSize, privateHist);
            add_word_to_private_hist(packed.z, from, rangeSize, privateHist);
            add_word_to_private_hist(packed.w, from, rangeSize, privateHist);
        }
    }
};

template <int ITEMS_PER_THREAD>
struct FullChunkProcessor<ITEMS_PER_THREAD, false, true> {
    __device__ __forceinline__ static void run(
        const unsigned char* ptr,
        unsigned int from,
        unsigned int rangeSize,
        unsigned int* privateHist)
    {
        const unsigned int* const wordPtr = reinterpret_cast<const unsigned int*>(ptr);

        #pragma unroll
        for (int i = 0; i < ITEMS_PER_THREAD / 4; ++i) {
            add_word_to_private_hist(wordPtr[i], from, rangeSize, privateHist);
        }
    }
};

template <int ITEMS_PER_THREAD>
struct FullChunkProcessor<ITEMS_PER_THREAD, false, false> {
    __device__ __forceinline__ static void run(
        const unsigned char* ptr,
        unsigned int from,
        unsigned int rangeSize,
        unsigned int* privateHist)
    {
        #pragma unroll
        for (int i = 0; i < ITEMS_PER_THREAD; ++i) {
            add_byte_to_private_hist(ptr[i], from, rangeSize, privateHist);
        }
    }
};

template <int THREADS_PER_BLOCK, int ITEMS_PER_THREAD>
__launch_bounds__(THREADS_PER_BLOCK)
__global__ void histogram_range_kernel(
    const char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    const unsigned int inputSize,
    const unsigned int from,
    const unsigned int rangeSize)
{
    static_assert(THREADS_PER_BLOCK % histogramWarpSize == 0, "THREADS_PER_BLOCK must be a multiple of 32.");
    static_assert(ITEMS_PER_THREAD > 0, "ITEMS_PER_THREAD must be positive.");

    extern __shared__ unsigned int shared[];

    constexpr int warpsPerBlock = THREADS_PER_BLOCK / histogramWarpSize;
    const unsigned int paddedRange = round_up_to_warp(rangeSize);

    // Layout in shared memory:
    //   [warp0 histogram | warp1 histogram | ...]
    // Each warp gets its own privatized histogram, padded to a multiple of 32 bins so every
    // sub-histogram starts on a warp-sized boundary.
    const unsigned int warpId = threadIdx.x / histogramWarpSize;
    unsigned int* const privateHist = shared + warpId * paddedRange;
    const unsigned int totalPrivateBins = static_cast<unsigned int>(warpsPerBlock) * paddedRange;

    // Zero the entire shared-memory histogram slab.
    for (unsigned int i = threadIdx.x; i < totalPrivateBins; i += static_cast<unsigned int>(THREADS_PER_BLOCK)) {
        shared[i] = 0u;
    }
    __syncthreads();

    const unsigned char* const inputBytes = reinterpret_cast<const unsigned char*>(input);

    // Use 64-bit only for outer address arithmetic so the kernel remains safe for near-4 GiB
    // buffers, while the hot histogram/bin arithmetic stays 32-bit.
    const size_t globalThread =
        static_cast<size_t>(blockIdx.x) * static_cast<size_t>(THREADS_PER_BLOCK) +
        static_cast<size_t>(threadIdx.x);
    const size_t totalThreads = static_cast<size_t>(gridDim.x) * static_cast<size_t>(THREADS_PER_BLOCK);
    const size_t gridStrideBytes = totalThreads * static_cast<size_t>(ITEMS_PER_THREAD);
    const size_t inputSizeBytes = static_cast<size_t>(inputSize);

    size_t idx = globalThread * static_cast<size_t>(ITEMS_PER_THREAD);

    while (idx < inputSizeBytes) {
        const unsigned int idx32 = static_cast<unsigned int>(idx);
        const unsigned int remaining = inputSize - idx32;

        if (remaining >= static_cast<unsigned int>(ITEMS_PER_THREAD)) {
            FullChunkProcessor<ITEMS_PER_THREAD>::run(inputBytes + idx, from, rangeSize, privateHist);
        } else {
            // Only the very last chunk for some threads takes this path.
            #pragma unroll
            for (int j = 0; j < ITEMS_PER_THREAD; ++j) {
                if (static_cast<unsigned int>(j) < remaining) {
                    add_byte_to_private_hist(inputBytes[idx + static_cast<size_t>(j)], from, rangeSize, privateHist);
                }
            }
        }

        idx += gridStrideBytes;
    }

    __syncthreads();

    // Merge the warp-private histograms. The global histogram is compact:
    // histogram[bin] corresponds to byte value (from + bin).
    for (unsigned int bin = threadIdx.x; bin < rangeSize; bin += static_cast<unsigned int>(THREADS_PER_BLOCK)) {
        unsigned int sum = 0u;

        #pragma unroll
        for (int w = 0; w < warpsPerBlock; ++w) {
            sum += shared[static_cast<unsigned int>(w) * paddedRange + bin];
        }

        if (sum != 0u) {
            atomicAdd(histogram + bin, sum);
        }
    }
}

} // namespace histogram_detail

void run_histogram(const char* input, unsigned int* histogram, unsigned int inputSize, int from, int to)
{
    // The interface has no stream parameter, so work is enqueued onto the default stream.
    // The caller is responsible for any synchronization.
    const cudaStream_t stream = nullptr;

    // Inclusive range [from, to].
    const unsigned int fromU = static_cast<unsigned int>(from);
    const unsigned int rangeSize = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes = static_cast<size_t>(rangeSize) * sizeof(unsigned int);

    // Compute a fresh histogram, not an accumulation of previous contents.
    cudaMemsetAsync(histogram, 0, histogramBytes, stream);

    if (inputSize == 0u) {
        return;
    }

    int device = 0;
    int smCount = 1;
    cudaGetDevice(&device);
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1) {
        smCount = 1;
    }

    // With the default 256-thread block size, 8 blocks/SM is the natural saturation target
    // for A100/H100 (2048 resident threads/SM). Grid-stride looping covers the rest of the input.
    const unsigned int workPerBlock =
        static_cast<unsigned int>(threadsPerBlock) * static_cast<unsigned int>(itemsPerThread);
    const unsigned int blocksForInput = histogram_detail::div_up_u32(inputSize, workPerBlock);
    const unsigned int saturationBlocks =
        static_cast<unsigned int>(smCount) * static_cast<unsigned int>(histogram_detail::targetBlocksPerSM);
    const unsigned int gridBlocks = (blocksForInput < saturationBlocks) ? blocksForInput : saturationBlocks;

    // One padded shared histogram per warp.
    const unsigned int paddedRange = histogram_detail::round_up_to_warp(rangeSize);
    const size_t sharedBytes =
        static_cast<size_t>(threadsPerBlock / histogram_detail::histogramWarpSize) *
        static_cast<size_t>(paddedRange) *
        sizeof(unsigned int);

    histogram_detail::histogram_range_kernel<threadsPerBlock, itemsPerThread>
        <<<gridBlocks, threadsPerBlock, sharedBytes, stream>>>(
            input,
            histogram,
            inputSize,
            fromU,
            rangeSize);
}

#include <cuda_runtime.h>

/*
 * Range-restricted byte histogram for a device-resident text buffer.
 *
 * Optimization strategy:
 * 1) Shared-memory privatization:
 *    Each thread block accumulates into a block-private histogram in shared memory.
 *    That collapses expensive per-byte global atomics down to one global atomic add
 *    per (block, bin) during the final merge.
 *
 * 2) Bank-conflict-free shared histogram copies:
 *    The shared histogram is replicated 32 times (one replica per warp lane) and laid
 *    out as [bin][replica]. Each thread updates replica = lane_id, so the bank index is:
 *
 *        bank = (bin * 32 + lane_id) % 32 = lane_id
 *
 *    Therefore the update path is bank-conflict-free within a warp for arbitrary bin
 *    values. The replication also reduces atomic contention on hot bins by up to 32x
 *    versus a single shared histogram.
 *
 * 3) Vectorized input traversal:
 *    The input is read as uchar4 values so each thread processes 4 bytes per load.
 *    itemsPerThread defaults to 16 bytes/thread, which is a good Ampere/Hopper default:
 *    enough ILP to amortize loop/range-check overhead without inflating register pressure.
 *
 * 4) Occupancy-limited launch:
 *    run_histogram launches only enough blocks to fill the GPU. Because each block keeps
 *    its private histogram across the entire grid-stride traversal and merges only once,
 *    overlaunching would mainly increase the final global atomic traffic.
 */

namespace {

constexpr int kWarpSize = 32;
constexpr int kBlockSize = 256;
constexpr int kCharsPerVector = 4;

// Tuning knob requested by the problem statement.
// Keep this a multiple of 4 so the vectorized uchar4 load path remains valid.
constexpr int itemsPerThread = 16;

constexpr unsigned int kWarpsPerBlock =
    static_cast<unsigned int>(kBlockSize / kWarpSize);
constexpr unsigned int kHistogramCopies =
    static_cast<unsigned int>(kWarpSize);
constexpr unsigned int kVectorsPerThread =
    static_cast<unsigned int>(itemsPerThread / kCharsPerVector);
constexpr unsigned int kBlockWork =
    static_cast<unsigned int>(kBlockSize * itemsPerThread);
constexpr unsigned int kVectorStrideBytes =
    static_cast<unsigned int>(kBlockSize * kCharsPerVector);
constexpr unsigned int kLaneMask = kHistogramCopies - 1u;
constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;

static_assert(kBlockSize % kWarpSize == 0, "kBlockSize must be a multiple of 32.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert(itemsPerThread % kCharsPerVector == 0,
              "itemsPerThread must be a multiple of 4 for vectorized uchar4 loads.");
static_assert(256u * kHistogramCopies * sizeof(unsigned int) <= 48u * 1024u,
              "The worst-case shared histogram must fit in the default dynamic shared-memory limit.");

__device__ __forceinline__ unsigned int warp_reduce_sum(unsigned int value) {
    #pragma unroll
    for (int offset = kWarpSize / 2; offset > 0; offset >>= 1) {
        value += __shfl_down_sync(kFullWarpMask, value, offset);
    }
    return value;
}

__device__ __forceinline__ void add_byte_to_private_histogram(
    unsigned char c,
    unsigned int from,
    unsigned int binCount,
    unsigned int* __restrict__ sharedHistogram,
    unsigned int replica)
{
    // Unsigned subtraction implements the two-sided range check in one comparison:
    //   c < from         -> underflow -> very large value -> rejected
    //   c > to           -> bin >= binCount             -> rejected
    //   from <= c <= to  -> 0 <= bin < binCount        -> accepted
    const unsigned int bin = static_cast<unsigned int>(c) - from;
    if (bin < binCount) {
        atomicAdd(&sharedHistogram[bin * kHistogramCopies + replica], 1u);
    }
}

__device__ __forceinline__ void add_vec4_to_private_histogram(
    uchar4 v,
    unsigned int from,
    unsigned int binCount,
    unsigned int* __restrict__ sharedHistogram,
    unsigned int replica)
{
    add_byte_to_private_histogram(v.x, from, binCount, sharedHistogram, replica);
    add_byte_to_private_histogram(v.y, from, binCount, sharedHistogram, replica);
    add_byte_to_private_histogram(v.z, from, binCount, sharedHistogram, replica);
    add_byte_to_private_histogram(v.w, from, binCount, sharedHistogram, replica);
}

__global__ __launch_bounds__(kBlockSize)
void histogram_range_kernel(
    const unsigned char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    unsigned int from,
    unsigned int binCount)
{
    extern __shared__ unsigned int sharedHistogram[];

    const unsigned int tid = threadIdx.x;
    const unsigned int lane = tid & kLaneMask;
    const unsigned int warp = tid >> 5;

    const size_t inputSize64 = static_cast<size_t>(inputSize);
    const size_t blockWork = static_cast<size_t>(kBlockWork);
    const size_t gridWork = static_cast<size_t>(gridDim.x) * blockWork;
    const size_t vectorStrideBytes = static_cast<size_t>(kVectorStrideBytes);

    // Zero the block-private histogram copies.
    const unsigned int sharedCounters = binCount * kHistogramCopies;
    for (unsigned int i = tid; i < sharedCounters; i += static_cast<unsigned int>(kBlockSize)) {
        sharedHistogram[i] = 0u;
    }
    __syncthreads();

    // Grid-stride traversal. Each block retains its private histogram across all assigned
    // tiles and merges to global memory only once at the end.
    for (size_t blockBase = static_cast<size_t>(blockIdx.x) * blockWork;
         blockBase < inputSize64;
         blockBase += gridWork)
    {
        const size_t tileRemaining = inputSize64 - blockBase;

        if (tileRemaining >= blockWork) {
            // Fast path: a full tile. The pointer is 4-byte aligned because:
            // - cudaMalloc returns aligned storage,
            // - the API is assumed to pass the base allocation pointer,
            // - blockBase is a multiple of 4,
            // - each thread accesses tid * 4.
            const uchar4* tile4 = reinterpret_cast<const uchar4*>(input + blockBase);

            #pragma unroll
            for (unsigned int vec = 0; vec < kVectorsPerThread; ++vec) {
                const uchar4 v = tile4[vec * static_cast<unsigned int>(kBlockSize) + tid];
                add_vec4_to_private_histogram(v, from, binCount, sharedHistogram, lane);
            }
        } else {
            // Tail tile: keep the same blocked access pattern, but guard loads near the end.
            #pragma unroll
            for (unsigned int vec = 0; vec < kVectorsPerThread; ++vec) {
                const size_t idx =
                    blockBase +
                    static_cast<size_t>(vec) * vectorStrideBytes +
                    static_cast<size_t>(tid) * kCharsPerVector;

                if (idx < inputSize64) {
                    const size_t remaining = inputSize64 - idx;

                    if (remaining >= kCharsPerVector) {
                        const uchar4 v = *reinterpret_cast<const uchar4*>(input + idx);
                        add_vec4_to_private_histogram(v, from, binCount, sharedHistogram, lane);
                    } else {
                        add_byte_to_private_histogram(input[idx], from, binCount, sharedHistogram, lane);
                        if (remaining > 1) {
                            add_byte_to_private_histogram(input[idx + 1], from, binCount, sharedHistogram, lane);
                        }
                        if (remaining > 2) {
                            add_byte_to_private_histogram(input[idx + 2], from, binCount, sharedHistogram, lane);
                        }
                    }
                }
            }
        }
    }

    __syncthreads();

    // Reduce the 32 replicas for each bin. One warp handles one bin at a time:
    // lane r reads replica r, then the warp sum is reduced with shuffles.
    for (unsigned int bin = warp; bin < binCount; bin += kWarpsPerBlock) {
        unsigned int sum = sharedHistogram[bin * kHistogramCopies + lane];
        sum = warp_reduce_sum(sum);

        if (lane == 0 && sum != 0u) {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

} // namespace

void run_histogram(const char *input, unsigned int *histogram, unsigned int inputSize, int from, int to)
{
    // The API contract says input and histogram are device pointers from cudaMalloc.
    // This function only enqueues work on the default stream; the caller performs any
    // synchronization it wants after the launch.
    cudaStream_t stream = nullptr;

    const unsigned int binCount = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes = static_cast<size_t>(binCount) * sizeof(unsigned int);
    const size_t sharedMemBytes =
        static_cast<size_t>(binCount) * kHistogramCopies * sizeof(unsigned int);
    const size_t blockWork = static_cast<size_t>(kBlockWork);

    // Compute a fresh histogram, not an accumulation.
    cudaMemsetAsync(histogram, 0, histogramBytes, stream);

    if (inputSize == 0u) {
        return;
    }

    // Bias the unified L1/shared-memory partition toward shared memory; this kernel is
    // dominated by shared-memory atomics and uses very little reusable L1 data.
    // This is a performance hint, not a correctness requirement.
    cudaFuncSetAttribute(
        histogram_range_kernel,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1) {
        smCount = 1;
    }

    int activeBlocksPerSm = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSm,
        histogram_range_kernel,
        kBlockSize,
        sharedMemBytes);
    if (activeBlocksPerSm < 1) {
        activeBlocksPerSm = 1;
    }

    // Because each block merges its private histogram only once, launch just enough blocks
    // to fill the GPU rather than creating unnecessary extra blocks that would only increase
    // the final global atomic traffic.
    const unsigned int maxResidentBlocks =
        static_cast<unsigned int>(smCount) * static_cast<unsigned int>(activeBlocksPerSm);
    const unsigned int blocksNeeded = static_cast<unsigned int>(
        (static_cast<size_t>(inputSize) + blockWork - 1u) / blockWork);
    const unsigned int gridSize =
        (blocksNeeded < maxResidentBlocks) ? blocksNeeded : maxResidentBlocks;

    histogram_range_kernel<<<static_cast<int>(gridSize), kBlockSize, sharedMemBytes, stream>>>(
        reinterpret_cast<const unsigned char*>(input),
        histogram,
        inputSize,
        static_cast<unsigned int>(from),
        binCount);

    // No synchronization here by design; the caller requested to own synchronization.
}

#include <cuda_runtime.h>
#include <cstdint>

namespace {

// Range-restricted histogram for device-resident text.
//
// Design notes:
//   * The input is processed by a persistent grid with a grid-stride loop so that
//     each block handles a large slice of a large file. That strongly amortizes
//     per-block shared-memory initialization and flush costs.
//   * Each block accumulates into a block-private histogram in shared memory.
//   * To avoid shared-memory bank conflicts, the shared histogram is replicated
//     32 times per block, matching the 32 shared-memory banks on modern NVIDIA
//     GPUs. The stride of each replica is forced to be odd so that
//       bank(copy * stride + bin)
//     becomes a permutation of the 32 banks as `copy` varies.
//   * After the input slice is processed, the 32 replicas are reduced and each
//     block performs only one global atomic add per output bin.
//
// The kernel is intentionally specialized for a fixed 256-thread block size.
// That matches the maximum 256 histogram bins and lets the flush phase map one
// thread to one bin in the worst case.

constexpr int blockSize = 256;

// One aligned 128-bit load per thread is a strong default on A100/H100 for a
// byte-stream histogram. It keeps the load side fully coalesced, keeps register
// pressure modest, and is large enough to amortize loop/control overhead.
constexpr int itemsPerThread = 16;

// 32 replicas = 32 shared-memory banks on Ampere/Hopper.
constexpr int histogramCopies = 32;

static_assert(blockSize == 256,
              "This implementation is tuned for exactly 256 threads per block.");
static_assert(itemsPerThread > 0 && (itemsPerThread % 16 == 0),
              "itemsPerThread must be a positive multiple of 16 for aligned uint4 loads.");

__host__ __device__ constexpr unsigned int padded_hist_stride(unsigned int rangeSize) {
    // Forcing the per-replica stride to be odd guarantees gcd(stride, 32) == 1,
    // so the same logical bin in different replicas maps to different banks.
    return rangeSize | 1u;
}

__device__ __forceinline__ void accumulate_char(unsigned int value,
                                                unsigned int from,
                                                unsigned int rangeSize,
                                                unsigned int* localHist) {
    // Unsigned subtraction plus a single bounds check covers both
    //   value < from
    // and
    //   value > to
    // without two comparisons.
    const unsigned int bin = value - from;
    if (bin < rangeSize) {
        atomicAdd(localHist + bin, 1u);
    }
}

__device__ __forceinline__ void accumulate_packed4(uint32_t packed,
                                                   unsigned int from,
                                                   unsigned int rangeSize,
                                                   unsigned int* localHist) {
    accumulate_char((packed      ) & 0xFFu, from, rangeSize, localHist);
    accumulate_char((packed >>  8) & 0xFFu, from, rangeSize, localHist);
    accumulate_char((packed >> 16) & 0xFFu, from, rangeSize, localHist);
    accumulate_char((packed >> 24) & 0xFFu, from, rangeSize, localHist);
}

__global__ __launch_bounds__(blockSize)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from,
                            unsigned int rangeSize) {
    extern __shared__ unsigned int sharedHist[];

    const unsigned int stride = padded_hist_stride(rangeSize);
    const unsigned int tid    = threadIdx.x;
    const unsigned int lane   = tid & 31u;
    const unsigned int warp   = tid >> 5;

    // Every lane in a warp uses a different replica, and the warp-dependent
    // rotation prevents identical lane IDs from all warps from always hitting
    // the same replica.
    const unsigned int copy = (lane + warp) & (histogramCopies - 1u);
    unsigned int* const localHist = sharedHist + copy * stride;

    const unsigned int totalSharedBins =
        static_cast<unsigned int>(histogramCopies) * stride;

    for (unsigned int i = tid; i < totalSharedBins; i += blockSize) {
        sharedHist[i] = 0u;
    }
    __syncthreads();

    const uint64_t n = static_cast<uint64_t>(inputSize);
    uint64_t idx =
        (static_cast<uint64_t>(blockIdx.x) * blockSize + tid) * itemsPerThread;
    const uint64_t gridStride =
        static_cast<uint64_t>(gridDim.x) * blockSize * itemsPerThread;

    if (n >= static_cast<uint64_t>(itemsPerThread)) {
        const uint64_t fullLimit = n - static_cast<uint64_t>(itemsPerThread);

        // The API contract says `input` is a cudaMalloc allocation. cudaMalloc
        // provides sufficient alignment for 16-byte vector loads, and the per-
        // thread starting offset is also a multiple of 16 because itemsPerThread
        // is constrained to a multiple of 16.
        const uint4* const input4 = reinterpret_cast<const uint4*>(input);

        for (; idx <= fullLimit; idx += gridStride) {
#pragma unroll
            for (int chunk = 0; chunk < itemsPerThread; chunk += 16) {
                const uint4 v = input4[(idx + static_cast<uint64_t>(chunk)) >> 4];
                accumulate_packed4(v.x, from, rangeSize, localHist);
                accumulate_packed4(v.y, from, rangeSize, localHist);
                accumulate_packed4(v.z, from, rangeSize, localHist);
                accumulate_packed4(v.w, from, rangeSize, localHist);
            }
        }
    }

    // After the full-chunk loop, each thread can have at most one partial tail.
    if (idx < n) {
        uint64_t end = idx + static_cast<uint64_t>(itemsPerThread);
        if (end > n) {
            end = n;
        }

        for (uint64_t i = idx; i < end; ++i) {
            // Cast through unsigned char so the histogram is always based on the
            // byte ordinal 0..255 regardless of host/compiler `char` signedness.
            accumulate_char(static_cast<unsigned char>(input[i]),
                            from,
                            rangeSize,
                            localHist);
        }
    }
    __syncthreads();

    // blockSize == 256 and rangeSize <= 256, so one thread can flush one bin.
    if (tid < rangeSize) {
        unsigned int sum = 0u;
        unsigned int offset = tid;

#pragma unroll
        for (int c = 0; c < histogramCopies; ++c) {
            sum += sharedHist[offset];
            offset += stride;
        }

        if (sum != 0u) {
            atomicAdd(histogram + tid, sum);
        }
    }
}

}  // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    // Per the API contract, `input` and `histogram` are device pointers returned
    // by cudaMalloc, and `from`/`to` form a valid inclusive byte range.
    const unsigned int fromU     = static_cast<unsigned int>(from);
    const unsigned int rangeSize = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes  = static_cast<size_t>(rangeSize) * sizeof(unsigned int);

    // The kernel accumulates into the final output with atomicAdd, so start from
    // a clean output buffer. Stream 0 is used because the requested API does not
    // carry a stream parameter. The caller owns synchronization/completion.
    cudaMemsetAsync(histogram, 0, histogramBytes, 0);

    if (inputSize == 0u) {
        return;
    }

    const size_t sharedMemBytes =
        static_cast<size_t>(histogramCopies) *
        static_cast<size_t>(padded_hist_stride(rangeSize)) *
        sizeof(unsigned int);

    // Persistent-grid launch:
    // launch roughly one occupancy-limited wave of blocks and let every block
    // walk the file with a grid-stride loop. For large inputs this is better
    // than launching one tiny block per ~4 KiB chunk because it minimizes the
    // shared-memory init/flush overhead per byte processed.
    int device = 0;
    cudaGetDevice(&device);

    int smCount = 1;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1) {
        smCount = 1;
    }

    int activeBlocksPerSM = 1;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM,
        histogram_range_kernel,
        blockSize,
        sharedMemBytes);
    if (activeBlocksPerSM < 1) {
        activeBlocksPerSM = 1;
    }

    const uint64_t workPerBlock =
        static_cast<uint64_t>(blockSize) * static_cast<uint64_t>(itemsPerThread);

    uint64_t requiredBlocks =
        (static_cast<uint64_t>(inputSize) + workPerBlock - 1u) / workPerBlock;
    if (requiredBlocks == 0u) {
        requiredBlocks = 1u;
    }

    uint64_t gridSize64 =
        static_cast<uint64_t>(smCount) * static_cast<uint64_t>(activeBlocksPerSM);
    if (gridSize64 > requiredBlocks) {
        gridSize64 = requiredBlocks;
    }
    if (gridSize64 == 0u) {
        gridSize64 = 1u;
    }

    histogram_range_kernel<<<static_cast<int>(gridSize64), blockSize, sharedMemBytes>>>(
        input,
        histogram,
        inputSize,
        fromU,
        rangeSize);
}

#include <cuda_runtime.h>
#include <cstddef>

namespace histogram_detail {

// User-requested tuning knob.
// 16 is a strong default on A100/H100-class GPUs for large inputs: it amortizes
// per-block shared-histogram setup/reduction while keeping register pressure modest.
constexpr int itemsPerThread = 16;

// 256 threads is intentional:
// - it is a common throughput sweet spot on modern NVIDIA GPUs,
// - it gives 8 warps/block,
// - and it matches the maximum possible histogram size (256 bins), so the final
//   block-local reduction can assign one thread to one output bin.
constexpr int kBlockSize = 256;
constexpr int kWarpSize  = 32;
constexpr int kMaxBins   = 256;

// Two launch variants are used:
// - <= 128 bins: 4 copies/warp remain thread-limited (full occupancy on A100/H100)
//   and further reduce residual shared-memory bank pressure.
// - > 128 bins: 2 copies/warp keep the worst-case 256-bin histogram at maximum occupancy.
constexpr int          kCopiesPerWarpWide   = 2;
constexpr int          kCopiesPerWarpNarrow = 4;
constexpr unsigned int kFourCopyCutoffBins  = 128u;

static_assert(kBlockSize % kWarpSize == 0, "kBlockSize must be a whole number of warps.");
static_assert(kBlockSize >= kMaxBins, "kBlockSize must cover the full 256-bin maximum.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");

static_assert(kCopiesPerWarpWide > 0 && kCopiesPerWarpWide <= kWarpSize, "Invalid wide-range copy count.");
static_assert((kCopiesPerWarpWide & (kCopiesPerWarpWide - 1)) == 0, "Wide-range copy count must be a power of two.");

static_assert(kCopiesPerWarpNarrow > 0 && kCopiesPerWarpNarrow <= kWarpSize, "Invalid narrow-range copy count.");
static_assert((kCopiesPerWarpNarrow & (kCopiesPerWarpNarrow - 1)) == 0, "Narrow-range copy count must be a power of two.");

// Shared-memory layout is copy-major:
//   [copy0 bins...padding][copy1 bins...padding]...
//
// The stride is rounded up to a multiple of the 32 shared-memory banks and then skewed by +1.
// This makes adjacent copies start on successive banks, so the same logical bin in different
// copies does not alias onto the same bank.
__host__ __device__ constexpr unsigned int padded_bins(const unsigned int numBins) {
    return ((numBins + (kWarpSize - 1u)) & ~(kWarpSize - 1u)) + 1u;
}

template <int BLOCK_SIZE, int COPIES_PER_WARP>
__host__ __device__ constexpr std::size_t shared_bytes_for_bins(const unsigned int numBins) {
    constexpr int kWarpsPerBlock = BLOCK_SIZE / kWarpSize;
    return static_cast<std::size_t>(kWarpsPerBlock * COPIES_PER_WARP) *
           static_cast<std::size_t>(padded_bins(numBins)) *
           sizeof(unsigned int);
}

// One byte update with warp-aggregated shared-memory atomics.
//
// The key encodes the exact target counter inside the warp as (bin, copyId).
// __match_any_sync() groups lanes that would hit the same shared counter, and only the
// leader lane performs the atomicAdd with the population count. For skewed text data
// (spaces, vowels, newlines, punctuation), this removes a large fraction of exact-address
// atomic collisions at very low overhead on Volta+ / Ampere / Hopper.
template <int COPIES_PER_WARP>
__device__ __forceinline__ void accumulate_byte_warp_aggregated(
    const unsigned char value,
    unsigned int* const localHist,
    const unsigned int from,
    const unsigned int numBins,
    const int copyId,
    const int laneId)
{
    const unsigned int bin = static_cast<unsigned int>(value) - from;
    if (bin < numBins) {
        const unsigned int key =
            bin * static_cast<unsigned int>(COPIES_PER_WARP) + static_cast<unsigned int>(copyId);

        const unsigned int peers      = __match_any_sync(__activemask(), key);
        const int          leaderLane = __ffs(peers) - 1;

        if (laneId == leaderLane) {
            atomicAdd(localHist + bin, static_cast<unsigned int>(__popc(peers)));
        }
    }
}

// Kernel overview:
// 1. Each block allocates several private histograms in shared memory:
//      warpsPerBlock * copiesPerWarp
//    This privatizes updates and spreads them across bank-skewed copies.
// 2. Threads walk the input in a grid-stride loop. In each iteration, a thread processes
//    itemsPerThread bytes spaced by blockDim.x, so every warp load is naturally coalesced.
// 3. At the end, the block reduces all of its shared sub-histograms and accumulates the
//    result into the final global histogram.
//
// Input bytes are read as unsigned char, not plain char, so values >= 128 are handled
// correctly regardless of the host compiler's signed-char default.
template <int BLOCK_SIZE, int ITEMS_PER_THREAD, int COPIES_PER_WARP>
__launch_bounds__(BLOCK_SIZE)
__global__ void histogram_range_kernel(
    const unsigned char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    const unsigned int inputSize,
    const unsigned int from,
    const unsigned int numBins)
{
    constexpr int         kWarpsPerBlock = BLOCK_SIZE / kWarpSize;
    constexpr int         kTotalCopies   = kWarpsPerBlock * COPIES_PER_WARP;
    constexpr std::size_t kTileSize      = static_cast<std::size_t>(BLOCK_SIZE) * ITEMS_PER_THREAD;

    extern __shared__ unsigned int sHist[];

    const int tid    = threadIdx.x;
    const int laneId = tid & (kWarpSize - 1);
    const int warpId = tid / kWarpSize;

    // Low-bit lane-to-copy mapping interleaves neighboring lanes across copies and is why
    // COPIES_PER_WARP is kept a power of two.
    const int copyId = laneId & (COPIES_PER_WARP - 1);

    const unsigned int paddedBins         = padded_bins(numBins);
    const unsigned int totalSharedCounters = static_cast<unsigned int>(kTotalCopies) * paddedBins;

    // Zero the shared sub-histograms.
    for (unsigned int i = static_cast<unsigned int>(tid); i < totalSharedCounters; i += BLOCK_SIZE) {
        sHist[i] = 0u;
    }
    __syncthreads();

    const unsigned int localHistOffset =
        static_cast<unsigned int>(warpId * COPIES_PER_WARP + copyId) * paddedBins;
    unsigned int* const localHist = sHist + localHistOffset;

    const std::size_t inputSize64 = static_cast<std::size_t>(inputSize);

    // 64-bit grid-stride index math avoids wrap-around for inputs close to the 4 GiB
    // limit implied by the unsigned-int inputSize parameter.
    const std::size_t gridStride = static_cast<std::size_t>(gridDim.x) * kTileSize;

    for (std::size_t index =
             static_cast<std::size_t>(blockIdx.x) * kTileSize + static_cast<std::size_t>(tid);
         index < inputSize64;
         index += gridStride)
    {
        #pragma unroll
        for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
            const std::size_t idx = index + static_cast<std::size_t>(item) * BLOCK_SIZE;

            if (idx < inputSize64) {
                accumulate_byte_warp_aggregated<COPIES_PER_WARP>(
                    input[idx], localHist, from, numBins, copyId, laneId);
            }
        }
    }

    __syncthreads();

    // Final block-local reduction: because BLOCK_SIZE >= 256, one thread can own one bin.
    if (static_cast<unsigned int>(tid) < numBins) {
        unsigned int sum = 0u;

        #pragma unroll
        for (int copy = 0; copy < kTotalCopies; ++copy) {
            sum += sHist[static_cast<unsigned int>(copy) * paddedBins + static_cast<unsigned int>(tid)];
        }

        // Tiny-input fast path: when only one block is launched, a plain store is sufficient.
        if (gridDim.x == 1) {
            histogram[tid] = sum;
        } else if (sum != 0u) {
            atomicAdd(histogram + tid, sum);
        }
    }
}

// Host-side launcher for one kernel variant.
// Only one resident wave of blocks is launched: the kernel itself grid-strides over the input,
// so extra waves would just repeat shared-histogram init/reduction more times.
template <int COPIES_PER_WARP>
inline void launch_histogram_variant(
    const char* input,
    unsigned int* histogram,
    const unsigned int inputSize,
    const unsigned int from,
    const unsigned int numBins)
{
    const std::size_t sharedBytes = shared_bytes_for_bins<kBlockSize, COPIES_PER_WARP>(numBins);

    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    int blocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &blocksPerSM,
        histogram_range_kernel<kBlockSize, itemsPerThread, COPIES_PER_WARP>,
        kBlockSize,
        sharedBytes);

    if (blocksPerSM < 1) {
        blocksPerSM = 1;
    }

    constexpr std::size_t kTileSize =
        static_cast<std::size_t>(kBlockSize) * static_cast<std::size_t>(itemsPerThread);

    const unsigned int neededBlocks = static_cast<unsigned int>(
        (static_cast<std::size_t>(inputSize) + kTileSize - 1u) / kTileSize);

    unsigned int launchBlocks = static_cast<unsigned int>(smCount * blocksPerSM);
    if (launchBlocks > neededBlocks) {
        launchBlocks = neededBlocks;
    }
    if (launchBlocks == 0u) {
        launchBlocks = 1u;
    }

    const dim3 grid(launchBlocks);
    const dim3 block(kBlockSize);

    histogram_range_kernel<kBlockSize, itemsPerThread, COPIES_PER_WARP>
        <<<grid, block, sharedBytes>>>(
            reinterpret_cast<const unsigned char*>(input),
            histogram,
            inputSize,
            from,
            numBins);
}

} // namespace histogram_detail

void run_histogram(
    const char* input,
    unsigned int* histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    const unsigned int fromU   = static_cast<unsigned int>(from);
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);

    // The output histogram must start from zero because the kernel only accumulates
    // block-local totals. This memset is asynchronous, matching the requirement that
    // synchronization is owned by the caller.
    cudaMemsetAsync(
        histogram,
        0,
        static_cast<std::size_t>(numBins) * sizeof(unsigned int));

    if (inputSize == 0u) {
        return;
    }

    // Range-dependent copy count:
    // - <= 128 bins: 4 copies/warp are effectively "free" on A100/H100 (still full occupancy).
    // -  > 128 bins: 2 copies/warp keep the full 256-bin case occupancy-maximal.
    if (numBins <= histogram_detail::kFourCopyCutoffBins) {
        histogram_detail::launch_histogram_variant<histogram_detail::kCopiesPerWarpNarrow>(
            input, histogram, inputSize, fromU, numBins);
    } else {
        histogram_detail::launch_histogram_variant<histogram_detail::kCopiesPerWarpWide>(
            input, histogram, inputSize, fromU, numBins);
    }

    // No host-side synchronization here by design; caller handles ordering / sync / error checks.
}

#include <cuda_runtime.h>
#include <cstddef>

/*
 * Range-restricted byte histogram optimized for large inputs on modern data-center GPUs
 * (e.g. A100/H100).
 *
 * Design choices:
 *   - blockThreads == 256:
 *       * exactly one thread per possible output bin (the range length is at most 256),
 *       * 8 warps/block is a good latency-hiding point for shared-memory atomics.
 *   - itemsPerThread == 16:
 *       * one aligned 128-bit uint4 load per thread on the fast path,
 *       * enough work per thread to amortize index arithmetic without driving register pressure up.
 *   - Shared-memory privatization:
 *       * each block accumulates into block-private histograms in shared memory,
 *       * only the final per-bin merge touches global memory.
 *   - Multiple shared-memory replicas per warp:
 *       * neighboring lanes are striped across several copies of the histogram,
 *         which reduces shared-memory atomic contention.
 *   - Odd replica stride:
 *       * successive replicas are separated by an odd number of 32-bit words,
 *         so the same logical bin in different replicas rotates across the 32 shared-memory banks,
 *         avoiding systematic bank conflicts between replicas.
 *
 * The public run_histogram() API zeros the output histogram and enqueues work on the current
 * (default) stream. It performs no synchronization because the caller explicitly handles that.
 */

constexpr int itemsPerThread   = 16;
constexpr int blockThreads     = 256;
constexpr int warpThreads      = 32;
constexpr int maxHistogramBins = 256;
constexpr int warpsPerBlock    = blockThreads / warpThreads;
constexpr int vectorBytes      = 16;  // sizeof(uint4)
constexpr int vectorsPerThread = itemsPerThread / vectorBytes;

static_assert(blockThreads == maxHistogramBins,
              "This implementation is tuned for exactly 256 threads per block.");
static_assert((blockThreads % warpThreads) == 0,
              "blockThreads must be a whole number of warps.");
static_assert(itemsPerThread > 0 && (itemsPerThread % vectorBytes) == 0,
              "itemsPerThread must be a positive multiple of 16 for the uint4 fast path.");

static __host__ __device__ __forceinline__ unsigned int private_hist_stride(const unsigned int numBins)
{
    // The next odd integer strictly larger than numBins.
    // Using an odd stride means the same logical bin in neighboring replicas is offset by
    // an odd number of 32-bit words, which is coprime with 32 banks and therefore rotates
    // that bin across banks instead of pinning it to the same bank in every replica.
    return numBins + 1u + (numBins & 1u);
}

static __device__ __forceinline__ void add_byte_to_private_hist(
    const unsigned int byteValue,
    const unsigned int fromValue,
    const unsigned int numBins,
    unsigned int* const myHist)
{
    // The histogram is relative to fromValue: bin 0 counts byte value 'fromValue'.
    // Unsigned subtraction naturally folds both range checks into one compare:
    // if byteValue < fromValue the subtraction underflows and the compare fails.
    const unsigned int bin = byteValue - fromValue;
    if (bin < numBins) {
        atomicAdd(myHist + bin, 1u);
    }
}

static __device__ __forceinline__ void add_word_to_private_hist(
    const unsigned int word,
    const unsigned int fromValue,
    const unsigned int numBins,
    unsigned int* const myHist)
{
    // One 32-bit word holds four bytes. CUDA devices are little-endian, so extracting bytes
    // by shifts yields the original character ordinals.
    add_byte_to_private_hist((word >>  0) & 0xFFu, fromValue, numBins, myHist);
    add_byte_to_private_hist((word >>  8) & 0xFFu, fromValue, numBins, myHist);
    add_byte_to_private_hist((word >> 16) & 0xFFu, fromValue, numBins, myHist);
    add_byte_to_private_hist((word >> 24) & 0xFFu, fromValue, numBins, myHist);
}

static __device__ __forceinline__ void add_uint4_to_private_hist(
    const uint4 packed,
    const unsigned int fromValue,
    const unsigned int numBins,
    unsigned int* const myHist)
{
    // A uint4 is a single 128-bit load containing 16 input bytes.
    add_word_to_private_hist(packed.x, fromValue, numBins, myHist);
    add_word_to_private_hist(packed.y, fromValue, numBins, myHist);
    add_word_to_private_hist(packed.z, fromValue, numBins, myHist);
    add_word_to_private_hist(packed.w, fromValue, numBins, myHist);
}

template <int COPIES_PER_WARP>
__launch_bounds__(blockThreads, 4)
__global__ void histogram_range_kernel(
    const unsigned char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    unsigned int fromValue,
    unsigned int numBins)
{
    static_assert(COPIES_PER_WARP >= 1 && COPIES_PER_WARP <= warpThreads,
                  "Invalid number of histogram copies per warp.");
    static_assert((COPIES_PER_WARP & (COPIES_PER_WARP - 1)) == 0,
                  "COPIES_PER_WARP must be a power of two.");

    constexpr int copiesPerBlock = warpsPerBlock * COPIES_PER_WARP;

    // Dynamic shared memory layout:
    //   [replica 0 bins ... pad][replica 1 bins ... pad]...[replica N bins ... pad]
    extern __shared__ unsigned int privateHist[];

    const unsigned int stride = private_hist_stride(numBins);
    const unsigned int totalPrivateBins = stride * static_cast<unsigned int>(copiesPerBlock);

    // Initialize all private histograms. The total private storage is intentionally kept modest
    // (roughly a few tens of KiB at the top of each bucket) so this setup cost is amortized well
    // for large inputs.
    for (unsigned int i = threadIdx.x; i < totalPrivateBins; i += blockThreads) {
        privateHist[i] = 0u;
    }
    __syncthreads();

    const unsigned int lane = threadIdx.x & (warpThreads - 1u);
    const unsigned int warp = threadIdx.x >> 5;

    // Round-robin striping of lanes across replicas:
    //   COPIES_PER_WARP == 32 -> 1 lane/replica
    //   COPIES_PER_WARP == 16 -> 2 lanes/replica
    //   COPIES_PER_WARP ==  8 -> 4 lanes/replica
    //   COPIES_PER_WARP ==  4 -> 8 lanes/replica
    // This spreads neighboring lanes over different replicas instead of clustering them.
    const unsigned int copyInWarp = lane & static_cast<unsigned int>(COPIES_PER_WARP - 1);
    const unsigned int replica    = warp * static_cast<unsigned int>(COPIES_PER_WARP) + copyInWarp;
    unsigned int* const myHist    = privateHist + replica * stride;

    const std::size_t n = static_cast<std::size_t>(inputSize);

    // The input buffer is specified to be allocated with cudaMalloc, so the base pointer is
    // naturally aligned. Keeping itemsPerThread a multiple of 16 preserves alignment for this path.
    const uint4* const inputVec4 = reinterpret_cast<const uint4*>(input);

    const std::size_t firstIndex =
        (static_cast<std::size_t>(blockIdx.x) * static_cast<std::size_t>(blockThreads) +
         static_cast<std::size_t>(threadIdx.x)) *
        static_cast<std::size_t>(itemsPerThread);

    const std::size_t gridStride =
        static_cast<std::size_t>(gridDim.x) *
        static_cast<std::size_t>(blockThreads) *
        static_cast<std::size_t>(itemsPerThread);

    std::size_t idx = firstIndex;

    // Fast path: each thread processes itemsPerThread bytes at a time via one or more uint4 loads.
    for (; idx + static_cast<std::size_t>(itemsPerThread) <= n; idx += gridStride) {
        const std::size_t vecBase = idx / static_cast<std::size_t>(vectorBytes);

        #pragma unroll
        for (int v = 0; v < vectorsPerThread; ++v) {
            const uint4 packed = inputVec4[vecBase + static_cast<std::size_t>(v)];
            add_uint4_to_private_hist(packed, fromValue, numBins, myHist);
        }
    }

    // Tail path: handle the last partial chunk, if any.
    if (idx < n) {
        const std::size_t tailEnd =
            ((idx + static_cast<std::size_t>(itemsPerThread)) < n)
                ? (idx + static_cast<std::size_t>(itemsPerThread))
                : n;

        for (std::size_t j = idx; j < tailEnd; ++j) {
            add_byte_to_private_hist(static_cast<unsigned int>(input[j]), fromValue, numBins, myHist);
        }
    }

    __syncthreads();

    // numBins <= 256, so one thread per logical output bin is enough for the block-local reduction.
    if (threadIdx.x < numBins) {
        const unsigned int bin = threadIdx.x;

        // Sum this logical bin across all replicas. Pointer bumping avoids repeated multiplies.
        const unsigned int* copyPtr = privateHist + bin;
        unsigned int sum = 0u;

        #pragma unroll 8
        for (int copy = 0; copy < copiesPerBlock; ++copy, copyPtr += stride) {
            sum += *copyPtr;
        }

        if (sum != 0u) {
            // For a single-block launch the output bins are disjoint, so a plain store is enough.
            // Otherwise merge block-private totals with one global atomic per bin.
            if (gridDim.x == 1) {
                histogram[bin] = sum;
            } else {
                atomicAdd(histogram + bin, sum);
            }
        }
    }
}

template <int COPIES_PER_WARP>
static inline void launch_histogram_kernel(
    const unsigned char* input,
    unsigned int* histogram,
    unsigned int inputSize,
    unsigned int fromValue,
    unsigned int numBins)
{
    constexpr int copiesPerBlock = warpsPerBlock * COPIES_PER_WARP;

    const std::size_t sharedBytes =
        static_cast<std::size_t>(copiesPerBlock) *
        static_cast<std::size_t>(private_hist_stride(numBins)) *
        sizeof(unsigned int);

    // The kernel is shared-memory/atomic heavy and streams the input once, so a maximal
    // shared-memory carveout is preferable on Ampere/Hopper-class parts.
    (void)cudaFuncSetAttribute(
        histogram_range_kernel<COPIES_PER_WARP>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    int activeBlocksPerSM = 1;
    (void)cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM,
        histogram_range_kernel<COPIES_PER_WARP>,
        blockThreads,
        sharedBytes);
    if (activeBlocksPerSM < 1) {
        activeBlocksPerSM = 1;
    }

    int device = 0;
    (void)cudaGetDevice(&device);

    int smCount = 1;
    (void)cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1) {
        smCount = 1;
    }

    // With grid-stride looping, launching only enough blocks to saturate the machine is ideal:
    // more blocks would only increase the final global merge traffic.
    constexpr unsigned int tileSize = static_cast<unsigned int>(blockThreads * itemsPerThread);
    const unsigned int requiredBlocks = 1u + (inputSize - 1u) / tileSize;

    unsigned int gridBlocks =
        static_cast<unsigned int>(activeBlocksPerSM) * static_cast<unsigned int>(smCount);
    if (gridBlocks < 1u) {
        gridBlocks = 1u;
    }
    if (gridBlocks > requiredBlocks) {
        gridBlocks = requiredBlocks;
    }

    histogram_range_kernel<COPIES_PER_WARP>
        <<<gridBlocks, blockThreads, sharedBytes>>>(input, histogram, inputSize, fromValue, numBins);
}

void run_histogram(
    const char* input,
    unsigned int* histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    // Assumes the problem-statement preconditions:
    //   0 <= from < to <= 255
    const unsigned int fromValue = static_cast<unsigned int>(from);
    const unsigned int numBins   = static_cast<unsigned int>(to - from + 1);

    // The API computes a fresh histogram, not an accumulation, so zero the destination here.
    (void)cudaMemsetAsync(
        histogram,
        0,
        static_cast<std::size_t>(numBins) * sizeof(unsigned int));

    if (inputSize == 0u) {
        return;
    }

    // Reinterpret as unsigned bytes so ordinals 128..255 are handled correctly even if host-side
    // char is signed.
    const unsigned char* const inputBytes = reinterpret_cast<const unsigned char*>(input);

    // Adaptive replica count:
    //   <=  32 bins -> 32 copies/warp (1 lane per copy)
    //   <=  64 bins -> 16 copies/warp (2 lanes per copy)
    //   <= 128 bins ->  8 copies/warp (4 lanes per copy)
    //   else        ->  4 copies/warp (8 lanes per copy)
    //
    // These buckets are tuned for 256-thread blocks and keep the shared-memory footprint near
    // a few tens of KiB at the top of each bucket while giving smaller ranges more replicas.
    if (numBins <= 32u) {
        launch_histogram_kernel<32>(inputBytes, histogram, inputSize, fromValue, numBins);
    } else if (numBins <= 64u) {
        launch_histogram_kernel<16>(inputBytes, histogram, inputSize, fromValue, numBins);
    } else if (numBins <= 128u) {
        launch_histogram_kernel<8>(inputBytes, histogram, inputSize, fromValue, numBins);
    } else {
        launch_histogram_kernel<4>(inputBytes, histogram, inputSize, fromValue, numBins);
    }
}

#include <cuda_runtime.h>
#include <cstdint>

/*
 * Range-restricted byte histogram for device-resident input.
 *
 * Output layout:
 *   histogram[i] == count of byte value (from + i)
 *
 * Important correctness detail:
 *   The input is interpreted as unsigned bytes, not as possibly signed C++ char.
 *   This makes ranges in [128, 255] work correctly on platforms where plain
 *   char is signed.
 *
 * Performance strategy:
 *   1) Each block builds a private histogram in shared memory.
 *   2) The shared histogram is replicated 32 times per block (one logical copy
 *      per warp lane / shared-memory bank).
 *   3) Lane N always updates copy N. The per-copy stride is forced to be odd
 *      (numBins or numBins + 1), so the same bin across the 32 copies maps to
 *      the 32 banks instead of colliding on a subset of banks.
 *   4) After scanning its portion of the input, the block merges the 32 copies
 *      and performs only one global atomic add per output bin.
 *   5) Full tiles use uchar4 vector loads; unaligned pointers or the final
 *      partial tile fall back to scalar loads.
 */
namespace {

constexpr int kWarpSize = 32;
constexpr int kBlockThreads = 256;
/*
 * Chosen for A100/H100-class GPUs:
 *   - 256 threads = 8 warps/block, a strong balance between occupancy and
 *     intra-block shared-atomic contention.
 *   - 16 bytes/thread gives enough ILP to amortize setup and shared-memory
 *     initialization while keeping register pressure low.
 *   - 16 is also a natural fit for four uchar4 vector loads.
 */
constexpr int itemsPerThread = 16;
constexpr int kSharedHistogramCopies = kWarpSize;
constexpr int kWarpsPerBlock = kBlockThreads / kWarpSize;
constexpr int kVectorWidth = 4;
constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;

static_assert(kBlockThreads % kWarpSize == 0, "Block size must be a multiple of 32.");
static_assert(kSharedHistogramCopies == kWarpSize,
              "This implementation uses one shared histogram copy per warp lane.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert((itemsPerThread % kVectorWidth) == 0,
              "itemsPerThread must be a multiple of 4 for the vectorized path.");

__device__ __forceinline__ unsigned int warp_reduce_sum(unsigned int value)
{
    #pragma unroll
    for (int offset = kWarpSize / 2; offset > 0; offset >>= 1) {
        value += __shfl_down_sync(kFullWarpMask, value, offset);
    }
    return value;
}

__device__ __forceinline__ void accumulate_byte(
    const unsigned int value,
    const unsigned int rangeBegin,
    const unsigned int numBins,
    unsigned int* myHistogram)
{
    /*
     * Unsigned subtraction turns the inclusive range test
     *   rangeBegin <= value <= rangeBegin + numBins - 1
     * into a single comparison:
     *   bin = value - rangeBegin; if (bin < numBins) ...
     *
     * Values below rangeBegin wrap around and therefore fail the comparison.
     */
    const unsigned int bin = value - rangeBegin;
    if (bin < numBins) {
        atomicAdd(myHistogram + bin, 1u);
    }
}

__device__ __forceinline__ void accumulate_uchar4(
    const uchar4 v,
    const unsigned int rangeBegin,
    const unsigned int numBins,
    unsigned int* myHistogram)
{
    accumulate_byte(static_cast<unsigned int>(v.x), rangeBegin, numBins, myHistogram);
    accumulate_byte(static_cast<unsigned int>(v.y), rangeBegin, numBins, myHistogram);
    accumulate_byte(static_cast<unsigned int>(v.z), rangeBegin, numBins, myHistogram);
    accumulate_byte(static_cast<unsigned int>(v.w), rangeBegin, numBins, myHistogram);
}

__global__ __launch_bounds__(kBlockThreads)
void histogram_kernel(const char* __restrict__ input,
                      unsigned int* __restrict__ histogram,
                      const unsigned int inputSize,
                      const unsigned int rangeBegin,
                      const unsigned int numBins)
{
    extern __shared__ unsigned int s_hist[];

    const unsigned int tid = threadIdx.x;
    const unsigned int lane = tid & (kWarpSize - 1u);
    const unsigned int warpId = tid >> 5;

    /*
     * Force an odd stride for each replicated histogram:
     *   even numBins -> numBins + 1
     *   odd  numBins -> numBins
     *
     * With 32 banks, any odd stride is relatively prime to 32. Therefore,
     * "same bin across the 32 copies" becomes a full permutation of the banks,
     * which removes the worst bank-conflict pattern. Padding cost is at most
     * one counter per copy.
     */
    const unsigned int copyStride = numBins | 1u;
    const unsigned int totalSharedWords = kSharedHistogramCopies * copyStride;

    // Zero the block-private shared histograms.
    for (unsigned int i = tid; i < totalSharedWords; i += kBlockThreads) {
        s_hist[i] = 0u;
    }
    __syncthreads();

    // Interpret input as unsigned bytes so values 128..255 are handled correctly.
    const unsigned char* const bytes = reinterpret_cast<const unsigned char*>(input);

    // Lane N always updates copy N.
    const unsigned int myHistBase = lane * copyStride;
    unsigned int* const myHistogram = s_hist + myHistBase;

    const size_t totalCount = static_cast<size_t>(inputSize);
    const size_t tileSize =
        static_cast<size_t>(kBlockThreads) * static_cast<size_t>(itemsPerThread);
    const size_t gridStride = static_cast<size_t>(gridDim.x) * tileSize;

    size_t tileStart = static_cast<size_t>(blockIdx.x) * tileSize;

    /*
     * Vectorized full-tile path.
     *
     * uchar4 loads require 4-byte alignment for defined behavior. cudaMalloc
     * allocations are naturally aligned, but this runtime check keeps the kernel
     * correct even if the caller passes a shifted device pointer into a larger
     * allocation.
     */
    const bool canVectorize =
        ((reinterpret_cast<std::uintptr_t>(bytes) &
          static_cast<std::uintptr_t>(kVectorWidth - 1)) == 0);

    if (canVectorize && totalCount >= tileSize) {
        constexpr int kVectorLoadsPerThread = itemsPerThread / kVectorWidth;
        const size_t vectorSpan =
            static_cast<size_t>(kBlockThreads) * static_cast<size_t>(kVectorWidth);
        const size_t lastFullTileStart = totalCount - tileSize;

        for (; tileStart <= lastFullTileStart; tileStart += gridStride) {
            #pragma unroll
            for (int v = 0; v < kVectorLoadsPerThread; ++v) {
                const size_t idx =
                    tileStart +
                    static_cast<size_t>(v) * vectorSpan +
                    static_cast<size_t>(tid) * static_cast<size_t>(kVectorWidth);

                const uchar4 data = *reinterpret_cast<const uchar4*>(bytes + idx);
                accumulate_uchar4(data, rangeBegin, numBins, myHistogram);
            }
        }
    }

    // Scalar path for the final partial tile, or for all tiles if vectorization is not possible.
    for (; tileStart < totalCount; tileStart += gridStride) {
        const size_t base = tileStart + static_cast<size_t>(tid);

        #pragma unroll
        for (int i = 0; i < itemsPerThread; ++i) {
            const size_t idx =
                base + static_cast<size_t>(i) * static_cast<size_t>(kBlockThreads);
            if (idx < totalCount) {
                accumulate_byte(static_cast<unsigned int>(bytes[idx]),
                                rangeBegin,
                                numBins,
                                myHistogram);
            }
        }
    }

    __syncthreads();

    /*
     * Warp-parallel merge of the 32 replicated shared histograms:
     *   - lane N reads copy N for the current bin,
     *   - the warp sums those 32 partial counts with shuffles,
     *   - lane 0 performs the final global atomic add.
     *
     * That keeps global atomic traffic down to one atomic per (block, bin) pair
     * instead of one atomic per matching input byte.
     */
    for (unsigned int bin = warpId; bin < numBins; bin += kWarpsPerBlock) {
        const unsigned int partial = s_hist[lane * copyStride + bin];
        const unsigned int sum = warp_reduce_sum(partial);

        if (lane == 0u && sum != 0u) {
            atomicAdd(histogram + bin, sum);
        }
    }
}

} // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    /*
     * Contract:
     *   - input and histogram are device pointers allocated by cudaMalloc.
     *   - histogram has exactly (to - from + 1) counters.
     *   - this function intentionally does not synchronize; the caller owns
     *     stream ordering / completion handling.
     */
    if (from < 0 || to > 255 || from > to) {
        return;
    }

    const unsigned int rangeBegin = static_cast<unsigned int>(from);
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);

    // Overwrite only the compact output range requested by the caller.
    (void)cudaMemsetAsync(histogram, 0, static_cast<size_t>(numBins) * sizeof(unsigned int));

    if (inputSize == 0u) {
        return;
    }

    const size_t sharedBytes =
        static_cast<size_t>(kSharedHistogramCopies) *
        static_cast<size_t>(numBins | 1u) *
        sizeof(unsigned int);

    /*
     * The kernel uses a grid-stride loop, so there is no benefit in launching
     * more blocks than the GPU can keep resident. Extra blocks would only add
     * more final global-atomic merge work.
     */
    int device = 0;
    int smCount = 1;
    int activeBlocksPerSm = 1;

    (void)cudaGetDevice(&device);
    (void)cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    (void)cudaOccupancyMaxActiveBlocksPerMultiprocessor(&activeBlocksPerSm,
                                                        histogram_kernel,
                                                        kBlockThreads,
                                                        sharedBytes);

    if (smCount < 1) {
        smCount = 1;
    }
    if (activeBlocksPerSm < 1) {
        activeBlocksPerSm = 1;
    }

    const unsigned int tileSize =
        static_cast<unsigned int>(kBlockThreads) * static_cast<unsigned int>(itemsPerThread);

    // inputSize > 0 here, so this overflow-safe form is valid.
    const unsigned int numTiles = 1u + (inputSize - 1u) / tileSize;
    const unsigned int maxResidentBlocks =
        static_cast<unsigned int>(smCount) * static_cast<unsigned int>(activeBlocksPerSm);
    const unsigned int gridSize =
        (numTiles < maxResidentBlocks) ? numTiles : maxResidentBlocks;

    histogram_kernel<<<gridSize, kBlockThreads, sharedBytes>>>(
        input,
        histogram,
        inputSize,
        rangeBegin,
        numBins);
}

#include <cuda_runtime.h>

// Device-resident range-limited byte histogram.
//
// Design tuned for large inputs on modern data-center GPUs (A100/H100 class):
//   * Shared-memory privatization keeps almost all atomics on-chip.
//   * Each CTA owns 32 interleaved copies of the histogram (one per shared-memory
//     bank / warp lane), which removes intra-warp bank conflicts during updates.
//   * A persistent grid-stride traversal sized to resident CTAs minimizes the
//     number of per-block global histogram flushes.
//   * The 32 copies are reduced with warp shuffles; lane j reads copy j, so the
//     readback is bank-conflict free as well.

namespace {

// User-tunable throughput knob. For large streaming inputs on recent NVIDIA GPUs,
// 16 items/thread is a strong default: it amortizes index math and loop overhead
// while keeping register pressure and code size modest.
constexpr int itemsPerThread = 16;

// 256 threads/block is a good balance here: enough warps to hide latency, but not
// so many that shared-memory atomic contention is unnecessarily amplified.
constexpr int threadsPerBlock = 256;

constexpr int kWarpSize = 32;

// Shared memory has 32 banks on modern NVIDIA GPUs. Using 32 interleaved copies
// makes the bank index equal to the lane id for every update. Max shared-memory
// footprint is therefore 256 bins * 32 copies * 4 B = 32 KiB.
constexpr int sharedHistogramCopies = 32;

constexpr int warpsPerBlock = threadsPerBlock / kWarpSize;
constexpr unsigned int fullWarpMask = 0xFFFFFFFFu;

constexpr size_t itemsPerBlock =
    static_cast<size_t>(threadsPerBlock) * static_cast<size_t>(itemsPerThread);
constexpr size_t lastItemOffset =
    static_cast<size_t>(itemsPerThread - 1) * static_cast<size_t>(threadsPerBlock);

static_assert((threadsPerBlock % kWarpSize) == 0,
              "threadsPerBlock must be a multiple of warp size.");
static_assert(sharedHistogramCopies == kWarpSize,
              "This implementation relies on 32-lane warps and 32 shared-memory banks.");
static_assert((sharedHistogramCopies & (sharedHistogramCopies - 1)) == 0,
              "sharedHistogramCopies must be a power of two.");
static_assert(itemsPerBlock > lastItemOffset,
              "Tail handling assumes at most one partial grid-stride iteration.");

// Update one bank-striped shared-memory sub-histogram entry.
//
// The range check is intentionally done with unsigned subtraction:
//   bin = value - rangeStart
// and a single comparison:
//   bin < numBins
// Values below rangeStart underflow and therefore fail the comparison.
__device__ __forceinline__
void accumulate_byte(unsigned char value,
                     unsigned int rangeStart,
                     unsigned int numBins,
                     unsigned int copy,
                     unsigned int* __restrict__ s_hist) {
    const unsigned int bin = static_cast<unsigned int>(value) - rangeStart;
    if (bin < numBins) {
        atomicAdd(&s_hist[bin * sharedHistogramCopies + copy], 1u);
    }
}

__global__ __launch_bounds__(threadsPerBlock)
void histogram_kernel(const char* __restrict__ input,
                      unsigned int* __restrict__ histogram,
                      unsigned int inputSize,
                      unsigned int rangeStart,
                      unsigned int numBins) {
    extern __shared__ unsigned int s_hist[];

    const unsigned int tid    = static_cast<unsigned int>(threadIdx.x);
    const unsigned int lane   = tid & static_cast<unsigned int>(kWarpSize - 1);
    const unsigned int warpId = tid >> 5;  // kWarpSize == 32

    const unsigned int totalCounters = numBins * sharedHistogramCopies;

    // Zero the CTA-private shared histogram.
    for (unsigned int i = tid; i < totalCounters; i += threadsPerBlock) {
        s_hist[i] = 0u;
    }
    __syncthreads();

    const unsigned char* __restrict__ input_u8 =
        reinterpret_cast<const unsigned char*>(input);
    const size_t inputSizeZ = static_cast<size_t>(inputSize);

    // Persistent grid-stride traversal.
    size_t base = static_cast<size_t>(blockIdx.x) * itemsPerBlock + static_cast<size_t>(tid);
    const size_t gridStride = static_cast<size_t>(gridDim.x) * itemsPerBlock;

    // Fast path: all items in the unrolled bundle are in-bounds, so no per-item checks.
    for (; base + lastItemOffset < inputSizeZ; base += gridStride) {
        const unsigned char* p = input_u8 + base;
        #pragma unroll
        for (int item = 0; item < itemsPerThread; ++item) {
            accumulate_byte(
                p[static_cast<size_t>(item) * static_cast<size_t>(threadsPerBlock)],
                rangeStart,
                numBins,
                lane,
                s_hist);
        }
    }

    // Tail: because gridStride >= itemsPerBlock > lastItemOffset, there can be at most
    // one partially full iteration left for each thread.
    if (base < inputSizeZ) {
        #pragma unroll
        for (int item = 0; item < itemsPerThread; ++item) {
            const size_t idx =
                base + static_cast<size_t>(item) * static_cast<size_t>(threadsPerBlock);
            if (idx < inputSizeZ) {
                accumulate_byte(input_u8[idx], rangeStart, numBins, lane, s_hist);
            }
        }
    }

    __syncthreads();

    // Reduce the 32 bank-striped copies back to one count per bin.
    // Each warp handles one bin at a time; lane j reads copy j, which is bank-conflict free.
    for (unsigned int bin = warpId; bin < numBins; bin += static_cast<unsigned int>(warpsPerBlock)) {
        unsigned int sum = s_hist[bin * sharedHistogramCopies + lane];

        #pragma unroll
        for (int offset = kWarpSize / 2; offset > 0; offset >>= 1) {
            sum += __shfl_down_sync(fullWarpMask, sum, offset);
        }

        if (lane == 0u && sum != 0u) {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

}  // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    const unsigned int rangeStart = static_cast<unsigned int>(from);
    const unsigned int numBins    = static_cast<unsigned int>(to - from + 1);

    // The contract is to compute a histogram, not accumulate into an existing one.
    // Use async memset because the caller explicitly owns synchronization.
    const size_t histogramBytes = static_cast<size_t>(numBins) * sizeof(unsigned int);
    cudaMemsetAsync(histogram, 0, histogramBytes, 0);

    if (inputSize == 0u) {
        return;
    }

    // Dynamic shared memory footprint = numBins * 32 copies * 4 B.
    const size_t sharedBytes =
        static_cast<size_t>(numBins) *
        static_cast<size_t>(sharedHistogramCopies) *
        sizeof(unsigned int);

    // Use a persistent-style grid sized to the number of resident CTAs. This keeps all
    // SMs busy on large inputs while minimizing the number of final global histogram flushes.
    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    int activeBlocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM,
        histogram_kernel,
        threadsPerBlock,
        sharedBytes);

    unsigned int maxResidentBlocks =
        static_cast<unsigned int>(smCount) * static_cast<unsigned int>(activeBlocksPerSM);
    if (maxResidentBlocks == 0u) {
        maxResidentBlocks = 1u;
    }

    const unsigned int neededBlocks = static_cast<unsigned int>(
        (static_cast<size_t>(inputSize) + itemsPerBlock - 1) / itemsPerBlock);

    const unsigned int gridSize =
        (neededBlocks < maxResidentBlocks) ? neededBlocks : maxResidentBlocks;

    // Default stream launch; the function signature does not expose a stream parameter,
    // and the caller is responsible for any synchronization/error handling policy.
    histogram_kernel<<<gridSize, threadsPerBlock, sharedBytes, 0>>>(
        input, histogram, inputSize, rangeStart, numBins);
}

#include <cuda_runtime.h>
#include <cstdint>

namespace histogram_detail {

// Tuned defaults for large inputs on modern data-center GPUs (A100/H100).
// - 256 threads/block gives 8 warps/block, enough parallelism while keeping inter-warp
//   contention on the shared histogram replicas moderate.
// - 16 items/thread maps naturally to one 128-bit (uint4) load per thread on the fast path,
//   amortizing shared-memory init/final-reduction overhead without bloating register usage.
constexpr int itemsPerThread   = 16;
constexpr int threadsPerBlock  = 256;

// One replica per warp lane / shared-memory bank.
// Together with a bank-skewed stride, this spreads updates across banks and sharply reduces
// shared-memory conflicts for hot bins.
constexpr int histogramReplicas = 32;

// Size of one block-sized chunk of input processed per grid-stride iteration.
constexpr unsigned int blockWork =
    static_cast<unsigned int>(threadsPerBlock * itemsPerThread);

// Vectorized fast path uses one uint4 load per 16 input bytes.
constexpr int vectorLoadBytes = static_cast<int>(sizeof(uint4));
constexpr bool vectorizedLoadPathAvailable =
    (itemsPerThread % vectorLoadBytes) == 0;

static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert(threadsPerBlock >= 256,
              "threadsPerBlock must be at least 256 so the epilogue can cover all possible bins.");
static_assert((threadsPerBlock & 31) == 0,
              "threadsPerBlock must be a multiple of 32.");
static_assert(histogramReplicas == 32,
              "This implementation assumes one shared-memory replica per warp lane.");
static_assert((histogramReplicas & (histogramReplicas - 1)) == 0,
              "histogramReplicas must be a power of two.");

// Warp-aggregated update into the lane-private shared-memory replica.
// All lanes participate. Lanes that target the same histogram bin are collapsed with
// __match_any_sync(), and only the first lane in each equivalence class issues the atomicAdd
// with the population count of the class. This is especially effective on text inputs, where
// repeated characters are common.
//
// On Volta+ (and therefore on A100/H100), __match_any_sync() is available and very fast.
// A conservative fallback is kept for older architectures so the code remains correct there.
__device__ __forceinline__
void accumulate_byte_warp_aggregated(unsigned int byteValue,
                                     bool present,
                                     unsigned int* replica,
                                     unsigned int lane,
                                     unsigned int from,
                                     unsigned int numBins)
{
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 700)
    constexpr unsigned int invalidKey = 0xFFFFFFFFu;

    const unsigned int bin = byteValue - from;
    const unsigned int key = (present && bin < numBins) ? bin : invalidKey;

    const unsigned int peers  = __match_any_sync(__activemask(), key);
    const unsigned int leader = static_cast<unsigned int>(__ffs(static_cast<int>(peers)) - 1);

    if (key != invalidKey && lane == leader) {
        atomicAdd(replica + bin, static_cast<unsigned int>(__popc(peers)));
    }
#else
    if (present) {
        const unsigned int bin = byteValue - from;
        if (bin < numBins) {
            atomicAdd(replica + bin, 1u);
        }
    }
#endif
}

// Process four bytes packed in one 32-bit word.
__device__ __forceinline__
void accumulate_packed_word(unsigned int word,
                            unsigned int* replica,
                            unsigned int lane,
                            unsigned int from,
                            unsigned int numBins)
{
    accumulate_byte_warp_aggregated((word >>  0) & 0xFFu, true, replica, lane, from, numBins);
    accumulate_byte_warp_aggregated((word >>  8) & 0xFFu, true, replica, lane, from, numBins);
    accumulate_byte_warp_aggregated((word >> 16) & 0xFFu, true, replica, lane, from, numBins);
    accumulate_byte_warp_aggregated((word >> 24) & 0xFFu, true, replica, lane, from, numBins);
}

// Common prologue: zero all shared-memory replicas.
template <int BLOCK_SIZE>
__device__ __forceinline__
void clear_shared_hist(unsigned int* s_hist, unsigned int totalWords)
{
    for (unsigned int i = threadIdx.x; i < totalWords; i += BLOCK_SIZE) {
        s_hist[i] = 0u;
    }
    __syncthreads();
}

// Common epilogue: reduce all per-block replicas into the global histogram.
// Because the output has at most 256 bins, one thread per output bin is enough.
template <int REPLICAS>
__device__ __forceinline__
void flush_shared_hist(const unsigned int* s_hist,
                       unsigned int* __restrict__ histogram,
                       unsigned int numBins,
                       unsigned int smemStride)
{
    __syncthreads();

    const unsigned int bin = threadIdx.x;
    if (bin < numBins) {
        const unsigned int* replicaBin = s_hist + bin;

        unsigned int sum = 0u;
#pragma unroll
        for (int r = 0; r < REPLICAS; ++r) {
            sum += replicaBin[static_cast<unsigned int>(r) * smemStride];
        }

        if (sum != 0u) {
            atomicAdd(histogram + bin, sum);
        }
    }
}

// Fast path: requires ITEMS_PER_THREAD to be a multiple of 16 and the input pointer
// to be 16-byte aligned. With the default itemsPerThread == 16, each thread issues
// exactly one aligned uint4 load per block-chunk iteration.
template <int BLOCK_SIZE, int ITEMS_PER_THREAD, int REPLICAS>
__global__ __launch_bounds__(BLOCK_SIZE)
void histogram_kernel_vectorized(const char* __restrict__ input,
                                 unsigned int* __restrict__ histogram,
                                 unsigned int inputSize,
                                 unsigned int from,
                                 unsigned int numBins,
                                 unsigned int smemStride)
{
    static_assert((BLOCK_SIZE & 31) == 0,
                  "BLOCK_SIZE must be a multiple of 32.");
    static_assert(BLOCK_SIZE >= 256,
                  "BLOCK_SIZE must be at least 256.");
    static_assert(REPLICAS == 32,
                  "This kernel assumes one shared-memory replica per warp lane.");
    static_assert((ITEMS_PER_THREAD % vectorLoadBytes) == 0,
                  "Vectorized kernel requires ITEMS_PER_THREAD to be a multiple of 16.");

    extern __shared__ unsigned int s_hist[];

    const unsigned char* const uinput =
        reinterpret_cast<const unsigned char*>(input);

    clear_shared_hist<BLOCK_SIZE>(
        s_hist, static_cast<unsigned int>(REPLICAS) * smemStride);

    const unsigned int lane = threadIdx.x & static_cast<unsigned int>(REPLICAS - 1);
    unsigned int* const replica = s_hist + lane * smemStride;

    // Use size_t for address arithmetic so the grid-stride stepping remains safe even
    // close to the 4 GiB limit implied by the unsigned int inputSize parameter.
    const size_t inputSizeBytes   = static_cast<size_t>(inputSize);
    const size_t localBlockWork   = static_cast<size_t>(BLOCK_SIZE) * ITEMS_PER_THREAD;
    const size_t gridStride       = static_cast<size_t>(gridDim.x) * localBlockWork;
    size_t       blockBase        = static_cast<size_t>(blockIdx.x) * localBlockWork;
    const size_t threadChunkBase  = static_cast<size_t>(threadIdx.x) * ITEMS_PER_THREAD;

    // Bulk path: the whole block-sized chunk is in range, so every vector load is valid
    // and, because blockBase and threadChunkBase are both multiples of 16, aligned.
    if (inputSizeBytes >= localBlockWork) {
        const size_t bulkLimit = inputSizeBytes - localBlockWork;

        for (; blockBase <= bulkLimit; blockBase += gridStride) {
            const size_t idx = blockBase + threadChunkBase;

#pragma unroll
            for (int vec = 0; vec < (ITEMS_PER_THREAD / vectorLoadBytes); ++vec) {
                const size_t vecOffset = static_cast<size_t>(vec) * vectorLoadBytes;
                const uint4 packed =
                    *reinterpret_cast<const uint4*>(uinput + idx + vecOffset);

                accumulate_packed_word(packed.x, replica, lane, from, numBins);
                accumulate_packed_word(packed.y, replica, lane, from, numBins);
                accumulate_packed_word(packed.z, replica, lane, from, numBins);
                accumulate_packed_word(packed.w, replica, lane, from, numBins);
            }
        }
    }

    // Tail path: at most one partial block-sized chunk remains for this block.
    // Every lane still participates in every warp-aggregation step; absent bytes are
    // represented by "present == false" and simply do not contribute.
    if (blockBase < inputSizeBytes) {
        const size_t idx = blockBase + threadChunkBase;

        unsigned int remaining = 0u;
        if (idx < inputSizeBytes) {
            const size_t tail = inputSizeBytes - idx;
            remaining = static_cast<unsigned int>(
                tail < static_cast<size_t>(ITEMS_PER_THREAD)
                    ? tail
                    : static_cast<size_t>(ITEMS_PER_THREAD));
        }

#pragma unroll
        for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
            const bool present = static_cast<unsigned int>(item) < remaining;

            unsigned int byteValue = 0u;
            if (present) {
                byteValue = static_cast<unsigned int>(
                    uinput[idx + static_cast<size_t>(item)]);
            }

            accumulate_byte_warp_aggregated(
                byteValue, present, replica, lane, from, numBins);
        }
    }

    flush_shared_hist<REPLICAS>(s_hist, histogram, numBins, smemStride);
}

// Scalar fallback: used when the device pointer is not 16-byte aligned or when
// itemsPerThread is changed to a value that is not a multiple of 16.
template <int BLOCK_SIZE, int ITEMS_PER_THREAD, int REPLICAS>
__global__ __launch_bounds__(BLOCK_SIZE)
void histogram_kernel_scalar(const char* __restrict__ input,
                             unsigned int* __restrict__ histogram,
                             unsigned int inputSize,
                             unsigned int from,
                             unsigned int numBins,
                             unsigned int smemStride)
{
    static_assert((BLOCK_SIZE & 31) == 0,
                  "BLOCK_SIZE must be a multiple of 32.");
    static_assert(BLOCK_SIZE >= 256,
                  "BLOCK_SIZE must be at least 256.");
    static_assert(REPLICAS == 32,
                  "This kernel assumes one shared-memory replica per warp lane.");

    extern __shared__ unsigned int s_hist[];

    const unsigned char* const uinput =
        reinterpret_cast<const unsigned char*>(input);

    clear_shared_hist<BLOCK_SIZE>(
        s_hist, static_cast<unsigned int>(REPLICAS) * smemStride);

    const unsigned int lane = threadIdx.x & static_cast<unsigned int>(REPLICAS - 1);
    unsigned int* const replica = s_hist + lane * smemStride;

    const size_t inputSizeBytes = static_cast<size_t>(inputSize);
    const size_t localBlockWork = static_cast<size_t>(BLOCK_SIZE) * ITEMS_PER_THREAD;
    const size_t gridStride     = static_cast<size_t>(gridDim.x) * localBlockWork;
    size_t       blockBase      = static_cast<size_t>(blockIdx.x) * localBlockWork;
    const size_t threadBase     = static_cast<size_t>(threadIdx.x);

    // Bulk path: each block-chunk is processed in a transposed layout
    // (item * BLOCK_SIZE + threadIdx.x), which gives fully coalesced scalar loads.
    if (inputSizeBytes >= localBlockWork) {
        const size_t bulkLimit = inputSizeBytes - localBlockWork;

        for (; blockBase <= bulkLimit; blockBase += gridStride) {
            const size_t base = blockBase + threadBase;

#pragma unroll
            for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
                const unsigned int byteValue = static_cast<unsigned int>(
                    uinput[base + static_cast<size_t>(item) * BLOCK_SIZE]);

                accumulate_byte_warp_aggregated(
                    byteValue, true, replica, lane, from, numBins);
            }
        }
    }

    // Tail path for the final partial chunk.
    if (blockBase < inputSizeBytes) {
        const size_t base = blockBase + threadBase;

#pragma unroll
        for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
            const size_t idx = base + static_cast<size_t>(item) * BLOCK_SIZE;
            const bool present = idx < inputSizeBytes;

            unsigned int byteValue = 0u;
            if (present) {
                byteValue = static_cast<unsigned int>(uinput[idx]);
            }

            accumulate_byte_warp_aggregated(
                byteValue, present, replica, lane, from, numBins);
        }
    }

    flush_shared_hist<REPLICAS>(s_hist, histogram, numBins, smemStride);
}

// The kernel uses a grid-stride loop with a uniform per-byte cost, so one occupancy-filling
// wave of blocks is sufficient. Launching many more blocks would mostly increase the number
// of final global atomic merges.
template <typename KernelFunc>
inline unsigned int compute_launch_blocks(KernelFunc kernel,
                                          size_t sharedMemBytes,
                                          unsigned int inputSize)
{
    int device = 0;
    int smCount = 1;
    int activeBlocksPerSM = 1;

    cudaGetDevice(&device);
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM, kernel, threadsPerBlock, sharedMemBytes);

    if (smCount < 1) {
        smCount = 1;
    }
    if (activeBlocksPerSM < 1) {
        activeBlocksPerSM = 1;
    }

    const unsigned int blocksForInput =
        inputSize / blockWork + static_cast<unsigned int>((inputSize % blockWork) != 0u);

    unsigned int numBlocks = blocksForInput;
    const unsigned int maxBlocks =
        static_cast<unsigned int>(smCount) *
        static_cast<unsigned int>(activeBlocksPerSM);

    if (numBlocks > maxBlocks) {
        numBlocks = maxBlocks;
    }
    if (numBlocks == 0u) {
        numBlocks = 1u;
    }

    return numBlocks;
}

// Compile-time dispatch:
// - if itemsPerThread is a multiple of 16, keep the vectorized fast path available and
//   choose it at runtime when the input pointer is aligned;
// - otherwise fall back to the scalar kernel unconditionally.
template <bool UseVectorizedFastPath>
struct launch_dispatch;

template <>
struct launch_dispatch<true> {
    static inline void launch(const char* input,
                              unsigned int* histogram,
                              unsigned int inputSize,
                              unsigned int from,
                              unsigned int numBins,
                              unsigned int smemStride,
                              size_t sharedMemBytes,
                              cudaStream_t stream)
    {
        // cudaMalloc() returns sufficiently aligned pointers, but callers may still pass
        // an offset pointer into a larger allocation. Use the fast path only when alignment
        // is preserved.
        const std::uintptr_t inputAddr =
            reinterpret_cast<std::uintptr_t>(input);
        const std::uintptr_t alignmentMask =
            static_cast<std::uintptr_t>(alignof(uint4) - 1u);

        if ((inputAddr & alignmentMask) == 0u) {
            const unsigned int numBlocks = compute_launch_blocks(
                histogram_kernel_vectorized<threadsPerBlock, itemsPerThread, histogramReplicas>,
                sharedMemBytes,
                inputSize);

            histogram_kernel_vectorized<
                threadsPerBlock, itemsPerThread, histogramReplicas>
                <<<numBlocks, threadsPerBlock, sharedMemBytes, stream>>>(
                    input, histogram, inputSize, from, numBins, smemStride);
        } else {
            const unsigned int numBlocks = compute_launch_blocks(
                histogram_kernel_scalar<threadsPerBlock, itemsPerThread, histogramReplicas>,
                sharedMemBytes,
                inputSize);

            histogram_kernel_scalar<
                threadsPerBlock, itemsPerThread, histogramReplicas>
                <<<numBlocks, threadsPerBlock, sharedMemBytes, stream>>>(
                    input, histogram, inputSize, from, numBins, smemStride);
        }
    }
};

template <>
struct launch_dispatch<false> {
    static inline void launch(const char* input,
                              unsigned int* histogram,
                              unsigned int inputSize,
                              unsigned int from,
                              unsigned int numBins,
                              unsigned int smemStride,
                              size_t sharedMemBytes,
                              cudaStream_t stream)
    {
        const unsigned int numBlocks = compute_launch_blocks(
            histogram_kernel_scalar<threadsPerBlock, itemsPerThread, histogramReplicas>,
            sharedMemBytes,
            inputSize);

        histogram_kernel_scalar<
            threadsPerBlock, itemsPerThread, histogramReplicas>
            <<<numBlocks, threadsPerBlock, sharedMemBytes, stream>>>(
                input, histogram, inputSize, from, numBins, smemStride);
    }
};

}  // namespace histogram_detail

void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    using namespace histogram_detail;

    const unsigned int fromU   = static_cast<unsigned int>(from);
    const unsigned int numBins = static_cast<unsigned int>(to - from) + 1u;

    // Round the logical histogram width up to a multiple of 32 and then add one extra slot.
    // This makes smemStride % 32 == 1, so the same logical bin in neighboring replicas is
    // shifted by one shared-memory bank each time.
    const unsigned int bankMask   = static_cast<unsigned int>(histogramReplicas - 1);
    const unsigned int smemStride = ((numBins + bankMask) & ~bankMask) + 1u;

    const size_t histogramBytes =
        static_cast<size_t>(numBins) * sizeof(unsigned int);
    const size_t sharedMemBytes =
        static_cast<size_t>(histogramReplicas) *
        static_cast<size_t>(smemStride) *
        sizeof(unsigned int);

    // The kernel merges per-block results into the global histogram with atomic adds,
    // so zero the output first. The API has no stream parameter; use the default stream
    // and leave synchronization/error observation to the caller as requested.
    cudaStream_t stream = 0;
    cudaMemsetAsync(histogram, 0, histogramBytes, stream);

    if (inputSize == 0u) {
        return;
    }

    launch_dispatch<vectorizedLoadPathAvailable>::launch(
        input,
        histogram,
        inputSize,
        fromU,
        numBins,
        smemStride,
        sharedMemBytes,
        stream);
}

#include <cuda_runtime.h>
#include <cstdint>

// Range-restricted byte histogram for a device-resident text buffer.
//
// histogram[bin] counts the number of input bytes whose unsigned ordinal value is
// (from + bin). Bytes outside [from, to] are ignored.
//
// Optimization strategy:
// 1) Each block accumulates into shared memory instead of hammering global memory.
// 2) Shared-memory histogram privatization uses 32 copies per block, indexed by warp lane.
//    This spreads hot-bin updates across the 32 shared-memory banks.
// 3) The distance between two copies is forced to an odd number of 32-bit words.
//    For same-bin updates from a warp, that makes the bank mapping a permutation mod 32,
//    removing the worst intra-warp bank-conflict pattern.
// 4) The grid is launched in a persistent-style configuration and walks the input with a
//    grid-stride loop, amortizing the final global reduction.
// 5) Full tiles use coalesced uchar4 vector loads; the rare partial tail tile falls back
//    to scalar loads.

constexpr int blockSize = 256;

// Requested tuning knob.
// 16 is a strong default on A100/H100-class GPUs for large inputs: enough ILP to
// cover latency, but still a modest register footprint for this atomic-heavy kernel.
constexpr int itemsPerThread = 16;

constexpr int warpLanes = 32;
constexpr int sharedHistCopies = warpLanes;

// Use 4-byte vector loads in the fast path.
using LoadType = uchar4;
constexpr int vectorWidth = sizeof(LoadType);

constexpr size_t tileCharsPerBlock =
    static_cast<size_t>(blockSize) * static_cast<size_t>(itemsPerThread);

static_assert(blockSize % warpLanes == 0, "blockSize must be a multiple of the warp size.");
static_assert(blockSize % vectorWidth == 0,
              "blockSize must preserve vector-load alignment across tiles.");

__host__ __device__ __forceinline__ int privatized_hist_stride(const int numBins)
{
    // Force an odd stride between histogram copies. With the per-lane copy layout
    // below, an odd stride makes copy->bank mapping a permutation modulo 32.
    return numBins | 1;
}

__device__ __forceinline__ void accumulate_byte(const unsigned int byteValue,
                                                const unsigned int lower,
                                                const unsigned int numBins,
                                                unsigned int *threadHist)
{
    // Unsigned subtraction + a single comparison handles both bounds at once.
    const unsigned int bin = byteValue - lower;
    if (bin < numBins) {
        atomicAdd(&threadHist[bin], 1u);
    }
}

__device__ __forceinline__ void accumulate_load(const LoadType packed,
                                                const unsigned int lower,
                                                const unsigned int numBins,
                                                unsigned int *threadHist)
{
    accumulate_byte(static_cast<unsigned int>(packed.x), lower, numBins, threadHist);
    accumulate_byte(static_cast<unsigned int>(packed.y), lower, numBins, threadHist);
    accumulate_byte(static_cast<unsigned int>(packed.z), lower, numBins, threadHist);
    accumulate_byte(static_cast<unsigned int>(packed.w), lower, numBins, threadHist);
}

__global__ __launch_bounds__(blockSize)
void histogram_range_kernel(const unsigned char *__restrict__ input,
                            unsigned int *__restrict__ histogram,
                            const unsigned int inputSize,
                            const unsigned int lower,
                            const unsigned int numBins)
{
    // Shared-memory layout:
    //   [copy 0][copy 1]...[copy 31]
    // Each thread updates the copy selected by its lane ID.
    // Different warps reuse the same lane-indexed copy set, which keeps shared memory
    // usage modest while removing the dominant intra-warp bank-conflict pattern.
    extern __shared__ unsigned int sHist[];

    const int tid = static_cast<int>(threadIdx.x);
    const int lane = tid & (warpLanes - 1);
    const unsigned int tidU = static_cast<unsigned int>(tid);
    const size_t tid64 = static_cast<size_t>(tid);

    const int stride = privatized_hist_stride(static_cast<int>(numBins));
    const int sharedWords = sharedHistCopies * stride;
    unsigned int *const threadHist = sHist + lane * stride;

    // Zero the block-private histograms.
    for (int i = tid; i < sharedWords; i += blockSize) {
        sHist[i] = 0u;
    }
    __syncthreads();

    constexpr int vecLoadsPerThread = itemsPerThread / vectorWidth;
    constexpr int scalarRemainder = itemsPerThread % vectorWidth;

    const size_t inputSize64 = static_cast<size_t>(inputSize);
    const size_t firstTileBase = static_cast<size_t>(blockIdx.x) * tileCharsPerBlock;
    const size_t gridStride = static_cast<size_t>(gridDim.x) * tileCharsPerBlock;

    // Full tiles can use vectorized loads when the input pointer itself is aligned.
    // A raw cudaMalloc buffer is aligned, but this extra check keeps the kernel correct
    // even if a caller passes an offset pointer into that buffer.
    const bool canVectorize =
        (reinterpret_cast<std::uintptr_t>(input) &
         static_cast<std::uintptr_t>(vectorWidth - 1)) == 0;

    const LoadType *const inputVec = reinterpret_cast<const LoadType *>(input);

    for (size_t tileBase = firstTileBase; tileBase < inputSize64; tileBase += gridStride) {
        if (canVectorize && tileBase + tileCharsPerBlock <= inputSize64) {
            // Fast path for a full tile: vector loads with no per-element bounds checks.
            const size_t tileBaseVec = tileBase / static_cast<size_t>(vectorWidth);

            #pragma unroll
            for (int vec = 0; vec < vecLoadsPerThread; ++vec) {
                const LoadType packed =
                    inputVec[tileBaseVec + static_cast<size_t>(vec) * blockSize + tid64];
                accumulate_load(packed, lower, numBins, threadHist);
            }

            const size_t scalarBase =
                tileBase +
                static_cast<size_t>(vecLoadsPerThread) * blockSize * static_cast<size_t>(vectorWidth);

            #pragma unroll
            for (int rem = 0; rem < scalarRemainder; ++rem) {
                const size_t idx = scalarBase + static_cast<size_t>(rem) * blockSize + tid64;
                accumulate_byte(static_cast<unsigned int>(input[idx]), lower, numBins, threadHist);
            }
        } else {
            // Tail path (or misaligned input pointer): scalar loads keep the fast path clean.
            #pragma unroll
            for (int item = 0; item < itemsPerThread; ++item) {
                const size_t idx = tileBase + static_cast<size_t>(item) * blockSize + tid64;
                if (idx < inputSize64) {
                    accumulate_byte(static_cast<unsigned int>(input[idx]), lower, numBins, threadHist);
                }
            }
        }
    }

    __syncthreads();

    // Reduce the 32 privatized copies into the final global histogram.
    for (unsigned int bin = tidU; bin < numBins; bin += blockSize) {
        unsigned int sum = 0u;

        #pragma unroll
        for (int copy = 0; copy < sharedHistCopies; ++copy) {
            sum += sHist[copy * stride + static_cast<int>(bin)];
        }

        if (sum != 0u) {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

static inline int ceil_div_size_t(const size_t x, const size_t y)
{
    return static_cast<int>(x / y + ((x % y) != 0));
}

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    const unsigned int lower = static_cast<unsigned int>(from);
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);

    // This function computes a fresh histogram, so clear the output first.
    // The caller requested that synchronization be handled externally; this function
    // only enqueues work on the default stream.
    cudaMemsetAsync(
        histogram, 0, static_cast<size_t>(numBins) * sizeof(unsigned int), 0);

    if (inputSize == 0u) {
        return;
    }

    const size_t sharedBytes =
        static_cast<size_t>(sharedHistCopies) *
        static_cast<size_t>(privatized_hist_stride(static_cast<int>(numBins))) *
        sizeof(unsigned int);

    // Persistent-style launch:
    // use roughly the number of concurrently resident blocks, then let each block
    // process many tiles through a grid-stride loop. This minimizes the number of
    // block-final global atomic reductions compared to launching one block per tile.
    int activeBlocksPerSM = 1;
    int queriedActiveBlocks = 0;
    if (cudaOccupancyMaxActiveBlocksPerMultiprocessor(
            &queriedActiveBlocks, histogram_range_kernel, blockSize, sharedBytes) == cudaSuccess &&
        queriedActiveBlocks > 0) {
        activeBlocksPerSM = queriedActiveBlocks;
    }

    int smCount = 1;
    int device = 0;
    if (cudaGetDevice(&device) == cudaSuccess) {
        int queriedSMs = 0;
        if (cudaDeviceGetAttribute(
                &queriedSMs, cudaDevAttrMultiProcessorCount, device) == cudaSuccess &&
            queriedSMs > 0) {
            smCount = queriedSMs;
        }
    }

    const int blocksNeeded =
        ceil_div_size_t(static_cast<size_t>(inputSize), tileCharsPerBlock);

    int gridSize = smCount * activeBlocksPerSM;
    if (gridSize < 1) {
        gridSize = 1;
    }
    if (gridSize > blocksNeeded) {
        gridSize = blocksNeeded;
    }

    histogram_range_kernel<<<gridSize, blockSize, sharedBytes, 0>>>(
        reinterpret_cast<const unsigned char *>(input),  // preserve byte ordinals 0..255
        histogram,
        inputSize,
        lower,
        numBins);
}

#include <cuda_runtime.h>

/*
  Range-restricted byte histogram for modern NVIDIA GPUs.

  Algorithm:
  1) Each thread block builds a private histogram in shared memory.
  2) To avoid shared-memory bank conflicts, every logical bin is replicated 32 times
     (one replica per warp lane) and the shared layout is transposed as [bin][lane].
     For 32-bit counters on the 32-bank shared memory used by A100/H100-class GPUs,
     bank = lane, independent of the bin value, so a warp update is bank-conflict free.
  3) After the block has processed all of its grid-stride tiles, the 32 replicas of each
     bin are reduced by a warp and atomically accumulated into the final global histogram.

  Tuning:
  - itemsPerThread controls how many input bytes each thread processes per tile.
  - Default = 16 because it maps naturally to one aligned 16-byte uint4 load per thread
    from cudaMalloc-aligned input, which is a strong default on recent data-center GPUs.
*/

namespace
{
constexpr int blockSize = 256;
constexpr int itemsPerThread = 16;
constexpr int histogramReplicaShift = 5;
constexpr int histogramReplicas = 1 << histogramReplicaShift;  // 32 replicas, one per warp lane.
constexpr int warpsPerBlock = blockSize / histogramReplicas;
constexpr int vectorBytes = sizeof(uint4);

static_assert(histogramReplicas == 32, "This kernel assumes 32-bank shared memory.");
static_assert(blockSize % histogramReplicas == 0, "blockSize must be a multiple of warp size.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert((itemsPerThread % vectorBytes) == 0,
              "itemsPerThread must be a multiple of 16 to preserve aligned uint4 loads.");

__device__ __forceinline__ void addByteToSharedHistogram(
    const unsigned int value,
    const unsigned int from,
    const unsigned int numBins,
    unsigned int* const laneHistogram)
{
    // Treat the input byte as an unsigned ordinal in [0, 255].
    // Unsigned subtraction followed by a single range check is cheaper than
    // two separate comparisons: values below 'from' underflow and fail the test.
    const unsigned int bin = value - from;
    if (bin < numBins)
    {
        // Shared-memory layout is [bin][lane], so for a fixed bin all 32 lanes in a warp
        // touch consecutive 32-bit words and therefore distinct banks.
        atomicAdd(laneHistogram + (bin << histogramReplicaShift), 1u);
    }
}

__device__ __forceinline__ void accumulatePackedWord(
    const unsigned int packed,
    const unsigned int from,
    const unsigned int numBins,
    unsigned int* const laneHistogram)
{
    addByteToSharedHistogram((packed >>  0) & 0xFFu, from, numBins, laneHistogram);
    addByteToSharedHistogram((packed >>  8) & 0xFFu, from, numBins, laneHistogram);
    addByteToSharedHistogram((packed >> 16) & 0xFFu, from, numBins, laneHistogram);
    addByteToSharedHistogram((packed >> 24) & 0xFFu, from, numBins, laneHistogram);
}

__device__ __forceinline__ void accumulateVector16(
    const uint4 packed16,
    const unsigned int from,
    const unsigned int numBins,
    unsigned int* const laneHistogram)
{
    accumulatePackedWord(packed16.x, from, numBins, laneHistogram);
    accumulatePackedWord(packed16.y, from, numBins, laneHistogram);
    accumulatePackedWord(packed16.z, from, numBins, laneHistogram);
    accumulatePackedWord(packed16.w, from, numBins, laneHistogram);
}

__global__ __launch_bounds__(blockSize, 4)
void histogramKernel(
    const char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    const unsigned int inputSize,
    const int from,
    const int to)
{
    // Dynamic shared memory holds numBins * 32 counters, laid out as [bin][lane].
    extern __shared__ unsigned int sharedHistogram[];

    const unsigned int lane = threadIdx.x & (histogramReplicas - 1);
    const unsigned int warpId = threadIdx.x >> histogramReplicaShift;

    const unsigned int fromU = static_cast<unsigned int>(from);
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);
    const unsigned int numSharedCounters = numBins << histogramReplicaShift;

    // Each thread writes the counters for its lane at indices:
    // laneHistogram[bin << 5] == sharedHistogram[(bin << 5) + lane]
    unsigned int* const laneHistogram = sharedHistogram + lane;

    // Zero the block-private histogram.
    for (unsigned int i = threadIdx.x; i < numSharedCounters; i += blockSize)
    {
        sharedHistogram[i] = 0u;
    }
    __syncthreads();

    // Input is guaranteed to come from cudaMalloc according to the problem statement,
    // so the base pointer is highly aligned. Because itemsPerThread is a multiple of 16
    // and each thread processes a contiguous chunk, all vector loads stay 16-byte aligned.
    const unsigned char* const inputBytes = reinterpret_cast<const unsigned char*>(input);
    const uint4* const inputVec4 = reinterpret_cast<const uint4*>(input);

    const size_t inputSizeZ = static_cast<size_t>(inputSize);
    const size_t blockWork = static_cast<size_t>(blockSize) * static_cast<size_t>(itemsPerThread);
    const size_t gridStride = static_cast<size_t>(gridDim.x) * blockWork;

    // Thread t in a block starts at a contiguous chunk of itemsPerThread bytes.
    size_t base =
        static_cast<size_t>(blockIdx.x) * blockWork +
        static_cast<size_t>(threadIdx.x) * static_cast<size_t>(itemsPerThread);

    // Fast path for full chunks: vectorized 16-byte loads.
    if (inputSizeZ >= static_cast<size_t>(itemsPerThread))
    {
        const size_t lastFullBase = inputSizeZ - static_cast<size_t>(itemsPerThread);
        for (; base <= lastFullBase; base += gridStride)
        {
#pragma unroll
            for (int offset = 0; offset < itemsPerThread; offset += vectorBytes)
            {
                const uint4 packed16 = inputVec4[(base + static_cast<size_t>(offset)) >> 4];
                accumulateVector16(packed16, fromU, numBins, laneHistogram);
            }
        }
    }

    // Tail path: at most one partial chunk per thread.
    if (base < inputSizeZ)
    {
#pragma unroll
        for (int i = 0; i < itemsPerThread; ++i)
        {
            const size_t idx = base + static_cast<size_t>(i);
            if (idx < inputSizeZ)
            {
                addByteToSharedHistogram(
                    static_cast<unsigned int>(inputBytes[idx]),
                    fromU,
                    numBins,
                    laneHistogram);
            }
        }
    }

    __syncthreads();

    // Reduce the 32 per-lane replicas of each bin with one warp per logical bin.
    // The read pattern is also bank-conflict free because sharedHistogram[(bin << 5) + lane]
    // maps lane k to bank k.
    for (unsigned int bin = warpId; bin < numBins; bin += warpsPerBlock)
    {
        const unsigned int localCount = sharedHistogram[(bin << histogramReplicaShift) + lane];
        const unsigned int blockCount = __reduce_add_sync(0xFFFFFFFFu, localCount);

        if (lane == 0 && blockCount != 0u)
        {
            // When only one block is launched, the global atomic is unnecessary.
            if (gridDim.x == 1)
            {
                histogram[bin] = blockCount;
            }
            else
            {
                atomicAdd(histogram + bin, blockCount);
            }
        }
    }
}
}  // namespace

void run_histogram(
    const char* input,
    unsigned int* histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    // The problem statement guarantees a valid range, but a cheap guard avoids
    // accidental misuse from causing invalid shared-memory sizing.
    if (from < 0 || to > 255 || from > to)
    {
        return;
    }

    const int numBins = to - from + 1;

    // The output buffer is defined as the final histogram, not an accumulator,
    // so clear it asynchronously before the kernel launch.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(numBins) * sizeof(unsigned int));

    // Nothing else to do for empty input; the asynchronous memset already produced
    // the correct all-zero histogram.
    if (inputSize == 0)
    {
        return;
    }

    const size_t sharedBytes =
        static_cast<size_t>(numBins) * static_cast<size_t>(histogramReplicas) * sizeof(unsigned int);

    // This kernel is shared-memory heavy and streams the input, so preferring shared
    // memory over L1 is the right default on recent architectures.
    cudaFuncSetAttribute(histogramKernel, cudaFuncAttributePreferredSharedMemoryCarveout, 100);

    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    int blocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &blocksPerSM,
        histogramKernel,
        blockSize,
        sharedBytes);

    if (blocksPerSM < 1)
    {
        blocksPerSM = 1;
    }

    const size_t blockWork = static_cast<size_t>(blockSize) * static_cast<size_t>(itemsPerThread);
    const size_t neededBlocks =
        (static_cast<size_t>(inputSize) + blockWork - 1) / blockWork;

    // The kernel uses a grid-stride loop, so launching only the number of blocks that
    // can reside concurrently is typically best: it keeps all SMs busy while minimizing
    // block-finalization overhead and the number of global atomics in the final merge.
    int gridSize = smCount * blocksPerSM;
    if (gridSize > static_cast<int>(neededBlocks))
    {
        gridSize = static_cast<int>(neededBlocks);
    }
    if (gridSize < 1)
    {
        gridSize = 1;
    }

    histogramKernel<<<gridSize, blockSize, sharedBytes>>>(
        input,
        histogram,
        inputSize,
        from,
        to);
}

#include <cuda_runtime.h>

namespace {

// Range-restricted byte histogram.
// Output bin i counts the occurrences of byte value (from + i).
//
// Tuning choices aimed at large inputs on modern NVIDIA data-center GPUs:
//   - blockThreads = 256: good balance between occupancy and intra-block contention.
//   - itemsPerThread = 16: one aligned 16-byte vector load (`uint4`) per full iteration.
//   - sharedHistogramCopies = 32: one shared histogram replica per warp lane.
//     With an odd replica stride, the same logical bin in consecutive replicas maps to
//     different shared-memory banks, eliminating intra-warp bank conflicts for hot bins.
//   - Grid-stride processing: launch only an occupancy-sized wave of blocks and let each
//     block iterate over the input, which keeps reduction traffic to global memory low.
constexpr int blockThreads = 256;
constexpr int itemsPerThread = 16;
constexpr int sharedHistogramCopies = 32;
constexpr int minBlocksPerSM = 4;
constexpr int vectorLoadBytes = static_cast<int>(sizeof(uint4));

static_assert(blockThreads > 0, "blockThreads must be positive.");
static_assert((blockThreads & 31) == 0, "blockThreads must be a multiple of 32.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert((itemsPerThread % vectorLoadBytes) == 0,
              "itemsPerThread must be a multiple of 16 to preserve aligned uint4 loads.");
static_assert((sharedHistogramCopies & (sharedHistogramCopies - 1)) == 0,
              "sharedHistogramCopies must be a power of two.");
static_assert(sharedHistogramCopies == 32,
              "This kernel is tuned for modern NVIDIA GPUs with 32-lane warps and 32 shared-memory banks.");

__host__ __device__ __forceinline__
unsigned int paddedHistStride(const unsigned int numBins) {
    // Smallest odd stride >= numBins.
    //
    // Shared-memory bank selection is address modulo 32. If the stride between
    // consecutive histogram replicas is odd, it is coprime with 32, so for any
    // logical bin `b` the addresses
    //   b, b + stride, b + 2*stride, ..., b + 31*stride
    // hit all 32 banks exactly once. This is the key bank-conflict avoidance trick.
    return numBins | 1u;
}

__device__ __forceinline__
void addByteToSharedReplica(const unsigned int value,
                            unsigned int* const replica,
                            const unsigned int from,
                            const unsigned int numBins) {
    // Inclusive range check written as subtract + unsigned compare.
    const unsigned int bin = value - from;
    if (bin < numBins) {
        atomicAdd(replica + bin, 1u);
    }
}

__device__ __forceinline__
void addPackedWordToSharedReplica(const unsigned int packed,
                                  unsigned int* const replica,
                                  const unsigned int from,
                                  const unsigned int numBins) {
    addByteToSharedReplica((packed      ) & 0xFFu, replica, from, numBins);
    addByteToSharedReplica((packed >>  8) & 0xFFu, replica, from, numBins);
    addByteToSharedReplica((packed >> 16) & 0xFFu, replica, from, numBins);
    addByteToSharedReplica((packed >> 24) & 0xFFu, replica, from, numBins);
}

__launch_bounds__(blockThreads, minBlocksPerSM)
__global__
void histogramKernel(const char* __restrict__ input,
                     unsigned int* __restrict__ histogram,
                     unsigned int inputSize,
                     int from,
                     int to) {
    extern __shared__ unsigned int sharedHist[];

    const unsigned int blockThreadsU = static_cast<unsigned int>(blockThreads);
    const unsigned int itemsPerThreadU = static_cast<unsigned int>(itemsPerThread);
    const unsigned int fromU = static_cast<unsigned int>(from);
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);
    const unsigned int stride = paddedHistStride(numBins);
    const unsigned int totalSharedWords =
        static_cast<unsigned int>(sharedHistogramCopies) * stride;

    // Replica selection by lane id. Because there are 32 replicas, the low 5 bits of
    // threadIdx.x choose the copy. Threads in the same warp therefore update different
    // replicas for the same logical bin.
    const unsigned int copyId =
        threadIdx.x & static_cast<unsigned int>(sharedHistogramCopies - 1);
    unsigned int* const replica = sharedHist + copyId * stride;

    // Cooperative initialization of all histogram replicas.
    for (unsigned int i = threadIdx.x; i < totalSharedWords; i += blockThreadsU) {
        sharedHist[i] = 0u;
    }
    __syncthreads();

    // Interpret input as unsigned bytes so ordinal values 128..255 are handled correctly
    // even if plain `char` is signed.
    const unsigned char* const bytes =
        reinterpret_cast<const unsigned char*>(input);

    // Grid-stride loop over large inputs. The host intentionally launches only enough
    // blocks to saturate the GPU; this loop lets those blocks cover the full buffer.
    const unsigned int threadBase =
        (blockIdx.x * blockThreadsU + threadIdx.x) * itemsPerThreadU;
    const unsigned int gridStride =
        gridDim.x * blockThreadsU * itemsPerThreadU;

    for (unsigned int index = threadBase; index < inputSize; index += gridStride) {
        const unsigned int remaining = inputSize - index;

        if (remaining >= itemsPerThreadU) {
            // Full chunk: aligned vector loads. cudaMalloc provides sufficient base
            // alignment, and the per-thread offset is always a multiple of 16 because
            // itemsPerThread is constrained to multiples of sizeof(uint4).
            const uint4* const vec =
                reinterpret_cast<const uint4*>(bytes + index);

            #pragma unroll
            for (int i = 0; i < itemsPerThread / vectorLoadBytes; ++i) {
                const uint4 v = vec[i];
                addPackedWordToSharedReplica(v.x, replica, fromU, numBins);
                addPackedWordToSharedReplica(v.y, replica, fromU, numBins);
                addPackedWordToSharedReplica(v.z, replica, fromU, numBins);
                addPackedWordToSharedReplica(v.w, replica, fromU, numBins);
            }
        } else {
            // Tail handling for the last partial chunk assigned to this thread.
            #pragma unroll
            for (int i = 0; i < itemsPerThread; ++i) {
                if (static_cast<unsigned int>(i) < remaining) {
                    addByteToSharedReplica(bytes[index + static_cast<unsigned int>(i)],
                                           replica,
                                           fromU,
                                           numBins);
                }
            }
        }
    }
    __syncthreads();

    // Reduce the 32 replicas into the final global histogram. Only one global atomic
    // per bin and block remains; all per-byte updates stayed local to shared memory.
    for (unsigned int bin = threadIdx.x; bin < numBins; bin += blockThreadsU) {
        unsigned int sum = 0u;
        const unsigned int* ptr = sharedHist + bin;

        #pragma unroll
        for (int copy = 0; copy < sharedHistogramCopies; ++copy) {
            sum += *ptr;
            ptr += stride;
        }

        if (sum != 0u) {
            atomicAdd(histogram + bin, sum);
        }
    }
}

} // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    // The problem statement guarantees a valid inclusive range:
    //   0 <= from < to <= 255
    // Output bin 0 corresponds to byte value `from`.
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes =
        static_cast<size_t>(numBins) * sizeof(unsigned int);

    // Enqueue the output clear on the default stream. The caller explicitly owns any
    // synchronization policy, so this function remains asynchronous with respect to host.
    cudaMemsetAsync(histogram, 0, histogramBytes, 0);

    if (inputSize == 0u) {
        return;
    }

    const unsigned int stride = paddedHistStride(numBins);
    const size_t sharedMemBytes =
        static_cast<size_t>(sharedHistogramCopies) *
        static_cast<size_t>(stride) *
        sizeof(unsigned int);

    // Launch just enough blocks to fill the machine for the current shared-memory
    // footprint. Launching many more blocks would only increase the final global
    // reduction traffic because the kernel already uses a grid-stride loop.
    int device = 0;
    cudaGetDevice(&device);

    int smCount = 1;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1) {
        smCount = 1;
    }

    int activeBlocksPerSM = 1;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM,
        histogramKernel,
        blockThreads,
        sharedMemBytes);
    if (activeBlocksPerSM < 1) {
        activeBlocksPerSM = 1;
    }

    int gridSize = smCount * activeBlocksPerSM;

    const size_t blockWork =
        static_cast<size_t>(blockThreads) * static_cast<size_t>(itemsPerThread);
    const size_t blocksNeeded =
        (static_cast<size_t>(inputSize) + blockWork - 1u) / blockWork;

    if (static_cast<size_t>(gridSize) > blocksNeeded) {
        gridSize = static_cast<int>(blocksNeeded);
    }
    if (gridSize < 1) {
        gridSize = 1;
    }

    histogramKernel<<<gridSize, blockThreads, sharedMemBytes, 0>>>(
        input,
        histogram,
        inputSize,
        from,
        to);

    // No synchronization and no explicit error handling here by design:
    // the fixed signature returns void, and the caller owns sync/error policy.
}

#include <cuda_runtime.h>

namespace {

// Range-restricted byte histogram with block-private shared-memory accumulation.
// Input bytes are treated as raw unsigned ordinals [0, 255], independent of the
// signedness of plain 'char' on the host.
//
// Shared-memory privatization / bank-conflict avoidance:
//   * Each block owns 32 logical histogram copies: one copy per warp lane.
//   * Physical layout is transposed as shared[bin][laneCopy], flattened as
//       shared[(bin << histogramCopyShift) + laneCopy].
//   * Shared memory has 32 banks and the counters are 32-bit, so the bank index is
//       ((bin * 32) + laneCopy) % 32 == laneCopy.
//     Therefore every lane in a warp always hits a distinct bank, even when the
//     entire warp updates the same bin. This completely removes intra-warp bank
//     conflicts while preserving 32 independent copies per block as requested.
//
// Kernel tuning choices for modern data-center GPUs (A100/H100):
//   * blockThreads = 256 is a strong balance between occupancy and shared-atomic
//     contention within a block.
//   * itemsPerThread = 16 is a good large-input default: it amortizes loop/index
//     overhead and maps naturally to one aligned 16-byte vector load (uint4) per
//     thread on the hot path. If retuned, keeping it a multiple of 16 preserves
//     the vectorized load path automatically.
constexpr int histogramCopies    = 32;
constexpr int histogramCopyShift = 5;
constexpr int blockThreads       = 256;
constexpr int warpsPerBlock      = blockThreads / histogramCopies;
constexpr int itemsPerThread     = 16;

constexpr int vectorBytes = static_cast<int>(sizeof(uint4));  // 16 bytes
constexpr int vectorLoads = itemsPerThread / vectorBytes;
constexpr bool useVectorLoads = (itemsPerThread % vectorBytes) == 0;

static_assert(histogramCopies == 32, "This implementation assumes one shared histogram copy per warp lane.");
static_assert((1 << histogramCopyShift) == histogramCopies, "histogramCopyShift must match histogramCopies.");
static_assert((blockThreads % histogramCopies) == 0, "blockThreads must be a multiple of 32.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert(vectorBytes == 16, "uint4 is expected to be 16 bytes.");

__device__ __forceinline__ unsigned int warp_reduce_sum(unsigned int v) {
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
        v += __shfl_down_sync(0xffffffffu, v, offset);
    }
    return v;
}

__device__ __forceinline__ void add_byte(unsigned int* __restrict__ sharedHist,
                                         unsigned int lane,
                                         unsigned int byteValue,
                                         unsigned int from,
                                         unsigned int numBins) {
    const unsigned int bin = byteValue - from;
    if (bin < numBins) {
        atomicAdd(sharedHist + (bin << histogramCopyShift) + lane, 1u);
    }
}

__device__ __forceinline__ void add_word(unsigned int* __restrict__ sharedHist,
                                         unsigned int lane,
                                         unsigned int word,
                                         unsigned int from,
                                         unsigned int numBins) {
    add_byte(sharedHist, lane,  word        & 0xffu, from, numBins);
    add_byte(sharedHist, lane, (word >> 8)  & 0xffu, from, numBins);
    add_byte(sharedHist, lane, (word >> 16) & 0xffu, from, numBins);
    add_byte(sharedHist, lane, (word >> 24) & 0xffu, from, numBins);
}

__device__ __forceinline__ void add_uint4(unsigned int* __restrict__ sharedHist,
                                          unsigned int lane,
                                          uint4 v,
                                          unsigned int from,
                                          unsigned int numBins) {
    add_word(sharedHist, lane, v.x, from, numBins);
    add_word(sharedHist, lane, v.y, from, numBins);
    add_word(sharedHist, lane, v.z, from, numBins);
    add_word(sharedHist, lane, v.w, from, numBins);
}

__global__ __launch_bounds__(blockThreads)
void histogram_kernel(const unsigned char* __restrict__ input,
                      unsigned int* __restrict__ histogram,
                      unsigned int inputSize,
                      unsigned int from,
                      unsigned int numBins) {
    extern __shared__ unsigned int sharedHist[];

    const unsigned int lane   = threadIdx.x & (histogramCopies - 1);
    const unsigned int warpId = threadIdx.x >> histogramCopyShift;

    const size_t inputSizeZ = static_cast<size_t>(inputSize);
    const size_t sharedCount = static_cast<size_t>(numBins) * histogramCopies;

    // Zero the block-private shared histogram copies.
    for (size_t i = threadIdx.x; i < sharedCount; i += blockThreads) {
        sharedHist[i] = 0u;
    }
    __syncthreads();

    const size_t tileSize    = static_cast<size_t>(blockThreads) * itemsPerThread;
    const size_t gridStride  = static_cast<size_t>(gridDim.x) * tileSize;
    const size_t threadBase0 = static_cast<size_t>(threadIdx.x) * itemsPerThread;

    // Grid-stride over block-sized tiles. Each thread consumes itemsPerThread bytes
    // from its tile, accumulating into the block-private shared histogram.
    for (size_t blockBase = static_cast<size_t>(blockIdx.x) * tileSize;
         blockBase < inputSizeZ;
         blockBase += gridStride) {
        const size_t threadBase = blockBase + threadBase0;
        if (threadBase >= inputSizeZ) {
            continue;
        }

        const size_t remaining = inputSizeZ - threadBase;
        const unsigned char* threadPtr = input + threadBase;

        if (useVectorLoads) {
            if (remaining >= static_cast<size_t>(itemsPerThread)) {
                // Fast path: full per-thread chunk. With the prompt's cudaMalloc
                // contract and itemsPerThread == 16 by default, this becomes one
                // aligned uint4 load per thread.
                const uint4* vectorPtr = reinterpret_cast<const uint4*>(threadPtr);
                #pragma unroll
                for (int chunk = 0; chunk < vectorLoads; ++chunk) {
                    add_uint4(sharedHist, lane, vectorPtr[chunk], from, numBins);
                }
            } else {
                // Final partial chunk.
                #pragma unroll
                for (int i = 0; i < itemsPerThread; ++i) {
                    if (static_cast<size_t>(i) < remaining) {
                        add_byte(sharedHist, lane, threadPtr[i], from, numBins);
                    }
                }
            }
        } else {
            // Scalar fallback for non-16-byte-multiple retunings of itemsPerThread.
            if (remaining >= static_cast<size_t>(itemsPerThread)) {
                #pragma unroll
                for (int i = 0; i < itemsPerThread; ++i) {
                    add_byte(sharedHist, lane, threadPtr[i], from, numBins);
                }
            } else {
                #pragma unroll
                for (int i = 0; i < itemsPerThread; ++i) {
                    if (static_cast<size_t>(i) < remaining) {
                        add_byte(sharedHist, lane, threadPtr[i], from, numBins);
                    }
                }
            }
        }
    }

    __syncthreads();

    // Fold the 32 lane-private copies back into one per-bin block result.
    // Each warp reduces one bin at a time across its 32 lanes, then atomically
    // accumulates into the final global histogram. This limits expensive global
    // atomics to one per non-zero bin per block.
    for (unsigned int bin = warpId; bin < numBins; bin += warpsPerBlock) {
        const unsigned int partial = sharedHist[(bin << histogramCopyShift) + lane];
        const unsigned int total = warp_reduce_sum(partial);
        if (lane == 0 && total != 0u) {
            atomicAdd(histogram + bin, total);
        }
    }
}

}  // namespace

void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);

    // The output histogram is defined for exactly this invocation, so zero it first.
    // This is asynchronous; the caller explicitly handles synchronization.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(numBins) * sizeof(unsigned int));

    if (inputSize == 0u) {
        return;
    }

    const size_t sharedBytes =
        static_cast<size_t>(numBins) * histogramCopies * sizeof(unsigned int);

    // Launch only enough CTAs to fill all currently resident slots at this shared-
    // memory footprint. The kernel grid-strides over the rest of the input, so extra
    // CTAs would not increase steady-state occupancy; they would only increase the
    // final global-atomic flush traffic.
    int device = 0;
    int smCount = 1;
    int activeBlocksPerSm = 1;
    cudaGetDevice(&device);
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSm,
        histogram_kernel,
        blockThreads,
        sharedBytes);

    if (smCount < 1) {
        smCount = 1;
    }
    if (activeBlocksPerSm < 1) {
        activeBlocksPerSm = 1;
    }

    const unsigned int tileItems = blockThreads * itemsPerThread;
    const unsigned int blocksNeeded = (inputSize + tileItems - 1u) / tileItems;
    const int maxResidentGrid = smCount * activeBlocksPerSm;

    int grid = static_cast<int>(blocksNeeded);
    if (grid < 1) {
        grid = 1;
    }
    if (grid > maxResidentGrid) {
        grid = maxResidentGrid;
    }

    // Reinterpret the char buffer as raw unsigned bytes so ordinal values are always
    // in the expected 0..255 range regardless of host-side char signedness.
    histogram_kernel<<<grid, blockThreads, sharedBytes>>>(
        reinterpret_cast<const unsigned char*>(input),
        histogram,
        inputSize,
        static_cast<unsigned int>(from),
        numBins);
}

#include <cuda_runtime.h>

// Range-restricted byte histogram for GPU-resident text buffers.
//
// Tuning rationale for A100/H100-class GPUs:
// - blockSize = 256: good balance between occupancy and shared-atomic contention.
// - itemsPerThread = 16: enough work per thread to amortize per-CTA setup/finalization
//   on large inputs, while keeping register pressure modest.
// - CTA-private shared histogram: absorbs the high-rate per-character increments.
// - 32 replicas per bin (one per warp lane): for bin b and lane l, the counter lives at
//   sharedHistogram[b * 32 + l]. This is conceptually 32 histograms with a stride of 32
//   counters between consecutive bins. A thread in lane l therefore always hits bank l,
//   eliminating intra-warp bank conflicts on updates.
// - Warp-level final reduction: one warp reduces the 32 replicas of a bin conflict-free
//   and emits a single global atomicAdd.
// - Worst-case shared footprint is 256 bins * 32 replicas * 4 B = 32 KB per CTA.

constexpr int blockSize = 256;
constexpr int minBlocksPerSm = 4;
constexpr int itemsPerThread = 16;

constexpr int histogramReplicas = 32;
constexpr int histogramReplicaShift = 5;
constexpr int warpsPerBlock = blockSize / histogramReplicas;

constexpr int vectorWidthBytes = 4;  // uchar4
constexpr int vectorsPerThread = itemsPerThread / vectorWidthBytes;
constexpr unsigned int fullWarpMask = 0xffffffffu;
constexpr unsigned int tileCharsPerBlock = static_cast<unsigned int>(blockSize * itemsPerThread);

static_assert(blockSize % histogramReplicas == 0, "blockSize must be a whole number of warps.");
static_assert(histogramReplicas == (1 << histogramReplicaShift), "Replica shift must match replica count.");
static_assert(itemsPerThread % vectorWidthBytes == 0, "itemsPerThread must be a multiple of 4 for uchar4 loads.");

static __device__ __forceinline__
void update_lane_private_hist(unsigned int* laneReplica,
                              unsigned int symbol,
                              unsigned int from,
                              unsigned int bins)
{
    const unsigned int bin = symbol - from;
    if (bin < bins) {
        // All warps in the CTA share the same 32 replicas, so shared-memory atomicAdd
        // is still required to resolve inter-warp collisions. Within a warp, however,
        // each lane touches a different bank because replica index == lane index.
        atomicAdd(laneReplica + (bin << histogramReplicaShift), 1u);
    }
}

static __device__ __forceinline__
void update_lane_private_hist4(unsigned int* laneReplica,
                               const uchar4 packed,
                               unsigned int from,
                               unsigned int bins)
{
    update_lane_private_hist(laneReplica, static_cast<unsigned int>(packed.x), from, bins);
    update_lane_private_hist(laneReplica, static_cast<unsigned int>(packed.y), from, bins);
    update_lane_private_hist(laneReplica, static_cast<unsigned int>(packed.z), from, bins);
    update_lane_private_hist(laneReplica, static_cast<unsigned int>(packed.w), from, bins);
}

static __device__ __forceinline__
unsigned int warp_reduce_sum(unsigned int value)
{
    #pragma unroll
    for (int offset = histogramReplicas / 2; offset > 0; offset >>= 1) {
        value += __shfl_down_sync(fullWarpMask, value, offset);
    }
    return value;
}

__global__ __launch_bounds__(blockSize, minBlocksPerSm)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from,
                            unsigned int bins)
{
    extern __shared__ unsigned int sharedHistogram[];

    const unsigned int lane = threadIdx.x & static_cast<unsigned int>(histogramReplicas - 1);
    const unsigned int warpId = threadIdx.x >> histogramReplicaShift;

    // Conceptually there are 32 per-CTA histograms. Physically they are interleaved by bin:
    //   [bin0: rep0..rep31][bin1: rep0..rep31]...
    // Replica `lane` is therefore the strided view sharedHistogram[lane + 32 * bin].
    unsigned int* const laneReplica = sharedHistogram + lane;

    // Treat the input as bytes so chars 128..255 are handled correctly even if `char` is signed.
    const unsigned char* const inputBytes = reinterpret_cast<const unsigned char*>(input);

    const unsigned int sharedCounterCount = bins << histogramReplicaShift;

    // Cooperative zeroing of the CTA-private histogram.
    for (unsigned int i = threadIdx.x; i < sharedCounterCount; i += blockSize) {
        sharedHistogram[i] = 0u;
    }
    __syncthreads();

    const size_t tileSize = static_cast<size_t>(tileCharsPerBlock);
    const size_t gridStride = tileSize * gridDim.x;
    const size_t inputSize64 = static_cast<size_t>(inputSize);

    // Persistent grid-stride loop over 4 KB tiles (with the default tuning).
    for (size_t base = static_cast<size_t>(blockIdx.x) * tileSize; base < inputSize64; base += gridStride) {
        const size_t remaining = inputSize64 - base;
        const unsigned char* const tileInput = inputBytes + base;

        if (remaining >= tileSize) {
            // Full-tile fast path.
            // Because the buffer comes from cudaMalloc and base advances in multiples of tileSize,
            // tileInput is 4-byte aligned here, so uchar4 loads are safe.
            // Each vector iteration makes a warp read 32 consecutive uchar4 values = 128 bytes,
            // which is naturally coalesced.
            const uchar4* const vectorInput = reinterpret_cast<const uchar4*>(tileInput);

            #pragma unroll
            for (int v = 0; v < vectorsPerThread; ++v) {
                const uchar4 packed = vectorInput[v * blockSize + threadIdx.x];
                update_lane_private_hist4(laneReplica, packed, from, bins);
            }
        } else {
            // Tail cleanup for the last partial tile handled by this CTA.
            #pragma unroll
            for (int item = 0; item < itemsPerThread; ++item) {
                const unsigned int localIndex = threadIdx.x + item * blockSize;
                if (localIndex < remaining) {
                    update_lane_private_hist(
                        laneReplica,
                        static_cast<unsigned int>(tileInput[localIndex]),
                        from,
                        bins);
                }
            }
        }
    }

    __syncthreads();

    // Final CTA reduction. One warp reduces one bin at a time:
    // lane L reads replica L of the bin, so the shared-memory reads are again bank-conflict free.
    for (unsigned int bin = warpId; bin < bins; bin += warpsPerBlock) {
        const unsigned int partial = sharedHistogram[(bin << histogramReplicaShift) + lane];
        const unsigned int sum = warp_reduce_sum(partial);

        if (lane == 0u && sum != 0u) {
            // One global atomic add per bin per CTA.
            atomicAdd(histogram + bin, sum);
        }
    }
}

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    const unsigned int fromValue = static_cast<unsigned int>(from);
    const unsigned int bins = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes = static_cast<size_t>(bins) * sizeof(unsigned int);

    // The output represents counts, not increments, so clear it before launching the kernel.
    // This is asynchronous with respect to the host and ordered before the kernel in stream 0.
    cudaMemsetAsync(histogram, 0, histogramBytes, 0);

    if (inputSize == 0u) {
        return;
    }

    const size_t sharedBytes =
        static_cast<size_t>(bins) * static_cast<size_t>(histogramReplicas) * sizeof(unsigned int);

    // Persistent-style launch: start roughly as many CTAs as can be resident, then let each CTA
    // grid-stride over the input. This minimizes the number of per-CTA histogram initializations
    // and final global reductions while still filling the GPU.
    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    int activeBlocksPerSm = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSm,
        histogram_range_kernel,
        blockSize,
        sharedBytes);

    const size_t numTiles =
        (static_cast<size_t>(inputSize) + static_cast<size_t>(tileCharsPerBlock) - 1u) /
        static_cast<size_t>(tileCharsPerBlock);

    const unsigned int sms = (smCount > 0) ? static_cast<unsigned int>(smCount) : 1u;
    const unsigned int residentBlocks =
        sms * ((activeBlocksPerSm > 0) ? static_cast<unsigned int>(activeBlocksPerSm) : 1u);

    const int gridSize = static_cast<int>(
        (numTiles < static_cast<size_t>(residentBlocks)) ? numTiles : residentBlocks);

    histogram_range_kernel<<<gridSize, blockSize, sharedBytes, 0>>>(
        input,
        histogram,
        inputSize,
        fromValue,
        bins);

    // No synchronization here by design; the caller owns stream/device synchronization.
}

#include <cuda_runtime.h>

// Range-restricted byte histogram optimized for modern NVIDIA data-center GPUs
// (A100/H100 class: 32-lane warps, 32-bank shared memory).
//
// Performance strategy:
// - Each thread block builds a private histogram in shared memory, then merges once to global
//   memory. This drastically reduces global atomic pressure versus directly atomically updating
//   the output histogram for every input byte.
// - To avoid shared-memory bank conflicts, the block-private histogram is replicated 32 times:
//   one logical copy per warp lane. The layout is transposed as [bin][lane], i.e.
//       shared[(bin << 5) + lane]
//   rather than [lane][bin]. For 4-byte counters on 32-bank shared memory, bank = index % 32,
//   so lane l always maps to bank l. This makes same-instruction accesses from a warp
//   bank-conflict-free, independent of the histogram range size.
// - Threads from different warps but with the same lane ID share the same copy. Correctness
//   across warps is provided by shared-memory atomicAdd; the 32-copy scheme specifically removes
//   intra-warp bank conflicts as requested.
// - Only the requested [from, to] sub-histogram is privatized in shared memory, not a full
//   256-bin histogram. Narrower ranges therefore use less shared memory and can run at higher
//   occupancy.
// - The final merge uses warp-level reduction: each lane loads one of the 32 copies for a bin,
//   the warp sums the 32 values with shuffle-down, and lane 0 performs one global atomicAdd.
//
// Tuning notes:
// - itemsPerThread = 16 is a good default for large text buffers on recent GPUs. It enables
//   the aligned 128-bit load fast path (thanks to cudaMalloc alignment) while keeping register
//   pressure modest.
// - kBlockSize = 256 (8 warps/block) is a good compromise between latency hiding and contention
//   on the 32 lane-owned shared histogram copies.
// - The host launcher caps the effective launch at 4 resident blocks/SM. That is usually enough
//   to saturate A100/H100-class GPUs for this kernel while avoiding unnecessary block-level
//   partial histograms that would increase the final global merge traffic.

constexpr int itemsPerThread      = 16;
constexpr int kBlockSize          = 256;
constexpr int kHistogramCopies    = 32;
constexpr int kHistogramCopiesLog2 = 5;   // 32 == 1 << 5
constexpr int kTargetBlocksPerSM  = 4;
constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;

static_assert(kHistogramCopies == 32, "This implementation intentionally uses exactly 32 shared histogram copies.");
static_assert((1 << kHistogramCopiesLog2) == kHistogramCopies, "kHistogramCopiesLog2 must match kHistogramCopies.");
static_assert(kBlockSize % kHistogramCopies == 0, "kBlockSize must be a multiple of 32.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");

__device__ __forceinline__ unsigned int warp_reduce_sum_u32(unsigned int value)
{
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
        value += __shfl_down_sync(kFullWarpMask, value, offset);
    }
    return value;
}

// Update one byte into the lane-owned shared histogram copy.
// The range test uses unsigned arithmetic so that
//     (c >= from && c < from + rangeSize)
// becomes one subtraction plus one compare.
__device__ __forceinline__ void update_shared_hist(unsigned int c,
                                                   unsigned int from,
                                                   unsigned int rangeSize,
                                                   unsigned int lane,
                                                   unsigned int* __restrict__ sharedHist)
{
    const unsigned int bin = c - from;
    if (bin < rangeSize) {
        atomicAdd(&sharedHist[(bin << kHistogramCopiesLog2) + lane], 1u);
    }
}

// Count four bytes loaded as one packed 32-bit word. Histogramming is order-independent,
// so we only need the four byte values, not their original order in memory.
__device__ __forceinline__ void process_packed4(unsigned int packed,
                                                unsigned int from,
                                                unsigned int rangeSize,
                                                unsigned int lane,
                                                unsigned int* __restrict__ sharedHist)
{
    update_shared_hist( packed        & 0xFFu, from, rangeSize, lane, sharedHist);
    update_shared_hist((packed >>  8) & 0xFFu, from, rangeSize, lane, sharedHist);
    update_shared_hist((packed >> 16) & 0xFFu, from, rangeSize, lane, sharedHist);
    update_shared_hist((packed >> 24) & 0xFFu, from, rangeSize, lane, sharedHist);
}

// Fast path for a full thread chunk.
// - If ItemsPerThread is a multiple of 16 (the default), use aligned 128-bit loads.
// - Otherwise, if it is a multiple of 4, use aligned 32-bit loads.
// - Otherwise fall back to scalar loads.
// The cudaMalloc alignment guarantee provided by the problem statement makes the vectorized
// paths valid for the default configuration.
template <int ItemsPerThread>
__device__ __forceinline__ void process_full_chunk(const unsigned char* __restrict__ ptr,
                                                   unsigned int from,
                                                   unsigned int rangeSize,
                                                   unsigned int lane,
                                                   unsigned int* __restrict__ sharedHist)
{
    if (ItemsPerThread % 16 == 0) {
        const uint4* vec = reinterpret_cast<const uint4*>(ptr);
        #pragma unroll
        for (int i = 0; i < ItemsPerThread / 16; ++i) {
            const uint4 v = vec[i];
            process_packed4(v.x, from, rangeSize, lane, sharedHist);
            process_packed4(v.y, from, rangeSize, lane, sharedHist);
            process_packed4(v.z, from, rangeSize, lane, sharedHist);
            process_packed4(v.w, from, rangeSize, lane, sharedHist);
        }
    } else if (ItemsPerThread % 4 == 0) {
        const unsigned int* words = reinterpret_cast<const unsigned int*>(ptr);
        #pragma unroll
        for (int i = 0; i < ItemsPerThread / 4; ++i) {
            process_packed4(words[i], from, rangeSize, lane, sharedHist);
        }
    } else {
        #pragma unroll
        for (int i = 0; i < ItemsPerThread; ++i) {
            update_shared_hist(ptr[i], from, rangeSize, lane, sharedHist);
        }
    }
}

// Tail path for the final partial chunk of the input.
template <int ItemsPerThread>
__device__ __forceinline__ void process_tail_chunk(const unsigned char* __restrict__ ptr,
                                                   unsigned int remaining,
                                                   unsigned int from,
                                                   unsigned int rangeSize,
                                                   unsigned int lane,
                                                   unsigned int* __restrict__ sharedHist)
{
    #pragma unroll
    for (int i = 0; i < ItemsPerThread; ++i) {
        if (static_cast<unsigned int>(i) < remaining) {
            update_shared_hist(ptr[i], from, rangeSize, lane, sharedHist);
        }
    }
}

// histogram[bin] counts byte value (from + bin).
// We pass (from, rangeSize) instead of (from, to) because it makes the range filter cheaper.
template <int ItemsPerThread>
__global__ __launch_bounds__(kBlockSize, kTargetBlocksPerSM)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from,
                            unsigned int rangeSize)
{
    extern __shared__ unsigned int sharedHist[];

    // Treat the input as unsigned bytes so values in [128, 255] are handled correctly even
    // if host-side `char` is signed.
    const unsigned char* __restrict__ inputBytes =
        reinterpret_cast<const unsigned char*>(input);

    // Shared storage holds exactly rangeSize * 32 counters.
    const unsigned int sharedEntries = rangeSize << kHistogramCopiesLog2;
    for (unsigned int i = threadIdx.x; i < sharedEntries; i += blockDim.x) {
        sharedHist[i] = 0u;
    }
    __syncthreads();

    const unsigned int lane = threadIdx.x & (kHistogramCopies - 1);

    // Use 64-bit indices for the grid-stride loop to avoid wraparound on very large inputs.
    const size_t n = static_cast<size_t>(inputSize);
    const size_t blockTileSize =
        static_cast<size_t>(blockDim.x) * static_cast<size_t>(ItemsPerThread);
    const size_t gridTileStride =
        static_cast<size_t>(gridDim.x) * blockTileSize;

    // Each block processes a grid-stride sequence of contiguous tiles.
    // Within a tile, each thread processes a contiguous chunk of ItemsPerThread bytes.
    for (size_t tileBase = static_cast<size_t>(blockIdx.x) * blockTileSize;
         tileBase < n;
         tileBase += gridTileStride)
    {
        const size_t threadBase =
            tileBase + static_cast<size_t>(threadIdx.x) * static_cast<size_t>(ItemsPerThread);

        if (threadBase >= n) {
            continue;
        }

        const unsigned int remaining = static_cast<unsigned int>(n - threadBase);
        const unsigned char* __restrict__ threadPtr = inputBytes + threadBase;

        if (remaining >= static_cast<unsigned int>(ItemsPerThread)) {
            process_full_chunk<ItemsPerThread>(threadPtr, from, rangeSize, lane, sharedHist);
        } else {
            process_tail_chunk<ItemsPerThread>(threadPtr, remaining, from, rangeSize, lane, sharedHist);
        }
    }

    __syncthreads();

    // Final merge:
    // one warp reduces the 32 lane-owned copies for each bin. This is bank-conflict-free too,
    // because lane l reads shared[(bin << 5) + l], i.e. always its own bank.
    const unsigned int warpId        = threadIdx.x >> kHistogramCopiesLog2;
    const unsigned int warpsPerBlock = blockDim.x >> kHistogramCopiesLog2;

    for (unsigned int bin = warpId; bin < rangeSize; bin += warpsPerBlock) {
        unsigned int sum = sharedHist[(bin << kHistogramCopiesLog2) + lane];
        sum = warp_reduce_sum_u32(sum);
        if (lane == 0u && sum != 0u) {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

static inline unsigned int ceil_div_u32(unsigned int num, unsigned int den)
{
    return num / den + ((num % den) != 0u);
}

// Enqueues the histogram computation on the default stream.
// No host-device synchronization is performed here; the caller requested to manage that.
void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    const unsigned int from_u    = static_cast<unsigned int>(from);
    const unsigned int rangeSize = static_cast<unsigned int>(to - from + 1);

    const size_t histogramBytes =
        static_cast<size_t>(rangeSize) * sizeof(unsigned int);

    // 32 shared-memory copies of the requested sub-histogram.
    const size_t sharedBytes =
        (static_cast<size_t>(rangeSize) << kHistogramCopiesLog2) * sizeof(unsigned int);

    // The API does not provide a stream parameter, so use the default stream.
    const cudaStream_t stream = 0;

    // Blocks merge with global atomicAdd, so the output histogram must start from zero.
    cudaMemsetAsync(histogram, 0, histogramBytes, stream);

    // Empty input: the asynchronous memset above already produced the correct all-zero result.
    if (inputSize == 0u) {
        return;
    }

    int device  = 0;
    int smCount = 1;
    cudaGetDevice(&device);
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1) {
        smCount = 1;
    }

    int activeBlocksPerSM = 1;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM,
        histogram_range_kernel<itemsPerThread>,
        kBlockSize,
        sharedBytes);
    if (activeBlocksPerSM < 1) {
        activeBlocksPerSM = 1;
    }

    // Histogram kernels pay a final global merge cost per block. Launch enough blocks to keep
    // the machine busy, but not so many that we create unnecessary extra partial histograms.
    int usefulBlocksPerSM = activeBlocksPerSM;
    if (usefulBlocksPerSM > kTargetBlocksPerSM) {
        usefulBlocksPerSM = kTargetBlocksPerSM;
    }

    const unsigned int tileSize     = static_cast<unsigned int>(kBlockSize * itemsPerThread);
    const unsigned int neededBlocks = ceil_div_u32(inputSize, tileSize);
    const int maxUsefulBlocks       = smCount * usefulBlocksPerSM;

    int gridSize = static_cast<int>(neededBlocks);
    if (gridSize > maxUsefulBlocks) {
        gridSize = maxUsefulBlocks;
    }
    if (gridSize < 1) {
        gridSize = 1;
    }

    histogram_range_kernel<itemsPerThread>
        <<<gridSize, kBlockSize, sharedBytes, stream>>>(
            input,
            histogram,
            inputSize,
            from_u,
            rangeSize);

    // Intentionally no synchronization here.
}

#include <cuda_runtime.h>

/*
    Range-restricted byte histogram for a device-resident char buffer.

    High-level algorithm:
      1) Each thread block accumulates into a privatized histogram in shared memory.
      2) The shared histogram is replicated 32 times per block, one logical copy per warp lane.
      3) Threads grid-stride over the input; each thread processes `itemsPerThread` chars per iteration.
      4) After the block finishes its local accumulation, the 32 replicas are reduced and atomically
         added to the final global histogram.

    Important layout detail requested by the prompt:
      sharedHistogram[bin * 32 + replica]

    with `replica == laneId`.

    Because the counters are 32-bit words and modern NVIDIA GPUs have 32 shared-memory banks,
    the bank selected by that address is:

        bank = (bin * 32 + laneId) % 32 = laneId

    So every lane always hits its own bank, independent of the bin number. This eliminates
    intra-warp bank conflicts for the histogram updates.

    The prompt asks for 32 copies per *thread block* (not per warp). Therefore multiple warps
    in the same block share each per-lane replica, and correctness requires shared-memory
    atomicAdd() for the updates.
*/

// 256 threads/block is a strong default on A100/H100 for this atomic-heavy pattern:
// it gives enough warps for good latency hiding without creating as much inter-warp
// contention on the shared replicas as a 512-thread block would.
constexpr int blockThreads = 256;

// Tuning knob requested by the prompt.
// For this kernel, 16 chars/thread is a good default on modern data-center GPUs:
// enough ILP to amortize loop/index overhead, while keeping register pressure and
// unrolled code size moderate.
constexpr int itemsPerThread = 16;

// Exactly 32 replicas are required by the prompt; this matches warp width and the
// number of shared-memory banks on modern NVIDIA GPUs.
constexpr int replicaCount = 32;

constexpr int warpsPerBlock = blockThreads / replicaCount;
constexpr size_t tileItems = static_cast<size_t>(blockThreads) * itemsPerThread;

static_assert(replicaCount == 32, "This implementation assumes 32 shared-memory banks / 32 warp lanes.");
static_assert(blockThreads % replicaCount == 0, "blockThreads must be a multiple of 32.");

// Warp-wide sum. Only lane 0 receives the full sum; that is sufficient for the final write-back.
__device__ __forceinline__ unsigned int warpReduceSum(unsigned int value) {
    #pragma unroll
    for (int offset = replicaCount / 2; offset > 0; offset >>= 1) {
        value += __shfl_down_sync(0xFFFFFFFFu, value, offset);
    }
    return value;
}

// Consume one byte and update the block-private shared histogram if the byte falls in range.
// The single-comparison range test works because unsigned subtraction turns
//     from <= byteValue <= to
// into
//     0 <= (byteValue - from) < numBins.
__device__ __forceinline__ void accumulateByte(
    unsigned int byteValue,
    unsigned int* sharedHistogram,
    unsigned int from,
    unsigned int numBins,
    unsigned int laneId)
{
    const unsigned int bin = byteValue - from;
    if (bin < numBins) {
        atomicAdd(&sharedHistogram[bin * replicaCount + laneId], 1u);
    }
}

__global__ __launch_bounds__(blockThreads)
void histogramKernel(
    const unsigned char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    unsigned int from,
    unsigned int numBins)
{
    // Dynamic shared memory size is numBins * 32 counters.
    extern __shared__ unsigned int sharedHistogram[];

    const unsigned int laneId = threadIdx.x & (replicaCount - 1);
    const unsigned int warpId = threadIdx.x >> 5;

    // Zero the block-private histogram.
    // Each warp owns a subset of bins, and each lane writes its own replica.
    // This access pattern is also bank-conflict free because replica == laneId.
    for (unsigned int bin = warpId; bin < numBins; bin += warpsPerBlock) {
        sharedHistogram[bin * replicaCount + laneId] = 0u;
    }
    __syncthreads();

    const size_t inputSize64 = static_cast<size_t>(inputSize);
    const size_t gridStride = static_cast<size_t>(gridDim.x) * tileItems;

    // Process all fully covered tiles without bounds checks in the inner loop.
    // In each unrolled round, threads in a warp read consecutive bytes, so global
    // loads remain naturally coalesced.
    size_t tileBase = static_cast<size_t>(blockIdx.x) * tileItems;
    for (; tileBase + tileItems <= inputSize64; tileBase += gridStride) {
        size_t idx = tileBase + static_cast<size_t>(threadIdx.x);

        #pragma unroll
        for (int item = 0; item < itemsPerThread; ++item, idx += blockThreads) {
            accumulateByte(static_cast<unsigned int>(input[idx]), sharedHistogram, from, numBins, laneId);
        }
    }

    // Tail path for the final partial tile(s) assigned to this block.
    for (; tileBase < inputSize64; tileBase += gridStride) {
        size_t idx = tileBase + static_cast<size_t>(threadIdx.x);

        #pragma unroll
        for (int item = 0; item < itemsPerThread; ++item, idx += blockThreads) {
            if (idx < inputSize64) {
                accumulateByte(static_cast<unsigned int>(input[idx]), sharedHistogram, from, numBins, laneId);
            }
        }
    }

    __syncthreads();

    // Reduce the 32 replicas for each bin.
    // Each warp owns a subset of bins; lane l reads replica l of that bin.
    // Since the replicas are interleaved as [bin][lane], these reads are also bank-conflict free.
    for (unsigned int bin = warpId; bin < numBins; bin += warpsPerBlock) {
        const unsigned int local = sharedHistogram[bin * replicaCount + laneId];
        const unsigned int sum = warpReduceSum(local);

        // Multiple blocks contribute to the same final histogram, so the global write-back is atomic.
        if (laneId == 0 && sum != 0u) {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

void run_histogram(const char *input, unsigned int *histogram, unsigned int inputSize, int from, int to)
{
    // Defensive validation. The prompt states the range is valid; if it is not,
    // there is no well-defined histogram size to operate on, so just return.
    if (from < 0 || from > 255 || to < 0 || to > 255 || to < from) {
        return;
    }

    // Inclusive range [from, to].
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes = static_cast<size_t>(numBins) * sizeof(unsigned int);

    // The function is expected to produce a fresh histogram, so clear the output first.
    // No host synchronization is performed here; caller requested to handle synchronization externally.
    cudaMemsetAsync(histogram, 0, histogramBytes, 0);

    if (inputSize == 0) {
        return;
    }

    // Shared-memory footprint:
    //   numBins * 32 replicas * 4 bytes
    // Worst case is 256 * 32 * 4 = 32 KiB, well within the normal per-block dynamic
    // shared-memory limit on modern NVIDIA GPUs, so no opt-in max-dynamic-shmem attribute is needed.
    const size_t sharedBytes = static_cast<size_t>(numBins) * replicaCount * sizeof(unsigned int);

    // Launch exactly one SM-resident wave of blocks.
    // Because each block grid-strides over the full input while reusing a single privatized histogram,
    // extra block waves would mostly increase block init/final-reduction overhead and the number of
    // global atomic write-backs.
    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1) {
        smCount = 1;
    }

    int activeBlocksPerSm = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSm,
        histogramKernel,
        blockThreads,
        sharedBytes);
    if (activeBlocksPerSm < 1) {
        activeBlocksPerSm = 1;
    }

    int gridBlocks = smCount * activeBlocksPerSm;
    const size_t numTiles = (static_cast<size_t>(inputSize) + tileItems - 1) / tileItems;
    if (numTiles < static_cast<size_t>(gridBlocks)) {
        gridBlocks = static_cast<int>(numTiles);
    }
    if (gridBlocks < 1) {
        gridBlocks = 1;
    }

    histogramKernel<<<gridBlocks, blockThreads, sharedBytes, 0>>>(
        reinterpret_cast<const unsigned char*>(input),
        histogram,
        inputSize,
        static_cast<unsigned int>(from),
        numBins);
}

#include <cuda_runtime.h>

namespace
{
// Tuned defaults for large inputs on modern data-center GPUs (A100/H100 class):
// - 256 threads/block keeps enough warps resident without doubling inter-warp
//   contention on the 32 lane-striped shared-memory replicas.
// - 16 items/thread amortizes address arithmetic and loop overhead while keeping
//   register pressure low under the shared-memory footprint of this kernel.
constexpr int itemsPerThread         = 16;
constexpr int histogramReplicaCount  = 32; // one replica per warp lane
constexpr int histogramReplicaStride = 32; // 32 uint32 words = 128 B
constexpr int blockSize              = 256;

static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert(histogramReplicaCount == 32, "This kernel assumes 32-thread warps.");
static_assert(histogramReplicaStride == 32, "Replica stride must be 32 words.");
static_assert(blockSize % histogramReplicaCount == 0, "blockSize must be a multiple of 32.");

__device__ __forceinline__ void tally_byte(
    const unsigned int byteValue,
    const unsigned int from_u,
    const unsigned int numBins_u,
    unsigned int* const s_lane_hist)
{
    // Unsigned subtraction turns the range test into a single comparison:
    // if byteValue < from_u, the subtraction underflows and the comparison fails.
    const unsigned int bin = byteValue - from_u;
    if (bin < numBins_u)
    {
        atomicAdd(&s_lane_hist[bin * histogramReplicaStride], 1u);
    }
}

__device__ __forceinline__ unsigned int warp_reduce_sum(unsigned int value)
{
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800)
    // A100/H100 target path: use the hardware-supported warp reduction intrinsic.
    return __reduce_add_sync(0xffffffffu, value);
#else
    // Portable fallback for older compilation targets.
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1)
    {
        value += __shfl_down_sync(0xffffffffu, value, offset);
    }
    return value;
#endif
}

template <int BLOCK_SIZE>
__global__ __launch_bounds__(BLOCK_SIZE)
void histogram_range_kernel(
    const char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    int from,
    int numBins)
{
    // Shared-memory layout: [bin][replica].
    //
    // Each bin owns 32 replicas, and replicas are spaced by 32 uint32 words
    // (128 bytes). For any fixed bin, replica r maps to a unique shared-memory
    // bank modulo a constant base rotation. By choosing replica = warp lane,
    // all concurrent updates from a warp hit distinct banks, eliminating
    // intra-warp bank conflicts while still allowing a block-private histogram.
    extern __shared__ unsigned int s_hist[];

    const unsigned int lane      = threadIdx.x & (histogramReplicaCount - 1);
    unsigned int* const s_lane_hist = s_hist + lane;
    const unsigned int numBins_u = static_cast<unsigned int>(numBins);

    // Parallel initialization of the block-private replicated histogram.
    for (unsigned int i = threadIdx.x; i < numBins_u * histogramReplicaStride; i += BLOCK_SIZE)
    {
        s_hist[i] = 0u;
    }
    __syncthreads();

    const unsigned int from_u = static_cast<unsigned int>(from);
    const unsigned char* const inputBytes = reinterpret_cast<const unsigned char*>(input);

    // Grid-stride over tiles. Within each tile, a thread processes items that are
    // striped by BLOCK_SIZE so that each inner-loop load is fully coalesced.
    const size_t blockTile   = static_cast<size_t>(BLOCK_SIZE) * itemsPerThread;
    const size_t threadBase  = static_cast<size_t>(blockIdx.x) * blockTile + threadIdx.x;
    const size_t gridStride  = static_cast<size_t>(gridDim.x) * blockTile;
    const size_t fullTileSpan = static_cast<size_t>(itemsPerThread - 1) * BLOCK_SIZE;
    const size_t inputSize64 = static_cast<size_t>(inputSize);

    size_t base = threadBase;

    // Fast path: full tiles need no per-item bounds checks.
    for (; base + fullTileSpan < inputSize64; base += gridStride)
    {
        #pragma unroll
        for (int item = 0; item < itemsPerThread; ++item)
        {
            const size_t idx = base + static_cast<size_t>(item) * BLOCK_SIZE;
            tally_byte(static_cast<unsigned int>(inputBytes[idx]), from_u, numBins_u, s_lane_hist);
        }
    }

    // Tail path: only the final partial tile per thread needs bounds checks.
    for (; base < inputSize64; base += gridStride)
    {
        #pragma unroll
        for (int item = 0; item < itemsPerThread; ++item)
        {
            const size_t idx = base + static_cast<size_t>(item) * BLOCK_SIZE;
            if (idx < inputSize64)
            {
                tally_byte(static_cast<unsigned int>(inputBytes[idx]), from_u, numBins_u, s_lane_hist);
            }
        }
    }

    __syncthreads();

    // Reduction across the 32 lane-striped replicas.
    //
    // Each warp reduces one bin at a time:
    // - lane r reads replica r (conflict-free),
    // - the warp sums the 32 replicas,
    // - lane 0 atomically adds the block contribution to global memory.
    const unsigned int warpId = threadIdx.x >> 5;
    constexpr unsigned int warpsPerBlock = BLOCK_SIZE / histogramReplicaCount;

    for (int bin = static_cast<int>(warpId); bin < numBins; bin += static_cast<int>(warpsPerBlock))
    {
        unsigned int value = s_lane_hist[static_cast<unsigned int>(bin) * histogramReplicaStride];
        value = warp_reduce_sum(value);

        if (lane == 0 && value != 0u)
        {
            atomicAdd(&histogram[bin], value);
        }
    }
}
} // namespace

void run_histogram(
    const char *input,
    unsigned int *histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    // The problem statement guarantees valid arguments, but a small guard keeps
    // the function safe for accidental misuse.
    if (from < 0 || to > 255 || from > to)
    {
        return;
    }

    const int numBins = to - from + 1;

    // The output must represent exactly this invocation, so clear it first.
    // Stream 0 is used because the function signature does not expose a stream;
    // caller-managed synchronization is intentionally left to the caller.
    cudaMemsetAsync(
        histogram,
        0,
        static_cast<size_t>(numBins) * sizeof(unsigned int),
        0);

    if (inputSize == 0)
    {
        return;
    }

    // This kernel is shared-memory heavy and streams the input once, so asking
    // the runtime for the maximum shared-memory carveout is the right default on
    // architectures with configurable L1/shared partitioning.
    cudaFuncSetAttribute(
        histogram_range_kernel<blockSize>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount <= 0)
    {
        smCount = 1;
    }

    // Max dynamic shared-memory requirement:
    // range_size * 32 replicas * 4 bytes.
    // Since range_size <= 256, the worst case is 32 KiB/block.
    const size_t sharedMemBytes =
        static_cast<size_t>(numBins) * histogramReplicaStride * sizeof(unsigned int);

    int activeBlocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM,
        histogram_range_kernel<blockSize>,
        blockSize,
        sharedMemBytes);
    if (activeBlocksPerSM <= 0)
    {
        activeBlocksPerSM = 1;
    }

    // Because the kernel uses a grid-stride loop, one occupancy-saturating wave
    // of blocks is enough: resident blocks keep pulling tiles until the entire
    // input is consumed, while minimizing the number of block-to-global merges.
    const size_t blockTile = static_cast<size_t>(blockSize) * itemsPerThread;
    const unsigned int blocksNeeded =
        static_cast<unsigned int>((static_cast<size_t>(inputSize) + blockTile - 1) / blockTile);

    unsigned int blocks = static_cast<unsigned int>(smCount * activeBlocksPerSM);
    if (blocks == 0u)
    {
        blocks = 1u;
    }
    if (blocks > blocksNeeded)
    {
        blocks = blocksNeeded;
    }
    if (blocks == 0u)
    {
        blocks = 1u;
    }

    histogram_range_kernel<blockSize><<<blocks, blockSize, sharedMemBytes, 0>>>(
        input,
        histogram,
        inputSize,
        from,
        numBins);
}

#include <cuda_runtime.h>
#include <cstdint>

namespace {

// Tunables chosen for modern data-center GPUs (A100/H100 class):
// - itemsPerThread = 16:
//     one aligned 128-bit load per thread per chunk on cudaMalloc memory;
//     good amortization of block-private histogram setup/final merge without
//     noticeably increasing register pressure.
//   If retuning, prefer multiples of 16 to keep the 128-bit load path enabled.
// - blockSize = 256:
//     8 warps per CTA is a good balance between occupancy and cross-warp
//     contention on the 32 lane-private shared histograms.
// - histogramCopies = 32:
//     one logical histogram copy per warp lane, matching the 32 shared-memory banks.
constexpr int itemsPerThread  = 16;
constexpr int blockSize       = 256;
constexpr int histogramCopies = 32;

static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert(blockSize % 32 == 0, "blockSize must be a multiple of warp size.");
static_assert(histogramCopies == 32, "The bank-avoidance scheme assumes exactly 32 copies.");

__device__ __forceinline__ void update_lane_private_histogram(
    unsigned int value,
    unsigned int from_u,
    unsigned int range,
    unsigned int* __restrict__ lanePrivateHistogram)
{
    // Unsigned subtraction turns the inclusive test value in [from, from + range - 1]
    // into a single compare. If value < from_u, the subtraction underflows and the
    // result is >= range, so the branch is still rejected correctly.
    const unsigned int bin = value - from_u;
    if (bin < range) {
        // lanePrivateHistogram is sHist + lane. The stride between consecutive bins of
        // the same logical copy is 32 words, so the actual shared address is:
        //   sHist[bin * 32 + lane]
        //
        // Shared-memory bank = address % 32 for 4-byte words, therefore bank = lane
        // regardless of bin. A warp can update arbitrary bins without intra-warp bank
        // conflicts. Different warps reuse the same 32 lane-private copies, so only
        // inter-warp collisions remain; those are handled by fast shared-memory atomics.
        atomicAdd(&lanePrivateHistogram[bin * histogramCopies], 1u);
    }
}

__device__ __forceinline__ void consume_packed_u32(
    uint32_t packed,
    unsigned int from_u,
    unsigned int range,
    unsigned int* __restrict__ lanePrivateHistogram)
{
    update_lane_private_histogram( packed        & 0xFFu, from_u, range, lanePrivateHistogram);
    update_lane_private_histogram((packed >>  8) & 0xFFu, from_u, range, lanePrivateHistogram);
    update_lane_private_histogram((packed >> 16) & 0xFFu, from_u, range, lanePrivateHistogram);
    update_lane_private_histogram((packed >> 24) & 0xFFu, from_u, range, lanePrivateHistogram);
}

template <int ITEMS_PER_THREAD>
__global__ __launch_bounds__(blockSize)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from_u,
                            unsigned int range)
{
    extern __shared__ unsigned int sHist[];

    // Interleaved shared layout:
    //   [bin0_copy0, bin0_copy1, ... bin0_copy31,
    //    bin1_copy0, bin1_copy1, ... bin1_copy31, ...]
    //
    // Each warp lane uses the logical copy with the same index as its lane id.
    // This layout is stronger than storing 32 contiguous copies with padding:
    // the bank index depends only on lane, not on the bin value.
    const unsigned int lane = threadIdx.x & 31u;
    unsigned int* const lanePrivateHistogram = sHist + lane;

    const unsigned int sharedElementCount = range * histogramCopies;

    // Zero the block-private histogram.
    for (unsigned int i = threadIdx.x; i < sharedElementCount; i += blockDim.x) {
        sHist[i] = 0u;
    }
    __syncthreads();

    const unsigned char* const inputBytes = reinterpret_cast<const unsigned char*>(input);
    const unsigned int globalThread = blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned int totalThreads = gridDim.x * blockDim.x;
    constexpr unsigned int itemsPerThreadU = static_cast<unsigned int>(ITEMS_PER_THREAD);

    // Full chunks are processed with compile-time-unrolled loads. For the default
    // ITEMS_PER_THREAD = 16 this becomes one aligned uint4 (128-bit) load per thread.
    // Because input is allocated with cudaMalloc and base = chunk * ITEMS_PER_THREAD,
    // the vectorized paths are aligned whenever ITEMS_PER_THREAD is a multiple of 16 or 4.
    const unsigned int fullChunks = inputSize / itemsPerThreadU;

    for (unsigned int chunk = globalThread; chunk < fullChunks; chunk += totalThreads) {
        const unsigned int base = chunk * itemsPerThreadU;

        if constexpr ((ITEMS_PER_THREAD % 16) == 0) {
            const uint4* const chunkPtr = reinterpret_cast<const uint4*>(inputBytes + base);
            #pragma unroll
            for (int i = 0; i < ITEMS_PER_THREAD / 16; ++i) {
                const uint4 v = chunkPtr[i];
                consume_packed_u32(v.x, from_u, range, lanePrivateHistogram);
                consume_packed_u32(v.y, from_u, range, lanePrivateHistogram);
                consume_packed_u32(v.z, from_u, range, lanePrivateHistogram);
                consume_packed_u32(v.w, from_u, range, lanePrivateHistogram);
            }
        } else if constexpr ((ITEMS_PER_THREAD % 4) == 0) {
            const uint32_t* const chunkPtr = reinterpret_cast<const uint32_t*>(inputBytes + base);
            #pragma unroll
            for (int i = 0; i < ITEMS_PER_THREAD / 4; ++i) {
                consume_packed_u32(chunkPtr[i], from_u, range, lanePrivateHistogram);
            }
        } else {
            #pragma unroll
            for (int i = 0; i < ITEMS_PER_THREAD; ++i) {
                update_lane_private_histogram(static_cast<unsigned int>(inputBytes[base + i]),
                                              from_u,
                                              range,
                                              lanePrivateHistogram);
            }
        }
    }

    // Handle the final partial chunk, if any. This tail is always < ITEMS_PER_THREAD bytes.
    const unsigned int tailStart = fullChunks * itemsPerThreadU;
    for (unsigned int idx = tailStart + globalThread; idx < inputSize; idx += totalThreads) {
        update_lane_private_histogram(static_cast<unsigned int>(inputBytes[idx]),
                                      from_u,
                                      range,
                                      lanePrivateHistogram);
    }

    __syncthreads();

    // Collapse the 32 shared copies into one per-block histogram and merge into global memory.
    // Only one global atomic per non-zero bin and block is emitted.
    for (unsigned int bin = threadIdx.x; bin < range; bin += blockDim.x) {
        unsigned int sum = 0u;
        const unsigned int base = bin * histogramCopies;

        #pragma unroll
        for (int copy = 0; copy < histogramCopies; ++copy) {
            sum += sHist[base + copy];
        }

        if (sum != 0u) {
            if (gridDim.x == 1) {
                // Single-block launch: the global histogram was zeroed before launch,
                // so a plain store is sufficient.
                histogram[bin] = sum;
            } else {
                atomicAdd(&histogram[bin], sum);
            }
        }
    }
}

} // anonymous namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    const unsigned int range = static_cast<unsigned int>(to - from + 1);

    // The API contract is "compute histogram", not "accumulate into existing contents",
    // so clear the output first. This is asynchronous; the caller owns synchronization.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(range) * sizeof(unsigned int), 0);

    if (inputSize == 0u) {
        return;
    }

    const size_t sharedBytes =
        static_cast<size_t>(range) * static_cast<size_t>(histogramCopies) * sizeof(unsigned int);

    // Grid-stride chunking means we do not need one CTA per chunk. Launch only the
    // number of CTAs that can reside concurrently; that keeps the SMs busy while
    // minimizing the number of per-block merges into the global histogram.
    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    int activeBlocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(&activeBlocksPerSM,
                                                  histogram_range_kernel<itemsPerThread>,
                                                  blockSize,
                                                  sharedBytes);

    constexpr unsigned int itemsPerThreadU = static_cast<unsigned int>(itemsPerThread);
    const unsigned int fullChunks = inputSize / itemsPerThreadU;
    const unsigned int blocksForOnePass =
        (fullChunks == 0u) ? 1u : (1u + (fullChunks - 1u) / static_cast<unsigned int>(blockSize));

    int gridSize = activeBlocksPerSM * smCount;
    if (gridSize < 1) {
        gridSize = 1;
    }
    if (blocksForOnePass < static_cast<unsigned int>(gridSize)) {
        gridSize = static_cast<int>(blocksForOnePass);
    }

    histogram_range_kernel<itemsPerThread><<<gridSize, blockSize, sharedBytes, 0>>>(
        input,
        histogram,
        inputSize,
        static_cast<unsigned int>(from),
        range);
}

#include <cuda_runtime.h>

/*
Range-restricted histogram for device-resident text.

Design:
- Each CTA builds a private histogram in shared memory.
- Every bin is replicated 32 times: one copy per warp lane / shared-memory bank.
- Shared layout is [bin][copy], i.e. blockHistogram[bin * bankStride + lane].
  With bankStride == 32 words, copy 'lane' always maps to bank 'lane', so the
  hot update path is free of intra-warp bank conflicts regardless of the bin.
- Threads from different warps but the same lane still share the same copy, so
  shared atomicAdd is required; replication reduces contention by 32x versus a
  single CTA-private histogram.
- itemsPerThread = 16 gives one aligned uint4 load per thread, which is a good
  balance of load efficiency, loop overhead, register pressure, and occupancy on
  modern data-center GPUs such as A100/H100.
*/

constexpr int histogramCopies = 32;
constexpr int bankStride = 32;   // One full shared-memory bank cycle in 4-byte words.
constexpr int vectorBytes = 16;  // uint4 load width in bytes.
constexpr int blockSize = 256;
constexpr int itemsPerThread = 16;

static_assert(histogramCopies == 32, "This implementation requires 32 shared histogram copies.");
static_assert(bankStride == 32, "This implementation relies on a 32-word shared-memory stride.");
static_assert(histogramCopies == bankStride, "Each copy must stay in a fixed shared-memory bank.");
static_assert(sizeof(unsigned int) == 4, "Shared-memory bank mapping assumes 4-byte counters.");
static_assert(blockSize > 0 && (blockSize % histogramCopies) == 0,
              "blockSize must be a positive multiple of 32.");
static_assert(itemsPerThread > 0 && (itemsPerThread % vectorBytes) == 0,
              "itemsPerThread must be a positive multiple of 16 for aligned uint4 loads.");

__device__ __forceinline__
void add_byte_to_lane_histogram(const unsigned int byteValue,
                                unsigned int* __restrict__ laneHistogram,
                                const unsigned int from,
                                const unsigned int numBins)
{
    const unsigned int bin = byteValue - from;
    if (bin < numBins) {
        atomicAdd(&laneHistogram[bin * bankStride], 1u);
    }
}

__device__ __forceinline__
void add_packed_word_to_lane_histogram(const unsigned int packedBytes,
                                       unsigned int* __restrict__ laneHistogram,
                                       const unsigned int from,
                                       const unsigned int numBins)
{
    add_byte_to_lane_histogram((packedBytes      ) & 0xFFu, laneHistogram, from, numBins);
    add_byte_to_lane_histogram((packedBytes >>  8) & 0xFFu, laneHistogram, from, numBins);
    add_byte_to_lane_histogram((packedBytes >> 16) & 0xFFu, laneHistogram, from, numBins);
    add_byte_to_lane_histogram((packedBytes >> 24) & 0xFFu, laneHistogram, from, numBins);
}

__device__ __forceinline__
void add_packed16_to_lane_histogram(const uint4 packed16,
                                    unsigned int* __restrict__ laneHistogram,
                                    const unsigned int from,
                                    const unsigned int numBins)
{
    add_packed_word_to_lane_histogram(packed16.x, laneHistogram, from, numBins);
    add_packed_word_to_lane_histogram(packed16.y, laneHistogram, from, numBins);
    add_packed_word_to_lane_histogram(packed16.z, laneHistogram, from, numBins);
    add_packed_word_to_lane_histogram(packed16.w, laneHistogram, from, numBins);
}

__device__ __forceinline__
unsigned int warp_reduce_sum(unsigned int value)
{
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
        value += __shfl_down_sync(0xFFFFFFFFu, value, offset);
    }
    return value;
}

template <int BLOCK_SIZE, int ITEMS_PER_THREAD>
__global__ __launch_bounds__(BLOCK_SIZE)
void range_histogram_kernel(const unsigned char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from,
                            unsigned int numBins)
{
    extern __shared__ unsigned int blockHistogram[];

    const unsigned int lane = threadIdx.x & (histogramCopies - 1);
    const unsigned int warpId = threadIdx.x / histogramCopies;
    constexpr unsigned int warpsPerBlock = BLOCK_SIZE / histogramCopies;

    // laneHistogram is this thread's per-lane shared copy:
    // laneHistogram[bin * bankStride] == blockHistogram[bin * bankStride + lane].
    unsigned int* const laneHistogram = blockHistogram + lane;

    // Clear the CTA-private shared histogram.
    const unsigned int sharedCount = numBins * histogramCopies;
    for (unsigned int i = threadIdx.x; i < sharedCount; i += BLOCK_SIZE) {
        blockHistogram[i] = 0u;
    }
    __syncthreads();

    constexpr int vectorsPerThread = ITEMS_PER_THREAD / vectorBytes;
    const size_t inputSize64 = static_cast<size_t>(inputSize);
    const size_t blockWork = static_cast<size_t>(BLOCK_SIZE) * ITEMS_PER_THREAD;
    const size_t gridWork = static_cast<size_t>(gridDim.x) * blockWork;
    const size_t threadOffset = static_cast<size_t>(threadIdx.x) * ITEMS_PER_THREAD;

    for (size_t blockBase = static_cast<size_t>(blockIdx.x) * blockWork;
         blockBase < inputSize64;
         blockBase += gridWork) {
        const size_t threadBase = blockBase + threadOffset;

        if (threadBase + ITEMS_PER_THREAD <= inputSize64) {
            // input is cudaMalloc-aligned and threadBase is a multiple of 16,
            // so this vectorized path uses aligned uint4 loads.
            const uint4* inputVec = reinterpret_cast<const uint4*>(input + threadBase);

            #pragma unroll
            for (int v = 0; v < vectorsPerThread; ++v) {
                add_packed16_to_lane_histogram(inputVec[v], laneHistogram, from, numBins);
            }
        } else if (threadBase < inputSize64) {
            // Only the very last partial chunk falls back to scalar byte loads.
            const size_t remaining = inputSize64 - threadBase;

            #pragma unroll
            for (int i = 0; i < ITEMS_PER_THREAD; ++i) {
                if (static_cast<size_t>(i) < remaining) {
                    add_byte_to_lane_histogram(
                        static_cast<unsigned int>(input[threadBase + static_cast<size_t>(i)]),
                        laneHistogram,
                        from,
                        numBins);
                }
            }
        }
    }

    __syncthreads();

    // Reduce the 32 lane-private copies. Each warp handles one bin at a time:
    // lane l reads copy l, which keeps this reduction bank-conflict free too.
    for (unsigned int bin = warpId; bin < numBins; bin += warpsPerBlock) {
        unsigned int sum = blockHistogram[bin * bankStride + lane];
        sum = warp_reduce_sum(sum);

        if (lane == 0u && sum != 0u) {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    const unsigned int fromValue = static_cast<unsigned int>(from);
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes = static_cast<size_t>(numBins) * sizeof(unsigned int);
    const size_t sharedBytes = static_cast<size_t>(numBins) * histogramCopies * sizeof(unsigned int);

    // The kernel accumulates per-CTA partial results into the global histogram,
    // so the output must be zeroed first. The API has no stream parameter, so
    // both operations use stream 0; synchronization/error handling is left to
    // the caller as requested.
    cudaMemsetAsync(histogram, 0, histogramBytes, 0);

    if (inputSize == 0u) {
        return;
    }

    int device = 0;
    cudaGetDevice(&device);

    int smCount = 1;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1) {
        smCount = 1;
    }

    int residentBlocksPerSM = 1;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &residentBlocksPerSM,
        range_histogram_kernel<blockSize, itemsPerThread>,
        blockSize,
        sharedBytes);
    if (residentBlocksPerSM < 1) {
        residentBlocksPerSM = 1;
    }

    const size_t blockWork = static_cast<size_t>(blockSize) * itemsPerThread;
    const size_t tiles = (static_cast<size_t>(inputSize) + blockWork - 1) / blockWork;
    const size_t maxResidentGrid = static_cast<size_t>(smCount) * static_cast<size_t>(residentBlocksPerSM);
    const unsigned int gridSize =
        static_cast<unsigned int>(tiles < maxResidentGrid ? tiles : maxResidentGrid);

    if (gridSize == 0u) {
        return;
    }

    // Launch only as many CTAs as can be resident concurrently. The kernel uses
    // a grid-stride loop, so more CTAs would mainly increase the number of final
    // global atomics without improving steady-state occupancy.
    range_histogram_kernel<blockSize, itemsPerThread><<<gridSize, blockSize, sharedBytes, 0>>>(
        reinterpret_cast<const unsigned char*>(input),  // treat chars as 0..255 ordinals
        histogram,
        inputSize,
        fromValue,
        numBins);
}

#include <cuda_runtime.h>

// Range-restricted byte histogram optimized for modern NVIDIA data-center GPUs.
//
// Design summary:
// - Each thread block builds a privatized histogram in shared memory.
// - Every bin is replicated 32 times, one logical copy per warp lane / shared-memory bank.
// - A thread updates only the copy indexed by its lane, so warp-wide updates are bank-conflict free.
// - After the block finishes its grid-stride chunk of the input, it reduces the 32 copies per bin
//   with warp shuffles and atomically adds the result to the output histogram in global memory.

namespace {

// 256 threads (8 warps) is a strong default on A100/H100 for this shared-atomic histogram:
// enough warps to hide latency, while keeping inter-warp contention on each per-lane copy moderate.
constexpr int kWarpSize          = 32;
constexpr int kHistogramCopies   = 32;
constexpr int kHistogramStride   = 32;  // stride in 32-bit words between consecutive bins of one copy
constexpr int kBlockThreads      = 256;
constexpr int kWarpsPerBlock     = kBlockThreads / kWarpSize;

// Large-input default: 16 bytes/thread => 4 KiB of input per CTA tile.
// This amortizes shared-histogram init/flush overhead well on Ampere/Hopper
// without inflating code size or register pressure too much.
constexpr int    itemsPerThread  = 16;
constexpr size_t kBlockWork      = static_cast<size_t>(kBlockThreads) * static_cast<size_t>(itemsPerThread);

constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;

static_assert(kHistogramCopies == kWarpSize, "Need one histogram copy per warp lane.");
static_assert((kBlockThreads % kWarpSize) == 0, "Block size must be a whole number of warps.");

__device__ __forceinline__ unsigned int warp_reduce_sum(unsigned int value) {
    #pragma unroll
    for (int offset = kWarpSize / 2; offset > 0; offset >>= 1) {
        value += __shfl_down_sync(kFullWarpMask, value, offset);
    }
    return value;
}

}  // namespace

__global__ __launch_bounds__(kBlockThreads)
void histogram_range_kernel(const unsigned char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            size_t inputSize,
                            unsigned int rangeBegin,
                            unsigned int rangeSize) {
    // Dynamic shared-memory layout:
    //   s_hist[bin * 32 + lane]
    //
    // This is a bin-major, copy-minor layout with 32 logical copies of every bin.
    // Copy 'lane' occupies indices:
    //   lane, lane + 32, lane + 64, ...
    //
    // Because shared memory has 32 banks and counters are 32-bit wide, lane l always maps to
    // bank (base_bank + l) % 32. Therefore, when a warp updates any set of bins, each lane touches
    // a distinct bank and the update is bank-conflict free within that warp.
    extern __shared__ unsigned int s_hist[];

    const unsigned int tid   = threadIdx.x;
    const unsigned int lane  = tid & (kWarpSize - 1);
    const unsigned int warp  = tid >> 5;
    const unsigned int words = rangeSize * kHistogramStride;

    // Zero only the portion of shared memory needed for the requested [from, to] range.
    for (unsigned int i = tid; i < words; i += kBlockThreads) {
        s_hist[i] = 0u;
    }
    __syncthreads();

    // This thread always updates the copy that corresponds to its warp lane.
    // Different warps share the same 32 copies, so shared-memory atomics are still required
    // to resolve inter-warp races on the same per-lane copy.
    unsigned int* const laneHistogram = s_hist + lane;

    const size_t gridWork = static_cast<size_t>(gridDim.x) * kBlockWork;

    // Persistent grid-stride processing. Each CTA consumes kBlockWork bytes per tile.
    for (size_t blockBase = static_cast<size_t>(blockIdx.x) * kBlockWork;
         blockBase < inputSize;
         blockBase += gridWork) {
        const size_t threadBase = blockBase + tid;

        if (blockBase + kBlockWork <= inputSize) {
            // Fast path for full 4 KiB CTA tiles: no per-item bounds checks.
            #pragma unroll
            for (int item = 0; item < itemsPerThread; ++item) {
                const size_t idx = threadBase + static_cast<size_t>(item) * kBlockThreads;
                const unsigned int value = static_cast<unsigned int>(input[idx]);

                // Branchless range test:
                //   if value < rangeBegin, unsigned underflow makes bin very large,
                //   so the compare fails automatically.
                const unsigned int bin = value - rangeBegin;
                if (bin < rangeSize) {
                    atomicAdd(laneHistogram + bin * kHistogramStride, 1u);
                }
            }
        } else {
            // Tail tile.
            #pragma unroll
            for (int item = 0; item < itemsPerThread; ++item) {
                const size_t idx = threadBase + static_cast<size_t>(item) * kBlockThreads;
                if (idx < inputSize) {
                    const unsigned int value = static_cast<unsigned int>(input[idx]);
                    const unsigned int bin = value - rangeBegin;
                    if (bin < rangeSize) {
                        atomicAdd(laneHistogram + bin * kHistogramStride, 1u);
                    }
                }
            }
        }
    }

    __syncthreads();

    // Flush the block-private histogram to global memory.
    // Each warp reduces one bin at a time: lane l reads copy l, so the flush path is also
    // bank-conflict free.
    for (unsigned int bin = warp; bin < rangeSize; bin += kWarpsPerBlock) {
        const unsigned int binBase = bin * kHistogramStride;
        unsigned int sum = s_hist[binBase + lane];
        sum = warp_reduce_sum(sum);

        // histogram[bin] corresponds to byte value (rangeBegin + bin).
        if (lane == 0 && sum != 0u) {
            atomicAdd(histogram + bin, sum);
        }
    }
}

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    const unsigned int rangeBegin = static_cast<unsigned int>(from);
    const unsigned int rangeSize  = static_cast<unsigned int>(to - from + 1);

    // histogram[0] corresponds to byte value 'from'.
    // The result must be produced from scratch, so zero the output first.
    // Use stream 0 and leave synchronization to the caller, as requested.
    cudaMemsetAsync(
        histogram,
        0,
        static_cast<size_t>(rangeSize) * sizeof(unsigned int),
        0);

    if (inputSize == 0u) {
        return;
    }

    const size_t sharedBytes =
        static_cast<size_t>(rangeSize) * kHistogramStride * sizeof(unsigned int);

    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    int activeBlocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM,
        histogram_range_kernel,
        kBlockThreads,
        sharedBytes);

    // Launch no more CTAs than can be resident concurrently.
    // The kernel is grid-stride, so oversubscribing the grid would only increase
    // per-CTA initialization / flush overhead and global atomic traffic.
    const size_t blocksForInput =
        (static_cast<size_t>(inputSize) + (kBlockWork - 1)) / kBlockWork;

    unsigned int gridSize = static_cast<unsigned int>(smCount * activeBlocksPerSM);
    if (gridSize == 0u) {
        gridSize = 1u;
    }
    if (static_cast<size_t>(gridSize) > blocksForInput) {
        gridSize = static_cast<unsigned int>(blocksForInput);
    }
    if (gridSize == 0u) {
        gridSize = 1u;
    }

    histogram_range_kernel<<<gridSize, kBlockThreads, sharedBytes, 0>>>(
        reinterpret_cast<const unsigned char*>(input),
        histogram,
        static_cast<size_t>(inputSize),
        rangeBegin,
        rangeSize);
}

#include <cuda_runtime.h>

namespace {

// One histogram replica per warp lane / shared-memory bank.
constexpr int kWarpLanes = 32;
constexpr int kHistogramReplicas = 32;

// 256 threads = 8 warps per block. This is a good fit for A100/H100-class GPUs while
// keeping the worst-case shared-memory footprint (256 bins * 32 replicas * 4 B = 32 KiB)
// low enough to allow multiple resident blocks per SM.
constexpr int kBlockSize = 256;
constexpr int kWarpsPerBlock = kBlockSize / kWarpLanes;

// Large-input default for modern NVIDIA GPUs: enough work per thread to amortize shared
// histogram setup/finalization, while still keeping the loop compact and fully unrollable.
constexpr int itemsPerThread = 16;
constexpr unsigned int kBlockWork = kBlockSize * itemsPerThread;

// This kernel has non-trivial per-block overhead (shared histogram zeroing + final reduction).
// Around 32 active warps/SM is typically enough on recent data-center GPUs, so we cap the
// launch at 4 blocks/SM rather than blindly launching every possible resident block.
constexpr int kTargetResidentBlocksPerSM = 4;

static_assert(kWarpLanes == 32, "This kernel relies on NVIDIA's 32-lane warp size.");
static_assert(kHistogramReplicas == kWarpLanes, "Use one replica per warp lane.");
static_assert((kBlockSize % kWarpLanes) == 0, "Block size must be a multiple of warp size.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");

__device__ __forceinline__ unsigned int warp_reduce_sum(unsigned int value) {
    #pragma unroll
    for (int offset = kWarpLanes / 2; offset > 0; offset >>= 1) {
        value += __shfl_down_sync(0xffffffffu, value, offset);
    }
    return value;
}

/*
  Shared-memory layout:
      s_hist[bin * 32 + replica]

  For 32-bit words, the shared-memory bank is (word_index % 32). With the above layout,
  replica r of every bin always maps to bank r. Threads use replica == lane, so within a warp
  every lane touches a distinct bank regardless of which bin it increments:
      bank(bin * 32 + lane) == lane

  This is the requested 32-copy histogram privatization scheme:
    - 32 total copies of the histogram per thread block
    - each copy is associated with one warp lane / one bank
    - updates are bank-conflict-free within a warp
    - reduction is also bank-conflict-free by having a warp read all 32 replicas of one bin
*/
__global__ __launch_bounds__(kBlockSize)
void histogram_range_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from,
                            unsigned int rangeSize) {
    extern __shared__ unsigned int s_hist[];

    const unsigned int tid    = threadIdx.x;
    const unsigned int lane   = tid & (kWarpLanes - 1u);
    const unsigned int warpId = tid >> 5;

    const unsigned int replicatedBins = rangeSize * kHistogramReplicas;

    // Zero the block-private histogram. Dynamic shared memory keeps the footprint proportional
    // to the requested [from, to] range instead of always reserving the full 256-bin table.
    for (unsigned int i = tid; i < replicatedBins; i += kBlockSize) {
        s_hist[i] = 0u;
    }
    __syncthreads();

    // Process the input in a blocked, fully coalesced pattern:
    // on each inner-loop iteration, threads in the block load a contiguous kBlockSize-byte span.
    // 64-bit index arithmetic is used so the code remains correct up to the full 4 GiB inputSize limit.
    const size_t n          = static_cast<size_t>(inputSize);
    const size_t blockWork  = static_cast<size_t>(kBlockWork);
    const size_t base0      = static_cast<size_t>(blockIdx.x) * blockWork + static_cast<size_t>(tid);
    const size_t gridStride = static_cast<size_t>(gridDim.x) * blockWork;

    for (size_t base = base0; base < n; base += gridStride) {
        #pragma unroll
        for (int i = 0; i < itemsPerThread; ++i) {
            const size_t idx = base + static_cast<size_t>(i) * kBlockSize;
            if (idx < n) {
                // Cast through unsigned char so byte values 128..255 are handled correctly even
                // when plain char is signed.
                const unsigned int c = static_cast<unsigned char>(input[idx]);

                // Single unsigned range test:
                //   bin = c - from
                //   bin < rangeSize  <=>  from <= c <= to
                const unsigned int bin = c - from;
                if (bin < rangeSize) {
                    atomicAdd(&s_hist[bin * kHistogramReplicas + lane], 1u);
                }
            }
        }
    }
    __syncthreads();

    // Reduce the 32 lane-private replicas. One warp reduces one bin at a time so lane r reads
    // replica r, which again maps one lane to one bank with no intra-warp bank conflicts.
    for (unsigned int bin = warpId; bin < rangeSize; bin += kWarpsPerBlock) {
        unsigned int sum = s_hist[bin * kHistogramReplicas + lane];
        sum = warp_reduce_sum(sum);

        if (lane == 0u && sum != 0u) {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

} // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    // The interface does not accept a stream, so work is enqueued on the default stream.
    // The caller is responsible for any synchronization/error handling policy.
    cudaStream_t stream = 0;

    const unsigned int rangeSize = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes  = static_cast<size_t>(rangeSize) * sizeof(unsigned int);

    // The kernel accumulates block results into the output via global atomics, so the output
    // histogram must be cleared before launch.
    cudaMemsetAsync(histogram, 0, histogramBytes, stream);

    if (inputSize == 0u) {
        return;
    }

    const size_t sharedBytes =
        static_cast<size_t>(rangeSize) * static_cast<size_t>(kHistogramReplicas) * sizeof(unsigned int);

    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    int maxActiveBlocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &maxActiveBlocksPerSM,
        histogram_range_kernel,
        kBlockSize,
        sharedBytes);

    if (maxActiveBlocksPerSM < 1) {
        maxActiveBlocksPerSM = 1;
    }

    int blocksPerSM = maxActiveBlocksPerSM;
    if (blocksPerSM > kTargetResidentBlocksPerSM) {
        blocksPerSM = kTargetResidentBlocksPerSM;
    }

    const unsigned int requiredBlocks = 1u + (inputSize - 1u) / kBlockWork;

    unsigned int launchBlocks = static_cast<unsigned int>(smCount * blocksPerSM);
    if (launchBlocks == 0u) {
        launchBlocks = 1u;
    }
    if (launchBlocks > requiredBlocks) {
        launchBlocks = requiredBlocks;
    }

    histogram_range_kernel<<<launchBlocks, kBlockSize, sharedBytes, stream>>>(
        input,
        histogram,
        inputSize,
        static_cast<unsigned int>(from),
        rangeSize);
}

#include <cuda_runtime.h>
#include <cstddef>

namespace
{
// Range-restricted byte histogram optimized for recent NVIDIA data-center GPUs.
//
// High-level strategy:
//  1) Each thread block builds a block-private histogram in shared memory.
//  2) The shared histogram is replicated 32 times: one logical copy per warp lane.
//  3) The copies are laid out with a stride such that stride % 32 == 1.
//     Therefore, for any fixed bin b, the 32 addresses
//         copy * stride + b
//     map to banks
//         (copy + b) % 32,
//     i.e. one distinct bank per copy. This removes the classic intra-warp bank
//     conflict when many lanes hit the same histogram bin.
//  4) Threads index the shared copies by lane id, not by warp id. Threads with
//     the same lane in different warps therefore share a copy; shared-memory
//     atomics are still required, but hot-bin updates no longer collide inside
//     a warp on the shared-memory banks.
//  5) After the block has processed its grid-stride slice of the input, one
//     thread per output bin reduces the 32 shared copies and atomically adds
//     the block result to the global histogram.
//
// Tuning choices for A100/H100-class GPUs:
//  * blockSize = 256 gives 8 warps/block. This is a good balance between
//    occupancy and contention on a given lane-indexed shared copy.
//  * itemsPerThread = 16 is a good default for large inputs: enough work to
//    amortize loop/control overhead without driving register pressure or code
//    size too high.
constexpr unsigned int histogramCopies = 32u;
constexpr unsigned int histogramCopiesMask = histogramCopies - 1u;
constexpr int          blockSize        = 256;
constexpr int          itemsPerThread   = 16;

static_assert(sizeof(unsigned int) == 4,
              "This layout assumes 32-bit counters (one shared-memory bank slot per counter).");
static_assert((histogramCopies & histogramCopiesMask) == 0u,
              "histogramCopies must be a power of two.");
static_assert(blockSize % histogramCopies == 0,
              "blockSize must be a whole number of warps.");
static_assert(blockSize >= 256,
              "blockSize must cover the full maximum histogram range (256 bins).");
static_assert(itemsPerThread > 0,
              "itemsPerThread must be positive.");

// Smallest stride >= range such that stride % 32 == 1.
// This is the bank-rotation trick that places the same bin across the 32 copies
// into 32 different banks.
inline unsigned int compute_shared_stride(const unsigned int range)
{
    return range + ((1u - (range & histogramCopiesMask)) & histogramCopiesMask);
}

__global__ void histogram_kernel(const char* __restrict__ input,
                                 unsigned int* __restrict__ histogram,
                                 const unsigned int inputSize,
                                 const unsigned int from,
                                 const unsigned int range,
                                 const unsigned int stride)
{
    extern __shared__ unsigned int sharedHist[];

    const unsigned int lane = threadIdx.x & histogramCopiesMask;

    // Treat the input as unsigned bytes so values 128..255 are handled correctly
    // regardless of whether plain 'char' is signed on the compilation target.
    const unsigned char* __restrict__ bytes =
        reinterpret_cast<const unsigned char*>(input);

    // Lane-private within a warp, but shared by the same lane across all warps
    // in the block. Hence the updates still use shared-memory atomics.
    unsigned int* const lanePrivateHist = sharedHist + lane * stride;

    const unsigned int totalSharedCounters = histogramCopies * stride;
    const size_t       n                   = static_cast<size_t>(inputSize);
    const size_t       blockTile           = static_cast<size_t>(blockDim.x) * itemsPerThread;
    const size_t       gridTile            = static_cast<size_t>(gridDim.x) * blockTile;

    // Zero the block-private histograms.
    for (unsigned int i = threadIdx.x; i < totalSharedCounters; i += blockDim.x)
    {
        sharedHist[i] = 0u;
    }
    __syncthreads();

    // Grid-stride loop over block tiles.
    //
    // For each unrolled "item" iteration, threads in a warp access consecutive
    // bytes, so global loads are naturally coalesced.
    for (size_t threadBase = static_cast<size_t>(blockIdx.x) * blockTile + threadIdx.x;
         threadBase < n;
         threadBase += gridTile)
    {
#pragma unroll
        for (int item = 0; item < itemsPerThread; ++item)
        {
            const size_t pos = threadBase + static_cast<size_t>(item) * blockDim.x;
            if (pos < n)
            {
                // Unsigned subtraction folds the inclusive range test
                //     from <= byte <= to
                // into the single comparison
                //     (byte - from) < range.
                const unsigned int bin = static_cast<unsigned int>(bytes[pos]) - from;
                if (bin < range)
                {
                    atomicAdd(&lanePrivateHist[bin], 1u);
                }
            }
        }
    }
    __syncthreads();

    // Final block-local reduction:
    // blockSize is 256, and the requested range is at most 256 bins, so one
    // thread can reduce exactly one output bin.
    const unsigned int bin = threadIdx.x;
    if (bin < range)
    {
        unsigned int sum = 0u;

#pragma unroll
        for (unsigned int copy = 0; copy < histogramCopies; ++copy)
        {
            sum += sharedHist[copy * stride + bin];
        }

        // histogram[bin] corresponds to input byte value (from + bin).
        if (sum != 0u)
        {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

} // namespace

void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // This interface has no stream parameter, so the default stream is used.
    // The function intentionally only enqueues work; caller-managed
    // synchronization/error observation happens outside this function.
    const cudaStream_t stream = 0;

    const unsigned int from_u = static_cast<unsigned int>(from);
    const unsigned int range  = static_cast<unsigned int>(to - from + 1);
    const unsigned int stride = compute_shared_stride(range);

    // Shared-memory footprint scales with the requested range, not with a fixed
    // 256-bin histogram.
    const size_t sharedBytes =
        static_cast<size_t>(histogramCopies) * static_cast<size_t>(stride) * sizeof(unsigned int);

    // The output histogram contains only bins [from, to], so zero exactly that range.
    (void)cudaMemsetAsync(histogram, 0, static_cast<size_t>(range) * sizeof(unsigned int), stream);

    if (inputSize == 0u)
    {
        return;
    }

    // Prefer shared memory over L1: this kernel is dominated by shared-memory
    // atomics, while input reads are a simple streaming pass.
    (void)cudaFuncSetAttribute(histogram_kernel,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    int device = 0;
    (void)cudaGetDevice(&device);

    int smCount = 1;
    (void)cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1)
    {
        smCount = 1;
    }

    int activeBlocksPerSM = 1;
    (void)cudaOccupancyMaxActiveBlocksPerMultiprocessor(&activeBlocksPerSM,
                                                        histogram_kernel,
                                                        blockSize,
                                                        sharedBytes);
    if (activeBlocksPerSM < 1)
    {
        activeBlocksPerSM = 1;
    }

    const size_t blockTile = static_cast<size_t>(blockSize) * itemsPerThread;
    const unsigned int blocksForInput =
        static_cast<unsigned int>((static_cast<size_t>(inputSize) + blockTile - 1u) / blockTile);

    // Launch only one occupancy-saturating wave of blocks. Because each block
    // performs one final global reduction of its private histogram, using more
    // blocks than can reside concurrently only increases global atomic traffic;
    // the grid-stride loop keeps the resident blocks busy on large inputs.
    const unsigned int residentBlocks =
        static_cast<unsigned int>(smCount) * static_cast<unsigned int>(activeBlocksPerSM);

    const unsigned int gridBlocks =
        (blocksForInput < residentBlocks) ? blocksForInput : residentBlocks;

    histogram_kernel<<<gridBlocks, blockSize, sharedBytes, stream>>>(
        input,
        histogram,
        inputSize,
        from_u,
        range,
        stride);
}

#include <cuda_runtime.h>
#include <cstddef>

namespace {

// Tuned for recent data-center GPUs (A100/H100 class):
// - 256 threads/block gives 8 warps, enough latency hiding without creating excessive
//   cross-warp contention on the 32 shared-memory histogram copies.
// - itemsPerThread = 16 means each block processes a 4 KiB tile per iteration
//   (256 * 16 bytes), which is a good balance between amortizing block setup/final merge
//   and keeping register pressure modest.
constexpr int threadsPerBlock = 256;
constexpr int histogramCopies = 32;
constexpr int itemsPerThread = 16;

constexpr unsigned int warpsPerBlock =
    static_cast<unsigned int>(threadsPerBlock / 32);
constexpr unsigned int workPerBlock =
    static_cast<unsigned int>(threadsPerBlock * itemsPerThread);
constexpr std::size_t fullTileLastItemOffset =
    static_cast<std::size_t>(threadsPerBlock) *
    static_cast<std::size_t>(itemsPerThread - 1);
constexpr unsigned int fullWarpMask = 0xFFFFFFFFu;

static_assert(histogramCopies == 32,
              "This bank-conflict-avoidance scheme requires 32 histogram copies.");
static_assert(threadsPerBlock % 32 == 0,
              "threadsPerBlock must be a multiple of the warp size.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");

__device__ __forceinline__ unsigned int warp_reduce_sum(unsigned int value) {
    // Standard tree reduction within one warp.
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
        value += __shfl_down_sync(fullWarpMask, value, offset);
    }
    return value;
}

// Shared-memory layout:
//   bin i, copy c  ->  s_hist[i * 32 + c]
//
// This layout is chosen so that lane c always hits bank c:
// - During updates, each thread uses copy = threadIdx.x % 32, so every lane in a warp
//   accesses a distinct bank regardless of which bin it updates.
// - Shared atomics are still needed because different warps in the same block reuse the
//   same 32 copies.
// - During the final reduction, one warp reduces one bin at a time; lane c reads copy c,
//   again producing conflict-free bank access.
__launch_bounds__(threadsPerBlock)
__global__ void histogram_kernel(const unsigned char* __restrict__ input,
                                 unsigned int* __restrict__ histogram,
                                 unsigned int inputSize,
                                 unsigned int from,
                                 unsigned int range) {
    extern __shared__ unsigned int s_hist[];

    const unsigned int tid = threadIdx.x;
    const unsigned int lane = tid & 31u;
    const unsigned int warpId = tid >> 5;

    // Pointer to this thread's private bank-aligned "column" through all bins:
    // myHist[bin * 32] == s_hist[bin * 32 + lane]
    unsigned int* const myHist = s_hist + lane;

    // Zero the shared histogram copies cooperatively.
    const unsigned int sharedEntries = range * histogramCopies;
    for (unsigned int i = tid; i < sharedEntries; i += threadsPerBlock) {
        s_hist[i] = 0u;
    }
    __syncthreads();

    // Grid-stride over block-sized tiles. Keeping only about one resident wave of blocks
    // (chosen by the host launcher) lets each block reuse its shared-memory histogram
    // across many tiles and emit only one global merge at the end.
    const std::size_t gridStride =
        static_cast<std::size_t>(gridDim.x) * static_cast<std::size_t>(workPerBlock);
    std::size_t base =
        static_cast<std::size_t>(blockIdx.x) * static_cast<std::size_t>(workPerBlock) +
        static_cast<std::size_t>(tid);

    // Fast path for full tiles: all items are in bounds, so the inner loop has no bounds checks.
    // The bin test uses unsigned subtraction:
    //   bin = value - from;
    //   if (bin < range) ...
    // This folds both lower and upper bound checks into one comparison.
    for (; base + fullTileLastItemOffset < inputSize; base += gridStride) {
        #pragma unroll
        for (int item = 0; item < itemsPerThread; ++item) {
            const unsigned int value =
                static_cast<unsigned int>(input[base + static_cast<std::size_t>(item) * threadsPerBlock]);
            const unsigned int bin = value - from;
            if (bin < range) {
                atomicAdd(&myHist[bin * histogramCopies], 1u);
            }
        }
    }

    // Tail path: only the last partial tile needs bounds checks.
    for (; base < inputSize; base += gridStride) {
        #pragma unroll
        for (int item = 0; item < itemsPerThread; ++item) {
            const std::size_t idx =
                base + static_cast<std::size_t>(item) * threadsPerBlock;
            if (idx < inputSize) {
                const unsigned int value = static_cast<unsigned int>(input[idx]);
                const unsigned int bin = value - from;
                if (bin < range) {
                    atomicAdd(&myHist[bin * histogramCopies], 1u);
                }
            }
        }
    }

    __syncthreads();

    // Reduce the 32 shared copies into the final global histogram.
    // One warp reduces one bin at a time:
    //   lane c reads copy c of the bin, then the warp sums across lanes.
    for (unsigned int bin = warpId; bin < range; bin += warpsPerBlock) {
        const unsigned int* const binBase = s_hist + bin * histogramCopies;
        unsigned int sum = binBase[lane];
        sum = warp_reduce_sum(sum);

        if (lane == 0 && sum != 0u) {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

}  // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    // The problem statement guarantees valid arguments, but a cheap guard avoids undefined
    // behavior if the function is misused.
    if (from < 0 || to > 255 || from > to) {
        return;
    }

    const unsigned int range = static_cast<unsigned int>(to - from + 1);

    // The kernel only accumulates into the output, so clear it first.
    // The caller requested to handle host/device synchronization externally, so use the
    // default stream asynchronously and do not synchronize here.
    cudaMemsetAsync(histogram,
                    0,
                    static_cast<std::size_t>(range) * sizeof(unsigned int),
                    0);

    if (inputSize == 0u) {
        return;
    }

    // Dynamic shared memory for 32 copies of the requested histogram range:
    //   range bins * 32 copies * sizeof(unsigned int)
    const std::size_t sharedBytes =
        static_cast<std::size_t>(range) *
        static_cast<std::size_t>(histogramCopies) *
        sizeof(unsigned int);

    // This kernel is dominated by shared-memory histogram privatization plus streaming reads,
    // so prefer the maximum shared-memory carveout.
    (void)cudaFuncSetAttribute(histogram_kernel,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    // Launch about one resident wave of blocks. For this kernel that is preferable to
    // launching one short-lived block per input tile, because each block initializes and
    // later merges its private shared histogram only once.
    int device = 0;
    int numSms = 1;
    if (cudaGetDevice(&device) == cudaSuccess) {
        int queriedSms = 0;
        if (cudaDeviceGetAttribute(&queriedSms,
                                   cudaDevAttrMultiProcessorCount,
                                   device) == cudaSuccess &&
            queriedSms > 0) {
            numSms = queriedSms;
        }
    }

    int residentBlocksPerSm = 1;
    if (cudaOccupancyMaxActiveBlocksPerMultiprocessor(&residentBlocksPerSm,
                                                      histogram_kernel,
                                                      threadsPerBlock,
                                                      sharedBytes) != cudaSuccess ||
        residentBlocksPerSm < 1) {
        residentBlocksPerSm = 1;
    }

    // Use an overflow-safe ceil_div because inputSize is 32-bit.
    const unsigned int blocksForInput = 1u + (inputSize - 1u) / workPerBlock;

    unsigned int gridSize =
        static_cast<unsigned int>(residentBlocksPerSm) *
        static_cast<unsigned int>(numSms);
    if (gridSize == 0u) {
        gridSize = 1u;
    }
    if (gridSize > blocksForInput) {
        gridSize = blocksForInput;
    }

    histogram_kernel<<<gridSize, threadsPerBlock, sharedBytes, 0>>>(
        reinterpret_cast<const unsigned char*>(input),
        histogram,
        inputSize,
        static_cast<unsigned int>(from),
        range);
}

#include <cuda_runtime.h>

// itemsPerThread is the requested tuning knob. For large streaming inputs on modern
// data-center GPUs (A100/H100 class), 16 is a strong default: it gives enough ILP to
// amortize loop overhead while keeping register pressure modest for this atomic-heavy kernel.
constexpr int itemsPerThread = 16;

// Exactly 32 privatized copies are required so that copy c maps to shared-memory bank c.
constexpr int histogramCopies = 32;

// We choose the smallest block size that still leaves at least this many resident warps
// per SM. Because the histogram has only 32 shared copies, fewer warps/block directly
// means less intra-block contention on hot bins.
constexpr int minUsefulResidentWarps = 32;

static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");

template <int BLOCK_SIZE>
__launch_bounds__(BLOCK_SIZE)
__global__ void histogram_range_kernel(const unsigned char *__restrict__ input,
                                       unsigned int *__restrict__ histogram,
                                       unsigned int inputSize,
                                       unsigned int rangeStart,
                                       unsigned int numBins) {
    static_assert(BLOCK_SIZE % histogramCopies == 0,
                  "BLOCK_SIZE must be a multiple of 32.");

    // Shared-memory layout:
    //   sHistogram[bin * 32 + copy]
    // where copy = threadIdx.x % 32.
    //
    // Since shared memory has 32 banks and each element is 4 bytes, address
    // (bin * 32 + copy) always maps to bank 'copy'. Therefore, for the histogram update
    // path, every lane in a warp hits a distinct bank regardless of the bin value.
    extern __shared__ unsigned int sHistogram[];

    const unsigned int lane = threadIdx.x & 31u;  // == threadIdx.x % 32
    const unsigned int totalPrivatizedBins = numBins * histogramCopies;

    // Zero the block-private histogram.
    for (unsigned int i = threadIdx.x; i < totalPrivatizedBins; i += BLOCK_SIZE) {
        sHistogram[i] = 0u;
    }
    __syncthreads();

    // Process a block-wide tile in a coalesced pattern:
    //   idx = tileBase + threadIdx.x + item * blockDim.x
    // Each inner-loop iteration therefore reads a contiguous byte span across the block.
    const size_t n = static_cast<size_t>(inputSize);
    const size_t tileSize = static_cast<size_t>(BLOCK_SIZE) * itemsPerThread;
    const size_t gridStride = static_cast<size_t>(gridDim.x) * tileSize;

    for (size_t tileBase = static_cast<size_t>(blockIdx.x) * tileSize;
         tileBase < n;
         tileBase += gridStride) {
        const size_t threadBase = tileBase + threadIdx.x;

#pragma unroll
        for (int item = 0; item < itemsPerThread; ++item) {
            const size_t idx = threadBase + static_cast<size_t>(item) * BLOCK_SIZE;
            if (idx < n) {
                // Interpret char as an unsigned byte in [0, 255], independent of host-side
                // signedness of 'char'. The range test uses unsigned arithmetic so it becomes
                // one compare after subtraction.
                const unsigned int byteVal = static_cast<unsigned int>(input[idx]);
                const unsigned int bin = byteVal - rangeStart;
                if (bin < numBins) {
                    atomicAdd(&sHistogram[bin * histogramCopies + lane], 1u);
                }
            }
        }
    }
    __syncthreads();

    // Merge the 32 bank-striped copies into the final global histogram.
    // This reduces global atomic traffic from "one atomic per input byte" to
    // "one atomic per nonzero bin per block".
    for (unsigned int bin = threadIdx.x; bin < numBins; bin += BLOCK_SIZE) {
        unsigned int sum = 0u;
        const unsigned int base = bin * histogramCopies;

#pragma unroll
        for (int copy = 0; copy < histogramCopies; ++copy) {
            sum += sHistogram[base + copy];
        }

        if (sum != 0u) {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

template <int BLOCK_SIZE>
static inline int get_active_blocks_per_sm(size_t sharedMemBytes) {
    static_assert(BLOCK_SIZE % histogramCopies == 0,
                  "BLOCK_SIZE must be a multiple of 32.");

    // This kernel is dominated by shared-memory atomics and performs streaming input reads,
    // so preferring shared memory over L1 is usually beneficial on Ampere/Hopper.
    cudaFuncSetAttribute(histogram_range_kernel<BLOCK_SIZE>,
                         cudaFuncAttributePreferredSharedMemoryCarveout,
                         100);

    int activeBlocksPerSm = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(&activeBlocksPerSm,
                                                  histogram_range_kernel<BLOCK_SIZE>,
                                                  BLOCK_SIZE,
                                                  sharedMemBytes);

    return (activeBlocksPerSm > 0) ? activeBlocksPerSm : 1;
}

template <int BLOCK_SIZE>
static inline void launch_histogram_kernel(const unsigned char *input,
                                           unsigned int *histogram,
                                           unsigned int inputSize,
                                           unsigned int rangeStart,
                                           unsigned int numBins,
                                           size_t sharedMemBytes,
                                           int smCount,
                                           int activeBlocksPerSm,
                                           cudaStream_t stream) {
    const size_t tileSize = static_cast<size_t>(BLOCK_SIZE) * itemsPerThread;
    const size_t blocksForInput64 =
        (static_cast<size_t>(inputSize) + tileSize - 1) / tileSize;

    // Launch one resident wave of blocks and let the kernel grid-stride over the full input.
    // That keeps the GPU busy while minimizing block finalization and global merge atomics.
    unsigned int launchBlocks =
        static_cast<unsigned int>(smCount) * static_cast<unsigned int>(activeBlocksPerSm);
    if (launchBlocks == 0u) {
        launchBlocks = 1u;
    }

    const unsigned int blocksForInput = static_cast<unsigned int>(blocksForInput64);
    if (launchBlocks > blocksForInput) {
        launchBlocks = blocksForInput;
    }

    histogram_range_kernel<BLOCK_SIZE>
        <<<static_cast<int>(launchBlocks), BLOCK_SIZE, sharedMemBytes, stream>>>(
            input, histogram, inputSize, rangeStart, numBins);
}

// Host launcher. Per the problem statement, 'input' and 'histogram' are device pointers
// allocated by cudaMalloc. The function intentionally does not synchronize; it uses the
// default stream because the required signature does not provide a stream parameter.
void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    cudaStream_t stream = 0;

    const unsigned int rangeStart = static_cast<unsigned int>(from);
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes = static_cast<size_t>(numBins) * sizeof(unsigned int);

    // The output must contain only the result of this invocation.
    cudaMemsetAsync(histogram, 0, histogramBytes, stream);

    if (inputSize == 0u) {
        return;
    }

    // Dynamic shared memory holds 32 copies of the requested range:
    //   [bin0_copy0..31, bin1_copy0..31, ...]
    // Worst-case valid input is 256 bins -> 256 * 32 * 4 B = 32 KiB.
    const size_t sharedMemBytes =
        static_cast<size_t>(numBins) * histogramCopies * sizeof(unsigned int);

    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1) {
        smCount = 1;
    }

    // The histogram has only 32 shared-memory copies, so contention on hot bins scales with
    // the number of warps per block. We therefore choose the smallest block size that still
    // leaves at least minUsefulResidentWarps resident warps per SM on the current device.
    const int active64 = get_active_blocks_per_sm<64>(sharedMemBytes);
    const int active128 = get_active_blocks_per_sm<128>(sharedMemBytes);
    const int active256 = get_active_blocks_per_sm<256>(sharedMemBytes);

    const int residentWarps64 = active64 * (64 / 32);
    const int residentWarps128 = active128 * (128 / 32);
    const int residentWarps256 = active256 * (256 / 32);

    const unsigned char *inputBytes =
        reinterpret_cast<const unsigned char *>(input);

    if (residentWarps64 >= minUsefulResidentWarps) {
        launch_histogram_kernel<64>(inputBytes,
                                    histogram,
                                    inputSize,
                                    rangeStart,
                                    numBins,
                                    sharedMemBytes,
                                    smCount,
                                    active64,
                                    stream);
    } else if (residentWarps128 >= minUsefulResidentWarps) {
        launch_histogram_kernel<128>(inputBytes,
                                     histogram,
                                     inputSize,
                                     rangeStart,
                                     numBins,
                                     sharedMemBytes,
                                     smCount,
                                     active128,
                                     stream);
    } else {
        // For larger ranges, 256 threads keeps occupancy healthy when shared memory begins
        // to limit active blocks.
        (void)residentWarps256;
        launch_histogram_kernel<256>(inputBytes,
                                     histogram,
                                     inputSize,
                                     rangeStart,
                                     numBins,
                                     sharedMemBytes,
                                     smCount,
                                     active256,
                                     stream);
    }
}

#include <cuda_runtime.h>

namespace
{
// 32 interleaved copies: copy c of logical bin b is stored at b * 32 + c.
// With 4-byte counters and 32 shared-memory banks, lane c always maps to bank c.
// Using copy = threadIdx.x % 32 therefore makes the hot update path bank-conflict-free.
constexpr int kHistogramCopies = 32;

// A 256-thread block is a good balance on A100/H100-class GPUs:
// enough warps to hide latency, but not so many that same-copy contention
// becomes excessive (each copy is shared by 8 warps at most).
constexpr int kBlockSize = 256;

// Requested tuning knob. 16 bytes/thread gives a 4 KiB tile per block:
// good amortization of loop/control overhead with modest register pressure
// after unrolling on modern data-center GPUs.
constexpr int itemsPerThread = 16;

static_assert(kHistogramCopies == 32, "This implementation assumes 32 shared-memory banks.");
static_assert((kBlockSize % kHistogramCopies) == 0, "Block size must be a multiple of 32.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");

__device__ __forceinline__ unsigned int warp_reduce_sum(unsigned int v)
{
    // Full-warp tree reduction. All 32 lanes participate in the reduction phase.
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1)
    {
        v += __shfl_down_sync(0xFFFFFFFFu, v, offset);
    }
    return v;
}

__device__ __forceinline__ void accumulate_byte(
    const unsigned int value,
    const unsigned int from,
    const unsigned int numBins,
    unsigned int* const localHist)
{
    // Unsigned subtraction folds both bounds checks into one compare:
    //   value in [from, from + numBins - 1]  <=>  (value - from) < numBins
    const unsigned int bin = value - from;
    if (bin < numBins)
    {
        atomicAdd(localHist + bin * kHistogramCopies, 1u);
    }
}

template <int ITEMS_PER_THREAD, int BLOCK_SIZE>
__global__ __launch_bounds__(BLOCK_SIZE)
void histogram_range_kernel(
    const unsigned char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    unsigned int from,
    unsigned int numBins)
{
    extern __shared__ unsigned int s_hist[];

    const unsigned int tid           = threadIdx.x;
    const unsigned int lane          = tid & (kHistogramCopies - 1);  // threadIdx.x % 32
    const unsigned int warpId        = tid / kHistogramCopies;
    const unsigned int warpsPerBlock = BLOCK_SIZE / kHistogramCopies;

    // Per-thread base pointer to "its" shared-memory copy.
    // Copy c of bin b is at localHist[b * 32], where localHist = s_hist + c.
    unsigned int* const localHist = s_hist + lane;

    // Shared storage holds exactly 32 copies of the requested range, not the full 256 bins.
    const unsigned int sharedElems = numBins * kHistogramCopies;
    for (unsigned int i = tid; i < sharedElems; i += BLOCK_SIZE)
    {
        s_hist[i] = 0u;
    }
    __syncthreads();

    // Each block processes tiles of BLOCK_SIZE * ITEMS_PER_THREAD bytes.
    // For a fixed "item" index, threads in a warp read consecutive bytes, so the loads are coalesced.
    const unsigned int tileSize   = BLOCK_SIZE * ITEMS_PER_THREAD;
    const unsigned int gridStride = gridDim.x * tileSize;

    // Fast path: full tiles where every access is in bounds, so the inner loop needs no tail checks.
    unsigned int blockBase = blockIdx.x * tileSize;
    if (inputSize >= tileSize)
    {
        const unsigned int lastFullBlockBase = inputSize - tileSize;
        for (; blockBase <= lastFullBlockBase; blockBase += gridStride)
        {
            const unsigned int threadBase = blockBase + tid;

            #pragma unroll
            for (int item = 0; item < ITEMS_PER_THREAD; ++item)
            {
                const unsigned int value = static_cast<unsigned int>(input[threadBase + item * BLOCK_SIZE]);
                accumulate_byte(value, from, numBins, localHist);
            }
        }
    }

    // Tail path: final partial tile(s).
    // Use offsets relative to blockBase so the bounds checks stay overflow-safe in 32-bit arithmetic.
    for (; blockBase < inputSize; blockBase += gridStride)
    {
        const unsigned int remaining = inputSize - blockBase;

        if (tid < remaining)
        {
            #pragma unroll
            for (int item = 0; item < ITEMS_PER_THREAD; ++item)
            {
                const unsigned int offset = tid + item * BLOCK_SIZE;
                if (offset < remaining)
                {
                    const unsigned int value = static_cast<unsigned int>(input[blockBase + offset]);
                    accumulate_byte(value, from, numBins, localHist);
                }
            }
        }
    }

    __syncthreads();

    // Final merge:
    // Use one warp to reduce one logical bin across the 32 copies. This is intentional:
    // with the b * 32 + c layout, lanes 0..31 reading the same bin access consecutive
    // shared-memory locations and therefore distinct banks. A naive thread-per-bin reduction
    // would instead read addresses with stride 32 and would create worst-case bank conflicts.
    for (unsigned int bin = warpId; bin < numBins; bin += warpsPerBlock)
    {
        unsigned int sum = s_hist[bin * kHistogramCopies + lane];
        sum = warp_reduce_sum(sum);

        if (lane == 0 && sum != 0u)
        {
            atomicAdd(histogram + bin, sum);
        }
    }
}

}  // namespace

void run_histogram(const char* input, unsigned int* histogram, unsigned int inputSize, int from, int to)
{
    // One output counter for each byte value in the inclusive range [from, to].
    // The problem statement guarantees 0 <= from < to <= 255, so numBins <= 256.
    // Max dynamic shared memory per block is therefore:
    //   256 bins * 32 copies * 4 bytes = 32 KiB
    // which fits comfortably within the default per-block dynamic shared-memory limit
    // on modern data-center GPUs such as A100/H100.
    const unsigned int numBins      = static_cast<unsigned int>(to - from + 1);
    const size_t histogramBytes     = static_cast<size_t>(numBins) * sizeof(unsigned int);
    const size_t sharedMemBytes     = static_cast<size_t>(numBins) * kHistogramCopies * sizeof(unsigned int);
    const unsigned int tileSize     = static_cast<unsigned int>(kBlockSize * itemsPerThread);
    const unsigned int blocksForInput = 1u + ((inputSize - 1u) / tileSize);

    // The function is intentionally asynchronous with respect to the host; the caller
    // is responsible for any required synchronization.
    cudaStream_t stream = nullptr;

    // Start from a clean output histogram on the same stream as the kernel launch.
    cudaMemsetAsync(histogram, 0, histogramBytes, stream);

    if (inputSize == 0u)
    {
        return;
    }

    // Launch only about as many blocks as can run concurrently.
    // Each block builds a private shared histogram and then atomically merges it
    // into the global result, so launching many more blocks than can be resident
    // at once only increases merge traffic. The grid-stride loop keeps all input covered.
    int device = 0;
    cudaGetDevice(&device);

    int smCount = 1;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount <= 0)
    {
        smCount = 1;
    }

    int maxBlocksPerSM = 1;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &maxBlocksPerSM,
        histogram_range_kernel<itemsPerThread, kBlockSize>,
        kBlockSize,
        sharedMemBytes);
    if (maxBlocksPerSM <= 0)
    {
        maxBlocksPerSM = 1;
    }

    const unsigned int residentGrid = static_cast<unsigned int>(smCount * maxBlocksPerSM);
    const unsigned int gridSize = (blocksForInput < residentGrid) ? blocksForInput : residentGrid;

    // Reinterpret as unsigned bytes so ordinal values 128..255 are handled correctly
    // even if plain "char" is signed on the compilation target.
    histogram_range_kernel<itemsPerThread, kBlockSize>
        <<<gridSize, kBlockSize, sharedMemBytes, stream>>>(
            reinterpret_cast<const unsigned char*>(input),
            histogram,
            inputSize,
            static_cast<unsigned int>(from),
            numBins);
}

#include <cuda_runtime.h>

// Tuning constants for modern data-center NVIDIA GPUs (A100/H100 class).
// - 256 threads/block gives 8 warps per block: enough concurrency while keeping
//   inter-warp contention on the shared histogram copies under control.
// - 8 items/thread is a good large-input default for byte histograms: it
//   amortizes loop/index overhead without inflating register pressure.
constexpr int itemsPerThread  = 8;
constexpr int blockThreads    = 256;
constexpr int histogramCopies = 32;
constexpr unsigned int fullWarpMask = 0xffffffffu;

static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert(histogramCopies == 32, "This layout assumes 32 shared-memory banks.");
static_assert(blockThreads % histogramCopies == 0,
              "blockThreads must be a multiple of 32 so blocks are composed of full warps.");

// Warp-wide reduction used when summing the 32 privatized copies of one histogram bin.
// Lane c reads copy c, so the shared-memory read pattern is also bank-conflict free.
__device__ __forceinline__ unsigned int warp_reduce_sum(unsigned int value) {
#pragma unroll
    for (int offset = histogramCopies / 2; offset > 0; offset >>= 1) {
        value += __shfl_down_sync(fullWarpMask, value, offset);
    }
    return value;
}

// Range-restricted byte histogram.
//
// Shared-memory privatization layout requested by the prompt:
//   sharedHistogram[bin * 32 + copy]
//
// where copy == threadIdx.x % 32.
//
// This layout makes copy c of every bin live in bank c:
// - Hot update path: lane c updates copy c -> each lane hits a distinct bank.
// - Final reduction path: one warp sums one bin at a time, and lane c reads copy c
//   -> again one bank per lane, so no shared-memory bank conflicts.
template <int BLOCK_THREADS, int ITEMS_PER_THREAD>
__launch_bounds__(BLOCK_THREADS)
__global__ void histogram_range_kernel(const char* __restrict__ input,
                                       unsigned int* __restrict__ histogram,
                                       unsigned int inputSize,
                                       unsigned int lower,
                                       unsigned int bins) {
    extern __shared__ unsigned int sharedHistogram[];

    const unsigned int tid  = threadIdx.x;
    const unsigned int lane = tid & 31u;  // Also the histogram copy index: threadIdx.x % 32.
    const unsigned int warp = tid >> 5;   // threadIdx.x / 32

    constexpr unsigned int warpsPerBlock =
        static_cast<unsigned int>(BLOCK_THREADS / histogramCopies);
    constexpr size_t blockTileItems =
        static_cast<size_t>(BLOCK_THREADS) * static_cast<size_t>(ITEMS_PER_THREAD);
    constexpr size_t maxItemOffset =
        static_cast<size_t>(ITEMS_PER_THREAD - 1) * static_cast<size_t>(BLOCK_THREADS);

    const size_t n = static_cast<size_t>(inputSize);
    const size_t gridTileItems = static_cast<size_t>(gridDim.x) * blockTileItems;
    size_t base = static_cast<size_t>(blockIdx.x) * blockTileItems + static_cast<size_t>(tid);

    const unsigned char* __restrict__ bytes =
        reinterpret_cast<const unsigned char*>(input);

    // Zero all shared histogram copies. The layout is dense, so a simple thread-stride loop is efficient.
    const unsigned int privatizedBins = bins * static_cast<unsigned int>(histogramCopies);
    for (unsigned int i = tid; i < privatizedBins; i += BLOCK_THREADS) {
        sharedHistogram[i] = 0u;
    }
    __syncthreads();

    // Fast path for complete tiles: no per-item bounds checks in the hot loop.
    // Only the single possible partial tile owned by this block needs the checked path below.
    const size_t fullTileEnd = (n > maxItemOffset) ? (n - maxItemOffset) : 0;

    for (; base < fullTileEnd; base += gridTileItems) {
#pragma unroll
        for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
            const unsigned int ch =
                static_cast<unsigned int>(bytes[base + static_cast<size_t>(item) * BLOCK_THREADS]);

            // Inclusive range test using unsigned arithmetic:
            // - ch < lower  => underflow, bin becomes very large
            // - ch > upper  => bin >= bins
            const unsigned int bin = ch - lower;
            if (bin < bins) {
                atomicAdd(&sharedHistogram[bin * histogramCopies + lane], 1u);
            }
        }
    }

    // Tail path for the final partial tile.
    for (; base < n; base += gridTileItems) {
#pragma unroll
        for (int item = 0; item < ITEMS_PER_THREAD; ++item) {
            const size_t idx = base + static_cast<size_t>(item) * BLOCK_THREADS;
            if (idx < n) {
                const unsigned int ch = static_cast<unsigned int>(bytes[idx]);
                const unsigned int bin = ch - lower;
                if (bin < bins) {
                    atomicAdd(&sharedHistogram[bin * histogramCopies + lane], 1u);
                }
            }
        }
    }

    __syncthreads();

    // Reduce the 32 privatized copies of each bin back into the global histogram.
    // Each warp handles one bin at a time:
    //   lane c reads copy c      -> bank-conflict-free
    //   warp reduction sums them -> one total per bin
    //   lane 0 does one global atomic add per bin and per block
    for (unsigned int bin = warp; bin < bins; bin += warpsPerBlock) {
        unsigned int sum = sharedHistogram[bin * histogramCopies + lane];
        sum = warp_reduce_sum(sum);
        if (lane == 0u && sum != 0u) {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

// Host launcher.
// The API contract says input/histogram are already cudaMalloc-allocated device buffers,
// and the caller is responsible for any synchronization. Because the function signature
// has no stream parameter, work is issued on the default stream.
void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    // The problem statement guarantees 0 <= from < to <= 255.
    const unsigned int lower = static_cast<unsigned int>(from);
    const unsigned int bins  = static_cast<unsigned int>(to - from + 1);
    const cudaStream_t stream = 0;

    // Zero exactly the requested output range.
    cudaMemsetAsync(histogram,
                    0,
                    static_cast<size_t>(bins) * sizeof(unsigned int),
                    stream);

    if (inputSize == 0u) {
        return;
    }

    // Dynamic shared memory must hold 32 copies of the requested histogram range.
    const size_t sharedBytes =
        static_cast<size_t>(bins) * static_cast<size_t>(histogramCopies) * sizeof(unsigned int);

    // Size the grid from actual occupancy for this dynamic shared-memory footprint.
    // The kernel is grid-stride and large-input oriented, so one occupancy-saturating
    // wave is sufficient; each block consumes more work through the grid-stride loop.
    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1) {
        smCount = 1;
    }

    int activeBlocksPerSm = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSm,
        histogram_range_kernel<blockThreads, itemsPerThread>,
        blockThreads,
        sharedBytes);
    if (activeBlocksPerSm < 1) {
        activeBlocksPerSm = 1;
    }

    const size_t tileItems =
        static_cast<size_t>(blockThreads) * static_cast<size_t>(itemsPerThread);
    const size_t numTiles =
        (static_cast<size_t>(inputSize) + tileItems - 1) / tileItems;

    const int maxResidentGrid = smCount * activeBlocksPerSm;
    int grid = maxResidentGrid;
    if (numTiles < static_cast<size_t>(grid)) {
        grid = static_cast<int>(numTiles);
    }
    if (grid < 1) {
        grid = 1;
    }

    histogram_range_kernel<blockThreads, itemsPerThread>
        <<<grid, blockThreads, sharedBytes, stream>>>(input, histogram, inputSize, lower, bins);
}

#include <cuda_runtime.h>
#include <stdint.h>

namespace {

// Restricted byte histogram for modern NVIDIA data-center GPUs.
//
// Design summary:
//   - The output is histogram[bin] where bin = byte_value - from.
//   - Each block owns a privatized histogram in shared memory.
//   - To avoid shared-memory bank conflicts during updates, the block-private histogram is replicated
//     32 times. A thread uses copy `threadIdx.x % 32`.
//   - The requested layout is used exactly:
//         offset(bin, copy) = bin * 32 + copy
//     Because the bank index is the low 5 bits, copy `c` always lives in bank `c`, so a warp can
//     update the privatized histograms with no intra-warp bank conflicts.
//   - The tuned default `itemsPerThread = 16` is a good fit for A100/H100-class GPUs: it maps to one
//     aligned 16-byte vector load per thread while amortizing block init/reduction overhead.
//   - The grid is sized by occupancy because this is a grid-stride kernel; launching only enough
//     resident blocks minimizes the number of per-block global merge atomics.

constexpr int histogramCopies = 32;
constexpr int blockSize       = 256;
constexpr int itemsPerThread  = 16;

static_assert(histogramCopies == 32,
              "This kernel relies on exactly 32 shared-memory histogram copies.");
static_assert((blockSize % 32) == 0,
              "blockSize must be a multiple of 32 so whole warps map cleanly to the 32 copies.");
static_assert(itemsPerThread > 0,
              "itemsPerThread must be positive.");

__device__ __forceinline__ unsigned int warp_reduce_sum(unsigned int value)
{
    // Portable warp reduction; the merge phase is tiny relative to the byte-processing phase.
    #pragma unroll
    for (int offset = histogramCopies / 2; offset > 0; offset >>= 1) {
        value += __shfl_down_sync(0xFFFFFFFFu, value, offset, histogramCopies);
    }
    return value;
}

__device__ __forceinline__ void accumulate_byte(
    unsigned char value,
    unsigned int from_u,
    unsigned int range_u,
    unsigned int* __restrict__ shared_hist_lane)
{
    // One unsigned comparison implements the inclusive range test:
    //   bin = value - from
    //   bin < range   <=>   from <= value <= to
    //
    // The input is interpreted as unsigned bytes so signed `char` does not mis-handle values > 127.
    const unsigned int bin = static_cast<unsigned int>(value) - from_u;
    if (bin < range_u) {
        // `shared_hist_lane` already points at this thread's copy (lane/copy number),
        // so only the requested `bin * 32` stride remains.
        atomicAdd(shared_hist_lane + bin * histogramCopies, 1u);
    }
}

__device__ __forceinline__ void accumulate_packed_u32(
    uint32_t packed,
    unsigned int from_u,
    unsigned int range_u,
    unsigned int* __restrict__ shared_hist_lane)
{
    // The tuned path loads a `uint4` (16 bytes). Each 32-bit word contains 4 consecutive bytes.
    // NVIDIA GPUs are little-endian, so repeatedly consuming the low byte is the natural unpacking.
    #pragma unroll
    for (int i = 0; i < 4; ++i) {
        const unsigned int bin = (packed & 0xFFu) - from_u;
        if (bin < range_u) {
            atomicAdd(shared_hist_lane + bin * histogramCopies, 1u);
        }
        packed >>= 8;
    }
}

template<int ItemsPerThread>
struct ChunkProcessor {
    static __device__ __forceinline__ void full(
        const unsigned char* __restrict__ input,
        uint64_t idx,
        unsigned int from_u,
        unsigned int range_u,
        unsigned int* __restrict__ shared_hist_lane,
        bool /*can_vectorize*/)
    {
        // Generic fallback if `itemsPerThread` is changed away from the tuned default.
        #pragma unroll
        for (int i = 0; i < ItemsPerThread; ++i) {
            accumulate_byte(input[idx + static_cast<uint64_t>(i)],
                            from_u, range_u, shared_hist_lane);
        }
    }
};

template<>
struct ChunkProcessor<16> {
    static __device__ __forceinline__ void full(
        const unsigned char* __restrict__ input,
        uint64_t idx,
        unsigned int from_u,
        unsigned int range_u,
        unsigned int* __restrict__ shared_hist_lane,
        bool can_vectorize)
    {
        if (can_vectorize) {
            // Tuned default path: one aligned 16-byte global load per thread.
            const uint4 v = reinterpret_cast<const uint4*>(input + idx)[0];
            accumulate_packed_u32(v.x, from_u, range_u, shared_hist_lane);
            accumulate_packed_u32(v.y, from_u, range_u, shared_hist_lane);
            accumulate_packed_u32(v.z, from_u, range_u, shared_hist_lane);
            accumulate_packed_u32(v.w, from_u, range_u, shared_hist_lane);
            return;
        }

        // Robust fallback for the uncommon case where the caller passes a sub-pointer that is not
        // 16-byte aligned. Correctness is unchanged; only the vector-load fast path is disabled.
        #pragma unroll
        for (int i = 0; i < 16; ++i) {
            accumulate_byte(input[idx + static_cast<uint64_t>(i)],
                            from_u, range_u, shared_hist_lane);
        }
    }
};

template<int ItemsPerThread>
static __device__ __forceinline__ void process_tail_chunk(
    const unsigned char* __restrict__ input,
    uint64_t idx,
    uint64_t input_size,
    unsigned int from_u,
    unsigned int range_u,
    unsigned int* __restrict__ shared_hist_lane)
{
    // Only the final partial chunk for a thread reaches this path, so a simple unrolled scalar tail
    // is the best trade-off.
    #pragma unroll
    for (int i = 0; i < ItemsPerThread; ++i) {
        const uint64_t pos = idx + static_cast<uint64_t>(i);
        if (pos < input_size) {
            accumulate_byte(input[pos], from_u, range_u, shared_hist_lane);
        }
    }
}

template<int ItemsPerThread>
__global__ __launch_bounds__(blockSize)
void histogram_kernel(
    const char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    extern __shared__ unsigned int shared_hist[];

    const unsigned int from_u  = static_cast<unsigned int>(from);
    const unsigned int range_u = static_cast<unsigned int>(to - from) + 1u;

    // Copy selection required by the prompt: threadIdx.x % 32.
    const unsigned int lane = threadIdx.x & 31u;

    // Shared layout is:
    //   bin 0: copy0 copy1 ... copy31
    //   bin 1: copy0 copy1 ... copy31
    //   ...
    //
    // So `shared_hist_lane = shared_hist + lane` means all accesses by this thread are to:
    //   shared_hist[bin * 32 + lane]
    // Every warp lane maps to a unique bank, eliminating intra-warp bank conflicts.
    unsigned int* const shared_hist_lane = shared_hist + lane;

    const unsigned int shared_entries = range_u * histogramCopies;

    // Zero the block-private histogram copies.
    for (unsigned int i = threadIdx.x; i < shared_entries; i += blockDim.x) {
        shared_hist[i] = 0u;
    }
    __syncthreads();

    const unsigned char* const input_u8 = reinterpret_cast<const unsigned char*>(input);
    const uint64_t input_size  = static_cast<uint64_t>(inputSize);
    const uint64_t block_work  = static_cast<uint64_t>(blockDim.x) *
                                 static_cast<uint64_t>(ItemsPerThread);
    const uint64_t grid_stride = static_cast<uint64_t>(gridDim.x) * block_work;

    // Each thread owns a contiguous chunk of `itemsPerThread` bytes. Across a warp, those chunks are
    // adjacent, so the global loads are naturally coalesced.
    uint64_t idx = static_cast<uint64_t>(blockIdx.x) * block_work +
                   static_cast<uint64_t>(threadIdx.x) *
                   static_cast<uint64_t>(ItemsPerThread);

    // When ItemsPerThread == 16, every full chunk begins at a multiple of 16, so alignment of the
    // base pointer alone determines whether all full-chunk vector loads are legal.
    const bool can_vectorize =
        (ItemsPerThread == 16) &&
        ((reinterpret_cast<uintptr_t>(input_u8) & static_cast<uintptr_t>(0x0F)) == 0u);

    for (; idx + static_cast<uint64_t>(ItemsPerThread) <= input_size; idx += grid_stride) {
        ChunkProcessor<ItemsPerThread>::full(
            input_u8, idx, from_u, range_u, shared_hist_lane, can_vectorize);
    }

    if (idx < input_size) {
        process_tail_chunk<ItemsPerThread>(
            input_u8, idx, input_size, from_u, range_u, shared_hist_lane);
    }

    __syncthreads();

    // Final merge:
    // each warp reduces one bin at a time. Lane `c` reads copy `c`, so the readback is also
    // bank-conflict-free under the [bin * 32 + copy] layout.
    const unsigned int warp            = threadIdx.x >> 5;
    const unsigned int warps_per_block = blockDim.x >> 5;

    for (unsigned int bin = warp; bin < range_u; bin += warps_per_block) {
        unsigned int sum = shared_hist[bin * histogramCopies + lane];
        sum = warp_reduce_sum(sum);
        if (lane == 0u && sum != 0u) {
            // One global atomic per (block, bin) keeps expensive global serialization small.
            atomicAdd(histogram + bin, sum);
        }
    }
}

} // anonymous namespace

void run_histogram(
    const char* input,
    unsigned int* histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    // Output size is exactly the requested inclusive range [from, to].
    const unsigned int range = static_cast<unsigned int>(to - from) + 1u;

    // The kernel accumulates into global memory with atomicAdd, so the output histogram must start at 0.
    // This is intentionally asynchronous; the caller requested to handle synchronization externally.
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(range) * sizeof(unsigned int), 0);

    if (inputSize == 0u) {
        return;
    }

    // Shared memory required by the prompt:
    //   (to - from + 1) bins * 32 copies * sizeof(unsigned int)
    //
    // Worst case:
    //   256 bins * 32 copies * 4 bytes = 32 KiB
    //
    // That comfortably fits on modern GPUs, so no opt-in for >48 KiB dynamic shared memory is needed.
    const size_t sharedMemBytes =
        static_cast<size_t>(range) * histogramCopies * sizeof(unsigned int);

    // This kernel is shared-memory heavy and streams the input once. On A100/H100-class GPUs,
    // preferring shared memory over L1 is typically the right carveout.
    cudaFuncSetAttribute(
        histogram_kernel<itemsPerThread>,
        cudaFuncAttributePreferredSharedMemoryCarveout,
        100);

    // Because the kernel is grid-stride, launching only enough resident blocks to fill the machine
    // is better than launching one block per input tile: fewer blocks means fewer final global merges.
    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    int activeBlocksPerSm = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSm,
        histogram_kernel<itemsPerThread>,
        blockSize,
        sharedMemBytes);

    if (smCount < 1) {
        smCount = 1;
    }
    if (activeBlocksPerSm < 1) {
        activeBlocksPerSm = 1;
    }

    const uint64_t workPerBlock =
        static_cast<uint64_t>(blockSize) * static_cast<uint64_t>(itemsPerThread);
    const uint64_t blocksNeeded =
        (static_cast<uint64_t>(inputSize) + workPerBlock - 1ull) / workPerBlock;

    uint64_t grid = static_cast<uint64_t>(smCount) *
                    static_cast<uint64_t>(activeBlocksPerSm);
    if (grid > blocksNeeded) {
        grid = blocksNeeded;
    }
    if (grid == 0u) {
        grid = 1u;
    }

    // No explicit synchronization here; the caller asked for asynchronous behavior.
    histogram_kernel<itemsPerThread>
        <<<static_cast<unsigned int>(grid), blockSize, sharedMemBytes, 0>>>(
            input, histogram, inputSize, from, to);
}

#include <cuda_runtime.h>

namespace {

// 32 privatized histograms per block, one per warp lane / shared-memory bank.
constexpr int histogramCopies = 32;

// 256 threads is a good balance on A100/H100-class GPUs: enough occupancy for
// the 32 KB worst-case shared histogram while not creating excessive shared-atomic
// contention inside a block.
constexpr int blockSize = 256;

// Large-input default tuned for modern GPUs. 16 bytes/thread amortizes the
// per-block shared-memory init/final merge well, keeps register pressure modest,
// and lines up naturally with four 32-bit vectorized loads per thread.
constexpr int itemsPerThread = 16;

// The hot loop uses 32-bit vectorized loads from the cudaMalloc-provided input.
static_assert(sizeof(unsigned int) == 4, "This code assumes 32-bit unsigned int.");
constexpr int bytesPerVectorLoad = 4;
constexpr int vectorLoadsPerThread = itemsPerThread / bytesPerVectorLoad;
constexpr int warpsPerBlock = blockSize / histogramCopies;

static_assert(histogramCopies == 32, "This kernel is written for 32 shared histogram copies.");
static_assert(blockSize % histogramCopies == 0, "blockSize must be a multiple of 32.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert(itemsPerThread % bytesPerVectorLoad == 0,
              "itemsPerThread must stay a multiple of 4 to preserve vectorized loads.");

template <bool FullRange>
__device__ __forceinline__ void accumulate_byte(unsigned int value,
                                                unsigned int fromValue,
                                                unsigned int range,
                                                unsigned int lane,
                                                unsigned int *sharedHistogram);

template <>
__device__ __forceinline__ void accumulate_byte<true>(unsigned int value,
                                                      unsigned int /*fromValue*/,
                                                      unsigned int /*range*/,
                                                      unsigned int lane,
                                                      unsigned int *sharedHistogram) {
    atomicAdd(sharedHistogram + value * histogramCopies + lane, 1u);
}

template <>
__device__ __forceinline__ void accumulate_byte<false>(unsigned int value,
                                                       unsigned int fromValue,
                                                       unsigned int range,
                                                       unsigned int lane,
                                                       unsigned int *sharedHistogram) {
    // Unsigned subtraction turns "value < fromValue" into a large number, so the
    // single comparison below rejects both out-of-range cases.
    const unsigned int bin = value - fromValue;
    if (bin < range) {
        atomicAdd(sharedHistogram + bin * histogramCopies + lane, 1u);
    }
}

template <bool FullRange>
__device__ __forceinline__ void accumulate_word(unsigned int packed,
                                                unsigned int fromValue,
                                                unsigned int range,
                                                unsigned int lane,
                                                unsigned int *sharedHistogram) {
    accumulate_byte<FullRange>( packed        & 0xFFu, fromValue, range, lane, sharedHistogram);
    accumulate_byte<FullRange>((packed >>  8) & 0xFFu, fromValue, range, lane, sharedHistogram);
    accumulate_byte<FullRange>((packed >> 16) & 0xFFu, fromValue, range, lane, sharedHistogram);
    accumulate_byte<FullRange>( packed >> 24,          fromValue, range, lane, sharedHistogram);
}

__device__ __forceinline__ unsigned int warp_reduce_sum(unsigned int value) {
#pragma unroll
    for (int offset = histogramCopies / 2; offset > 0; offset >>= 1) {
        value += __shfl_down_sync(0xFFFFFFFFu, value, offset);
    }
    return value;
}

// Histogram kernel overview:
// 1. Each block allocates 32 privatized histograms in shared memory.
// 2. Copy c of bin i lives at sharedHistogram[i * 32 + c].
//    Because bank index is (address_in_words % 32), lane c always lands in bank c,
//    so a warp updating the same bin is free of shared-memory bank conflicts.
// 3. Threads update their lane's copy with shared-memory atomics.
// 4. At the end, one warp reduces the 32 copies of each bin via warp shuffles and
//    merges the per-block total into the global histogram.
template <bool FullRange>
__global__ __launch_bounds__(blockSize)
void histogram_kernel(const char * __restrict__ input,
                      unsigned int * __restrict__ histogram,
                      unsigned int inputSize,
                      unsigned int fromValue,
                      unsigned int range) {
    extern __shared__ unsigned int sharedHistogram[];

    const unsigned int lane = threadIdx.x & 31u;
    const unsigned int warp = threadIdx.x >> 5;

    const unsigned int sharedEntryCount = range * histogramCopies;
    for (unsigned int i = threadIdx.x; i < sharedEntryCount; i += blockSize) {
        sharedHistogram[i] = 0u;
    }
    __syncthreads();

    // The problem statement says the input buffer is cudaMalloc'ed, so this fast path
    // uses aligned 32-bit loads. If callers ever pass sub-slices, keeping them 4-byte
    // aligned preserves this path's intended behavior/performance.
    const unsigned char * __restrict__ bytes =
        reinterpret_cast<const unsigned char *>(input);
    const unsigned int * __restrict__ words =
        reinterpret_cast<const unsigned int *>(input);

    // Each block iteration processes blockSize * itemsPerThread bytes.
    // For each vector-load slot i, a warp reads 32 consecutive 32-bit words
    // (128 bytes), which is perfectly coalesced.
    const size_t wordCount = static_cast<size_t>(inputSize) / bytesPerVectorLoad;
    const size_t wordTileStride = static_cast<size_t>(blockSize) * vectorLoadsPerThread;
    const size_t gridWordStride = static_cast<size_t>(gridDim.x) * wordTileStride;
    const size_t fullWordTileLimit =
        (wordCount > static_cast<size_t>(blockSize) * (vectorLoadsPerThread - 1))
            ? (wordCount - static_cast<size_t>(blockSize) * (vectorLoadsPerThread - 1))
            : size_t{0};

    size_t wordBase = static_cast<size_t>(blockIdx.x) * wordTileStride + threadIdx.x;

    // Main path: all vector loads are in bounds, so the inner loop is branch-free.
    for (; wordBase < fullWordTileLimit; wordBase += gridWordStride) {
#pragma unroll
        for (int i = 0; i < vectorLoadsPerThread; ++i) {
            const unsigned int packed = words[wordBase + static_cast<size_t>(i) * blockSize];
            accumulate_word<FullRange>(packed, fromValue, range, lane, sharedHistogram);
        }
    }

    // Tail path for the final partial tile of 32-bit words.
    for (; wordBase < wordCount; wordBase += gridWordStride) {
#pragma unroll
        for (int i = 0; i < vectorLoadsPerThread; ++i) {
            const size_t wordIndex = wordBase + static_cast<size_t>(i) * blockSize;
            if (wordIndex < wordCount) {
                const unsigned int packed = words[wordIndex];
                accumulate_word<FullRange>(packed, fromValue, range, lane, sharedHistogram);
            }
        }
    }

    // Handle the final 0..3 bytes that do not form a full 32-bit word.
    // Only block 0 touches this suffix so the bytes are counted exactly once.
    const size_t tailByteBase = wordCount * bytesPerVectorLoad;
    if (blockIdx.x == 0u) {
        const size_t tailByteCount = static_cast<size_t>(inputSize) - tailByteBase;
        if (static_cast<size_t>(threadIdx.x) < tailByteCount) {
            accumulate_byte<FullRange>(
                static_cast<unsigned int>(bytes[tailByteBase + threadIdx.x]),
                fromValue,
                range,
                lane,
                sharedHistogram);
        }
    }

    __syncthreads();

    // Final merge:
    // Each warp reduces one bin at a time by reading the 32 privatized copies of
    // that bin. Lane c reads copy c, the warp sums via shuffles, and lane 0 merges
    // the per-block total into the global histogram.
    for (unsigned int bin = warp; bin < range; bin += warpsPerBlock) {
        unsigned int blockBinCount = sharedHistogram[bin * histogramCopies + lane];
        blockBinCount = warp_reduce_sum(blockBinCount);

        if (lane == 0u && blockBinCount != 0u) {
            if (gridDim.x == 1u) {
                // Fast path for tiny inputs that need only one block.
                histogram[bin] = blockBinCount;
            } else {
                atomicAdd(histogram + bin, blockBinCount);
            }
        }
    }
}

template <bool FullRange>
inline void launch_histogram_kernel(const char *input,
                                    unsigned int *histogram,
                                    unsigned int inputSize,
                                    unsigned int fromValue,
                                    unsigned int range,
                                    size_t sharedMemBytes) {
    // This kernel benefits more from shared-memory capacity/occupancy than from L1.
    // Request the shared-heavy carveout to maximize resident blocks, especially for
    // the worst-case 32 KB/block shared histogram.
    cudaFuncSetAttribute(histogram_kernel<FullRange>,
                         cudaFuncAttributePreferredSharedMemoryCarveout,
                         100);

    int device = 0;
    cudaGetDevice(&device);

    int smCount = 1;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    int activeBlocksPerSm = 1;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSm,
        histogram_kernel<FullRange>,
        blockSize,
        sharedMemBytes);

    if (smCount < 1) {
        smCount = 1;
    }
    if (activeBlocksPerSm < 1) {
        activeBlocksPerSm = 1;
    }

    // Launch only enough blocks to fill the machine. The grid-stride loop covers
    // the whole input, and limiting the grid avoids unnecessary per-block merges
    // into the global histogram.
    const size_t tileBytes = static_cast<size_t>(blockSize) * itemsPerThread;
    size_t launchBlocks = (static_cast<size_t>(inputSize) + tileBytes - 1u) / tileBytes;

    const size_t maxUsefulBlocks =
        static_cast<size_t>(smCount) * static_cast<size_t>(activeBlocksPerSm);

    if (launchBlocks > maxUsefulBlocks) {
        launchBlocks = maxUsefulBlocks;
    }
    if (launchBlocks == 0u) {
        launchBlocks = 1u;
    }

    histogram_kernel<FullRange>
        <<<static_cast<unsigned int>(launchBlocks), blockSize, sharedMemBytes>>>(
            input,
            histogram,
            inputSize,
            fromValue,
            range);
}

}  // namespace

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    // The output is defined as absolute counts for the requested range, so clear
    // it first. The caller explicitly handles synchronization, so this function
    // only enqueues work on the default stream.
    const unsigned int range = static_cast<unsigned int>(to - from + 1);
    cudaMemsetAsync(
        histogram,
        0,
        static_cast<size_t>(range) * sizeof(unsigned int),
        0);

    if (inputSize == 0u) {
        return;
    }

    // Dynamic shared memory holds 32 privatized copies of the requested histogram range.
    const size_t sharedMemBytes =
        static_cast<size_t>(range) * histogramCopies * sizeof(unsigned int);

    // range == 256 implies the full [0, 255] histogram; that specialization removes
    // the range test from the hot loop entirely.
    if (range == 256u) {
        launch_histogram_kernel<true>(
            input,
            histogram,
            inputSize,
            0u,
            range,
            sharedMemBytes);
    } else {
        launch_histogram_kernel<false>(
            input,
            histogram,
            inputSize,
            static_cast<unsigned int>(from),
            range,
            sharedMemBytes);
    }
}

#include <cuda_runtime.h>

// Tuned for modern datacenter GPUs (A100/H100 class).
// - 32 copies: one privatized histogram copy per warp lane / shared-memory bank.
// - 256 threads: 8 warps per block, a good balance between occupancy and per-copy contention.
// - 16 items/thread: 4096 input bytes per full block tile; this is a strong default for
//   large inputs because it amortizes loop overhead without needlessly increasing code size
//   or register pressure.
constexpr int histogramCopies = 32;
constexpr int blockThreads = 256;
constexpr int itemsPerThread = 16;

static_assert(histogramCopies == 32, "The bank-striped layout assumes 32 shared-memory banks.");
static_assert(blockThreads % histogramCopies == 0, "blockThreads must be a multiple of 32.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");

__device__ __forceinline__ unsigned int warp_reduce_sum(unsigned int x) {
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
        x += __shfl_down_sync(0xffffffffu, x, offset);
    }
    return x;
}

/*
  Range-restricted byte histogram.

  Design:
  - Input is treated as unsigned bytes so ordinal values 0..255 are handled correctly even if
    the host compiler's plain `char` is signed.
  - Each block owns 32 privatized histograms in shared memory.
  - Shared-memory layout is bank-striped:
        counter(bin, copy) -> sharedHistogram[bin * 32 + copy]
    For a thread with lane/copy `c`, every update goes to addresses:
        c, 32 + c, 64 + c, ...
    so that thread always touches the same bank, and a warp updating arbitrary bins remains
    bank-conflict free because lane `l` maps to bank `l` (modulo the base-bank offset).
  - The shared histogram lives for the whole grid-stride traversal and is flushed only once,
    which strongly amortizes initialization and global-atomic overhead on large inputs.
  - Final reduction uses one warp per bin: lane `l` reads copy `l`, then a warp shuffle sum
    produces the block contribution with no shared-memory bank conflicts.
*/
template <int ItemsPerThread>
__global__ __launch_bounds__(blockThreads)
void histogram_range_kernel(const char * __restrict__ input,
                            unsigned int * __restrict__ histogram,
                            unsigned int inputSize,
                            unsigned int from,
                            unsigned int numBins) {
    extern __shared__ unsigned int sharedHistogram[];

    const unsigned int tid = threadIdx.x;
    const unsigned int lane = tid & (histogramCopies - 1); // Equivalent to threadIdx.x % 32.
    const unsigned int warp = tid >> 5;                    // threadIdx.x / 32.
    const unsigned int warpsPerBlock = blockDim.x >> 5;

    const size_t totalSharedCounters = static_cast<size_t>(numBins) * histogramCopies;

    // Zero all 32 privatized histogram copies.
    for (size_t i = tid; i < totalSharedCounters; i += blockDim.x) {
        sharedHistogram[i] = 0u;
    }
    __syncthreads();

    const unsigned char *const inputBytes = reinterpret_cast<const unsigned char *>(input);

    // Each thread updates its own lane-selected histogram copy.
    unsigned int *const myHistogramCopy = sharedHistogram + lane;

    const size_t n = static_cast<size_t>(inputSize);
    const size_t threadStride = static_cast<size_t>(blockDim.x);
    const size_t blockItems = threadStride * ItemsPerThread;
    const size_t gridStrideItems = blockItems * static_cast<size_t>(gridDim.x);

    // Block-stride traversal over contiguous tiles. Within a tile, item `k` for thread `t`
    // reads tileBase + k * blockDim.x + t, so each warp performs coalesced byte loads.
    size_t tileBase = static_cast<size_t>(blockIdx.x) * blockItems;

    // Fast path for full tiles: no per-item bounds checks.
    for (; tileBase + blockItems <= n; tileBase += gridStrideItems) {
        size_t idx = tileBase + tid;

        #pragma unroll
        for (int item = 0; item < ItemsPerThread; ++item, idx += threadStride) {
            const unsigned int ch = inputBytes[idx];

            // Unsigned subtraction turns the inclusive [from, to] test into one range compare.
            const unsigned int bin = ch - from;
            if (bin < numBins) {
                atomicAdd(myHistogramCopy + static_cast<size_t>(bin) * histogramCopies, 1u);
            }
        }
    }

    // Tail tile.
    if (tileBase < n) {
        size_t idx = tileBase + tid;

        #pragma unroll
        for (int item = 0; item < ItemsPerThread; ++item, idx += threadStride) {
            if (idx < n) {
                const unsigned int ch = inputBytes[idx];
                const unsigned int bin = ch - from;
                if (bin < numBins) {
                    atomicAdd(myHistogramCopy + static_cast<size_t>(bin) * histogramCopies, 1u);
                }
            }
        }
    }

    __syncthreads();

    // Reduce the 32 copies back to the output histogram.
    // One warp owns one bin at a time, so lane `l` reads copy `l`; those 32 loads are
    // naturally bank conflict free with the requested bank-striped layout.
    for (unsigned int bin = warp; bin < numBins; bin += warpsPerBlock) {
        const unsigned int *const binCopies =
            sharedHistogram + static_cast<size_t>(bin) * histogramCopies;

        unsigned int blockCount = binCopies[lane];
        blockCount = warp_reduce_sum(blockCount);

        if (lane == 0) {
            if (gridDim.x == 1) {
                // Single-block launch: no global atomic needed.
                histogram[bin] = blockCount;
            } else if (blockCount != 0u) {
                atomicAdd(histogram + bin, blockCount);
            }
        }
    }
}

static inline unsigned int ceil_div_u32(unsigned int a, unsigned int b) {
    // Overflow-safe ceil(a / b) for 32-bit unsigned inputs.
    return a / b + ((a % b) != 0u);
}

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to) {
    const unsigned int fromU = static_cast<unsigned int>(from);
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);

    const size_t histogramBytes = static_cast<size_t>(numBins) * sizeof(unsigned int);

    // Dynamic shared memory stores 32 privatized copies of the requested histogram range.
    // Full-range worst case: 256 bins * 32 copies * 4 bytes = 32 KiB per block.
    const size_t sharedBytes =
        static_cast<size_t>(numBins) * histogramCopies * sizeof(unsigned int);

    // This function computes a fresh histogram, so clear the destination first.
    // No host-device synchronization is performed here; the caller handles it.
    cudaMemsetAsync(histogram, 0, histogramBytes, 0);

    if (inputSize == 0u) {
        return;
    }

    // Launch only a resident wave of blocks. Because each block keeps its privatized shared
    // histogram for the entire grid-stride traversal, this persistent-CTA style launch avoids
    // paying shared-memory setup/flush overhead more often than necessary.
    int activeBlocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &activeBlocksPerSM,
        histogram_range_kernel<itemsPerThread>,
        blockThreads,
        sharedBytes);

    if (activeBlocksPerSM < 1) {
        activeBlocksPerSM = 1;
    }

    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    if (smCount < 1) {
        smCount = 1;
    }

    const unsigned int blockItems = blockThreads * itemsPerThread;
    const unsigned int totalTiles = ceil_div_u32(inputSize, blockItems);
    const unsigned int maxResidentBlocks =
        static_cast<unsigned int>(activeBlocksPerSM) * static_cast<unsigned int>(smCount);
    const unsigned int gridBlocks =
        (totalTiles < maxResidentBlocks) ? totalTiles : maxResidentBlocks;

    histogram_range_kernel<itemsPerThread><<<gridBlocks, blockThreads, sharedBytes, 0>>>(
        input,
        histogram,
        inputSize,
        fromU,
        numBins);
}

#include <cuda_runtime.h>

// Range-restricted byte histogram optimized for modern NVIDIA data-center GPUs.
//
// Design:
// - Each block privatizes the requested histogram range in shared memory.
// - To eliminate shared-memory bank conflicts during updates, the shared histogram stores 32
//   interleaved copies. Copy c of bin b lives at s_hist[b * 32 + c], and thread t always updates
//   copy (t & 31). Within a warp, every lane therefore maps to a distinct bank.
// - Input is processed with a grid-stride loop. The compile-time constant itemsPerThread controls
//   how much input each thread consumes. 16 is a good default on A100/H100-class GPUs for this
//   shared-atomic-heavy kernel: it provides useful ILP without materially hurting occupancy.
// - Reduction back to global memory is done warp-by-warp: each warp reduces one bin at a time by
//   reading the 32 copies conflict-free, then emits a single global atomic add.
//
// Full-range worst-case shared-memory footprint:
// 256 bins * 32 copies * 4 bytes = 32 KiB per block.

constexpr int kHistogramCopies      = 32;
constexpr int kHistogramCopiesLog2  = 5;
constexpr unsigned int kCopyMask    = static_cast<unsigned int>(kHistogramCopies - 1);
constexpr int kBlockSize            = 256;
constexpr int kMinBlocksPerSM       = 5;
constexpr int itemsPerThread        = 16;
constexpr int kVectorWidth          = 4;
constexpr int kVectorsPerThread     = itemsPerThread / kVectorWidth;
constexpr unsigned int kFullWarpMask = 0xFFFFFFFFu;

static_assert(kHistogramCopies == (1 << kHistogramCopiesLog2),
              "kHistogramCopiesLog2 must match kHistogramCopies.");
static_assert((kHistogramCopies & (kHistogramCopies - 1)) == 0,
              "kHistogramCopies must be a power of two.");
static_assert(kBlockSize % kHistogramCopies == 0,
              "The block size must be a whole number of warps.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert(itemsPerThread % kVectorWidth == 0,
              "The vectorized load path requires itemsPerThread to be a multiple of 4.");

__device__ __forceinline__ unsigned int warp_reduce_sum(unsigned int value) {
    // Lane 0 receives the full sum; other lanes hold partial values, which is fine because only
    // lane 0 performs the final global atomic add.
#pragma unroll
    for (int offset = kHistogramCopies / 2; offset > 0; offset >>= 1) {
        value += __shfl_down_sync(kFullWarpMask, value, offset);
    }
    return value;
}

__device__ __forceinline__ void update_private_histogram(
    unsigned int* __restrict__ privateHist,
    const unsigned int from,
    const unsigned int numBins,
    const unsigned char value)
{
    // Unsigned subtraction folds both range checks into one compare:
    //   value in [from, from + numBins - 1]  <=>  (value - from) < numBins
    const unsigned int bin = static_cast<unsigned int>(value) - from;
    if (bin < numBins) {
        // privateHist already points at this thread's copy index (lane), so stepping by 32 lands on
        // the same copy for the next logical histogram bin:
        //   privateHist[bin * 32] == s_hist[bin * 32 + lane]
        atomicAdd(&privateHist[bin << kHistogramCopiesLog2], 1u);
    }
}

__device__ __forceinline__ void update_private_histogram4(
    unsigned int* __restrict__ privateHist,
    const unsigned int from,
    const unsigned int numBins,
    const uchar4 values)
{
    update_private_histogram(privateHist, from, numBins, values.x);
    update_private_histogram(privateHist, from, numBins, values.y);
    update_private_histogram(privateHist, from, numBins, values.z);
    update_private_histogram(privateHist, from, numBins, values.w);
}

__global__ __launch_bounds__(kBlockSize, kMinBlocksPerSM)
void range_histogram_kernel(const char* __restrict__ input,
                            unsigned int* __restrict__ histogram,
                            const unsigned int inputSize,
                            const unsigned int from,
                            const unsigned int numBins)
{
    extern __shared__ unsigned int s_hist[];

    const unsigned int tid           = threadIdx.x;
    const unsigned int lane          = tid & kCopyMask;
    const unsigned int warpId        = tid >> kHistogramCopiesLog2;
    const unsigned int warpsPerBlock = blockDim.x >> kHistogramCopiesLog2;

    // Offset the shared histogram base by the thread's copy index. This lets the hot update path
    // use a single shifted index per bin.
    unsigned int* const privateHist = s_hist + lane;

    // Zero the block-private histogram copies.
    const unsigned int sharedWords = numBins << kHistogramCopiesLog2;
    for (unsigned int i = tid; i < sharedWords; i += blockDim.x) {
        s_hist[i] = 0u;
    }
    __syncthreads();

    const unsigned char* __restrict__ input_u8 =
        reinterpret_cast<const unsigned char*>(input);

    // The API contract states that input points to a cudaMalloc allocation, so the base pointer is
    // naturally aligned. Because each thread starts at a 4-byte-aligned index and advances in
    // 4-byte steps, these uchar4 loads stay aligned and reduce load instruction count.
    const uchar4* __restrict__ input_vec =
        reinterpret_cast<const uchar4*>(input_u8);

    const unsigned long long inputSize64 =
        static_cast<unsigned long long>(inputSize);

    const unsigned long long blockVectorStride =
        static_cast<unsigned long long>(blockDim.x) * static_cast<unsigned long long>(kVectorWidth);
    const unsigned long long workPerBlock =
        blockVectorStride * static_cast<unsigned long long>(kVectorsPerThread);

    const unsigned long long base0 =
        static_cast<unsigned long long>(blockIdx.x) * workPerBlock +
        static_cast<unsigned long long>(tid) * static_cast<unsigned long long>(kVectorWidth);

    const unsigned long long gridStride =
        static_cast<unsigned long long>(gridDim.x) * workPerBlock;

    // Grid-stride traversal of the input.
    for (unsigned long long base = base0; base < inputSize64; base += gridStride) {
#pragma unroll
        for (int v = 0; v < kVectorsPerThread; ++v) {
            const unsigned long long idx64 =
                base + static_cast<unsigned long long>(v) * blockVectorStride;

            if (idx64 < inputSize64) {
                const unsigned int idx = static_cast<unsigned int>(idx64);
                const unsigned int remaining = inputSize - idx;

                if (remaining >= static_cast<unsigned int>(kVectorWidth)) {
                    const uchar4 bytes = input_vec[idx >> 2];
                    update_private_histogram4(privateHist, from, numBins, bytes);
                } else {
                    // Final partial vector near EOF.
                    const unsigned char* const tail = input_u8 + idx;
                    if (remaining > 0u) update_private_histogram(privateHist, from, numBins, tail[0]);
                    if (remaining > 1u) update_private_histogram(privateHist, from, numBins, tail[1]);
                    if (remaining > 2u) update_private_histogram(privateHist, from, numBins, tail[2]);
                }
            }
        }
    }

    __syncthreads();

    // Conflict-free reduction of the 32 copies:
    // one warp handles one logical bin at a time, and lane c reads copy c.
    for (unsigned int bin = warpId; bin < numBins; bin += warpsPerBlock) {
        const unsigned int binBase = bin << kHistogramCopiesLog2;
        unsigned int count = s_hist[binBase + lane];
        count = warp_reduce_sum(count);

        if (lane == 0u && count != 0u) {
            atomicAdd(&histogram[bin], count);
        }
    }
}

void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // Precondition from the interface contract:
    //   - input and histogram are device pointers allocated with cudaMalloc
    //   - 0 <= from < to <= 255
    // The caller also owns synchronization, so this function only enqueues work.

    const unsigned int fromU   = static_cast<unsigned int>(from);
    const unsigned int numBins = static_cast<unsigned int>(to - from + 1);

    // The kernel only accumulates, so start from a clean output histogram.
    const cudaStream_t stream = 0;
    cudaMemsetAsync(histogram,
                    0,
                    static_cast<size_t>(numBins) * sizeof(unsigned int),
                    stream);

    if (inputSize == 0u) {
        return;
    }

    // Favor a shared-memory-heavy carveout: this kernel is dominated by shared atomics while the
    // input read stream is one-pass and cache-light. This is a performance hint, not a requirement.
    (void)cudaFuncSetAttribute(range_histogram_kernel,
                               cudaFuncAttributePreferredSharedMemoryCarveout,
                               100);

    // Shared memory requested in the prompt: 32 copies of the selected histogram range.
    // Worst case (full 0..255 range) is 32 KiB/block, so no max-dynamic-shmem opt-in is needed.
    const size_t sharedBytes =
        static_cast<size_t>(numBins) *
        static_cast<size_t>(kHistogramCopies) *
        sizeof(unsigned int);

    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    if (smCount < 1) {
        smCount = 1;
    }

    int activeBlocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(&activeBlocksPerSM,
                                                  range_histogram_kernel,
                                                  kBlockSize,
                                                  sharedBytes);
    if (activeBlocksPerSM < 1) {
        activeBlocksPerSM = 1;
    }

    int gridSize = smCount * activeBlocksPerSM;

    // Avoid launching blocks that would only pay the shared-histogram init/reduction cost without
    // owning any initial input tile.
    const unsigned long long workPerBlock =
        static_cast<unsigned long long>(kBlockSize) *
        static_cast<unsigned long long>(itemsPerThread);

    const int maxUsefulBlocks = static_cast<int>(
        (static_cast<unsigned long long>(inputSize) + workPerBlock - 1ull) / workPerBlock);

    if (gridSize > maxUsefulBlocks) {
        gridSize = maxUsefulBlocks;
    }
    if (gridSize < 1) {
        gridSize = 1;
    }

    range_histogram_kernel<<<gridSize, kBlockSize, sharedBytes, stream>>>(
        input,
        histogram,
        inputSize,
        fromU,
        numBins);
}

#include <cuda_runtime.h>
#include <stdint.h>

// Tuned defaults for recent datacenter GPUs (A100/H100 class):
// - 16 bytes/thread maps to one aligned uint4 load per thread.
// - 256 threads/block keeps plenty of warps resident while limiting contention
//   on the 32 bank-striped shared-memory histogram copies.
constexpr int itemsPerThread   = 16;
constexpr int histogramCopies  = 32;
constexpr int threadsPerBlock  = 256;
constexpr int vectorWidthBytes = sizeof(uint4);
constexpr int vectorChunkCount = itemsPerThread / vectorWidthBytes;

static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert((itemsPerThread % vectorWidthBytes) == 0,
              "itemsPerThread must stay a multiple of 16 so each thread can use aligned uint4 loads.");
static_assert(histogramCopies == 32,
              "The bank-conflict avoidance scheme relies on exactly 32 shared-memory histogram copies.");

__device__ __forceinline__ void update_private_histogram(
    unsigned int byte,
    unsigned int from_u,
    unsigned int range,
    unsigned int* privateCopy)
{
    // Unsigned subtraction turns the range test into a single comparison:
    // byte in [from, to]  <=>  (byte - from) < range.
    const unsigned int rel = byte - from_u;
    if (rel < range) {
        // privateCopy points to the thread's bank-striped copy:
        // bin b lives at privateCopy[b * 32], which is s_hist[b * 32 + copy].
        atomicAdd(&privateCopy[rel * histogramCopies], 1u);
    }
}

__device__ __forceinline__ void accumulate_word_bytes(
    unsigned int word,
    unsigned int from_u,
    unsigned int range,
    unsigned int* privateCopy)
{
    update_private_histogram( word        & 0xFFu, from_u, range, privateCopy);
    update_private_histogram((word >>  8) & 0xFFu, from_u, range, privateCopy);
    update_private_histogram((word >> 16) & 0xFFu, from_u, range, privateCopy);
    update_private_histogram((word >> 24) & 0xFFu, from_u, range, privateCopy);
}

__device__ __forceinline__ void accumulate_uint4_bytes(
    uint4 v,
    unsigned int from_u,
    unsigned int range,
    unsigned int* privateCopy)
{
    accumulate_word_bytes(v.x, from_u, range, privateCopy);
    accumulate_word_bytes(v.y, from_u, range, privateCopy);
    accumulate_word_bytes(v.z, from_u, range, privateCopy);
    accumulate_word_bytes(v.w, from_u, range, privateCopy);
}

__device__ __forceinline__ void load_and_accumulate_uint4(
    const char* ptr,
    unsigned int from_u,
    unsigned int range,
    unsigned int* privateCopy)
{
    // The input buffer is allocated by cudaMalloc, so it is naturally well aligned.
    // With itemsPerThread kept as a multiple of 16, every thread chunk start is also
    // 16-byte aligned, which lets the fast path use a single uint4 load.
    const uint4 v = *reinterpret_cast<const uint4*>(ptr);
    accumulate_uint4_bytes(v, from_u, range, privateCopy);
}

__global__ __launch_bounds__(threadsPerBlock)
void histogram_kernel(
    const char* __restrict__ input,
    unsigned int* __restrict__ histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    extern __shared__ unsigned int s_hist[];

    // Shared-memory layout:
    //   s_hist[bin * 32 + copy]
    // For any fixed bin, copies 0..31 map one-to-one onto the 32 shared-memory banks.
    // Each thread always updates copy = threadIdx.x % 32, eliminating intra-warp bank
    // conflicts even when many lanes hit the same logical bin.
    const unsigned int range  = static_cast<unsigned int>(to - from + 1);
    const unsigned int from_u = static_cast<unsigned int>(from);
    const unsigned int tid    = threadIdx.x;
    const unsigned int copy   = tid & (histogramCopies - 1);

    unsigned int* const privateCopy = s_hist + copy;

    // Initialize all 32 copies of the block-private histogram.
    const unsigned int sharedBins = range * histogramCopies;
    for (unsigned int i = tid; i < sharedBins; i += blockDim.x) {
        s_hist[i] = 0u;
    }
    __syncthreads();

    const size_t inputSize64      = static_cast<size_t>(inputSize);
    const size_t threadChunkBytes = static_cast<size_t>(itemsPerThread);
    const size_t vectorWidth      = static_cast<size_t>(vectorWidthBytes);

    const size_t globalThread =
        static_cast<size_t>(blockIdx.x) * static_cast<size_t>(blockDim.x) + static_cast<size_t>(tid);
    const size_t start  = globalThread * threadChunkBytes;
    const size_t stride =
        static_cast<size_t>(gridDim.x) * static_cast<size_t>(blockDim.x) * threadChunkBytes;

    // Grid-stride loop over per-thread chunks.
    for (size_t base = start; base < inputSize64; base += stride) {
        const size_t remaining = inputSize64 - base;

        if (remaining >= threadChunkBytes) {
            // Fast path: the whole per-thread chunk is available.
            #pragma unroll
            for (int chunk = 0; chunk < vectorChunkCount; ++chunk) {
                const size_t chunkOffset = static_cast<size_t>(chunk) * vectorWidth;
                load_and_accumulate_uint4(input + base + chunkOffset, from_u, range, privateCopy);
            }
        } else {
            // Tail path for the last partial chunk seen by this grid-stride thread.
            #pragma unroll
            for (int chunk = 0; chunk < vectorChunkCount; ++chunk) {
                const size_t chunkOffset = static_cast<size_t>(chunk) * vectorWidth;
                if (chunkOffset < remaining) {
                    const size_t chunkRemaining = remaining - chunkOffset;

                    if (chunkRemaining >= vectorWidth) {
                        load_and_accumulate_uint4(input + base + chunkOffset, from_u, range, privateCopy);
                    } else {
                        // Scalar tail uses unsigned-char conversion to avoid sign extension.
                        #pragma unroll
                        for (int i = 0; i < vectorWidthBytes; ++i) {
                            if (static_cast<size_t>(i) < chunkRemaining) {
                                update_private_histogram(
                                    static_cast<unsigned char>(input[base + chunkOffset + static_cast<size_t>(i)]),
                                    from_u,
                                    range,
                                    privateCopy);
                            }
                        }
                    }
                }
            }
        }
    }

    __syncthreads();

    // Merge the 32 bank-striped copies into the final global histogram.
    // bin is relative to 'from': histogram[0] counts byte value 'from'.
    for (unsigned int bin = tid; bin < range; bin += blockDim.x) {
        const unsigned int* const binCopies = s_hist + bin * histogramCopies;

        // Four independent accumulation chains reduce dependency depth a bit.
        unsigned int sum0 = 0u;
        unsigned int sum1 = 0u;
        unsigned int sum2 = 0u;
        unsigned int sum3 = 0u;

        #pragma unroll
        for (int c = 0; c < histogramCopies; c += 4) {
            sum0 += binCopies[c + 0];
            sum1 += binCopies[c + 1];
            sum2 += binCopies[c + 2];
            sum3 += binCopies[c + 3];
        }

        const unsigned int sum = (sum0 + sum1) + (sum2 + sum3);
        if (sum != 0u) {
            atomicAdd(&histogram[bin], sum);
        }
    }
}

void run_histogram(
    const char* input,
    unsigned int* histogram,
    unsigned int inputSize,
    int from,
    int to)
{
    // Fresh result, not accumulation into a previous histogram.
    // The caller owns synchronization; this function only enqueues work on the default stream.
    const unsigned int range = static_cast<unsigned int>(to - from + 1);
    cudaMemsetAsync(histogram, 0, static_cast<size_t>(range) * sizeof(unsigned int), 0);

    if (inputSize == 0u) {
        return;
    }

    // Dynamic shared memory must hold 32 bank-striped copies of the requested sub-histogram.
    const size_t sharedMemBytes =
        static_cast<size_t>(range) * static_cast<size_t>(histogramCopies) * sizeof(unsigned int);

    // Launch only enough blocks to fill resident capacity. The kernel is grid-stride, so
    // extra blocks would mostly add overhead and increase the number of final global atomics.
    int device = 0;
    int smCount = 1;
    int blocksPerSM = 1;
    cudaGetDevice(&device);
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &blocksPerSM,
        histogram_kernel,
        threadsPerBlock,
        sharedMemBytes);

    const unsigned long long workPerBlock =
        static_cast<unsigned long long>(threadsPerBlock) * static_cast<unsigned long long>(itemsPerThread);
    const unsigned long long blocksNeeded =
        (static_cast<unsigned long long>(inputSize) + workPerBlock - 1ull) / workPerBlock;
    const unsigned long long maxResidentGrid =
        static_cast<unsigned long long>(smCount) * static_cast<unsigned long long>(blocksPerSM);

    int grid = static_cast<int>(blocksNeeded < maxResidentGrid ? blocksNeeded : maxResidentGrid);
    if (grid < 1) {
        grid = 1;
    }

    histogram_kernel<<<grid, threadsPerBlock, sharedMemBytes>>>(
        input, histogram, inputSize, from, to);
}

#include <cuda_runtime.h>
#include <cstddef>
#include <cstdint>

// Restricted-range text histogram for modern NVIDIA data-center GPUs:
//  1) Each block builds a block-private histogram in shared memory.
//  2) The shared histogram is replicated 32 times and bank-striped so that
//     bin i of copy c is stored at offset i * 32 + c.
//  3) Each thread always updates copy (threadIdx.x % 32), eliminating intra-warp
//     shared-memory bank conflicts even when many threads hit the same bin.
//  4) Blocks process the input in a persistent grid-stride loop and merge their
//     block-local histograms into the global output with one atomic add per bin.
//
// Controls how many input characters each thread processes per grid-stride
// iteration. For large inputs on A100/H100-class GPUs, 16 is a good default:
// it maps the hot path to one aligned 16-byte uint4 load per thread while
// keeping shared-memory atomic pressure and register use in a good balance.
constexpr int itemsPerThread = 16;

namespace {

// 256 threads = 8 warps, which is a good compromise between occupancy and
// per-copy contention, and it also matches the maximum possible histogram
// length (256 bins) so the epilogue can assign one thread to one bin.
constexpr int kBlockThreads = 256;

// One copy per warp lane / shared-memory bank.
constexpr unsigned int kHistogramCopies = 32u;
constexpr unsigned int kLaneMask        = kHistogramCopies - 1u;

// Vector width for the input hot path: one uint4 = 16 bytes.
constexpr int kBytesPerVector  = 16;
constexpr int kVectorsPerThread = itemsPerThread / kBytesPerVector;

// Bytes processed by one block per grid-stride iteration.
constexpr size_t kBlockWork = static_cast<size_t>(kBlockThreads) * itemsPerThread;

static_assert(sizeof(unsigned int) == 4,
              "The bank-striped shared-memory layout assumes 4-byte counters.");
static_assert(sizeof(uint4) == kBytesPerVector, "Unexpected uint4 size.");
static_assert(kHistogramCopies == 32u,
              "The bank-striped layout is defined for exactly 32 copies.");
static_assert(kBlockThreads % 32 == 0,
              "Block size should be a whole number of warps.");
static_assert(itemsPerThread > 0, "itemsPerThread must be positive.");
static_assert(itemsPerThread % kBytesPerVector == 0,
              "itemsPerThread must be a multiple of 16 for the uint4 input path.");

__device__ __forceinline__
void accumulate_byte(const unsigned int value,
                     unsigned int* const threadCopy,
                     const unsigned int rangeBegin,
                     const unsigned int rangeLen)
{
    // Unsigned subtraction turns the inclusive range check
    // [rangeBegin, rangeBegin + rangeLen - 1] into one comparison.
    // Values below rangeBegin underflow to a large unsigned number and fail.
    const unsigned int bin = value - rangeBegin;
    if (bin < rangeLen) {
        // threadCopy already points at this thread's copy column (copy = lane),
        // so stepping by 32 moves between bins while keeping the same copy:
        // address = (bin * 32) + lane.
        atomicAdd(&threadCopy[bin * kHistogramCopies], 1u);
    }
}

__device__ __forceinline__
void accumulate_packed_u32(const uint32_t packed,
                           unsigned int* const threadCopy,
                           const unsigned int rangeBegin,
                           const unsigned int rangeLen)
{
    // CUDA GPUs are little-endian, so the least-significant byte is the
    // earliest character in memory for the 32-bit word loaded through uint4.
    accumulate_byte( packed        & 0xFFu, threadCopy, rangeBegin, rangeLen);
    accumulate_byte((packed >>  8) & 0xFFu, threadCopy, rangeBegin, rangeLen);
    accumulate_byte((packed >> 16) & 0xFFu, threadCopy, rangeBegin, rangeLen);
    accumulate_byte((packed >> 24) & 0xFFu, threadCopy, rangeBegin, rangeLen);
}

__device__ __forceinline__
void accumulate_uint4(const uint4 packed16,
                      unsigned int* const threadCopy,
                      const unsigned int rangeBegin,
                      const unsigned int rangeLen)
{
    accumulate_packed_u32(packed16.x, threadCopy, rangeBegin, rangeLen);
    accumulate_packed_u32(packed16.y, threadCopy, rangeBegin, rangeLen);
    accumulate_packed_u32(packed16.z, threadCopy, rangeBegin, rangeLen);
    accumulate_packed_u32(packed16.w, threadCopy, rangeBegin, rangeLen);
}

__global__ __launch_bounds__(kBlockThreads)
void histogram_kernel(const char* __restrict__ input,
                      unsigned int* __restrict__ histogram,
                      const unsigned int inputSize,
                      const unsigned int rangeBegin,
                      const unsigned int rangeLen)
{
    // Dynamic shared storage for 32 bank-striped copies of only the active range.
    // Layout: sharedHist[bin * 32 + copy].
    extern __shared__ unsigned int sharedHist[];

    const unsigned int tid  = static_cast<unsigned int>(threadIdx.x);
    const size_t tid64      = static_cast<size_t>(tid);
    const unsigned int lane = tid & kLaneMask;  // Equivalent to threadIdx.x % 32.

    // Each thread always targets its lane-selected copy. Within a warp, if all
    // threads hit the same bin, they still touch 32 distinct banks because the
    // copy index differs by lane. Threads from different warps but the same lane
    // still share a copy, so shared-memory atomics remain necessary.
    unsigned int* const threadCopy = sharedHist + lane;

    const unsigned int sharedBins = rangeLen * kHistogramCopies;

    // Cooperative shared-memory initialization for the privatized histogram.
    for (unsigned int i = tid; i < sharedBins; i += kBlockThreads) {
        sharedHist[i] = 0u;
    }
    __syncthreads();

    // Interpret input as bytes in [0, 255] regardless of whether host-side
    // char is signed or unsigned.
    const unsigned char* const inputBytes = reinterpret_cast<const unsigned char*>(input);

    // The problem statement says the buffers are cudaMalloc-allocated; that
    // alignment is sufficient for the aligned uint4 load path below.
    const uint4* const inputVec = reinterpret_cast<const uint4*>(input);

    const size_t inputSizeSz = static_cast<size_t>(inputSize);
    const size_t gridStride  = static_cast<size_t>(gridDim.x) * kBlockWork;

    // The hot path updates shared memory only; global memory is touched just
    // once per bin in the epilogue.
    size_t chunkBase = static_cast<size_t>(blockIdx.x) * kBlockWork;

    // Full chunks: no bounds checks in the vectorized hot path.
    for (; chunkBase + kBlockWork <= inputSizeSz; chunkBase += gridStride) {
        const size_t vectorBase = chunkBase / kBytesPerVector;

        #pragma unroll
        for (int vec = 0; vec < kVectorsPerThread; ++vec) {
            const size_t vectorIndex =
                vectorBase + tid64 + static_cast<size_t>(vec) * kBlockThreads;
            const uint4 packed = inputVec[vectorIndex];
            accumulate_uint4(packed, threadCopy, rangeBegin, rangeLen);
        }
    }

    // Optional final partial chunk for this block.
    if (chunkBase < inputSizeSz) {
        const size_t vectorBase = chunkBase / kBytesPerVector;

        #pragma unroll
        for (int vec = 0; vec < kVectorsPerThread; ++vec) {
            const size_t vectorIndex =
                vectorBase + tid64 + static_cast<size_t>(vec) * kBlockThreads;
            const size_t byteIndex = vectorIndex * kBytesPerVector;

            if (byteIndex + kBytesPerVector <= inputSizeSz) {
                const uint4 packed = inputVec[vectorIndex];
                accumulate_uint4(packed, threadCopy, rangeBegin, rangeLen);
            } else {
                // The very end of the input may not fill a whole uint4.
                #pragma unroll
                for (int byte = 0; byte < kBytesPerVector; ++byte) {
                    const size_t idx = byteIndex + static_cast<size_t>(byte);
                    if (idx < inputSizeSz) {
                        accumulate_byte(static_cast<unsigned int>(inputBytes[idx]),
                                        threadCopy,
                                        rangeBegin,
                                        rangeLen);
                    }
                }
            }
        }
    }

    __syncthreads();

    // Final merge: because the legal range has at most 256 bins and the block
    // size is 256, one thread can reduce one bin across the 32 shared copies.
    if (tid < rangeLen) {
        const unsigned int base = tid * kHistogramCopies;
        unsigned int sum = 0u;

        #pragma unroll
        for (unsigned int copy = 0; copy < kHistogramCopies; ++copy) {
            sum += sharedHist[base + copy];
        }

        // One global atomic add per bin per block.
        if (sum != 0u) {
            atomicAdd(&histogram[tid], sum);
        }
    }
}

}  // namespace

void run_histogram(const char* input,
                   unsigned int* histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // Histogram length is the inclusive character range [from, to].
    const unsigned int rangeBegin = static_cast<unsigned int>(from);
    const unsigned int rangeLen   = static_cast<unsigned int>(to - from + 1);

    // The kernel merges block-local histograms into global memory with atomic
    // adds, so the output must be cleared first. This is enqueued on stream 0;
    // the interface has no stream parameter and the caller requested that
    // synchronization be handled externally.
    const size_t histogramBytes = static_cast<size_t>(rangeLen) * sizeof(unsigned int);
    cudaMemsetAsync(histogram, 0, histogramBytes, 0);

    if (inputSize == 0u) {
        return;
    }

    // Dynamic shared memory for 32 copies of only the active histogram range.
    // Worst case: 256 bins * 32 copies * 4 bytes = 32 KiB, so no opt-in for
    // >48 KiB dynamic shared memory is needed.
    const size_t sharedBytes = histogramBytes * kHistogramCopies;

    // Persistent-CTA style launch: cap the grid at the number of concurrently
    // resident blocks. That keeps the GPU full while minimizing per-block
    // shared-histogram init/finalize overhead and reducing the number of global
    // atomic merges in the epilogue.
    int device = 0;
    cudaGetDevice(&device);

    int smCount = 0;
    cudaDeviceGetAttribute(&smCount, cudaDevAttrMultiProcessorCount, device);

    int blocksPerSM = 0;
    cudaOccupancyMaxActiveBlocksPerMultiprocessor(&blocksPerSM,
                                                  histogram_kernel,
                                                  kBlockThreads,
                                                  sharedBytes);

    const int maxResidentBlocks =
        (smCount > 0 && blocksPerSM > 0) ? (smCount * blocksPerSM) : 1;

    const uint64_t blockWork = static_cast<uint64_t>(kBlockWork);
    const uint64_t blocksNeeded =
        (static_cast<uint64_t>(inputSize) + blockWork - 1ULL) / blockWork;

    const uint64_t launchBlocks64 =
        (blocksNeeded < static_cast<uint64_t>(maxResidentBlocks))
            ? blocksNeeded
            : static_cast<uint64_t>(maxResidentBlocks);

    int gridBlocks = static_cast<int>(launchBlocks64);
    if (gridBlocks < 1) {
        gridBlocks = 1;
    }

    // Launch on stream 0; caller owns synchronization and any post-launch
    // error checking.
    histogram_kernel<<<gridBlocks, kBlockThreads, sharedBytes>>>(
        input,
        histogram,
        inputSize,
        rangeBegin,
        rangeLen);
}
